def get_record_book_boss_catalog() -> list[dict[str, str | bool]]:
    catalog: list[dict[str, str | bool]] = []
    added_bosses: set[str] = set()
    absolute_bosses = sorted(
        RECORD_BOOK_ABSOLUTE_BOSSES,
        key=lambda boss_name: (
            RECORD_BOOK_AREAS.index(RECORD_BOOK_ABSOLUTE_SOURCE_AREAS.get(
                boss_name,
                next((area for area, bosses in RECORD_BOOK_BOSS_ORDER.items() if boss_name in bosses), "요툰하임"),
            ))
            if RECORD_BOOK_ABSOLUTE_SOURCE_AREAS.get(
                boss_name,
                next((area for area, bosses in RECORD_BOOK_BOSS_ORDER.items() if boss_name in bosses), "요툰하임"),
            ) in RECORD_BOOK_AREAS
            else len(RECORD_BOOK_AREAS),
            boss_name,
        ),
    )
    for boss_name in absolute_bosses:
        source_area = RECORD_BOOK_ABSOLUTE_SOURCE_AREAS.get(
            boss_name,
            next((area for area, bosses in RECORD_BOOK_BOSS_ORDER.items() if boss_name in bosses), "절대자"),
        )
        catalog.append(
            {
                "boss_name": boss_name,
                "source_area": source_area,
                "display_area": "절대자",
                "chapter_label": RECORD_BOOK_CHAPTER_LABELS.get(source_area, RECORD_BOOK_CHAPTER_LABELS["절대자"]),
                "absolute": True,
            }
        )
        added_bosses.add(boss_name)
    for area in RECORD_BOOK_AREAS:
        for boss_name in RECORD_BOOK_BOSS_ORDER.get(area, []):
            if boss_name in added_bosses:
                continue
            catalog.append(
                {
                    "boss_name": boss_name,
                    "source_area": area,
                    "display_area": area,
                    "chapter_label": RECORD_BOOK_CHAPTER_LABELS.get(area, area),
                    "absolute": False,
                }
            )
            added_bosses.add(boss_name)
    return catalog


def _read_build_metadata_file() -> dict[str, str]:
    for base_dir in (get_resource_root(), get_app_root()):
        metadata_path = os.path.join(base_dir, BUILD_METADATA_FILENAME)
        if not os.path.exists(metadata_path):
            continue
        try:
            with open(metadata_path, "r", encoding="utf-8") as metadata_file:
                loaded = json.load(metadata_file)
        except (OSError, json.JSONDecodeError):
            continue
        if isinstance(loaded, dict):
            return {str(key): str(value) for key, value in loaded.items() if value}
    return {}


def _run_git_text_command(args: list[str]) -> str | None:
    repo_root = get_app_root()
    if not os.path.isdir(os.path.join(repo_root, ".git")):
        return None
    try:
        completed = subprocess.run(
            ["git", *args],
            cwd=repo_root,
            capture_output=True,
            text=True,
            encoding="utf-8",
            check=True,
        )
    except (OSError, subprocess.SubprocessError):
        return None
    value = completed.stdout.strip()
    return value or None


def load_build_metadata() -> dict[str, str]:
    metadata = {
        "author": DEFAULT_AUTHOR_NAME,
        "version": DEFAULT_APP_VERSION,
        "last_updated": DEFAULT_LAST_UPDATED,
        "build_detail_version": DEFAULT_BUILD_DETAIL_VERSION,
        "build_timestamp": DEFAULT_BUILD_TIMESTAMP,
    }
    metadata.update(_read_build_metadata_file())
    latest_tag = _run_git_text_command(["tag", "--sort=-creatordate"])
    if latest_tag:
        metadata["version"] = latest_tag.splitlines()[0].strip() or metadata["version"]
    detailed_version = _run_git_text_command(["describe", "--tags", "--always", "--dirty"])
    if detailed_version:
        metadata["build_detail_version"] = detailed_version
    latest_commit_date = _run_git_text_command(["log", "-1", "--format=%cs"])
    if latest_commit_date:
        metadata["last_updated"] = latest_commit_date
    latest_commit_datetime = _run_git_text_command(["log", "-1", "--format=%cd", "--date=format:%Y-%m-%d %H:%M:%S"])
    if latest_commit_datetime:
        metadata["build_timestamp"] = latest_commit_datetime
    return metadata


