def get_builtin_background_path(background_key: str) -> str:
    parts = BUILTIN_BACKGROUNDS.get(background_key, BUILTIN_BACKGROUNDS[DEFAULT_BG_KEY])
    return os.path.join(get_resource_root(), *parts)


def get_background_key_from_legacy_path(path: str) -> str | None:
    normalized_name = os.path.basename(path)
    for background_key, parts in BUILTIN_BACKGROUNDS.items():
        if normalized_name == parts[-1]:
            return background_key
    return None


def get_button_icon_path(icon_key: str, state: str = "normal") -> str:
    parts = BUTTON_ICON_FILES[icon_key][state]
    return os.path.join(get_resource_root(), *parts)


def get_png_image_size(path: str) -> tuple[int, int] | None:
    try:
        with open(path, "rb") as image_file:
            header = image_file.read(24)
    except OSError:
        return None
    if len(header) < 24 or header[:8] != b"\x89PNG\r\n\x1a\n":
        return None
    width = int.from_bytes(header[16:20], "big")
    height = int.from_bytes(header[20:24], "big")
    return width, height


def get_button_icon_target_size(icon_key: str, state: str) -> int:
    targets = BUTTON_ICON_TARGET_SIZE.get(icon_key, {"normal": 54, "pressed": 50})
    return targets.get(state, targets.get("normal", 54))


def get_button_icon_max_dimension(icon_key: str) -> int:
    max_dimension = 1
    for state in ("normal", "pressed"):
        image_size = get_png_image_size(get_button_icon_path(icon_key, state))
        if image_size is None:
            continue
        max_dimension = max(max_dimension, image_size[0], image_size[1])
    return max_dimension


def get_button_hitbox_half_size(icon_key: str) -> int:
    targets = BUTTON_ICON_TARGET_SIZE.get(icon_key, {"normal": 54, "hover": 50, "pressed": 46})
    max_target = max(targets.values())
    return max(24, math.ceil(max_target / 2) + 6)


def configure_windows_dpi() -> None:
    if sys.platform != "win32":
        return
    try:
        ctypes.windll.shcore.SetProcessDpiAwareness(1)
        return
    except Exception:
        pass


def configure_tk_scaling(root: tk.Tk) -> None:
    try:
        root.tk.call("tk", "scaling", DEFAULT_TK_SCALING)
    except tk.TclError:
        pass


def _build_elevated_launch_command() -> tuple[str, str, str]:
    executable = sys.executable
    if getattr(sys, "frozen", False):
        parameters = subprocess.list2cmdline(sys.argv[1:])
        working_dir = str(Path(executable).resolve().parent)
    else:
        script_path = str(Path(__file__).resolve())
        parameters = subprocess.list2cmdline([script_path, *sys.argv[1:]])
        working_dir = str(Path(script_path).resolve().parent)
    return executable, parameters, working_dir


def _is_process_admin() -> bool:
    if os.name != "nt":
        return False
    try:
        return bool(ctypes.windll.shell32.IsUserAnAdmin())
    except Exception:
        return False


def ensure_admin_elevation() -> bool:
    if os.name != "nt":
        return True
    try:
        if _is_process_admin():
            return True
    except Exception:
        return True
    try:
        executable, parameters, working_dir = _build_elevated_launch_command()
        result = int(
            ctypes.windll.shell32.ShellExecuteW(
                None,
                "runas",
                executable,
                parameters,
                working_dir,
                1,
            )
            or 0
        )
    except Exception:
        result = 0
    if result > 32:
        return False
    return True


def format_seconds(seconds: float, show_centiseconds: bool = False) -> str:
    safe_seconds = max(0.0, seconds)
    whole_seconds = int(safe_seconds)
    minutes = whole_seconds // 60
    remaining_seconds = whole_seconds % 60
    if show_centiseconds:
        centiseconds = int((safe_seconds - whole_seconds) * 100)
        return f"{minutes:02d}:{remaining_seconds:02d}:{centiseconds:02d}"
    return f"{minutes:02d}:{remaining_seconds:02d}"


def coerce_seconds_number(value) -> float | None:
    if isinstance(value, bool):
        return None
    if isinstance(value, (int, float)):
        numeric = float(value)
    else:
        try:
            numeric = float(str(value).strip())
        except (TypeError, ValueError):
            return None
    if not math.isfinite(numeric):
        return None
    return max(0.0, numeric)


