    def _parse_int(self, value: str | None, fallback: int) -> int:
        try:
            return int(value) if value is not None else fallback
        except (TypeError, ValueError):
            return fallback

    def _build_distribution_default_log_stats_enabled_map(self) -> dict[str, bool]:
        enabled_bosses = {
            "티르",
            "토르",
            "오딘",
            "수르트",
            "미미르",
            "이미르",
            "에기르",
            "발리",
            "샤무크",
            "그로아",
            "노트",
            "스칼드메르",
            "히로킨",
            "헤이드",
            "호드",
            "프레이",
            "엘디르",
            "스쿨드",
            "안나",
            "스카디",
            "최하층굴베",
            "최하층스네르",
            "최하층강글",
            "10층",
        }
        return {
            str(item.get("boss_name") or ""): str(item.get("boss_name") or "") in enabled_bosses
            for item in get_record_book_boss_catalog()
            if str(item.get("boss_name") or "").strip()
        }

    def _default_schedule_alarm_settings_payload(self) -> dict[str, object]:
        default_offsets = [300, 60]
        boss_overrides = {
            str(item.get("boss_name") or ""): {
                "enabled": True,
                "offsets": list(default_offsets),
            }
            for item in get_record_book_boss_catalog()
            if str(item.get("boss_name") or "").strip()
        }
        return {
            "master_enabled": True,
            "common_offsets": default_offsets,
            "countdown_enabled": False,
            "countdown_start_seconds": 15,
            "fixed_boss_enabled": True,
            "voice_name": SCHEDULE_ALARM_FEMALE_VOICE_NAME,
            "boss_overrides": boss_overrides,
        }

    def _normalize_schedule_alarm_offsets(self, values: object) -> list[int]:
        offsets: set[int] = set()
        if isinstance(values, (list, tuple, set)):
            for raw_value in values:
                try:
                    seconds = int(raw_value)
                except (TypeError, ValueError):
                    continue
                if 0 < seconds <= 24 * 60 * 60:
                    offsets.add(seconds)
        return sorted(offsets, reverse=True)

    def _normalize_schedule_boss_alarm_entry(self, value: object) -> dict[str, object]:
        if isinstance(value, dict):
            enabled = bool(value.get("enabled", False))
            offsets = self._normalize_schedule_alarm_offsets(value.get("offsets", []))
        else:
            enabled = False
            offsets = []
        return {
            "enabled": enabled and bool(offsets),
            "offsets": offsets,
        }

    def _normalize_schedule_boss_alarm_settings_map(self, payload: object) -> dict[str, dict[str, object]]:
        normalized: dict[str, dict[str, object]] = {}
        if not isinstance(payload, dict):
            return normalized
        for boss_name, value in payload.items():
            canonical_name = self._get_canonical_boss_name(str(boss_name or "").strip()) or str(boss_name or "").strip()
            if not canonical_name:
                continue
            normalized[canonical_name] = self._normalize_schedule_boss_alarm_entry(value)
        return normalized

    def _load_schedule_alarm_settings(self) -> dict[str, object]:
        payload = self._default_schedule_alarm_settings_payload()
        if not os.path.exists(SCHEDULE_ALARM_SETTINGS_PATH):
            return payload
        try:
            with open(SCHEDULE_ALARM_SETTINGS_PATH, "r", encoding="utf-8") as file:
                loaded = json.load(file)
        except (OSError, json.JSONDecodeError):
            return payload
        if not isinstance(loaded, dict):
            return payload
        payload["master_enabled"] = bool(loaded.get("master_enabled", payload["master_enabled"]))
        payload["common_offsets"] = self._normalize_schedule_alarm_offsets(loaded.get("common_offsets", payload["common_offsets"]))
        payload["countdown_enabled"] = bool(loaded.get("countdown_enabled", payload["countdown_enabled"]))
        payload["countdown_start_seconds"] = min(60, max(1, self._parse_int(str(loaded.get("countdown_start_seconds") or "10"), 10)))
        payload["fixed_boss_enabled"] = bool(loaded.get("fixed_boss_enabled", payload["fixed_boss_enabled"]))
        payload["voice_name"] = str(loaded.get("voice_name") or payload["voice_name"]).strip() or SCHEDULE_ALARM_FEMALE_VOICE_NAME
        payload["boss_overrides"] = self._normalize_schedule_boss_alarm_settings_map(loaded.get("boss_overrides", {}))
        return payload

    def _save_schedule_alarm_settings(self) -> None:
        payload = {
            "master_enabled": bool(self.schedule_alarm_master_var.get()) if hasattr(self, "schedule_alarm_master_var") else bool(self.schedule_alarm_master_enabled_default),
            "common_offsets": self._normalize_schedule_alarm_offsets(getattr(self, "schedule_alarm_common_offsets", [])),
            "countdown_enabled": bool(self.schedule_alarm_countdown_enabled_var.get()) if hasattr(self, "schedule_alarm_countdown_enabled_var") else False,
            "countdown_start_seconds": min(60, max(1, self._parse_int(self.schedule_alarm_countdown_start_var.get() if hasattr(self, "schedule_alarm_countdown_start_var") else "10", 10))),
            "fixed_boss_enabled": bool(self.schedule_fixed_boss_alarm_enabled_var.get()) if hasattr(self, "schedule_fixed_boss_alarm_enabled_var") else False,
            "voice_name": str(getattr(self, "schedule_alarm_voice_name", "") or SCHEDULE_ALARM_FEMALE_VOICE_NAME).strip() or SCHEDULE_ALARM_FEMALE_VOICE_NAME,
            "boss_overrides": {},
        }
        for boss_name, entry in sorted(getattr(self, "schedule_boss_alarm_settings", {}).items()):
            canonical_name = self._get_canonical_boss_name(str(boss_name or "").strip()) or str(boss_name or "").strip()
            if not canonical_name:
                continue
            normalized_entry = self._normalize_schedule_boss_alarm_entry(entry)
            payload["boss_overrides"][canonical_name] = normalized_entry
        try:
            with open(SCHEDULE_ALARM_SETTINGS_PATH, "w", encoding="utf-8") as file:
                json.dump(payload, file, ensure_ascii=False, indent=2)
        except OSError:
            return

    def _sync_schedule_alarm_settings_with_boss_definitions(self) -> None:
        current_settings = dict(getattr(self, "schedule_boss_alarm_settings", {}))
        synced: dict[str, dict[str, object]] = {}
        for boss_name, item in self.schedule_boss_definitions.items():
            canonical_name = str(item.get("boss_name") or boss_name).strip()
            if not canonical_name:
                continue
            synced[canonical_name] = self._normalize_schedule_boss_alarm_entry(current_settings.get(canonical_name, {}))
        self.schedule_boss_alarm_settings = synced

    def _widget_available(self, widget: tk.Widget | None) -> bool:
        if widget is None:
            return False
        try:
            return bool(widget.winfo_exists())
        except tk.TclError:
            return False

    def _report_callback_exception(self, exc_type, exc_value, exc_traceback) -> None:
        try:
            log_path = os.path.join(get_app_root(), "boss_timer_runtime_error.log")
            with open(log_path, "a", encoding="utf-8") as error_file:
                error_file.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}]\n")
                error_file.write("".join(traceback.format_exception(exc_type, exc_value, exc_traceback)))
                error_file.write("\n")
        except Exception:
            pass
        try:
            self._show_centered_error("콜백 오류", f"{exc_value}\n\n자세한 내용은 boss_timer_runtime_error.log를 확인하세요.")
        except Exception:
            pass

    def _bind_hover_button(self, button: tk.Widget, normal_bg: str, hover_bg: str, normal_fg: str | None = None, hover_fg: str | None = None) -> None:
        def is_disabled() -> bool:
            try:
                return str(button.cget("state")) == "disabled"
            except tk.TclError:
                return False

        def on_enter(_event=None) -> None:
            if is_disabled():
                return
            try:
                button.config(bg=hover_bg, activebackground=hover_bg)
                if hover_fg is not None:
                    button.config(fg=hover_fg, activeforeground=hover_fg)
            except tk.TclError:
                return

        def on_leave(_event=None) -> None:
            if is_disabled():
                return
            try:
                button.config(bg=normal_bg, activebackground=normal_bg)
                if normal_fg is not None:
                    button.config(fg=normal_fg, activeforeground=normal_fg)
            except tk.TclError:
                return

        button.bind("<Enter>", on_enter)
        button.bind("<Leave>", on_leave)

    def _has_active_season(self) -> bool:
        return bool(re.fullmatch(r"\d+", str(self.current_season_no or "").strip()))

    def _load_season_history(self) -> None:
        self.season_history_map = {}
        if not os.path.exists(SEASON_HISTORY_PATH):
            return
        try:
            with open(SEASON_HISTORY_PATH, "r", encoding="utf-8") as file:
                payload = json.load(file)
        except (OSError, json.JSONDecodeError):
            return
        entries: list[dict] = []
        if isinstance(payload, list):
            entries = [entry for entry in payload if isinstance(entry, dict)]
        elif isinstance(payload, dict):
            raw_entries = payload.get("seasons")
            if isinstance(raw_entries, list):
                entries = [entry for entry in raw_entries if isinstance(entry, dict)]
            else:
                entries = [
                    {"season_no": key, **value}
                    for key, value in payload.items()
                    if isinstance(value, dict)
                ]
        normalized: dict[str, dict[str, str]] = {}
        for entry in entries:
            season_no = re.sub(r"[^0-9]", "", str(entry.get("season_no") or "").strip())
            if not season_no:
                continue
            started_at = str(entry.get("started_at") or "").strip()
            ended_at = str(entry.get("ended_at") or "").strip()
            archive_label = str(entry.get("archive_label") or "").strip()
            normalized[season_no] = {
                "season_no": season_no,
                "started_at": started_at,
                "ended_at": ended_at,
                "archive_label": archive_label,
            }
        self.season_history_map = normalized

    def _prune_missing_archive_history_entries(self) -> bool:
        if not isinstance(self.season_history_map, dict) or not self.season_history_map:
            return False
        current_season_text = re.sub(r"[^0-9]", "", str(self.current_season_no or "").strip())
        archive_root = self._get_log_archive_dir()
        removed = False
        for season_no in list(self.season_history_map.keys()):
            if season_no == current_season_text:
                continue
            expected_dir = os.path.join(archive_root, self._get_archive_season_label(season_no))
            if os.path.isdir(expected_dir):
                continue
            self.season_history_map.pop(season_no, None)
            removed = True
        if removed:
            self._save_season_history()
        return removed

    def _save_season_history(self) -> None:
        entries = [
            {
                "season_no": season_no,
                "started_at": str(entry.get("started_at") or "").strip(),
                "ended_at": str(entry.get("ended_at") or "").strip(),
                "archive_label": str(entry.get("archive_label") or "").strip(),
            }
            for season_no, entry in sorted(
                self.season_history_map.items(),
                key=lambda item: int(item[0]) if str(item[0]).isdigit() else -1,
            )
        ]
        try:
            with open(SEASON_HISTORY_PATH, "w", encoding="utf-8") as file:
                json.dump(entries, file, ensure_ascii=False, indent=2)
        except OSError:
            return

    def _record_season_history_transition(
        self,
        previous_season_no: str | int | None,
        previous_started_at: str | None,
        current_season_no: str | int | None,
        current_started_at: str | None,
    ) -> None:
        previous_text = re.sub(r"[^0-9]", "", str(previous_season_no or "").strip())
        current_text = re.sub(r"[^0-9]", "", str(current_season_no or "").strip())
        previous_started_text = str(previous_started_at or "").strip()
        current_started_text = str(current_started_at or "").strip()
        changed = False
        if previous_text and previous_text != current_text:
            previous_entry = dict(self.season_history_map.get(previous_text) or {})
            previous_entry["season_no"] = previous_text
            if previous_started_text and not str(previous_entry.get("started_at") or "").strip():
                previous_entry["started_at"] = previous_started_text
            if current_started_text:
                previous_entry["ended_at"] = current_started_text
            self.season_history_map[previous_text] = previous_entry
            changed = True
        if current_text:
            current_entry = dict(self.season_history_map.get(current_text) or {})
            current_entry["season_no"] = current_text
            if current_started_text:
                current_entry["started_at"] = current_started_text
            current_entry["ended_at"] = ""
            self.season_history_map[current_text] = current_entry
            changed = True
        if changed:
            self._save_season_history()

    def _get_next_season_number_text(self) -> str:
        if self._has_active_season():
            try:
                return str(int(self.current_season_no) + 1)
            except ValueError:
                return "1"
        return "1"

    def _get_existing_archive_season_numbers(self) -> set[str]:
        season_numbers: set[str] = set()
        for entry in self._get_archive_management_all_entries():
            season_no_text = str(entry.get("season_no_text") or "").strip()
            if season_no_text.isdigit():
                season_numbers.add(str(int(season_no_text)))
        return season_numbers

    def _show_season_setup_dialog(self, parent: tk.Widget | None = None) -> bool:
        host = parent if self._widget_available(parent) else self.root
        dialog = tk.Toplevel(host)
        dialog.title("새 시즌 시작")
        dialog.resizable(False, False)
        dialog.configure(bg="#eff6ff")
        self._center_window_over_parent(dialog, host, 430, 312)
        result = {"confirmed": False}
        season_var = tk.StringVar(value=self._get_next_season_number_text())
        status_var = tk.StringVar(value="n차 숫자만 입력하세요.")
        current_season_label = self._get_archive_season_label(self.current_season_no) if self._has_active_season() else "-"
        now = datetime.now()
        start_year_var = tk.StringVar(value=now.strftime("%Y년"))
        start_month_var = tk.StringVar(value=now.strftime("%m월"))
        start_day_var = tk.StringVar(value=now.strftime("%d일"))
        start_hour_var = tk.StringVar(value=now.strftime("%H시"))
        start_minute_var = tk.StringVar(value=now.strftime("%M분"))

        tk.Label(dialog, text="새 시즌 시작", font=self.header_font, bg="#dbeafe", fg="#0f172a").place(x=0, y=0, width=430, height=40)
        tk.Label(dialog, text="n차 입력", font=self.button_font, bg="#eff6ff", fg="#0f172a", anchor="w").place(x=22, y=58, width=78, height=24)
        entry = tk.Entry(
            dialog,
            textvariable=season_var,
            font=(self.current_font_family, 12, "bold"),
            bg="#ffffff",
            fg="#0f172a",
            relief="solid",
            bd=1,
            justify="center",
        )
        entry.place(x=94, y=56, width=88, height=28)
        tk.Label(
            dialog,
            text=f"현재 시즌: {current_season_label}",
            font=self.percent_font,
            bg="#eff6ff",
            fg="#1e3a8a",
            anchor="w",
        ).place(x=196, y=60, width=212, height=20)
        tk.Label(dialog, text="시작 시간", font=self.button_font, bg="#eff6ff", fg="#0f172a", anchor="w").place(x=22, y=96, width=78, height=24)
        start_year_values = [f"{year}년" for year in range(now.year - 2, now.year + 3)]
        start_month_values = [f"{month:02d}월" for month in range(1, 13)]
        start_day_values = [f"{day:02d}일" for day in range(1, 32)]
        start_hour_values = [f"{hour:02d}시" for hour in range(0, 24)]
        start_minute_values = [f"{minute:02d}분" for minute in range(0, 60)]
        ttk.Combobox(dialog, textvariable=start_year_var, values=start_year_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=94, y=92, width=84, height=28)
        ttk.Combobox(dialog, textvariable=start_month_var, values=start_month_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=186, y=92, width=58, height=28)
        ttk.Combobox(dialog, textvariable=start_day_var, values=start_day_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=252, y=92, width=58, height=28)
        ttk.Combobox(dialog, textvariable=start_hour_var, values=start_hour_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=318, y=92, width=58, height=28)
        ttk.Combobox(dialog, textvariable=start_minute_var, values=start_minute_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=384, y=92, width=58, height=28)
        tk.Label(
            dialog,
            text=(
                "- 서버이전 기준으로 차수를 정하는걸 추천드립니다.\n"
                "- 서버이전 차수 정보는 오딘카페 -> 공지사항에서 확인할 수 있습니다.\n"
                "- 현재 시즌 차수를 입력 할 시 현재시즌 시작일이 변경 됩니다.\n"
                "- 사용자 임의 차수를 입력하셔도 무방합니다."
            ),
            font=(self.current_font_family, 9, "bold"),
            bg="#eff6ff",
            fg="#475569",
            justify="left",
            anchor="nw",
        ).place(x=22, y=136, width=386, height=90)
        tk.Label(dialog, textvariable=status_var, font=(self.current_font_family, 9, "bold"), bg="#eff6ff", fg="#b45309", anchor="w").place(x=22, y=234, width=386, height=18)

        def close_with(value: bool) -> None:
            result["confirmed"] = value
            try:
                dialog.grab_release()
            except tk.TclError:
                pass
            dialog.destroy()

        def confirm() -> None:
            previous_season_text = str(self.current_season_no or "").strip()
            previous_started_text = str(self.current_season_started_at or "").strip()
            season_text = re.sub(r"[^0-9]", "", season_var.get())
            if not season_text:
                status_var.set("숫자만 입력할 수 있습니다.")
                return
            season_text = str(int(season_text))
            try:
                start_datetime = datetime(
                    int(re.sub(r"[^0-9]", "", start_year_var.get()) or "0"),
                    int(re.sub(r"[^0-9]", "", start_month_var.get()) or "0"),
                    int(re.sub(r"[^0-9]", "", start_day_var.get()) or "0"),
                    int(re.sub(r"[^0-9]", "", start_hour_var.get()) or "0"),
                    int(re.sub(r"[^0-9]", "", start_minute_var.get()) or "0"),
                    0,
                )
            except ValueError:
                status_var.set("시작 시간 형식을 확인하세요.")
                return
            current_season_text = ""
            if self._has_active_season():
                try:
                    current_season_text = str(int(self.current_season_no))
                except ValueError:
                    current_season_text = ""
            if season_text in self._get_existing_archive_season_numbers() and season_text != current_season_text:
                status_var.set("보관 기록에 이미 존재하는 차수입니다.")
                return
            timestamp_text = start_datetime.strftime("%Y-%m-%d %H:%M:%S")
            if current_season_text and season_text == current_season_text:
                if not self._show_same_season_restart_dialog(timestamp_text, parent=dialog):
                    status_var.set("같은 시즌 재시작을 취소했습니다.")
                    return
            self.current_season_no = season_text
            self.current_season_started_at = timestamp_text
            self._record_season_history_transition(
                previous_season_text,
                previous_started_text,
                self.current_season_no,
                self.current_season_started_at,
            )
            if hasattr(self, "log_history_folder_path_var") and self.log_history_folder_path_var is not None:
                self.log_history_folder_path_var.set(self._get_logs_dir())
            self._update_archive_keep_seasons_description()
            self._save_settings()
            close_with(True)

        def on_write(*_args) -> None:
            cleaned = re.sub(r"[^0-9]", "", season_var.get())
            if cleaned != season_var.get():
                season_var.set(cleaned)

        season_var.trace_add("write", on_write)
        tk.Button(dialog, text="시작", font=self.button_font, bg="#2563eb", fg="#ffffff", activebackground="#1d4ed8", activeforeground="#ffffff", relief="raised", bd=1, highlightthickness=0, command=confirm, cursor="hand2").place(x=234, y=270, width=80, height=28)
        tk.Button(dialog, text="취소", font=self.button_font, bg="#e2e8f0", fg="#334155", activebackground="#cbd5e1", activeforeground="#334155", relief="raised", bd=1, highlightthickness=0, command=lambda: close_with(False), cursor="hand2").place(x=326, y=270, width=82, height=28)
        dialog.bind("<Return>", lambda _event: confirm())
        dialog.grab_set()
        entry.focus_set()
        entry.selection_range(0, tk.END)
        dialog.wait_window()
        return bool(result["confirmed"])

    def _ensure_season_ready(self, parent: tk.Widget | None = None) -> bool:
        if self._has_active_season():
            return True
        return self._show_season_setup_dialog(parent=parent)

    def _bind_record_subtab_hover(self, button: tk.Button, mode: str, hover_bg: str, hover_fg: str) -> None:
        def on_enter(_event=None) -> None:
            if self.log_record_subview_var.get() == mode:
                return
            try:
                button.config(bg=hover_bg, activebackground=hover_bg, fg=hover_fg, activeforeground=hover_fg)
            except tk.TclError:
                return

        def on_leave(_event=None) -> None:
            try:
                self._apply_record_subtab_style()
            except tk.TclError:
                return

        button.bind("<Enter>", on_enter)
        button.bind("<Leave>", on_leave)

    def _show_tooltip(self, text: str, *, widget: tk.Widget | None = None, canvas_x: int | None = None, canvas_y: int | None = None) -> None:
        self._hide_tooltip()
        if widget is not None:
            x = widget.winfo_rootx() + widget.winfo_width() + 8
            y = widget.winfo_rooty() + 6
        elif canvas_x is not None and canvas_y is not None:
            x = self.root.winfo_rootx() + canvas_x + 12
            y = self.root.winfo_rooty() + canvas_y + 12
        else:
            return
        self.tooltip_window = tk.Toplevel(self.root)
        self.tooltip_window.wm_overrideredirect(True)
        self.tooltip_window.attributes("-topmost", True)
        self.tooltip_window.geometry(f"+{x}+{y}")
        label = tk.Label(
            self.tooltip_window,
            text=text,
            font=(self.current_font_family, 9, "bold"),
            bg="#ffffff",
            fg="#374151",
            relief="solid",
            bd=1,
            padx=6,
            pady=2,
        )
        label.pack()

    def _hide_tooltip(self) -> None:
        if self.tooltip_window is not None:
            try:
                self.tooltip_window.destroy()
            except tk.TclError:
                pass
            self.tooltip_window = None

    def _get_logs_dir(self) -> str:
        if self._has_active_season():
            return self._get_archive_season_dir(self.current_season_no)
        archive_dir = self._get_log_archive_dir()
        os.makedirs(archive_dir, exist_ok=True)
        return archive_dir

    def _get_log_archive_dir(self) -> str:
        archive_dir = os.path.join(get_app_root(), LOG_ARCHIVE_DIRNAME)
        os.makedirs(archive_dir, exist_ok=True)
        return archive_dir

    def _get_season_prestart_archive_dir(self) -> str:
        archive_dir = os.path.join(get_app_root(), SEASON_PRESTART_ARCHIVE_DIRNAME)
        os.makedirs(archive_dir, exist_ok=True)
        return archive_dir

    def _get_archive_season_label(self, season_no: str | int | None) -> str:
        season_text = re.sub(r"[^0-9]", "", str(season_no or "").strip())
        if not season_text:
            return "미분류 시즌"
        season_entry = dict(self.season_history_map.get(season_text) or {})
        archive_label = str(season_entry.get("archive_label") or "").strip()
        if archive_label:
            return archive_label
        return f"{int(season_text)}차 시즌"

    def _get_archive_entry_season_no_from_label(self, season_label: str | None) -> str:
        normalized_label = str(season_label or "").strip()
        if not normalized_label:
            return ""
        season_match = re.search(r"(\d+)\s*차\s*시즌", normalized_label)
        if season_match:
            return str(int(season_match.group(1)))
        for season_no, season_entry in self.season_history_map.items():
            if normalized_label == str(season_entry.get("archive_label") or "").strip():
                return str(season_no or "").strip()
        return ""

    def _get_archive_season_dir(self, season_no: str | int | None) -> str:
        season_dir = os.path.join(self._get_log_archive_dir(), self._get_archive_season_label(season_no))
        os.makedirs(season_dir, exist_ok=True)
        return season_dir

    def _get_log_month_key(self, recorded_at: str | None = None) -> str:
        try:
            if recorded_at:
                return datetime.strptime(str(recorded_at), "%Y-%m-%d %H:%M:%S").strftime("%Y-%m")
        except ValueError:
            pass
        return datetime.now().strftime("%Y-%m")

    def _get_log_month_dir(self, season_no: str | int | None, recorded_at: str | None = None) -> str:
        month_dir = os.path.join(self._get_archive_season_dir(season_no), self._get_log_month_key(recorded_at))
        os.makedirs(month_dir, exist_ok=True)
        return month_dir

    def _get_season_prestart_month_dir(self, season_no: str | int | None, recorded_at: str | None = None) -> str:
        month_dir = os.path.join(
            self._get_season_prestart_archive_dir(),
            self._get_archive_season_label(season_no),
            self._get_log_month_key(recorded_at),
        )
        os.makedirs(month_dir, exist_ok=True)
        return month_dir

    def _default_record_book_data(self) -> dict:
        chapter_enabled = {section: True for section in self.record_book_sections if section != "기타"}
        boss_enabled = {item["boss_name"]: True for item in self.record_book_catalog}
        for section_name in ("니다벨리르", "알브하임"):
            if section_name in chapter_enabled:
                chapter_enabled[section_name] = False
        for boss_name in ("최하층굴베", "최하층스네르", "최하층강글", "4층"):
            if boss_name in boss_enabled:
                boss_enabled[boss_name] = False
        return {
            "version": 1,
            "section_order": [section for section in self.record_book_sections if section != "기타"],
            "chapter_enabled": chapter_enabled,
            "boss_enabled": boss_enabled,
            "records": {},
        }

    def _normalize_boss_lookup_key(self, text: str) -> str:
        return re.sub(r"\s+", "", (text or "").strip()).lower()

    def _rebuild_boss_name_resolution_maps(self) -> None:
        lookup: dict[str, str] = {}
        display_alias_map: dict[str, str] = {}
        alt_names_map: dict[str, set[str]] = {}
        known_canonical_names: set[str] = set()

        def register(canonical_name: str, candidate_name: str, *, display_alias: bool = False) -> None:
            canonical = (canonical_name or "").strip()
            candidate = (candidate_name or "").strip()
            if not canonical or not candidate:
                return
            lookup[self._normalize_boss_lookup_key(candidate)] = canonical
            alt_names_map.setdefault(canonical, set()).add(candidate)
            if display_alias and candidate != canonical:
                display_alias_map.setdefault(canonical, candidate)

        for item in self.record_book_catalog:
            canonical = str(item.get("boss_name") or "").strip()
            if not canonical:
                continue
            known_canonical_names.add(canonical)
            register(canonical, canonical)

        for boss_name, item in self.schedule_boss_definitions.items():
            canonical = str(item.get("boss_name") or boss_name).strip()
            if not canonical:
                continue
            known_canonical_names.add(canonical)
            register(canonical, canonical)
            alias = str(item.get("alias") or "").strip()
            if alias:
                register(canonical, alias, display_alias=True)

        for source_name, target_name in RECORD_BOOK_ABBREV_MAP.items():
            source = str(source_name or "").strip()
            target = str(target_name or "").strip()
            if not source or not target:
                continue
            source_is_canonical = source in known_canonical_names
            target_is_canonical = target in known_canonical_names
            if source_is_canonical:
                register(source, target, display_alias=True)
                continue
            if target_is_canonical:
                register(target, source)
                register(target, target)
                continue
            target_canonical = lookup.get(self._normalize_boss_lookup_key(target))
            if target_canonical:
                register(target_canonical, source)

        self.boss_name_lookup_map = lookup
        self.boss_display_alias_map = display_alias_map
        self.boss_alt_names_map = alt_names_map

    def _get_canonical_boss_name(self, raw_name: str) -> str:
        cleaned = (raw_name or "").strip()
        if not cleaned:
            return ""
        return self.boss_name_lookup_map.get(self._normalize_boss_lookup_key(cleaned), cleaned)

    def _get_display_boss_name(self, raw_name: str) -> str:
        canonical = self._get_canonical_boss_name(raw_name)
        if not canonical:
            return ""
        return self.boss_display_alias_map.get(canonical, canonical)

    def _get_record_book_display_name(self, raw_name: str) -> str:
        canonical = self._normalize_record_book_boss_name(raw_name)
        if not canonical:
            return ""
        display_name = self._get_display_boss_name(canonical)
        if display_name:
            return display_name
        return RECORD_BOOK_ABBREV_MAP.get(canonical, canonical)

    def _normalize_record_book_boss_name(self, raw_name: str) -> str:
        return self._get_canonical_boss_name(raw_name)

    def _normalize_record_book_data(self, loaded: dict | None) -> dict:
        data = self._default_record_book_data()
        if not isinstance(loaded, dict):
            return data
        loaded_chapters = loaded.get("chapter_enabled", {})
        if isinstance(loaded_chapters, dict):
            for area_name, enabled in loaded_chapters.items():
                if area_name in data["chapter_enabled"]:
                    data["chapter_enabled"][area_name] = bool(enabled)
        loaded_order = loaded.get("section_order", [])
        if isinstance(loaded_order, list):
            normalized_order = []
            for section_name in loaded_order:
                if section_name in data["chapter_enabled"] and section_name not in normalized_order:
                    normalized_order.append(section_name)
            for section_name in data["section_order"]:
                if section_name not in normalized_order:
                    normalized_order.append(section_name)
            data["section_order"] = normalized_order
        loaded_bosses = loaded.get("boss_enabled", {})
        if isinstance(loaded_bosses, dict):
            for boss_name, enabled in loaded_bosses.items():
                normalized_name = self._normalize_record_book_boss_name(str(boss_name))
                if normalized_name in data["boss_enabled"]:
                    data["boss_enabled"][normalized_name] = bool(enabled)
        loaded_records = loaded.get("records", {})
        if not isinstance(loaded_records, dict):
            return data
        for date_key, boss_map in loaded_records.items():
            if not isinstance(date_key, str) or not isinstance(boss_map, dict):
                continue
            normalized_date = date_key.strip()
            if not normalized_date:
                continue
            data["records"].setdefault(normalized_date, {})
            for boss_name, entry in boss_map.items():
                normalized_boss = self._normalize_record_book_boss_name(str(boss_name))
                if normalized_boss not in data["boss_enabled"] or not isinstance(entry, dict):
                    continue
                ally_count = max(0, self._parse_int(str(entry.get("ally", 0)), 0))
                enemy_count = max(0, self._parse_int(str(entry.get("enemy", 0)), 0))
                ally_defaults = {
                    "ally_main": ally_count >= 1,
                    "ally_invasion": ally_count >= 2,
                    "ally_main_extra": ally_count >= 3,
                    "ally_invasion_extra": ally_count >= 4,
                }
                enemy_defaults = {
                    "enemy_main": enemy_count >= 1,
                    "enemy_invasion": enemy_count >= 2,
                    "enemy_main_extra": enemy_count >= 3,
                    "enemy_invasion_extra": enemy_count >= 4,
                }
                normalized_entry = {
                    **ally_defaults,
                    **enemy_defaults,
                }
                for key in normalized_entry:
                    if key in entry:
                        normalized_entry[key] = bool(entry.get(key))
                memo = str(entry.get("memo", "")).strip()
                data["records"][normalized_date][normalized_boss] = {
                    "ally_main": normalized_entry["ally_main"],
                    "ally_invasion": normalized_entry["ally_invasion"],
                    "ally_main_extra": normalized_entry["ally_main_extra"],
                    "ally_invasion_extra": normalized_entry["ally_invasion_extra"],
                    "enemy_main": normalized_entry["enemy_main"],
                    "enemy_invasion": normalized_entry["enemy_invasion"],
                    "enemy_main_extra": normalized_entry["enemy_main_extra"],
                    "enemy_invasion_extra": normalized_entry["enemy_invasion_extra"],
                    "memo": memo,
                }
        return data

    def _get_record_book_storage_dir(self) -> str:
        storage_dir = os.path.join(get_app_root(), RECORD_BOOK_STORAGE_DIRNAME)
        os.makedirs(storage_dir, exist_ok=True)
        return storage_dir

    def _get_record_book_month_key(self, date_key: str | None = None) -> str:
        raw_date = (date_key or "").strip()
        if raw_date:
            try:
                return datetime.strptime(raw_date, RECORD_BOOK_DATE_FORMAT).strftime("%Y-%m")
            except ValueError:
                pass
        return self.record_book_data_month_key or datetime.now().strftime("%Y-%m")

    def _get_record_book_file_path(self, month_key: str | None = None) -> str:
        effective_month_key = month_key or self.record_book_data_month_key or datetime.now().strftime("%Y-%m")
        return os.path.join(self._get_record_book_storage_dir(), f"{effective_month_key}.json")

    def _get_record_book_all_month_keys(self) -> list[str]:
        storage_dir = self._get_record_book_storage_dir()
        month_keys: set[str] = set()
        for filename in os.listdir(storage_dir):
            if not filename.lower().endswith(".json"):
                continue
            month_key = filename[:-5]
            try:
                datetime.strptime(month_key, "%Y-%m")
            except ValueError:
                continue
            month_keys.add(month_key)
        month_keys.add(datetime.now().strftime("%Y-%m"))
        if self.record_book_data_month_key:
            month_keys.add(self.record_book_data_month_key)
        return sorted(month_keys)

    def _load_record_book_data_for_month(self, month_key: str) -> dict:
        record_book_path = self._get_record_book_file_path(month_key)
        legacy_fallback_path = RECORD_BOOK_PATH if month_key == datetime.now().strftime("%Y-%m") else None
        source_path = record_book_path
        if not os.path.exists(source_path) and legacy_fallback_path and os.path.exists(legacy_fallback_path):
            source_path = legacy_fallback_path
        if not os.path.exists(source_path):
            return self._default_record_book_data()
        try:
            with open(source_path, "r", encoding="utf-8") as record_file:
                loaded = json.load(record_file)
        except (OSError, json.JSONDecodeError):
            loaded = None
        return self._normalize_record_book_data(loaded)

    def _save_record_book_data_for_month(self, month_key: str, data: dict) -> None:
        normalized = self._normalize_record_book_data(data)
        with open(self._get_record_book_file_path(month_key), "w", encoding="utf-8") as record_file:
            json.dump(normalized, record_file, ensure_ascii=False, indent=2)

    def _delete_record_book_month_file_if_empty(self, month_key: str, data: dict) -> None:
        if data.get("records"):
            return
        if month_key == datetime.now().strftime("%Y-%m"):
            self._save_record_book_data_for_month(month_key, data)
            return
        file_path = self._get_record_book_file_path(month_key)
        try:
            if os.path.exists(file_path):
                os.remove(file_path)
        except OSError:
            return

    def _iter_month_keys_in_range(self, start_date: datetime, end_date: datetime) -> list[str]:
        current = datetime(start_date.year, start_date.month, 1)
        end_month = datetime(end_date.year, end_date.month, 1)
        month_keys: list[str] = []
        while current <= end_month:
            month_keys.append(current.strftime("%Y-%m"))
            if current.month == 12:
                current = datetime(current.year + 1, 1, 1)
            else:
                current = datetime(current.year, current.month + 1, 1)
        return month_keys

    def _get_record_book_retention_days(self) -> int | None:
        mapping = {
            "30일": 30,
            "60일": 60,
            "90일": 90,
            "100일": 100,
            "1년": 365,
            "영구": None,
        }
        return mapping.get(self.record_book_retention_var.get(), None)

    def _make_record_book_average_cache_key(self, boss_name: str, limit: int | None, days: int | None) -> str:
        limit_value = "*" if limit is None else str(limit)
        days_value = "*" if days is None else str(days)
        return f"{boss_name}|{limit_value}|{days_value}"

    def _get_record_book_average_candidate_names(self, boss_name: str) -> list[str]:
        canonical_name = self._get_canonical_boss_name(boss_name)
        candidate_names = set(self.boss_alt_names_map.get(canonical_name, set()))
        if canonical_name:
            candidate_names.add(canonical_name)
        if not candidate_names and boss_name:
            candidate_names.add(boss_name)
        return sorted(candidate_names)

    def _get_record_book_average_cache_signature(self, boss_name: str) -> dict[str, dict[str, int]]:
        signature: dict[str, dict[str, int]] = {}
        for candidate_name in self._get_record_book_average_candidate_names(boss_name):
            total_size = 0
            latest_mtime_ns = 0
            found_any = False
            for log_path in self._find_log_paths_for_boss_in_folder(self._get_logs_dir(), candidate_name):
                if not os.path.exists(log_path):
                    continue
                try:
                    stat_result = os.stat(log_path)
                except OSError:
                    continue
                found_any = True
                total_size += int(stat_result.st_size)
                latest_mtime_ns = max(
                    latest_mtime_ns,
                    int(getattr(stat_result, "st_mtime_ns", int(stat_result.st_mtime * 1_000_000_000))),
                )
            if found_any:
                signature[candidate_name] = {
                    "mtime_ns": latest_mtime_ns,
                    "size": total_size,
                }
        return signature

    def _load_record_book_average_cache(self) -> dict[str, dict]:
        if not os.path.exists(RECORD_BOOK_AVG_CACHE_PATH):
            return {}
        try:
            with open(RECORD_BOOK_AVG_CACHE_PATH, "r", encoding="utf-8") as cache_file:
                loaded = json.load(cache_file)
        except (OSError, json.JSONDecodeError):
            return {}
        if not isinstance(loaded, dict):
            return {}
        entries = loaded.get("entries", loaded)
        if not isinstance(entries, dict):
            return {}
        normalized_entries: dict[str, dict] = {}
        for raw_key, raw_entry in entries.items():
            if not isinstance(raw_key, str) or not isinstance(raw_entry, dict):
                continue
            raw_signature = raw_entry.get("signature", {})
            normalized_signature: dict[str, dict[str, int]] = {}
            if isinstance(raw_signature, dict):
                for candidate_name, info in raw_signature.items():
                    if not isinstance(candidate_name, str) or not isinstance(info, dict):
                        continue
                    try:
                        normalized_signature[candidate_name] = {
                            "mtime_ns": int(info.get("mtime_ns", 0)),
                            "size": int(info.get("size", 0)),
                        }
                    except (TypeError, ValueError):
                        continue
            value = raw_entry.get("value")
            if value is not None:
                try:
                    value = float(value)
                except (TypeError, ValueError):
                    value = None
            normalized_entries[raw_key] = {
                "value": value,
                "signature": normalized_signature,
            }
        return normalized_entries

    def _save_record_book_average_cache(self) -> None:
        payload = {
            "version": 1,
            "entries": self.record_book_avg_cut_disk_cache,
        }
        try:
            with open(RECORD_BOOK_AVG_CACHE_PATH, "w", encoding="utf-8") as cache_file:
                json.dump(payload, cache_file, ensure_ascii=False, indent=2)
        except OSError:
            pass

    def _load_record_book_data(self, month_key: str | None = None) -> dict:
        effective_month_key = month_key or self.record_book_data_month_key or datetime.now().strftime("%Y-%m")
        record_book_path = self._get_record_book_file_path(effective_month_key)
        legacy_fallback_path = RECORD_BOOK_PATH if effective_month_key == datetime.now().strftime("%Y-%m") else None
        source_path = record_book_path
        if not os.path.exists(source_path) and legacy_fallback_path and os.path.exists(legacy_fallback_path):
            source_path = legacy_fallback_path
        if not os.path.exists(source_path):
            data = self._normalize_record_book_data(self._load_default_record_book_seed_data())
            self.record_book_data_month_key = effective_month_key
            self._save_record_book_data(data)
            return data
        try:
            with open(source_path, "r", encoding="utf-8") as record_file:
                loaded = json.load(record_file)
        except (OSError, json.JSONDecodeError):
            loaded = None
        self.record_book_data_month_key = effective_month_key
        return self._normalize_record_book_data(loaded)

    def _load_default_record_book_seed_data(self) -> dict:
        self._seed_init_file_from_resource(DEFAULT_RECORD_BOOK_SEED_FILENAME)
        seed_path = os.path.join(INIT_DIR, DEFAULT_RECORD_BOOK_SEED_FILENAME)
        if not os.path.exists(seed_path):
            return self._default_record_book_data()
        try:
            with open(seed_path, "r", encoding="utf-8") as record_file:
                loaded = json.load(record_file)
        except (OSError, json.JSONDecodeError):
            return self._default_record_book_data()
        if not isinstance(loaded, dict):
            return self._default_record_book_data()
        sanitized = dict(loaded)
        sanitized["records"] = {}
        return sanitized

    def _save_record_book_data(self, data: dict | None = None) -> None:
        normalized = self._normalize_record_book_data(data or self.record_book_data)
        with open(self._get_record_book_file_path(), "w", encoding="utf-8") as record_file:
            json.dump(normalized, record_file, ensure_ascii=False, indent=2)
        self.record_book_data = normalized

    def _ensure_record_book_data_for_date(self, date_key: str) -> None:
        month_key = self._get_record_book_month_key(date_key)
        if month_key == self.record_book_data_month_key:
            return
        self.record_book_data_month_key = month_key
        self.record_book_data = self._load_record_book_data(month_key)
        if hasattr(self, "record_book_inner_frame"):
            self._rebuild_record_book_rows()

    def _get_record_book_date_key(self) -> str:
        raw_value = self._compose_record_book_date_from_fields()
        try:
            parsed = datetime.strptime(raw_value, RECORD_BOOK_DATE_FORMAT)
        except ValueError:
            normalized = datetime.now().strftime(RECORD_BOOK_DATE_FORMAT)
            self._set_record_book_date_fields(normalized)
            return normalized
        normalized = parsed.strftime(RECORD_BOOK_DATE_FORMAT)
        self._set_record_book_date_fields(normalized)
        return normalized

    def _set_record_book_date_fields(self, date_key: str) -> None:
        self.record_book_date_var.set(date_key)
        year, month, day = date_key.split("-")
        self.record_book_year_var.set(year)
        self.record_book_month_var.set(month)
        self.record_book_day_var.set(day)

    def _compose_record_book_date_from_fields(self) -> str:
        year = (self.record_book_year_var.get() or "").strip()
        month = (self.record_book_month_var.get() or "").strip().zfill(2)
        day = (self.record_book_day_var.get() or "").strip().zfill(2)
        composed = f"{year}-{month}-{day}"
        self.record_book_date_var.set(composed)
        return composed

    def _load_record_book_date_if_changed(self, *, force: bool = False) -> bool:
        if self.record_book_date_change_busy:
            return False
        self.record_book_date_change_busy = True
        try:
            date_key = self._get_record_book_date_key()
            if not force and date_key == self.record_book_loaded_date_key:
                return False
            previous_date_key = self.record_book_loaded_date_key
            if not force and self.record_book_dirty and previous_date_key:
                should_continue = self._confirm_record_book_pending_changes(
                    "날짜를 변경하기 전에 현재 기록지를 저장하시겠습니까?",
                    save_date_key=previous_date_key,
                )
                if not should_continue:
                    self._set_record_book_date_fields(previous_date_key)
                    return False
            self._load_record_book_date()
            return True
        finally:
            self.record_book_date_change_busy = False

    def _update_record_book_window_title(self) -> None:
        if self.record_book_window is None or not self.record_book_window.winfo_exists():
            return
        title = "보스 기록표"
        if self.record_book_dirty:
            title += " *"
        self.record_book_window.title(title)

    def _set_record_book_dirty(self, dirty: bool = True) -> None:
        was_dirty = self.record_book_dirty
        self.record_book_dirty = dirty
        self._update_record_book_window_title()
        self._update_record_book_save_button_state()
        if dirty and not was_dirty:
            self._start_record_book_save_button_blink()
        elif not dirty:
            self._stop_record_book_save_button_blink()

    def _build_record_book_ui_snapshot(self, date_key: str | None = None) -> dict[str, object]:
        effective_date = date_key or self.record_book_loaded_date_key or self._get_record_book_date_key()
        chapter_enabled = {area_name: bool(var.get()) for area_name, var in self.record_book_area_enabled_vars.items()}
        boss_enabled = {boss_name: bool(var.get()) for boss_name, var in self.record_book_boss_enabled_vars.items()}
        daily_records: dict[str, dict[str, bool | str]] = {}
        for boss_name, row_vars in self.record_book_row_vars.items():
            memo_widget = self.record_book_row_widgets.get(boss_name, {}).get("memo")
            memo_text = ""
            if memo_widget is not None:
                try:
                    memo_text = memo_widget.get("1.0", "end-1c").strip()
                except tk.TclError:
                    memo_text = str(row_vars["memo"].get() or "").strip()
            else:
                memo_text = str(row_vars["memo"].get() or "").strip()
            entry = {
                "ally_main": bool(row_vars["ally_main"].get()),
                "ally_invasion": bool(row_vars["ally_invasion"].get()),
                "ally_main_extra": bool(row_vars["ally_main_extra"].get()),
                "ally_invasion_extra": bool(row_vars["ally_invasion_extra"].get()),
                "enemy_main": bool(row_vars["enemy_main"].get()),
                "enemy_invasion": bool(row_vars["enemy_invasion"].get()),
                "enemy_main_extra": bool(row_vars["enemy_main_extra"].get()),
                "enemy_invasion_extra": bool(row_vars["enemy_invasion_extra"].get()),
                "memo": memo_text,
            }
            if any(
                (
                    entry["ally_main"],
                    entry["ally_invasion"],
                    entry["ally_main_extra"],
                    entry["ally_invasion_extra"],
                    entry["enemy_main"],
                    entry["enemy_invasion"],
                    entry["enemy_main_extra"],
                    entry["enemy_invasion_extra"],
                    memo_text,
                )
            ):
                daily_records[boss_name] = entry
        return {
            "date_key": effective_date,
            "chapter_enabled": chapter_enabled,
            "boss_enabled": boss_enabled,
            "daily_records": daily_records,
            "section_order": list(self.record_book_data.get("section_order", [])),
        }

    def _store_record_book_loaded_snapshot(self, date_key: str | None = None) -> None:
        self.record_book_loaded_snapshot = self._build_record_book_ui_snapshot(date_key)

    def _update_record_book_dirty_from_ui(self) -> None:
        current_snapshot = self._build_record_book_ui_snapshot()
        self._set_record_book_dirty(current_snapshot != self.record_book_loaded_snapshot)

    def _get_record_book_schedule_slot_presence(self, date_key: str | None = None) -> tuple[bool, dict[str, dict[str, bool]]]:
        effective_date = date_key or self.record_book_loaded_date_key or self._get_record_book_date_key()
        try:
            target_date = datetime.strptime(effective_date, RECORD_BOOK_DATE_FORMAT)
        except ValueError:
            return False, {}
        schedule_mode_active = bool(self.schedule_events)
        window_start = target_date.replace(hour=0, minute=0, second=0, microsecond=0)
        window_end = window_start + timedelta(days=1)
        now = self._get_schedule_reference_datetime()
        reference_datetime = now if now.date() == window_start.date() else window_end - timedelta(seconds=1)
        cutoff_datetime = self._get_schedule_maintenance_cutoff_datetime(reference_datetime)
        slot_presence: dict[str, dict[str, bool]] = {}
        for item in self.schedule_events:
            scheduled_at = item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime):
                continue
            if scheduled_at < window_start or scheduled_at >= window_end:
                continue
            if not self._is_schedule_event_visible(
                scheduled_at,
                item.get("created_at") if isinstance(item.get("created_at"), datetime) else None,
                reference_datetime,
                cutoff_datetime,
                is_invasion=self._is_schedule_invasion_item(item),
            ):
                continue
            boss_name = self._normalize_record_book_boss_name(str(item.get("boss_name") or item.get("display_name") or ""))
            if not boss_name or boss_name not in self.record_book_catalog_map:
                continue
            slot_key = "invasion" if bool(item.get("is_invasion")) else "main"
            slot_presence.setdefault(boss_name, {"main": False, "invasion": False})[slot_key] = True
        return schedule_mode_active, slot_presence

    def _update_record_book_save_button_state(self) -> None:
        if self.record_book_save_button is None:
            return
        try:
            if self.record_book_dirty:
                self.record_book_save_button.config(
                    state="normal",
                    bg="#2563eb",
                    fg="#ffffff",
                    activebackground="#1d4ed8",
                    activeforeground="#ffffff",
                    disabledforeground="#ffffff",
                    cursor="hand2",
                )
            else:
                self.record_book_save_button.config(
                    state="disabled",
                    bg="#bfdbfe",
                    fg="#eff6ff",
                    activebackground="#bfdbfe",
                    activeforeground="#eff6ff",
                    disabledforeground="#eff6ff",
                    cursor="arrow",
                )
        except tk.TclError:
            return

    def _stop_record_book_save_button_blink(self) -> None:
        if self.record_book_save_button is None:
            return
        if self.record_book_save_blink_after_id is not None and self.record_book_window is not None and self.record_book_window.winfo_exists():
            try:
                self.record_book_window.after_cancel(self.record_book_save_blink_after_id)
            except tk.TclError:
                pass
        self.record_book_save_blink_after_id = None
        self.record_book_save_blink_end_time = 0.0
        self.record_book_save_blink_on = False
        self._update_record_book_save_button_state()

    def _start_record_book_save_button_blink(self) -> None:
        if self.record_book_save_button is None or self.record_book_window is None or not self.record_book_window.winfo_exists():
            return
        self._stop_record_book_save_button_blink()
        self.record_book_save_blink_end_time = time.perf_counter() + 2.5
        self.record_book_save_blink_on = False
        self._record_book_save_button_blink_tick()

    def _record_book_save_button_blink_tick(self) -> None:
        if self.record_book_save_button is None or self.record_book_window is None or not self.record_book_window.winfo_exists():
            self.record_book_save_blink_after_id = None
            return
        if not self.record_book_dirty:
            self._stop_record_book_save_button_blink()
            return
        if time.perf_counter() >= self.record_book_save_blink_end_time:
            self.record_book_save_blink_after_id = None
            self.record_book_save_blink_on = False
            self._update_record_book_save_button_state()
            return
        self.record_book_save_blink_on = not self.record_book_save_blink_on
        try:
            if self.record_book_save_blink_on:
                self.record_book_save_button.config(
                    bg="#60a5fa",
                    fg="#ffffff",
                    activebackground="#3b82f6",
                    activeforeground="#ffffff",
                )
            else:
                self.record_book_save_button.config(
                    bg="#2563eb",
                    fg="#ffffff",
                    activebackground="#1d4ed8",
                    activeforeground="#ffffff",
                )
            self.record_book_save_blink_after_id = self.record_book_window.after(500, self._record_book_save_button_blink_tick)
        except tk.TclError:
            self.record_book_save_blink_after_id = None

    def _capture_record_book_ui_state_to_memory(self, date_key: str | None = None) -> str:
        effective_date = date_key or self.record_book_loaded_date_key or self._get_record_book_date_key()
        self._ensure_record_book_data_for_date(effective_date)
        for area_name, var in self.record_book_area_enabled_vars.items():
            self.record_book_data.setdefault("chapter_enabled", {})[area_name] = bool(var.get())
        for boss_name, var in self.record_book_boss_enabled_vars.items():
            self.record_book_data.setdefault("boss_enabled", {})[boss_name] = bool(var.get())
        daily_records: dict[str, dict[str, bool | str]] = {}
        for boss_name, row_vars in self.record_book_row_vars.items():
            ally_main = bool(row_vars["ally_main"].get())
            ally_invasion = bool(row_vars["ally_invasion"].get())
            ally_main_extra = bool(row_vars["ally_main_extra"].get())
            ally_invasion_extra = bool(row_vars["ally_invasion_extra"].get())
            enemy_main = bool(row_vars["enemy_main"].get())
            enemy_invasion = bool(row_vars["enemy_invasion"].get())
            enemy_main_extra = bool(row_vars["enemy_main_extra"].get())
            enemy_invasion_extra = bool(row_vars["enemy_invasion_extra"].get())
            memo_widget = self.record_book_row_widgets[boss_name]["memo"]
            memo = memo_widget.get("1.0", "end-1c").strip()
            row_vars["memo"].set(memo)
            if (
                ally_main
                or ally_invasion
                or ally_main_extra
                or ally_invasion_extra
                or enemy_main
                or enemy_invasion
                or enemy_main_extra
                or enemy_invasion_extra
                or memo
            ):
                daily_records[boss_name] = {
                    "ally_main": ally_main,
                    "ally_invasion": ally_invasion,
                    "ally_main_extra": ally_main_extra,
                    "ally_invasion_extra": ally_invasion_extra,
                    "enemy_main": enemy_main,
                    "enemy_invasion": enemy_invasion,
                    "enemy_main_extra": enemy_main_extra,
                    "enemy_invasion_extra": enemy_invasion_extra,
                    "memo": memo,
                }
        if daily_records:
            self.record_book_data.setdefault("records", {})[effective_date] = daily_records
        else:
            self.record_book_data.setdefault("records", {}).pop(effective_date, None)
        return effective_date

    def _discard_record_book_pending_changes(self) -> None:
        current_date_key = self.record_book_loaded_date_key or datetime.now().strftime(RECORD_BOOK_DATE_FORMAT)
        month_key = self._get_record_book_month_key(current_date_key)
        self.record_book_data_month_key = month_key
        self.record_book_data = self._load_record_book_data(month_key)
        self.record_book_loaded_snapshot = {}
        self._set_record_book_dirty(False)

    def _confirm_record_book_pending_changes(self, prompt_text: str, *, save_date_key: str | None = None) -> bool:
        if not self.record_book_dirty:
            return True
        choice = self._show_record_book_save_dialog(prompt_text)
        if choice is None:
            return False
        if choice:
            self._save_record_book_date(date_key=save_date_key)
            return True
        self._discard_record_book_pending_changes()
        self.record_book_status_var.set("저장하지 않은 변경사항을 취소했습니다.")
        return True

