    def _serialize_schedule_state_value(self, value):
        if isinstance(value, datetime):
            return {"__type__": "datetime", "value": value.isoformat()}
        if isinstance(value, tuple):
            return {"__type__": "tuple", "items": [self._serialize_schedule_state_value(item) for item in value]}
        if isinstance(value, list):
            return [self._serialize_schedule_state_value(item) for item in value]
        if isinstance(value, dict):
            return {str(key): self._serialize_schedule_state_value(item) for key, item in value.items()}
        return value

    def _deserialize_schedule_state_value(self, value):
        if isinstance(value, list):
            return [self._deserialize_schedule_state_value(item) for item in value]
        if isinstance(value, dict):
            if value.get("__type__") == "datetime":
                try:
                    return datetime.fromisoformat(str(value.get("value") or ""))
                except ValueError:
                    return None
            if value.get("__type__") == "tuple":
                raw_items = value.get("items")
                if isinstance(raw_items, list):
                    return tuple(self._deserialize_schedule_state_value(item) for item in raw_items)
                return tuple()
            return {str(key): self._deserialize_schedule_state_value(item) for key, item in value.items()}
        return value

    def _normalize_schedule_quick_cut_history_entries(self, entries: list[object]) -> list[dict[str, object]]:
        normalized_entries: list[dict[str, object]] = []
        for raw_entry in entries:
            if not isinstance(raw_entry, dict):
                continue
            entry = dict(raw_entry)
            identity = entry.get("identity")
            if not (isinstance(identity, tuple) and len(identity) == 4):
                continue
            match_key = entry.get("match_key")
            if not (isinstance(match_key, tuple) and len(match_key) == 3):
                entry["match_key"] = self._get_schedule_cut_match_key(identity=identity)
            item = entry.get("item")
            if isinstance(item, dict):
                entry["item"] = self._normalize_schedule_state_item(dict(item))
            backup = entry.get("backup")
            if isinstance(backup, dict):
                entry["backup"] = {
                    "schedule_events": [dict(item) for item in backup.get("schedule_events", []) if isinstance(item, dict)],
                    "schedule_active_entries": [dict(item) for item in backup.get("schedule_active_entries", []) if isinstance(item, dict)],
                    "schedule_control_events": [dict(item) for item in backup.get("schedule_control_events", []) if isinstance(item, dict)],
                    "previous_meta": dict(backup.get("previous_meta")) if isinstance(backup.get("previous_meta"), dict) else None,
                }
            entry["active_after"] = None
            normalized_entries.append(entry)
        return normalized_entries

    def _load_schedule_state(self) -> None:
        if not os.path.exists(SCHEDULE_STATE_PATH):
            return
        try:
            with open(SCHEDULE_STATE_PATH, "r", encoding="utf-8") as file:
                payload = json.load(file)
        except (OSError, json.JSONDecodeError):
            return

        restored = self._deserialize_schedule_state_value(payload)
        if not isinstance(restored, dict):
            return

        base_datetime_value = restored.get("base_datetime")
        if isinstance(base_datetime_value, datetime):
            self.schedule_base_year_var.set(base_datetime_value.strftime("%Y년"))
            self.schedule_base_month_var.set(base_datetime_value.strftime("%m월"))
            self.schedule_base_day_var.set(base_datetime_value.strftime("%d일"))
            self.schedule_base_hour_var.set(base_datetime_value.strftime("%H시"))
            self.schedule_base_minute_var.set(base_datetime_value.strftime("%M분"))

        view_date_value = restored.get("view_date")
        if isinstance(view_date_value, datetime):
            self.schedule_view_year_var.set(view_date_value.strftime("%Y년"))
            self.schedule_view_month_var.set(view_date_value.strftime("%m월"))
            self.schedule_view_day_var.set(view_date_value.strftime("%d일"))
            self.schedule_view_weekday_var.set(f"({self._get_weekday_label(view_date_value)})")
            self._refresh_schedule_view_weekday_style(view_date_value)

        maintenance_weekday = str(restored.get("maintenance_weekday") or "").strip()
        if maintenance_weekday in {"월", "화", "수", "목", "금", "토", "일"}:
            self.schedule_maintenance_weekday_var.set(maintenance_weekday)
        maintenance_hour = str(restored.get("maintenance_hour") or "").strip()
        maintenance_hour_digits = re.sub(r"[^0-9]", "", maintenance_hour)
        if maintenance_hour_digits:
            self.schedule_maintenance_hour_var.set(f"{int(maintenance_hour_digits):02d}시")
        maintenance_minute = str(restored.get("maintenance_minute") or "").strip()
        maintenance_minute_digits = re.sub(r"[^0-9]", "", maintenance_minute)
        if maintenance_minute_digits:
            self.schedule_maintenance_minute_var.set(f"{int(maintenance_minute_digits):02d}분")
        self.schedule_input_past_enabled = bool(restored.get("schedule_input_past_enabled", self.schedule_input_past_enabled))
        self.schedule_input_past_var.set(self.schedule_input_past_enabled)

        schedule_events = restored.get("schedule_events")
        if isinstance(schedule_events, list):
            self.schedule_events = self._normalize_schedule_event_items([item for item in schedule_events if isinstance(item, dict)])

        schedule_active_entries = restored.get("schedule_active_entries")
        if isinstance(schedule_active_entries, list):
            self.schedule_active_entries = self._normalize_schedule_active_items([item for item in schedule_active_entries if isinstance(item, dict)])

        schedule_control_events = restored.get("schedule_control_events")
        if isinstance(schedule_control_events, list):
            self.schedule_control_events = [item for item in schedule_control_events if isinstance(item, dict)]

        saved_ocr_items = restored.get("schedule_input_ocr_saved_items")
        if isinstance(saved_ocr_items, list):
            normalized_saved_items = []
            for raw_item in saved_ocr_items:
                normalized_item = self._normalize_schedule_input_ocr_queue_item(raw_item) if isinstance(raw_item, dict) else None
                if normalized_item is not None:
                    normalized_saved_items.append(normalized_item)
            self.schedule_input_ocr_saved_items = normalized_saved_items
            valid_item_ids = {str(item.get("id") or "") for item in normalized_saved_items}
            saved_ocr_results = restored.get("schedule_input_ocr_saved_results")
            if isinstance(saved_ocr_results, list):
                self.schedule_input_ocr_saved_results = self._normalize_schedule_input_ocr_saved_results(saved_ocr_results, valid_item_ids)
            saved_invasion_mode = restored.get("schedule_input_ocr_saved_invasion_mode")
            self.schedule_input_ocr_saved_invasion_mode = bool(saved_invasion_mode) if isinstance(saved_invasion_mode, bool) else None

        schedule_last_import_meta = restored.get("schedule_last_import_meta")
        if isinstance(schedule_last_import_meta, dict):
            self.schedule_last_import_meta = schedule_last_import_meta

        schedule_delete_active_cutoff_datetime = restored.get("schedule_delete_active_cutoff_datetime")
        if isinstance(schedule_delete_active_cutoff_datetime, datetime):
            self.schedule_delete_active_cutoff_datetime = schedule_delete_active_cutoff_datetime.replace(microsecond=0)

        tree_quick_cut_history = restored.get("schedule_tree_quick_cut_history")
        if isinstance(tree_quick_cut_history, list):
            self.schedule_tree_quick_cut_history = self._normalize_schedule_quick_cut_history_entries(tree_quick_cut_history)

        active_quick_cut_history = restored.get("schedule_active_quick_cut_history")
        if isinstance(active_quick_cut_history, list):
            self.schedule_active_quick_cut_history = self._normalize_schedule_quick_cut_history_entries(active_quick_cut_history)

        self._prune_schedule_quick_cut_histories()

    def _normalize_schedule_state_item(self, item: dict[str, object]) -> dict[str, object]:
        normalized = dict(item)
        if str(normalized.get("state") or "") == "control" or str(normalized.get("control_type") or ""):
            return normalized
        source_name = str(
            normalized.get("raw_name")
            or normalized.get("display_name")
            or normalized.get("boss_name")
            or ""
        ).strip()
        if not source_name:
            return normalized
        boss_info = self._normalize_schedule_input_boss_name(source_name)
        normalized.update(boss_info)
        normalized["respawn_seconds"] = self._get_schedule_respawn_seconds_for_state_item(normalized)
        cut_at = self._get_schedule_event_cut_datetime(normalized)
        if isinstance(cut_at, datetime):
            normalized["cut_at"] = cut_at
        else:
            normalized.pop("cut_at", None)
        normalized.pop("last_cut_time_text", None)
        normalized.pop("last_cut_datetime", None)
        return normalized

    def _is_schedule_invasion_item(self, item: dict[str, object] | None) -> bool:
        if not isinstance(item, dict):
            return False
        if bool(item.get("is_invasion")):
            return True
        raw_key = str(item.get("raw_key") or "").strip()
        if raw_key.startswith("invasion:"):
            return True
        source_name = str(item.get("raw_name") or item.get("display_name") or item.get("boss_name") or "").strip()
        return self._normalize_schedule_boss_lookup_key(source_name).startswith("침공")

    def _get_schedule_respawn_seconds_for_state_item(self, item: dict[str, object] | None) -> int:
        if not isinstance(item, dict):
            return 0
        return self._get_schedule_respawn_seconds_for_boss(str(item.get("boss_name") or ""))

    def _get_schedule_event_cut_datetime(self, item: dict[str, object] | None) -> datetime | None:
        if not isinstance(item, dict):
            return None
        cut_at = item.get("cut_at")
        if isinstance(cut_at, datetime):
            return cut_at.replace(microsecond=0)
        legacy_cut_at = item.get("last_cut_datetime")
        if isinstance(legacy_cut_at, datetime):
            return legacy_cut_at.replace(microsecond=0)
        legacy_cut_text = str(item.get("last_cut_time_text") or "").strip()
        scheduled_at = item.get("scheduled_at")
        if not legacy_cut_text or not isinstance(scheduled_at, datetime):
            return None
        match = re.fullmatch(r"(?P<hour>\d{2}):(?P<minute>\d{2})(?::(?P<second>\d{2}))?", legacy_cut_text)
        if match is None:
            return None
        try:
            return scheduled_at.replace(
                hour=int(match.group("hour") or 0),
                minute=int(match.group("minute") or 0),
                second=int(match.group("second") or 0),
                microsecond=0,
            )
        except ValueError:
            return None

    def _get_schedule_event_cut_time_text(self, item: dict[str, object] | None) -> str:
        cut_at = self._get_schedule_event_cut_datetime(item)
        if not isinstance(cut_at, datetime):
            return ""
        return cut_at.strftime("%H:%M:%S")

    def _normalize_schedule_event_items(self, items: list[dict[str, object]]) -> list[dict[str, object]]:
        deduped: dict[tuple[str, str, str], dict[str, object]] = {}
        for item in items:
            normalized = self._normalize_schedule_state_item(item)
            scheduled_at = normalized.get("scheduled_at")
            scheduled_key = scheduled_at.isoformat() if isinstance(scheduled_at, datetime) else ""
            dedupe_key = (
                str(normalized.get("raw_key") or ""),
                scheduled_key,
                str(normalized.get("state") or ""),
            )
            deduped[dedupe_key] = normalized
        return sorted(
            deduped.values(),
            key=lambda item: (item.get("scheduled_at") or datetime.max, str(item.get("display_name") or item.get("boss_name") or "")),
        )

    def _normalize_schedule_active_items(self, items: list[dict[str, object]]) -> list[dict[str, object]]:
        deduped: dict[str, dict[str, object]] = {}
        for item in items:
            normalized = self._normalize_schedule_state_item(item)
            dedupe_key = self._get_schedule_panel_dedupe_key(normalized) or str(normalized.get("raw_key") or "")
            if not dedupe_key:
                continue
            existing = deduped.get(dedupe_key)
            current_created = normalized.get("created_at")
            existing_created = existing.get("created_at") if isinstance(existing, dict) else None
            if not isinstance(existing_created, datetime) or (
                isinstance(current_created, datetime) and current_created >= existing_created
            ):
                deduped[dedupe_key] = normalized
        return sorted(
            deduped.values(),
            key=lambda item: str(item.get("display_name") or item.get("boss_name") or ""),
        )

    def _normalize_schedule_input_ocr_queue_item(self, item: dict[str, object]) -> dict[str, object] | None:
        if not isinstance(item, dict):
            return None
        image_path = str(item.get("path") or "").strip()
        if not image_path or not os.path.exists(image_path):
            return None
        normalized = {
            "id": str(item.get("id") or uuid.uuid4().hex),
            "path": image_path,
            "width": max(0, int(item.get("width") or 0)),
            "height": max(0, int(item.get("height") or 0)),
            "thumbnail": None,
            "area_guess": str(item.get("area_guess") or ""),
            "warning_count": max(0, int(item.get("warning_count") or 0)),
            "source": str(item.get("source") or ""),
            "captured_at": item.get("captured_at") if isinstance(item.get("captured_at"), datetime) else datetime.now(),
        }
        content_hash = str(item.get("content_hash") or "").strip()
        if content_hash:
            normalized["content_hash"] = content_hash
        return normalized

    def _normalize_schedule_input_ocr_saved_results(self, results: list[object], valid_item_ids: set[str]) -> list[dict[str, object]]:
        normalized_results: list[dict[str, object]] = []
        for raw_item in results:
            if not isinstance(raw_item, dict):
                continue
            item_id = str(raw_item.get("item_id") or "")
            if item_id and valid_item_ids and item_id not in valid_item_ids:
                continue
            normalized_results.append(dict(raw_item))
        return normalized_results

    def _prune_schedule_quick_cut_histories(self, reference_datetime: datetime | None = None) -> bool:
        cutoff_reference = reference_datetime or self._get_schedule_reference_datetime()
        before_tree_count = len(self.schedule_tree_quick_cut_history)
        before_active_count = len(self.schedule_active_quick_cut_history)

        def keep_tree_entry(entry: dict[str, object]) -> bool:
            cut_datetime = self._get_schedule_quick_cut_action_at(entry)
            return (
                isinstance(cut_datetime, datetime)
                and cutoff_reference <= cut_datetime + timedelta(seconds=SCHEDULE_TREE_QUICK_CUT_RETENTION_SECONDS)
            )

        def keep_active_entry(entry: dict[str, object]) -> bool:
            cut_datetime = self._get_schedule_quick_cut_action_at(entry)
            return (
                isinstance(cut_datetime, datetime)
                and cutoff_reference <= cut_datetime + timedelta(seconds=SCHEDULE_ACTIVE_QUICK_CUT_RETENTION_SECONDS)
            )

        self.schedule_tree_quick_cut_history = [
            dict(entry) for entry in self.schedule_tree_quick_cut_history if isinstance(entry, dict) and keep_tree_entry(entry)
        ]
        self.schedule_active_quick_cut_history = [
            dict(entry) for entry in self.schedule_active_quick_cut_history if isinstance(entry, dict) and keep_active_entry(entry)
        ]
        self.schedule_tree_overlay_cooldowns = {}
        self.schedule_active_overlay_cooldowns = {}
        return (
            before_tree_count != len(self.schedule_tree_quick_cut_history)
            or before_active_count != len(self.schedule_active_quick_cut_history)
        )

    def _save_schedule_state(self) -> None:
        payload = {
            "base_datetime": self._get_schedule_base_datetime(),
            "view_date": self._get_schedule_view_datetime(),
            "maintenance_weekday": self.schedule_maintenance_weekday_var.get(),
            "maintenance_hour": self.schedule_maintenance_hour_var.get(),
            "maintenance_minute": self.schedule_maintenance_minute_var.get(),
            "schedule_input_past_enabled": bool(self.schedule_input_past_enabled),
            "schedule_events": self.schedule_events,
            "schedule_active_entries": self.schedule_active_entries,
            "schedule_control_events": self.schedule_control_events,
            "schedule_input_ocr_saved_items": self.schedule_input_ocr_saved_items,
            "schedule_input_ocr_saved_results": self.schedule_input_ocr_saved_results,
            "schedule_input_ocr_saved_invasion_mode": self.schedule_input_ocr_saved_invasion_mode,
            "schedule_last_import_meta": self.schedule_last_import_meta,
            "schedule_tree_quick_cut_history": self.schedule_tree_quick_cut_history,
            "schedule_active_quick_cut_history": self.schedule_active_quick_cut_history,
            "schedule_delete_active_cutoff_datetime": getattr(self, "schedule_delete_active_cutoff_datetime", None),
        }
        try:
            with open(SCHEDULE_STATE_PATH, "w", encoding="utf-8") as file:
                json.dump(self._serialize_schedule_state_value(payload), file, ensure_ascii=False, indent=2)
        except OSError:
            return

    def _get_weekday_label(self, date_value: datetime) -> str:
        return ("월", "화", "수", "목", "금", "토", "일")[date_value.weekday()]

    def _parse_schedule_time_sync_datetime(self, raw_value: str | None) -> datetime | None:
        text = str(raw_value or "").strip()
        if not text:
            return None
        normalized = re.sub(r"\s+", " ", text)
        korean_ampm_match = re.match(r"^(\d{4}-\d{1,2}-\d{1,2})\s+(오전|오후)\s+(\d{1,2}:\d{2}:\d{2})$", normalized)
        if korean_ampm_match:
            date_part, ampm_text, time_part = korean_ampm_match.groups()
            try:
                hour_text, minute_text, second_text = time_part.split(":")
                hour_value = int(hour_text)
                if ampm_text == "오후" and hour_value < 12:
                    hour_value += 12
                elif ampm_text == "오전" and hour_value == 12:
                    hour_value = 0
                return datetime.strptime(
                    f"{date_part} {hour_value:02d}:{minute_text}:{second_text}",
                    "%Y-%m-%d %H:%M:%S",
                )
            except ValueError:
                pass
        for fmt in (
            "%Y-%m-%d %H:%M:%S",
            "%Y-%m-%dT%H:%M:%S",
            "%m/%d/%Y %I:%M:%S %p",
            "%m/%d/%Y %H:%M:%S",
        ):
            try:
                return datetime.strptime(normalized, fmt)
            except ValueError:
                continue
        return None

    def _refresh_schedule_time_sync_status_text(self) -> None:
        if getattr(self, "schedule_time_sync_in_progress", False):
            text = "Windows 시간 동기화 기록 확인 중..."
        else:
            success_at = self._parse_schedule_time_sync_datetime(getattr(self, "schedule_time_sync_last_success_at", ""))
            last_status = str(getattr(self, "schedule_time_sync_last_status", "") or "").strip().lower()
            if isinstance(success_at, datetime):
                text = f"Windows 마지막 시간 동기화: {success_at.strftime('%Y-%m-%d %H:%M:%S')}"
            elif last_status == "query_failed":
                failed_at = self._parse_schedule_time_sync_datetime(getattr(self, "schedule_time_sync_last_attempt_at", ""))
                if isinstance(failed_at, datetime):
                    text = f"Windows 시간 동기화 기록 확인 실패: {failed_at.strftime('%Y-%m-%d %H:%M:%S')}"
                else:
                    text = "Windows 시간 동기화 기록 확인 실패"
            elif last_status == "query_ok":
                text = "Windows 마지막 시간 동기화: 기록 없음"
            else:
                text = "Windows 마지막 시간 동기화: 확인 필요"
            auto_result = str(getattr(self, "schedule_time_sync_last_auto_result", "") or "").strip().lower()
            if auto_result == "success":
                text = f"{text} (자동 성공)"
            elif auto_result == "failed":
                text = f"{text} (자동 실패)"
        if hasattr(self, "schedule_time_sync_status_var") and self.schedule_time_sync_status_var is not None:
            try:
                self.schedule_time_sync_status_var.set(text)
            except tk.TclError:
                pass

    def _clear_schedule_time_sync_after(self) -> None:
        if self.schedule_time_sync_after_id is not None and self.root is not None and self.root.winfo_exists():
            try:
                self.root.after_cancel(self.schedule_time_sync_after_id)
            except tk.TclError:
                pass
        self.schedule_time_sync_after_id = None

    def _queue_schedule_time_sync_check(self, delay_ms: int, *, reason: str) -> None:
        self._clear_schedule_time_sync_after()
        if not self._callbacks_available():
            return
        delay_ms = max(1000, int(delay_ms))
        try:
            self.schedule_time_sync_after_id = self.root.after(
                delay_ms,
                lambda: self._schedule_time_sync_periodic_check(reason=reason),
            )
        except tk.TclError:
            self.schedule_time_sync_after_id = None

    def _get_schedule_time_sync_due_delay_ms(self, now_value: datetime | None = None) -> int:
        now_value = now_value or datetime.now()
        success_at = self._parse_schedule_time_sync_datetime(getattr(self, "schedule_time_sync_last_success_at", ""))
        if not isinstance(success_at, datetime):
            return 0
        due_at = success_at + timedelta(seconds=SCHEDULE_TIME_SYNC_INTERVAL_SECONDS)
        return max(0, int((due_at - now_value).total_seconds() * 1000))

    def _should_auto_sync_schedule_time(self, now_value: datetime | None = None) -> bool:
        now_value = now_value or datetime.now()
        success_at = self._parse_schedule_time_sync_datetime(getattr(self, "schedule_time_sync_last_success_at", ""))
        if not isinstance(success_at, datetime):
            return True
        return (now_value - success_at).total_seconds() >= SCHEDULE_TIME_SYNC_INTERVAL_SECONDS

    def _extract_schedule_time_sync_success_text_from_message(self, message: str) -> str:
        for part in str(message or "").split("|"):
            key, _, value = part.strip().partition("=")
            if key == "success":
                return value.strip()
        return ""

    def _extract_w32tm_status_field(self, output_text: str, *prefixes: str) -> str:
        lines = [str(line or "").strip() for line in str(output_text or "").splitlines()]
        lowered_prefixes = [prefix.lower() for prefix in prefixes]
        for line in lines:
            lowered = line.lower()
            for prefix in lowered_prefixes:
                if lowered.startswith(prefix):
                    return line.split(":", 1)[1].strip() if ":" in line else ""
        return ""

    def _extract_w32tm_last_success_time_text(self, output_text: str) -> str:
        lines = [str(line or "").strip() for line in str(output_text or "").splitlines() if str(line or "").strip()]
        for line in lines:
            lowered = line.lower()
            if "last successful sync time" in lowered:
                return line.split(":", 1)[1].strip() if ":" in line else ""
            if "마지막으로 동기화한 시간" in line and ":" in line:
                candidate = line.split(":", 1)[1].strip()
                if self._parse_schedule_time_sync_datetime(candidate) is not None:
                    return candidate
            if "성공" in line and "동기화" in line and "시간" in line and ":" in line:
                candidate = line.split(":", 1)[1].strip()
                if self._parse_schedule_time_sync_datetime(candidate) is not None:
                    return candidate
        return ""

    def _decode_windows_time_command_output(self, completed: subprocess.CompletedProcess) -> str:
        output_chunks: list[str] = []
        for raw_part in (completed.stdout, completed.stderr):
            if not raw_part:
                continue
            decoded_part = None
            for encoding_name in (
                locale.getpreferredencoding(False),
                "cp949",
                "utf-8",
            ):
                if not encoding_name:
                    continue
                try:
                    decoded_part = raw_part.decode(encoding_name)
                    break
                except UnicodeDecodeError:
                    continue
            if decoded_part is None:
                decoded_part = raw_part.decode("utf-8", errors="replace")
            output_chunks.append(decoded_part)
        return "\n".join(part for part in output_chunks if part).strip()

    def _run_windows_time_status_query_command(self) -> tuple[bool, str]:
        creation_flags = getattr(subprocess, "CREATE_NO_WINDOW", 0)
        try:
            completed = subprocess.run(
                ["w32tm", "/query", "/status", "/verbose"],
                capture_output=True,
                text=False,
                creationflags=creation_flags,
                check=False,
            )
        except OSError as exc:
            return False, str(exc)
        output = self._decode_windows_time_command_output(completed)
        if completed.returncode != 0:
            return False, output or "Windows 시간 상태 조회에 실패했습니다."
        last_success = self._extract_w32tm_last_success_time_text(output)
        last_error = self._extract_w32tm_status_field(output, "Last Sync Error:", "마지막 동기화 오류:")
        source = self._extract_w32tm_status_field(output, "Source:", "원본:")
        status_parts = []
        if last_success:
            status_parts.append(f"success={last_success}")
        if source:
            status_parts.append(f"source={source}")
        if last_error:
            status_parts.append(f"error={last_error}")
        return True, " | ".join(status_parts)

    def _run_windows_time_resync_command(self) -> tuple[bool, str]:
        creation_flags = getattr(subprocess, "CREATE_NO_WINDOW", 0)
        try:
            completed = subprocess.run(
                ["w32tm", "/resync", "/force"],
                capture_output=True,
                text=False,
                creationflags=creation_flags,
                check=False,
            )
        except OSError as exc:
            return False, str(exc)
        output = self._decode_windows_time_command_output(completed)
        if completed.returncode != 0:
            return False, output or "Windows 시간 동기화에 실패했습니다."
        return True, output or "Windows 시간 동기화 성공"

    def _finalize_schedule_time_sync_result(
        self,
        *,
        success: bool,
        attempted_at_text: str,
        message: str,
        reason: str,
        auto_result: str | None = None,
    ) -> None:
        self.schedule_time_sync_in_progress = False
        self.schedule_time_sync_last_attempt_at = attempted_at_text
        self.schedule_time_sync_last_status = "query_ok" if success else "query_failed"
        self.schedule_time_sync_last_error = "" if success else str(message or "").strip()
        if auto_result is not None:
            self.schedule_time_sync_last_auto_result = str(auto_result or "").strip().lower()
        if success:
            success_text = self._extract_schedule_time_sync_success_text_from_message(message)
            parsed_success = self._parse_schedule_time_sync_datetime(success_text)
            if isinstance(parsed_success, datetime):
                self.schedule_time_sync_last_success_at = parsed_success.strftime("%Y-%m-%d %H:%M:%S")
                if auto_result is None and not self._should_auto_sync_schedule_time(parsed_success):
                    self.schedule_time_sync_last_auto_result = ""
        else:
            self.schedule_time_sync_last_success_at = str(getattr(self, "schedule_time_sync_last_success_at", "") or "")
        self._refresh_schedule_time_sync_status_text()
        try:
            self._save_settings()
        except Exception:
            pass
        self._plan_schedule_time_sync_next_check()

    def _plan_schedule_time_sync_next_check(self) -> None:
        self._clear_schedule_time_sync_after()
        if not self._callbacks_available():
            return
        if not bool(getattr(self, "is_admin_process", False)):
            self._queue_schedule_time_sync_check(SCHEDULE_TIME_SYNC_PERIODIC_CHECK_MS, reason="poll")
            return
        now_value = datetime.now()
        if self._should_auto_sync_schedule_time(now_value):
            if str(getattr(self, "schedule_time_sync_last_auto_result", "") or "").strip().lower() == "failed":
                self._queue_schedule_time_sync_check(SCHEDULE_TIME_SYNC_PERIODIC_CHECK_MS, reason="poll")
            else:
                self._queue_schedule_time_sync_check(1000, reason="due")
            return
        self._queue_schedule_time_sync_check(self._get_schedule_time_sync_due_delay_ms(now_value), reason="due")

    def _perform_schedule_time_sync(self, *, reason: str = "auto") -> None:
        if self.schedule_time_sync_in_progress:
            return
        self.schedule_time_sync_in_progress = True
        self._refresh_schedule_time_sync_status_text()
        attempted_at_text = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        is_admin_process = bool(getattr(self, "is_admin_process", False))

        def worker() -> None:
            first_query_success, first_query_message = self._run_windows_time_status_query_command()
            final_success = first_query_success
            final_message = first_query_message
            auto_result = None
            query_success_at_text = self._extract_schedule_time_sync_success_text_from_message(first_query_message)
            parsed_query_success_at = self._parse_schedule_time_sync_datetime(query_success_at_text)
            auto_sync_needed = reason == "startup" and is_admin_process and (
                not isinstance(parsed_query_success_at, datetime)
                or (datetime.now() - parsed_query_success_at).total_seconds() >= SCHEDULE_TIME_SYNC_INTERVAL_SECONDS
            )
            if auto_sync_needed:
                sync_success, _sync_message = self._run_windows_time_resync_command()
                auto_result = "success" if sync_success else "failed"
                if sync_success:
                    time.sleep(1.0)
                followup_query_success, followup_query_message = self._run_windows_time_status_query_command()
                if followup_query_success or not first_query_success:
                    final_success = followup_query_success
                    final_message = followup_query_message

            def finish() -> None:
                self._finalize_schedule_time_sync_result(
                    success=final_success,
                    attempted_at_text=attempted_at_text,
                    message=final_message,
                    reason=reason,
                    auto_result=auto_result,
                )

            try:
                self.root.after(0, finish)
            except tk.TclError:
                pass

        threading.Thread(target=worker, daemon=True).start()

    def _schedule_time_sync_periodic_check(self, *, initial: bool = False, reason: str | None = None) -> None:
        self.schedule_time_sync_after_id = None
        if not self._callbacks_available():
            return
        self._perform_schedule_time_sync(reason=reason or ("startup" if initial else "poll"))

    def _get_schedule_maintenance_weekday_index(self) -> int:
        weekday_map = {"월": 0, "화": 1, "수": 2, "목": 3, "금": 4, "토": 5, "일": 6}
        weekday_text = str(self.schedule_maintenance_weekday_var.get() or "").strip()
        return weekday_map.get(weekday_text, 2)

    def _get_schedule_invasion_weekday_index(self) -> int:
        weekday_map = {"월": 0, "화": 1, "수": 2, "목": 3, "금": 4, "토": 5, "일": 6}
        weekday_text = str(self.schedule_invasion_weekday_var.get() or "").strip()
        return weekday_map.get(weekday_text, 2)

    def _is_schedule_invasion_datetime_visible(self, scheduled_at: datetime | None) -> bool:
        return isinstance(scheduled_at, datetime) and scheduled_at.weekday() == self._get_schedule_invasion_weekday_index()

    def _refresh_schedule_view_weekday_style(self, date_value: datetime) -> None:
        if self.schedule_view_weekday_label is None:
            return
        if date_value.weekday() == 6:
            fg = "#b91c1c"
        elif date_value.weekday() == 5:
            fg = "#1d4ed8"
        else:
            fg = "#475569"
        try:
            self.schedule_view_weekday_label.config(fg=fg)
        except tk.TclError:
            return

    def _get_schedule_base_datetime(self) -> datetime | None:
        try:
            year = int(re.sub(r"[^0-9]", "", (self.schedule_base_year_var.get() or "").strip()))
            month = int(re.sub(r"[^0-9]", "", (self.schedule_base_month_var.get() or "").strip()))
            day = int(re.sub(r"[^0-9]", "", (self.schedule_base_day_var.get() or "").strip()))
            hour = int(re.sub(r"[^0-9]", "", (self.schedule_base_hour_var.get() or "").strip()))
            minute = int(re.sub(r"[^0-9]", "", (self.schedule_base_minute_var.get() or "").strip()))
            return datetime(year, month, day, hour, minute)
        except ValueError:
            return None

    def _get_schedule_view_datetime(self) -> datetime | None:
        try:
            year = int(re.sub(r"[^0-9]", "", (self.schedule_view_year_var.get() or "").strip()))
            month = int(re.sub(r"[^0-9]", "", (self.schedule_view_month_var.get() or "").strip()))
            day = int(re.sub(r"[^0-9]", "", (self.schedule_view_day_var.get() or "").strip()))
            return datetime(year, month, day)
        except ValueError:
            return None

    def _set_schedule_view_datetime_fields(self, date_value: datetime) -> None:
        self.schedule_view_year_var.set(date_value.strftime("%Y년"))
        self.schedule_view_month_var.set(date_value.strftime("%m월"))
        self.schedule_view_day_var.set(date_value.strftime("%d일"))
        self.schedule_view_weekday_var.set(f"({self._get_weekday_label(date_value)})")
        self._refresh_schedule_view_weekday_style(date_value)

    def _get_schedule_maintenance_cutoff_datetime(self, reference_datetime: datetime) -> datetime | None:
        weekday_map = {"월": 0, "화": 1, "수": 2, "목": 3, "금": 4, "토": 5, "일": 6}
        weekday_text = str(self.schedule_maintenance_weekday_var.get() or "").strip()
        target_weekday = weekday_map.get(weekday_text, 2)
        try:
            hour = int(re.sub(r"[^0-9]", "", (self.schedule_maintenance_hour_var.get() or "").strip()))
            minute = int(re.sub(r"[^0-9]", "", (self.schedule_maintenance_minute_var.get() or "").strip()))
        except ValueError:
            hour = 8
            minute = 0
        if hour == 0 and minute == 0:
            return None
        target_weekday = self._get_schedule_maintenance_weekday_index()
        days_until = (target_weekday - reference_datetime.weekday()) % 7
        target_datetime = (reference_datetime + timedelta(days=days_until)).replace(
            hour=hour,
            minute=minute,
            second=0,
            microsecond=0,
        )
        if target_datetime <= reference_datetime:
            target_datetime += timedelta(days=7)
        return target_datetime

    def _get_schedule_previous_maintenance_datetime(self, reference_datetime: datetime) -> datetime | None:
        weekday_map = {"월": 0, "화": 1, "수": 2, "목": 3, "금": 4, "토": 5, "일": 6}
        weekday_text = str(self.schedule_maintenance_weekday_var.get() or "").strip()
        target_weekday = weekday_map.get(weekday_text, 2)
        try:
            hour = int(re.sub(r"[^0-9]", "", (self.schedule_maintenance_hour_var.get() or "").strip()))
            minute = int(re.sub(r"[^0-9]", "", (self.schedule_maintenance_minute_var.get() or "").strip()))
        except ValueError:
            hour = 8
            minute = 0
        if hour == 0 and minute == 0:
            return None
        target_weekday = self._get_schedule_maintenance_weekday_index()
        days_since = (reference_datetime.weekday() - target_weekday) % 7
        target_datetime = (reference_datetime - timedelta(days=days_since)).replace(
            hour=hour,
            minute=minute,
            second=0,
            microsecond=0,
        )
        if target_datetime > reference_datetime:
            target_datetime -= timedelta(days=7)
        return target_datetime

    def _get_schedule_view_refresh_key(self) -> tuple[int, int, int] | None:
        view_datetime = self._get_schedule_view_datetime()
        if view_datetime is None:
            return None
        return (view_datetime.year, view_datetime.month, view_datetime.day)

    def _get_schedule_maintenance_refresh_key(self) -> tuple[str, str, str]:
        weekday_text = str(self.schedule_maintenance_weekday_var.get() or "").strip()
        hour_digits = re.sub(r"[^0-9]", "", str(self.schedule_maintenance_hour_var.get() or "").strip())
        minute_digits = re.sub(r"[^0-9]", "", str(self.schedule_maintenance_minute_var.get() or "").strip())
        return (
            weekday_text,
            f"{int(hour_digits):02d}" if hour_digits else "",
            f"{int(minute_digits):02d}" if minute_digits else "",
        )

    def _update_schedule_refresh_scope_keys(self) -> None:
        self.schedule_last_refreshed_view_key = self._get_schedule_view_refresh_key()
        self.schedule_last_refreshed_maintenance_key = self._get_schedule_maintenance_refresh_key()

    def _get_schedule_reference_datetime(self) -> datetime:
        return datetime.now().replace(microsecond=0)

    def _get_schedule_default_server_open_datetime(self, reference_datetime: datetime | None = None) -> datetime:
        base_reference = reference_datetime if isinstance(reference_datetime, datetime) else self._get_schedule_reference_datetime()
        base_reference = base_reference.replace(second=0, microsecond=0)
        target_weekday = 2
        days_since = (base_reference.weekday() - target_weekday) % 7
        candidate = (base_reference - timedelta(days=days_since)).replace(hour=10, minute=0, second=0, microsecond=0)
        if candidate >= base_reference:
            candidate -= timedelta(days=7)
        return candidate

    def _get_schedule_last_imported_at(self) -> datetime | None:
        if isinstance(self.schedule_last_import_meta, dict):
            imported_at = self.schedule_last_import_meta.get("imported_at")
            if isinstance(imported_at, datetime):
                return imported_at
        created_candidates: list[datetime] = []
        for item in self.schedule_events + self.schedule_active_entries:
            created_at = item.get("created_at")
            if isinstance(created_at, datetime):
                created_candidates.append(created_at)
        return max(created_candidates) if created_candidates else None

    def _get_schedule_active_control_event(self, reference_datetime: datetime) -> dict[str, object] | None:
        candidates: list[dict[str, object]] = []
        previous_maintenance = self._get_schedule_previous_maintenance_datetime(reference_datetime)
        imported_at = self._get_schedule_last_imported_at()
        if previous_maintenance is not None and (imported_at is None or imported_at < previous_maintenance):
            candidates.append(
                {
                    "control_type": "maintenance_stale",
                    "scheduled_at": previous_maintenance,
                    "display_name": "정기점검",
                    "created_at": previous_maintenance,
                }
            )
        for item in self.schedule_control_events:
            scheduled_at = item.get("scheduled_at")
            if isinstance(scheduled_at, datetime) and scheduled_at <= reference_datetime:
                candidates.append(item)
        if not candidates:
            return None
        candidates.sort(key=lambda item: item.get("scheduled_at") or datetime.min)
        return candidates[-1]

    def _is_schedule_event_visible(
        self,
        scheduled_at: datetime,
        created_at: datetime | None,
        reference_datetime: datetime,
        future_cutoff_datetime: datetime | None,
        *,
        is_invasion: bool = False,
    ) -> bool:
        if is_invasion and not self._is_schedule_invasion_datetime_visible(scheduled_at):
            return False
        if future_cutoff_datetime is not None and scheduled_at >= future_cutoff_datetime:
            return False
        active_control = self._get_schedule_active_control_event(reference_datetime)
        if active_control is None:
            return True
        control_time = active_control.get("scheduled_at")
        if not isinstance(control_time, datetime):
            return True
        control_type = str(active_control.get("control_type") or "")
        if control_type == "server_open":
            return scheduled_at >= control_time
        if control_type in {"temporary_maintenance", "maintenance_stale"}:
            if scheduled_at < control_time:
                return True
            return isinstance(created_at, datetime) and created_at > control_time
        return True

    def _get_schedule_stale_cutoff_datetime(self, reference_datetime: datetime) -> datetime | None:
        previous_maintenance = self._get_schedule_previous_maintenance_datetime(reference_datetime)
        if previous_maintenance is None:
            return None
        imported_at = self._get_schedule_last_imported_at()
        if imported_at is None or imported_at < previous_maintenance:
            return previous_maintenance
        return None

    def _get_schedule_invasion_generation_end_datetime(self, reference_datetime: datetime) -> datetime:
        target_weekday = self._get_schedule_invasion_weekday_index()
        days_until = (target_weekday - reference_datetime.weekday()) % 7
        target_date = (reference_datetime + timedelta(days=days_until)).date()
        return datetime(target_date.year, target_date.month, target_date.day, 23, 59, 59)

    def _get_schedule_generation_end_datetime(
        self,
        reference_datetime: datetime,
        *,
        include_delete_cutoff: bool = True,
    ) -> datetime:
        cutoff_datetime = self._get_schedule_maintenance_cutoff_datetime(reference_datetime)
        generation_end = cutoff_datetime if cutoff_datetime is not None else (reference_datetime + timedelta(days=7)).replace(microsecond=0)
        if include_delete_cutoff:
            delete_cutoff_datetime = self.schedule_delete_active_cutoff_datetime
            if isinstance(delete_cutoff_datetime, datetime):
                delete_cutoff_datetime = delete_cutoff_datetime.replace(microsecond=0)
                if delete_cutoff_datetime < generation_end:
                    generation_end = delete_cutoff_datetime - timedelta(microseconds=1)
        return generation_end

    def _clear_schedule_active_entries_for_active_control(self, reference_datetime: datetime | None = None) -> bool:
        resolved_reference = reference_datetime if isinstance(reference_datetime, datetime) else self._get_schedule_reference_datetime()
        active_control = self._get_schedule_active_control_event(resolved_reference)
        if not isinstance(active_control, dict):
            return False
        control_type = str(active_control.get("control_type") or "")
        control_time = active_control.get("scheduled_at")
        if control_type != "maintenance_stale" or not isinstance(control_time, datetime):
            return False

        def _is_after_control(item: dict[str, object]) -> bool:
            created_at = item.get("created_at")
            return isinstance(created_at, datetime) and created_at > control_time

        before_active_entries = len(self.schedule_active_entries)
        before_active_history = len(self.schedule_active_quick_cut_history)
        preserved_active_entries = [
            dict(item)
            for item in self.schedule_active_entries
            if isinstance(item, dict) and _is_after_control(item)
        ]
        preserved_active_history = [
            dict(entry)
            for entry in self.schedule_active_quick_cut_history
            if isinstance(entry, dict)
            and isinstance(entry.get("item"), dict)
            and _is_after_control(entry.get("item"))
        ]
        changed = (
            before_active_entries != len(preserved_active_entries)
            or before_active_history != len(preserved_active_history)
        )
        if not changed:
            return False
        self.schedule_active_entries = self._normalize_schedule_active_items(preserved_active_entries)
        self.schedule_active_quick_cut_history = self._normalize_schedule_quick_cut_history_entries(preserved_active_history)
        self.schedule_active_overlay_cooldowns = {}
        self.schedule_cut_request_cooldowns = {}
        return True

    def _prune_schedule_event_generation_limits(self, reference_datetime: datetime | None = None) -> bool:
        resolved_reference = reference_datetime if isinstance(reference_datetime, datetime) else self._get_schedule_reference_datetime()
        invasion_end = self._get_schedule_invasion_generation_end_datetime(resolved_reference)
        preserved_events: list[dict[str, object]] = []
        removed = False
        for item in self.schedule_events:
            if not isinstance(item, dict):
                continue
            scheduled_at = item.get("scheduled_at")
            if self._is_schedule_invasion_item(item) and isinstance(scheduled_at, datetime):
                if scheduled_at > invasion_end or not self._is_schedule_invasion_datetime_visible(scheduled_at):
                    removed = True
                    continue
            preserved_events.append(item)
        if not removed:
            return False
        self.schedule_events = preserved_events
        return True

    def _get_schedule_reference_datetime_for_precision(self, reference_datetime: datetime, precision: str) -> datetime:
        if precision == "second":
            return reference_datetime.replace(microsecond=0)
        return reference_datetime.replace(second=0, microsecond=0)

    def _set_schedule_base_datetime_fields(self, date_value: datetime) -> None:
        self.schedule_base_year_var.set(date_value.strftime("%Y년"))
        self.schedule_base_month_var.set(date_value.strftime("%m월"))
        self.schedule_base_day_var.set(date_value.strftime("%d일"))
        self.schedule_base_hour_var.set(date_value.strftime("%H시"))
        self.schedule_base_minute_var.set(date_value.strftime("%M분"))
        self._update_schedule_base_label()

    def _update_schedule_base_label(self, _event=None) -> None:
        start_datetime = self._get_schedule_base_datetime()
        if start_datetime is None:
            self.schedule_base_label_var.set("서버 오픈 시간을 올바르게 입력하세요.")
            self.schedule_input_current_var.set("")
            return
        start_weekday = self._get_weekday_label(start_datetime)
        reference_datetime = self._get_schedule_reference_datetime()
        self.schedule_base_label_var.set(f"{start_datetime.strftime(f'%Y-%m-%d ({start_weekday}) %H:%M')}")
        self.schedule_input_current_var.set(f"오늘: {reference_datetime.strftime('%y-%m-%d %H시 %M분')}")
        self.schedule_status_var.set("현재시간을 기준으로 서버 오픈 시간 이후 스케쥴을 생성합니다.")

    def _set_schedule_input_past_generation_enabled(self, enabled: bool, *, reset_to_now: bool = False) -> None:
        self.schedule_input_past_enabled = bool(enabled)
        if hasattr(self, "schedule_input_past_var") and self.schedule_input_past_var is not None:
            self.schedule_input_past_var.set(self.schedule_input_past_enabled)
        if self.schedule_input_past_enabled and reset_to_now:
            self._set_schedule_base_datetime_fields(self._get_schedule_default_server_open_datetime())
        for widget, place_kwargs in self.schedule_input_base_widget_places:
            if widget is None:
                continue
            try:
                if self.schedule_input_past_enabled:
                    widget.place(**place_kwargs)
                    if isinstance(widget, ttk.Combobox):
                        widget.config(state="normal")
                    else:
                        widget.config(fg="#0f172a")
                else:
                    widget.place_forget()
            except tk.TclError:
                continue
        if self.schedule_input_base_hint_widget is not None and self.schedule_input_base_hint_place is not None:
            try:
                if self.schedule_input_past_enabled and self.schedule_input_base_hint_widget.winfo_exists():
                    self.schedule_input_base_hint_widget.place(**self.schedule_input_base_hint_place)
                else:
                    self.schedule_input_base_hint_widget.place_forget()
            except tk.TclError:
                pass
        if self._is_schedule_input_compact_mode():
            return
        if self.schedule_input_ocr_queue_frame is not None and self.schedule_input_ocr_queue_frame.winfo_exists():
            try:
                self.schedule_input_ocr_queue_frame.place(x=18, y=148, width=724, height=SCHEDULE_INPUT_OCR_QUEUE_HEIGHT)
            except tk.TclError:
                pass
        if self.schedule_input_text is not None and self.schedule_input_text.winfo_exists():
            try:
                self.schedule_input_text.place_configure(x=18, y=252, width=724, height=244)
            except tk.TclError:
                pass

    def _toggle_schedule_input_past_generation(self) -> None:
        enabled = bool(self.schedule_input_past_var.get()) if hasattr(self, "schedule_input_past_var") and self.schedule_input_past_var is not None else (not self.schedule_input_past_enabled)
        self._set_schedule_input_past_generation_enabled(enabled, reset_to_now=enabled)

    def _get_active_schedule_input_backup(self) -> dict[str, object] | None:
        if self.schedule_input_undo_edit_context:
            return self.schedule_last_edit_backup
        return self.schedule_last_import_backup

    def _get_schedule_input_import_undo_target(self) -> dict[str, object] | None:
        return self.schedule_last_import_backup if isinstance(self.schedule_last_import_backup, dict) else None

    def _get_schedule_input_edit_undo_target(self) -> dict[str, object] | None:
        return self.schedule_last_edit_backup if isinstance(self.schedule_last_edit_backup, dict) else None

    def _get_schedule_quick_cut_action_at(self, entry: dict[str, object] | None) -> datetime | None:
        if not isinstance(entry, dict):
            return None
        action_at = entry.get("action_at")
        if isinstance(action_at, datetime):
            return action_at
        cut_datetime = entry.get("cut_datetime")
        if isinstance(cut_datetime, datetime):
            return cut_datetime
        return None

    def _get_latest_schedule_quick_cut_undo_target(self) -> tuple[str, dict[str, object]] | None:
        candidates: list[tuple[datetime, str, dict[str, object]]] = []
        if self.schedule_tree_quick_cut_history:
            tree_entry = self.schedule_tree_quick_cut_history[-1]
            tree_action_at = self._get_schedule_quick_cut_action_at(tree_entry)
            if tree_action_at is not None:
                candidates.append((tree_action_at, "tree_quick_cut", tree_entry))
        if self.schedule_active_quick_cut_history:
            active_entry = self.schedule_active_quick_cut_history[-1]
            active_action_at = self._get_schedule_quick_cut_action_at(active_entry)
            if active_action_at is not None:
                candidates.append((active_action_at, "active_quick_cut", active_entry))
        if not candidates:
            return None
        candidates.sort(key=lambda row: row[0])
        _, target_kind, target_entry = candidates[-1]
        return target_kind, target_entry

    def _get_active_schedule_input_undo_target(self) -> tuple[str, dict[str, object]] | None:
        if self.schedule_input_undo_edit_context:
            edit_backup = self._get_schedule_input_edit_undo_target()
            if isinstance(edit_backup, dict):
                return "edit_backup", edit_backup
            return None
        import_backup = self._get_schedule_input_import_undo_target()
        if isinstance(import_backup, dict):
            return "import_backup", import_backup
        return None

    def _get_schedule_visible_cutoff_datetime(self) -> datetime | None:
        reference_datetime = self._get_schedule_reference_datetime()
        cutoff_datetime = self._get_schedule_maintenance_cutoff_datetime(reference_datetime)
        delete_cutoff_datetime = self.schedule_delete_active_cutoff_datetime
        if isinstance(delete_cutoff_datetime, datetime):
            delete_cutoff_datetime = delete_cutoff_datetime.replace(microsecond=0)
            if cutoff_datetime is None or delete_cutoff_datetime < cutoff_datetime:
                cutoff_datetime = delete_cutoff_datetime
        return cutoff_datetime

    def _get_schedule_available_event_dates(self) -> list[datetime.date]:
        reference_datetime = self._get_schedule_reference_datetime()
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        active_control = self._get_schedule_active_control_event(reference_datetime)
        available_dates = {
            scheduled_at.date()
            for item in self.schedule_events
            for scheduled_at, created_at in [(item.get("scheduled_at"), item.get("created_at"))]
            if isinstance(scheduled_at, datetime)
            and self._is_schedule_event_visible(
                scheduled_at,
                created_at if isinstance(created_at, datetime) else None,
                reference_datetime,
                cutoff_datetime,
                is_invasion=self._is_schedule_invasion_item(item),
            )
        }
        for scheduled_at, *_rest in self._get_fixed_boss_schedule_rows():
            available_dates.add(scheduled_at.date())
        for item in self.schedule_control_events:
            scheduled_at = item.get("scheduled_at")
            if isinstance(scheduled_at, datetime):
                available_dates.add(scheduled_at.date())
        if active_control is not None:
            control_time = active_control.get("scheduled_at")
            if isinstance(control_time, datetime):
                available_dates.add(control_time.date())
        next_maintenance = self._get_schedule_maintenance_cutoff_datetime(reference_datetime)
        if next_maintenance is not None:
            available_dates.add(next_maintenance.date())
        return sorted(available_dates)

    def _get_fixed_boss_schedule_rows(self) -> list[tuple[datetime, str, str, str, str, str, str, str]]:
        if not self.fixed_boss_entries:
            return []
        view_datetime = self._get_schedule_view_datetime()
        if view_datetime is None:
            return []
        reference_now = self._get_schedule_reference_datetime()
        window_start = view_datetime.replace(hour=0, minute=0, second=0, microsecond=0)
        window_end = window_start + timedelta(days=2)
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        weekday_labels = ("월", "화", "수", "목", "금", "토", "일")
        reference_today = self._get_schedule_reference_datetime().date()
        reference_week_start = reference_today - timedelta(days=reference_today.weekday())
        rows: list[tuple[datetime, str, str, str, str, str]] = []
        current_date = window_start.date()
        end_date = (window_end - timedelta(seconds=1)).date()
        while current_date <= end_date:
            weekday_text = weekday_labels[current_date.weekday()]
            candidate_week_start = current_date - timedelta(days=current_date.weekday())
            week_offset = (candidate_week_start - reference_week_start).days // 7
            for item in self.fixed_boss_entries:
                if not bool(item.get("enabled", True)):
                    continue
                if weekday_text not in item.get("days", []):
                    continue
                repeat_mode = str(item.get("repeat_mode") or "weekly")
                if repeat_mode == "biweekly_current" and week_offset % 2 != 0:
                    continue
                if repeat_mode == "biweekly_next" and week_offset % 2 != 1:
                    continue
                time_text = self._normalize_fixed_boss_time_text(str(item.get("time_text") or "00:00:00"))
                try:
                    hour = int(time_text[0:2])
                    minute = int(time_text[3:5])
                    second = int(time_text[6:8])
                except ValueError:
                    continue
                scheduled_at = datetime(
                    current_date.year,
                    current_date.month,
                    current_date.day,
                    hour,
                    minute,
                    second,
                )
                if scheduled_at < window_start or scheduled_at >= window_end:
                    continue
                if not self._is_schedule_event_visible(scheduled_at, None, reference_now, cutoff_datetime):
                    continue
                rows.append(
                    (
                        scheduled_at,
                        self._get_schedule_boss_display_name({"boss_name": str(item.get("boss_name") or "")}, prefer_alias=True, include_star=True),
                        "경과" if scheduled_at < reference_now else "고정",
                        "ON" if bool(self.schedule_fixed_boss_alarm_enabled_var.get()) else "OFF",
                        "-",
                        "고정보스",
                        self._normalize_hex_color(str(item.get("text_color") or DEFAULT_FIXED_BOSS_TEXT_COLOR), DEFAULT_FIXED_BOSS_TEXT_COLOR),
                        self._normalize_hex_color(str(item.get("bg_color") or DEFAULT_FIXED_BOSS_BG_COLOR), DEFAULT_FIXED_BOSS_BG_COLOR),
                    )
                )
            current_date += timedelta(days=1)
        rows.sort(key=lambda row: (row[0], row[1]))
        return rows

    def _get_fixed_boss_schedule_rows_for_alarm(self, reference_datetime: datetime, days: int = 3) -> list[tuple[datetime, str, str, str, str, str, str, str]]:
        if not self.fixed_boss_entries:
            return []
        window_start = reference_datetime.replace(hour=0, minute=0, second=0, microsecond=0)
        window_end = window_start + timedelta(days=max(1, int(days)))
        weekday_labels = ("월", "화", "수", "목", "금", "토", "일")
        reference_week_start = reference_datetime.date() - timedelta(days=reference_datetime.weekday())
        rows: list[tuple[datetime, str, str, str, str, str, str, str]] = []
        current_date = window_start.date()
        end_date = (window_end - timedelta(seconds=1)).date()
        while current_date <= end_date:
            weekday_text = weekday_labels[current_date.weekday()]
            candidate_week_start = current_date - timedelta(days=current_date.weekday())
            week_offset = (candidate_week_start - reference_week_start).days // 7
            for item in self.fixed_boss_entries:
                if not bool(item.get("enabled", True)):
                    continue
                if weekday_text not in item.get("days", []):
                    continue
                repeat_mode = str(item.get("repeat_mode") or "weekly")
                if repeat_mode == "biweekly_current" and week_offset % 2 != 0:
                    continue
                if repeat_mode == "biweekly_next" and week_offset % 2 != 1:
                    continue
                time_text = self._normalize_fixed_boss_time_text(str(item.get("time_text") or "00:00:00"))
                try:
                    hour = int(time_text[0:2])
                    minute = int(time_text[3:5])
                    second = int(time_text[6:8])
                except ValueError:
                    continue
                scheduled_at = datetime(current_date.year, current_date.month, current_date.day, hour, minute, second)
                if scheduled_at < window_start or scheduled_at >= window_end:
                    continue
                rows.append(
                    (
                        scheduled_at,
                        str(item.get("boss_name") or ""),
                        "경과" if scheduled_at < reference_datetime else "고정",
                        "ON" if bool(self.schedule_fixed_boss_alarm_enabled_var.get()) else "OFF",
                        "-",
                        "고정보스",
                        self._normalize_hex_color(str(item.get("text_color") or DEFAULT_FIXED_BOSS_TEXT_COLOR), DEFAULT_FIXED_BOSS_TEXT_COLOR),
                        self._normalize_hex_color(str(item.get("bg_color") or DEFAULT_FIXED_BOSS_BG_COLOR), DEFAULT_FIXED_BOSS_BG_COLOR),
                    )
                )
            current_date += timedelta(days=1)
        rows.sort(key=lambda row: (row[0], row[1]))
        return rows

    def _get_fixed_boss_schedule_rows_for_share_range(
        self,
        reference_datetime: datetime,
        start_datetime: datetime,
        end_datetime: datetime,
    ) -> list[tuple[datetime, str, str, str, str, str, str, str]]:
        if not self.fixed_boss_entries:
            return []
        window_start = start_datetime.replace(microsecond=0)
        window_end = end_datetime.replace(microsecond=0) + timedelta(seconds=1)
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        weekday_labels = ("월", "화", "수", "목", "금", "토", "일")
        reference_today = reference_datetime.date()
        reference_week_start = reference_today - timedelta(days=reference_today.weekday())
        rows: list[tuple[datetime, str, str, str, str, str, str, str]] = []
        current_date = window_start.date()
        end_date = (window_end - timedelta(seconds=1)).date()
        while current_date <= end_date:
            weekday_text = weekday_labels[current_date.weekday()]
            candidate_week_start = current_date - timedelta(days=current_date.weekday())
            week_offset = (candidate_week_start - reference_week_start).days // 7
            for item in self.fixed_boss_entries:
                if not bool(item.get("enabled", True)):
                    continue
                if weekday_text not in item.get("days", []):
                    continue
                repeat_mode = str(item.get("repeat_mode") or "weekly")
                if repeat_mode == "biweekly_current" and week_offset % 2 != 0:
                    continue
                if repeat_mode == "biweekly_next" and week_offset % 2 != 1:
                    continue
                time_text = self._normalize_fixed_boss_time_text(str(item.get("time_text") or "00:00:00"))
                try:
                    hour = int(time_text[0:2])
                    minute = int(time_text[3:5])
                    second = int(time_text[6:8])
                except ValueError:
                    continue
                scheduled_at = datetime(current_date.year, current_date.month, current_date.day, hour, minute, second)
                if scheduled_at < window_start or scheduled_at >= window_end:
                    continue
                if not self._is_schedule_event_visible(scheduled_at, None, reference_datetime, cutoff_datetime):
                    continue
                rows.append(
                    (
                        scheduled_at,
                        self._get_schedule_boss_display_name({"boss_name": str(item.get("boss_name") or "")}, prefer_alias=True, include_star=True),
                        "경과" if scheduled_at < reference_datetime else "고정",
                        "ON" if bool(self.schedule_fixed_boss_alarm_enabled_var.get()) else "OFF",
                        "-",
                        "고정보스",
                        self._normalize_hex_color(str(item.get("text_color") or DEFAULT_FIXED_BOSS_TEXT_COLOR), DEFAULT_FIXED_BOSS_TEXT_COLOR),
                        self._normalize_hex_color(str(item.get("bg_color") or DEFAULT_FIXED_BOSS_BG_COLOR), DEFAULT_FIXED_BOSS_BG_COLOR),
                    )
                )
            current_date += timedelta(days=1)
        rows.sort(key=lambda row: (row[0], row[1]))
        return rows

    def _format_schedule_break_duration_text(self, total_seconds: int | float) -> str:
        total_minutes = max(0, int(round(float(total_seconds) / 60.0)))
        hours, minutes = divmod(total_minutes, 60)
        if hours > 0:
            return f"{hours}시간 {minutes}분"
        return f"{minutes}분"

    def _round_schedule_break_minutes_to_half_hour(self, gap_minutes: int) -> int:
        rounded = int(round(max(1, int(gap_minutes)) / 30.0) * 30)
        return max(30, rounded)

    def _build_default_schedule_break_entries(self) -> list[dict[str, object]]:
        entries: list[dict[str, object]] = []
        for min_gap in range(50, (24 * 60) + 1, 30):
            max_gap = min((24 * 60), min_gap + 29)
            midpoint = (min_gap + max_gap) // 2
            rounded_minutes = self._round_schedule_break_minutes_to_half_hour(midpoint)
            label_text = "휴식"
            if rounded_minutes == 90:
                label_text = "꿀잠시간"
            elif rounded_minutes == 150:
                label_text = "자유시간"
            display_mode = "actual" if min_gap == 50 else "fixed"
            display_text = "" if display_mode == "actual" else self._format_schedule_break_duration_text(rounded_minutes * 60)
            entries.append(
                {
                    "min_gap_minutes": min_gap,
                    "max_gap_minutes": max_gap,
                    "label_text": label_text,
                    "display_mode": display_mode,
                    "display_text": display_text,
                    "row_scale": 1.0 if min_gap == 50 else 1.5,
                    "font_size": 10,
                    "bold": False,
                    "text_color": DEFAULT_SCHEDULE_BREAK_TEXT_COLOR,
                    "bg_color": DEFAULT_SCHEDULE_BREAK_BG_COLOR,
                    "enabled": True,
                }
            )
        return entries

    def _normalize_schedule_break_rule_entry(self, entry: object) -> dict[str, object] | None:
        if not isinstance(entry, dict):
            return None
        min_gap = max(0, self._parse_int(str(entry.get("min_gap_minutes") or "0"), 0))
        max_gap = max(min_gap, self._parse_int(str(entry.get("max_gap_minutes") or str(min_gap)), min_gap))
        label_text = str(entry.get("label_text") or "").strip() or "휴식"
        display_mode = str(entry.get("display_mode") or "actual").strip()
        if display_mode not in {"actual", "fixed", "rounded_30m"}:
            display_mode = "actual"
        display_text = str(entry.get("display_text") or "").strip()
        try:
            row_scale = float(entry.get("row_scale") or 1.0)
        except (TypeError, ValueError):
            row_scale = 1.0
        row_scale = min(3.0, max(0.5, row_scale))
        font_size = min(24, max(8, self._parse_int(str(entry.get("font_size") or "10"), 10)))
        return {
            "min_gap_minutes": min_gap,
            "max_gap_minutes": max_gap,
            "label_text": label_text,
            "display_mode": display_mode,
            "display_text": display_text,
            "row_scale": row_scale,
            "font_size": font_size,
            "bold": bool(entry.get("bold", False)),
            "text_color": self._normalize_hex_color(str(entry.get("text_color") or DEFAULT_SCHEDULE_BREAK_TEXT_COLOR), DEFAULT_SCHEDULE_BREAK_TEXT_COLOR),
            "bg_color": self._normalize_hex_color(str(entry.get("bg_color") or DEFAULT_SCHEDULE_BREAK_BG_COLOR), DEFAULT_SCHEDULE_BREAK_BG_COLOR),
            "enabled": bool(entry.get("enabled", True)),
        }

    def _load_schedule_break_rules(self) -> list[dict[str, object]]:
        self._ensure_init_dir()
        default_entries = self._build_default_schedule_break_entries()
        if not os.path.exists(SCHEDULE_BREAK_RULES_PATH):
            return default_entries
        try:
            with open(SCHEDULE_BREAK_RULES_PATH, "r", encoding="utf-8") as file:
                payload = json.load(file)
        except (OSError, json.JSONDecodeError):
            return default_entries
        if not isinstance(payload, list):
            return default_entries
        normalized_entries: list[dict[str, object]] = []
        for raw_entry in payload:
            normalized_entry = self._normalize_schedule_break_rule_entry(raw_entry)
            if isinstance(normalized_entry, dict):
                normalized_entries.append(normalized_entry)
        return normalized_entries or default_entries

    def _save_schedule_break_rules(self) -> None:
        self._ensure_init_dir()
        payload = [
            self._normalize_schedule_break_rule_entry(entry)
            for entry in self.schedule_break_entries
        ]
        payload = [entry for entry in payload if isinstance(entry, dict)]
        with open(SCHEDULE_BREAK_RULES_PATH, "w", encoding="utf-8") as file:
            json.dump(payload, file, ensure_ascii=False, indent=2)

    def _schedule_boss_metric_source_mode_options(self) -> dict[str, str]:
        return {
            "자동(사용자→평균)": "user_first",
            "자동(평균→사용자)": "average_first",
            "사용자만": "user_only",
            "평균만": "average_only",
            "사용 안 함": "disabled",
        }

    def _get_schedule_boss_metric_source_mode_label(self, mode: str | None) -> str:
        normalized_mode = str(mode or "").strip() or self.schedule_boss_metric_source_mode_default
        options = self._schedule_boss_metric_source_mode_options()
        for label, value in options.items():
            if value == normalized_mode:
                return label
        return next(iter(options.keys()))

    def _get_schedule_boss_metric_source_mode_value(self, label_or_mode: str | None) -> str:
        normalized = str(label_or_mode or "").strip()
        options = self._schedule_boss_metric_source_mode_options()
        if normalized in options.values():
            return normalized
        return options.get(normalized, self.schedule_boss_metric_source_mode_default)

    def _build_default_schedule_boss_metrics(self) -> dict[str, dict[str, object]]:
        defaults: dict[str, dict[str, object]] = {}
        for item in self._get_schedule_boss_metric_target_items():
            boss_name = str(item.get("boss_name") or "").strip()
            if not boss_name:
                continue
            defaults[boss_name] = {
                "boss_name": boss_name,
                "source_mode": self.schedule_boss_metric_source_mode_default,
                "user_duration_seconds": 0,
                "score": None,
                "war_score": None,
            }
        return defaults

    def _strip_schedule_invasion_prefix(self, text: str | None) -> str:
        normalized_text = str(text or "").strip()
        if not normalized_text:
            return ""
        return re.sub(r"^침공[\s_:：-]*", "", normalized_text).strip()

    def _get_schedule_boss_metric_target_name(self, item_or_name: dict[str, object] | str | None) -> str:
        candidates: list[str] = []
        if isinstance(item_or_name, dict):
            for key in ("boss_name", "display_name", "raw_name"):
                text = str(item_or_name.get(key) or "").strip()
                if text:
                    candidates.append(self._strip_schedule_invasion_prefix(text))
        else:
            text = str(item_or_name or "").strip()
            if text:
                candidates.append(self._strip_schedule_invasion_prefix(text))
        fixed_names = {
            self._get_canonical_boss_name(str(entry.get("boss_name") or "").strip()) or str(entry.get("boss_name") or "").strip()
            for entry in self.fixed_boss_entries
            if str(entry.get("boss_name") or "").strip()
        }
        for candidate in candidates:
            canonical_name = self._get_canonical_boss_name(candidate) or candidate
            if canonical_name in self.schedule_boss_definitions or canonical_name in fixed_names:
                return canonical_name
        return ""

    def _get_schedule_boss_metric_target_item(self, boss_name: str | None) -> dict[str, object] | None:
        target_name = self._get_schedule_boss_metric_target_name(boss_name)
        if not target_name:
            return None
        for item in self._get_schedule_boss_metric_target_items():
            if str(item.get("boss_name") or "").strip() == target_name:
                return item
        return None

    def _normalize_schedule_boss_metric_score_value(self, value: object) -> int | float | None:
        if value is None:
            return None
        text = str(value).strip()
        if not text:
            return None
        try:
            numeric = float(text)
        except (TypeError, ValueError):
            return None
        if not math.isfinite(numeric):
            return None
        if numeric.is_integer():
            return int(numeric)
        return numeric

    def _normalize_schedule_boss_metric_entry(self, raw_entry: object, boss_name: str) -> dict[str, object]:
        source_mode = self.schedule_boss_metric_source_mode_default
        user_duration_seconds = 0
        score_value: int | float | None = None
        war_score_value: int | float | None = None
        if isinstance(raw_entry, dict):
            source_mode = self._get_schedule_boss_metric_source_mode_value(raw_entry.get("source_mode"))
            raw_duration = raw_entry.get("user_duration_seconds")
            if isinstance(raw_duration, (int, float)) and float(raw_duration) > 0:
                user_duration_seconds = max(0, int(round(float(raw_duration))))
            score_value = self._normalize_schedule_boss_metric_score_value(raw_entry.get("score"))
            war_score_value = self._normalize_schedule_boss_metric_score_value(raw_entry.get("war_score"))
            if war_score_value is None:
                war_score_value = score_value
        return {
            "boss_name": boss_name,
            "source_mode": source_mode,
            "user_duration_seconds": user_duration_seconds,
            "score": score_value,
            "war_score": war_score_value,
        }

    def _load_schedule_boss_metrics(self) -> dict[str, dict[str, object]]:
        defaults = self._build_default_schedule_boss_metrics()
        metrics = {boss_name: dict(entry) for boss_name, entry in defaults.items()}
        self._ensure_init_dir()
        if not os.path.exists(SCHEDULE_BOSS_METRICS_PATH):
            self.schedule_boss_metrics = metrics
            self._save_schedule_boss_metrics()
            return metrics
        try:
            with open(SCHEDULE_BOSS_METRICS_PATH, "r", encoding="utf-8") as file:
                payload = json.load(file)
        except (OSError, json.JSONDecodeError):
            return metrics
        if not isinstance(payload, dict):
            return metrics
        for raw_boss_name, raw_entry in payload.items():
            boss_name = self._get_canonical_boss_name(str(raw_boss_name or "").strip()) or str(raw_boss_name or "").strip()
            if not boss_name or boss_name not in defaults:
                continue
            metrics[boss_name] = self._normalize_schedule_boss_metric_entry(raw_entry, boss_name)
        return metrics

    def _save_schedule_boss_metrics(self) -> None:
        self._ensure_init_dir()
        payload: dict[str, dict[str, object]] = {}
        for item in self._get_schedule_boss_metric_target_items():
            boss_name = str(item.get("boss_name") or "").strip()
            if not boss_name:
                continue
            entry = self._normalize_schedule_boss_metric_entry(self.schedule_boss_metrics.get(boss_name, {}), boss_name)
            payload[boss_name] = {
                "source_mode": str(entry.get("source_mode") or self.schedule_boss_metric_source_mode_default),
                "user_duration_seconds": int(entry.get("user_duration_seconds") or 0),
                "score": entry.get("score"),
                "war_score": entry.get("war_score"),
            }
        with open(SCHEDULE_BOSS_METRICS_PATH, "w", encoding="utf-8") as file:
            json.dump(payload, file, ensure_ascii=False, indent=2)

    def _sync_schedule_boss_metrics_with_definitions(self, old_name: str | None = None, new_name: str | None = None) -> None:
        defaults = self._build_default_schedule_boss_metrics()
        synced: dict[str, dict[str, object]] = {}
        old_key = str(old_name or "").strip()
        new_key = str(new_name or "").strip()
        for boss_name in defaults:
            source_entry = self.schedule_boss_metrics.get(boss_name)
            if source_entry is None and old_key and new_key == boss_name:
                source_entry = self.schedule_boss_metrics.get(old_key)
            synced[boss_name] = self._normalize_schedule_boss_metric_entry(source_entry or {}, boss_name)
        self.schedule_boss_metrics = synced
        self._save_schedule_boss_metrics()

    def _format_schedule_boss_metric_duration_text(self, total_seconds: int | float | None) -> str:
        if total_seconds is None:
            return ""
        seconds = max(0, int(round(float(total_seconds))))
        if seconds <= 0:
            return ""
        hours, remainder = divmod(seconds, 3600)
        minutes, remainder_seconds = divmod(remainder, 60)
        parts: list[str] = []
        if hours > 0:
            parts.append(f"{hours}시간")
            if minutes > 0 or remainder_seconds > 0:
                parts.append(f"{minutes}분")
            if remainder_seconds > 0:
                parts.append(f"{remainder_seconds}초")
            return " ".join(parts)
        if minutes > 0:
            parts.append(f"{minutes}분")
            if remainder_seconds > 0:
                parts.append(f"{remainder_seconds}초")
            return " ".join(parts)
        return f"{remainder_seconds}초"

    def _parse_schedule_boss_metric_duration_input(self, text: str) -> int | None:
        cleaned = re.sub(r"\s+", " ", (text or "").strip())
        if not cleaned:
            return None
        compact = re.sub(r"\s+", "", cleaned)
        if re.fullmatch(r"\d{1,2}:\d{1,2}(?::\d{1,2})?", compact):
            parts = [int(part) for part in compact.split(":")]
            if len(parts) == 2:
                minutes, seconds = parts
                return max(0, (minutes * 60) + seconds)
            hours, minutes, seconds = parts
            return max(0, (hours * 3600) + (minutes * 60) + seconds)
        if re.fullmatch(r"\d+", compact):
            digit_len = len(compact)
            if digit_len <= 2:
                return max(0, int(compact))
            if digit_len in {3, 4}:
                minutes = int(compact[:-2])
                seconds = int(compact[-2:])
                return max(0, (minutes * 60) + seconds)
            if digit_len in {5, 6}:
                hours = int(compact[:-4])
                minutes = int(compact[-4:-2])
                seconds = int(compact[-2:])
                return max(0, (hours * 3600) + (minutes * 60) + seconds)
            if digit_len > 6:
                return None
        phrase_match = re.fullmatch(
            r"(?:(?P<days>\d+)일)?(?:(?P<hours>\d+)시간)?(?:(?P<minutes>\d+)분)?(?:(?P<seconds>\d+)초)?",
            compact,
        )
        if phrase_match and any(phrase_match.group(name) for name in ("days", "hours", "minutes", "seconds")):
            days = int(phrase_match.group("days") or "0")
            hours = int(phrase_match.group("hours") or "0")
            minutes = int(phrase_match.group("minutes") or "0")
            seconds = int(phrase_match.group("seconds") or "0")
            return max(0, (days * 86400) + (hours * 3600) + (minutes * 60) + seconds)
        return None

    def _normalize_schedule_boss_metric_duration_var(self, variable: tk.StringVar | None) -> None:
        if variable is None:
            return
        raw_text = str(variable.get() or "").strip()
        if not raw_text:
            return
        total_seconds = self._parse_schedule_boss_metric_duration_input(raw_text)
        if total_seconds is None:
            return
        variable.set(self._format_schedule_boss_metric_duration_text(total_seconds))

    def _update_schedule_boss_metric_duration_placeholder(self) -> None:
        entry = getattr(self, "schedule_boss_metric_duration_entry", None)
        placeholder = getattr(self, "schedule_boss_metric_duration_placeholder_label", None)
        if not self._widget_available(entry) or not self._widget_available(placeholder):
            return
        try:
            has_text = bool(str(self.schedule_boss_metric_user_duration_var.get() or "").strip())
            has_focus = self.schedule_boss_metrics_window.focus_get() == entry if self._widget_available(self.schedule_boss_metrics_window) else False
        except tk.TclError:
            return
        if has_text or has_focus:
            try:
                placeholder.place_forget()
            except tk.TclError:
                return
        else:
            try:
                placeholder.place(x=124, y=162, width=240, height=16)
            except tk.TclError:
                return

    def _on_schedule_boss_metric_duration_focus_in(self, _event=None) -> None:
        self._update_schedule_boss_metric_duration_placeholder()

    def _on_schedule_boss_metric_duration_focus_out(self, _event=None) -> None:
        self._normalize_schedule_boss_metric_duration_var(getattr(self, "schedule_boss_metric_user_duration_var", None))
        self._update_schedule_boss_metric_duration_placeholder()
        self._on_schedule_boss_metric_form_value_changed()

    def _on_schedule_boss_metric_bulk_duration_focus_out(self, _event=None) -> None:
        self._normalize_schedule_boss_metric_duration_var(getattr(self, "schedule_boss_metric_bulk_user_duration_var", None))

    def _get_schedule_boss_metric_tree_area_text(self, area_name: str | None) -> str:
        normalized_area = str(area_name or "").strip()
        return str(RECORD_BOOK_CHAPTER_LABELS.get(normalized_area, normalized_area) or "").strip()

    def _get_schedule_boss_metric_preview_entry(self, boss_name: str) -> dict[str, object]:
        canonical_name = self._get_canonical_boss_name(boss_name) or str(boss_name or "").strip()
        if not canonical_name:
            return self._normalize_schedule_boss_metric_entry({}, "")
        preview_entry = self.schedule_boss_metric_draft_entries.get(canonical_name)
        if isinstance(preview_entry, dict):
            return self._normalize_schedule_boss_metric_entry(preview_entry, canonical_name)
        return self._get_schedule_boss_metric_entry(canonical_name)

    def _is_schedule_boss_metric_entry_equal(self, left: dict[str, object] | None, right: dict[str, object] | None, boss_name: str) -> bool:
        normalized_left = self._normalize_schedule_boss_metric_entry(left or {}, boss_name)
        normalized_right = self._normalize_schedule_boss_metric_entry(right or {}, boss_name)
        return (
            str(normalized_left.get("source_mode") or "") == str(normalized_right.get("source_mode") or "")
            and int(normalized_left.get("user_duration_seconds") or 0) == int(normalized_right.get("user_duration_seconds") or 0)
            and self._normalize_schedule_boss_metric_score_value(normalized_left.get("score"))
            == self._normalize_schedule_boss_metric_score_value(normalized_right.get("score"))
            and self._normalize_schedule_boss_metric_score_value(normalized_left.get("war_score"))
            == self._normalize_schedule_boss_metric_score_value(normalized_right.get("war_score"))
        )

    def _get_schedule_boss_metric_form_entry(self, boss_name: str) -> tuple[dict[str, object] | None, str]:
        user_duration_text = str(self.schedule_boss_metric_user_duration_var.get() or "").strip()
        user_duration_seconds = self._parse_schedule_boss_metric_duration_input(user_duration_text) if user_duration_text else None
        if user_duration_text and user_duration_seconds is None:
            return None, "사용자 소요시간 형식이 올바르지 않습니다. 예: 5 / 90 / 115 / 0115 / 10115 / 01:01:15 / 2시간30분"
        score_text = str(self.schedule_boss_metric_score_var.get() or "").strip()
        score_value = self._normalize_schedule_boss_metric_score_value(score_text)
        if score_text and score_value is None:
            return None, "점수는 숫자만 입력하세요."
        war_score_text = str(self.schedule_boss_metric_war_score_var.get() or "").strip()
        war_score_value = self._normalize_schedule_boss_metric_score_value(war_score_text)
        if war_score_text and war_score_value is None:
            return None, "쟁점수는 숫자만 입력하세요."
        return (
            self._normalize_schedule_boss_metric_entry(
                {
                    "source_mode": self._get_schedule_boss_metric_source_mode_value(self.schedule_boss_metric_source_mode_var.get()),
                    "user_duration_seconds": int(user_duration_seconds or 0),
                    "score": score_value,
                    "war_score": war_score_value,
                },
                boss_name,
            ),
            "",
        )

    def _has_pending_schedule_boss_metric_drafts(self) -> bool:
        return any(
            not self._is_schedule_boss_metric_entry_equal(draft_entry, self.schedule_boss_metrics.get(boss_name, {}), boss_name)
            for boss_name, draft_entry in self.schedule_boss_metric_draft_entries.items()
        )

    def _build_schedule_boss_metric_average_seconds_map(self) -> dict[str, int]:
        cache_key = self._get_schedule_average_cut_cache_key()
        if self.schedule_boss_metric_average_cache_key == cache_key:
            return dict(self.schedule_boss_metric_average_seconds_map)
        if not cache_key[0]:
            self.schedule_boss_metric_average_cache_key = cache_key
            self.schedule_boss_metric_average_seconds_map = {}
            return {}
        boss_data = self._collect_log_stats_boss_data_from_folder(cache_key[0])
        average_map: dict[str, int] = {}
        for boss_name, boss_bucket in boss_data.items():
            dataset = self._build_log_analysis_dataset(list(boss_bucket.get("records", [])), fallback_boss_name=str(boss_name))
            avg_cut_seconds = dataset.get("avg_cut_seconds")
            if isinstance(avg_cut_seconds, (int, float)) and float(avg_cut_seconds) > 0:
                canonical_name = self._get_canonical_boss_name(str(boss_name)) or str(boss_name)
                average_map[canonical_name] = max(1, int(round(float(avg_cut_seconds))))
        self.schedule_boss_metric_average_cache_key = cache_key
        self.schedule_boss_metric_average_seconds_map = dict(average_map)
        return average_map

    def _get_schedule_boss_metric_average_seconds(self, boss_name: str) -> int | None:
        canonical_name = self._get_canonical_boss_name(boss_name) or str(boss_name or "").strip()
        if not canonical_name:
            return None
        average_map = self._build_schedule_boss_metric_average_seconds_map()
        average_seconds = average_map.get(canonical_name)
        if isinstance(average_seconds, int) and average_seconds > 0:
            return average_seconds
        return None

    def _get_schedule_boss_metric_entry(self, boss_name: str) -> dict[str, object]:
        canonical_name = self._get_canonical_boss_name(boss_name) or str(boss_name or "").strip()
        if not canonical_name:
            return self._normalize_schedule_boss_metric_entry({}, "")
        return self._normalize_schedule_boss_metric_entry(self.schedule_boss_metrics.get(canonical_name, {}), canonical_name)

    def _get_schedule_boss_metric_effective_duration_seconds(self, item_or_name: dict[str, object] | str | None) -> int | None:
        boss_name = self._get_schedule_boss_metric_target_name(item_or_name)
        if not boss_name:
            return None
        entry = self._get_schedule_boss_metric_entry(boss_name)
        source_mode = str(entry.get("source_mode") or self.schedule_boss_metric_source_mode_default)
        user_duration_seconds = int(entry.get("user_duration_seconds") or 0)
        average_duration_seconds = self._get_schedule_boss_metric_average_seconds(boss_name) or 0
        if source_mode == "user_only":
            return user_duration_seconds or None
        if source_mode == "average_only":
            return average_duration_seconds or None
        if source_mode == "average_first":
            return average_duration_seconds or user_duration_seconds or None
        if source_mode == "disabled":
            return None
        return user_duration_seconds or average_duration_seconds or None

    def _is_schedule_boss_metric_break_duration_enabled(self) -> bool:
        try:
            return bool(self.schedule_boss_metric_duration_enabled_var.get())
        except Exception:
            return bool(getattr(self, "schedule_boss_metric_duration_enabled_default", False))

    def _is_schedule_boss_metric_schedule_duration_enabled(self) -> bool:
        try:
            return bool(self.schedule_boss_metric_schedule_duration_enabled_var.get())
        except Exception:
            return bool(getattr(self, "schedule_boss_metric_schedule_duration_enabled_default", False))

    def _get_schedule_boss_metric_score(self, item_or_name: dict[str, object] | str | None) -> int | float | None:
        boss_name = self._get_schedule_boss_metric_target_name(item_or_name)
        if not boss_name:
            return None
        entry = self._get_schedule_boss_metric_entry(boss_name)
        return self._normalize_schedule_boss_metric_score_value(entry.get("score"))

    def _get_schedule_boss_metric_war_score(self, item_or_name: dict[str, object] | str | None) -> int | float | None:
        boss_name = self._get_schedule_boss_metric_target_name(item_or_name)
        if not boss_name:
            return None
        entry = self._get_schedule_boss_metric_entry(boss_name)
        return self._normalize_schedule_boss_metric_score_value(entry.get("war_score"))

    def _get_schedule_item_effective_end_datetime(self, item: dict[str, object] | None) -> datetime | None:
        if not isinstance(item, dict):
            return None
        explicit_end_at = item.get("explicit_end_at")
        if isinstance(explicit_end_at, datetime):
            return explicit_end_at.replace(microsecond=0)
        cut_datetime = self._get_schedule_event_cut_datetime(item)
        if isinstance(cut_datetime, datetime):
            return cut_datetime.replace(microsecond=0)
        scheduled_at = item.get("scheduled_at")
        if not isinstance(scheduled_at, datetime):
            return None
        if self._is_schedule_boss_metric_break_duration_enabled():
            metric_duration_seconds = self._get_schedule_boss_metric_effective_duration_seconds(item)
            if isinstance(metric_duration_seconds, int) and metric_duration_seconds > 0:
                return (scheduled_at + timedelta(seconds=metric_duration_seconds)).replace(microsecond=0)
        for key in ("user_duration_seconds", "custom_duration_seconds", "average_duration_seconds", "avg_duration_seconds"):
            raw_value = item.get(key)
            if isinstance(raw_value, (int, float)) and float(raw_value) > 0:
                return (scheduled_at + timedelta(seconds=float(raw_value))).replace(microsecond=0)
        return scheduled_at.replace(microsecond=0)

    def _reapply_schedule_boss_metric_schedule_times(self) -> bool:
        if not isinstance(getattr(self, "schedule_events", None), list) or not self.schedule_events:
            return False
        reference_now = self._get_schedule_reference_datetime()
        apply_enabled = self._is_schedule_boss_metric_schedule_duration_enabled()
        chain_indices: dict[str, list[int]] = {}
        for index, item in enumerate(self.schedule_events):
            if not isinstance(item, dict) or str(item.get("state") or "") != "scheduled":
                continue
            scheduled_at = item.get("scheduled_at")
            raw_key = str(item.get("raw_key") or "").strip()
            if not isinstance(scheduled_at, datetime) or not raw_key:
                continue
            chain_indices.setdefault(raw_key, []).append(index)
        updated_events: list[dict[str, object]] = []
        changed = False
        inferred_cycle_meta: dict[int, tuple[datetime, int]] = {}
        for raw_key, indices in chain_indices.items():
            if not indices:
                continue
            sorted_indices = sorted(
                indices,
                key=lambda idx: (
                    self.schedule_events[idx].get("scheduled_at") or datetime.max,
                    idx,
                ),
            )
            row_anchor_map: dict[int, datetime] = {}
            for idx in sorted_indices:
                current_item = self.schedule_events[idx]
                scheduled_value = current_item.get("scheduled_at")
                anchor_value = current_item.get("cycle_anchor_at")
                if isinstance(anchor_value, datetime):
                    row_anchor_at = anchor_value.replace(microsecond=0)
                elif isinstance(scheduled_value, datetime):
                    row_anchor_at = scheduled_value.replace(microsecond=0)
                else:
                    continue
                row_anchor_map[idx] = row_anchor_at
            if not row_anchor_map:
                continue
            seed_index = sorted_indices[-1]
            for idx in sorted_indices:
                row_anchor_at = row_anchor_map.get(idx)
                if isinstance(row_anchor_at, datetime) and row_anchor_at >= reference_now:
                    seed_index = idx
                    break
            seed_anchor_at = row_anchor_map.get(seed_index)
            if not isinstance(seed_anchor_at, datetime):
                continue
            needs_repair = False
            for idx in sorted_indices:
                row_anchor_at = row_anchor_map.get(idx)
                if not isinstance(row_anchor_at, datetime):
                    continue
                if row_anchor_at < seed_anchor_at:
                    expected_direction = -1
                elif row_anchor_at > seed_anchor_at:
                    expected_direction = 1
                else:
                    expected_direction = 0
                current_item = self.schedule_events[idx]
                stored_direction = current_item.get("cycle_offset_direction")
                stored_anchor = current_item.get("cycle_anchor_at")
                normalized_stored_anchor = stored_anchor.replace(microsecond=0) if isinstance(stored_anchor, datetime) else None
                if not isinstance(stored_direction, int) or int(stored_direction) != expected_direction:
                    needs_repair = True
                    break
                if normalized_stored_anchor != row_anchor_at:
                    needs_repair = True
                    break
            if not needs_repair:
                continue
            for idx in sorted_indices:
                row_anchor_at = row_anchor_map.get(idx)
                if not isinstance(row_anchor_at, datetime):
                    continue
                if row_anchor_at < seed_anchor_at:
                    direction = -1
                elif row_anchor_at > seed_anchor_at:
                    direction = 1
                else:
                    direction = 0
                inferred_cycle_meta[idx] = (row_anchor_at, direction)
        for item_index, item in enumerate(self.schedule_events):
            if not isinstance(item, dict) or str(item.get("state") or "") != "scheduled":
                updated_events.append(item)
                continue
            scheduled_at = item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime):
                updated_events.append(item)
                continue
            new_item = dict(item)
            stored_anchor = new_item.get("cycle_anchor_at")
            stored_direction_raw = new_item.get("cycle_offset_direction")
            stored_direction = int(stored_direction_raw) if isinstance(stored_direction_raw, int) else 0
            inferred_meta = inferred_cycle_meta.get(item_index)
            if isinstance(inferred_meta, tuple):
                stored_anchor = inferred_meta[0]
                stored_direction = int(inferred_meta[1])
                if new_item.get("cycle_anchor_at") != stored_anchor:
                    new_item["cycle_anchor_at"] = stored_anchor
                    changed = True
                if new_item.get("cycle_offset_direction") != stored_direction:
                    new_item["cycle_offset_direction"] = stored_direction
                    changed = True
            metric_duration_seconds = self._get_schedule_boss_metric_effective_duration_seconds(new_item)
            if apply_enabled and isinstance(metric_duration_seconds, int) and metric_duration_seconds > 0:
                anchor_at = stored_anchor.replace(microsecond=0) if isinstance(stored_anchor, datetime) else scheduled_at.replace(microsecond=0)
                if stored_direction < 0:
                    adjusted_scheduled_at = (anchor_at - timedelta(seconds=metric_duration_seconds)).replace(microsecond=0)
                elif stored_direction > 0:
                    adjusted_scheduled_at = (anchor_at + timedelta(seconds=metric_duration_seconds)).replace(microsecond=0)
                else:
                    adjusted_scheduled_at = anchor_at
                if scheduled_at.replace(microsecond=0) != adjusted_scheduled_at or not isinstance(stored_anchor, datetime):
                    changed = True
                new_item["cycle_anchor_at"] = anchor_at
                new_item["scheduled_at"] = adjusted_scheduled_at
            else:
                if isinstance(stored_anchor, datetime):
                    restored_scheduled_at = stored_anchor.replace(microsecond=0)
                    if scheduled_at.replace(microsecond=0) != restored_scheduled_at:
                        changed = True
                    new_item["scheduled_at"] = restored_scheduled_at
                if "cycle_anchor_at" in new_item:
                    new_item.pop("cycle_anchor_at", None)
                    changed = True
                if "cycle_offset_direction" in new_item:
                    new_item.pop("cycle_offset_direction", None)
                    changed = True
            updated_events.append(new_item)
        if not changed:
            return False
        self.schedule_events = self._normalize_schedule_event_items(updated_events)
        return True

    def _get_schedule_break_rule_for_gap(self, gap_seconds: int | float) -> dict[str, object] | None:
        gap_minutes = max(0, int(math.floor(float(gap_seconds) / 60.0)))
        for entry in self.schedule_break_entries:
            if not isinstance(entry, dict) or not bool(entry.get("enabled", True)):
                continue
            min_gap = self._parse_int(str(entry.get("min_gap_minutes") or "0"), 0)
            max_gap = self._parse_int(str(entry.get("max_gap_minutes") or str(min_gap)), min_gap)
            if min_gap <= gap_minutes <= max_gap:
                return dict(entry)
        return None

    def _resolve_schedule_break_display_text(self, rule: dict[str, object], gap_seconds: int | float) -> str:
        display_mode = str(rule.get("display_mode") or "actual").strip()
        if display_mode == "fixed":
            fixed_text = str(rule.get("display_text") or "").strip()
            return fixed_text or self._format_schedule_break_duration_text(gap_seconds)
        if display_mode == "rounded_30m":
            gap_minutes = max(1, int(round(float(gap_seconds) / 60.0)))
            rounded_minutes = self._round_schedule_break_minutes_to_half_hour(gap_minutes)
            return self._format_schedule_break_duration_text(rounded_minutes * 60)
        return self._format_schedule_break_duration_text(gap_seconds)

    def _build_schedule_break_row_payload(
        self,
        *,
        previous_end_at: datetime,
        next_start_at: datetime,
        rule: dict[str, object],
        excluded_note_suffix: str = "",
    ) -> dict[str, object]:
        gap_seconds = max(0, int((next_start_at - previous_end_at).total_seconds()))
        actual_text = self._format_schedule_break_duration_text(gap_seconds)
        display_text = self._resolve_schedule_break_display_text(rule, gap_seconds)
        label_text = str(rule.get("label_text") or "휴식").strip() or "휴식"
        return {
            "scheduled_at": previous_end_at.replace(microsecond=0),
            "end_at": next_start_at.replace(microsecond=0),
            "gap_seconds": gap_seconds,
            "actual_text": actual_text,
            "display_text": display_text,
            "label_text": label_text,
            "row_scale": float(rule.get("row_scale") or 1.0),
            "font_size": int(rule.get("font_size") or 10),
            "bold": bool(rule.get("bold", False)),
            "text_color": self._normalize_hex_color(str(rule.get("text_color") or DEFAULT_SCHEDULE_BREAK_TEXT_COLOR), DEFAULT_SCHEDULE_BREAK_TEXT_COLOR),
            "bg_color": self._normalize_hex_color(str(rule.get("bg_color") or DEFAULT_SCHEDULE_BREAK_BG_COLOR), DEFAULT_SCHEDULE_BREAK_BG_COLOR),
            "rule": dict(rule),
            "excluded_note_suffix": str(excluded_note_suffix or "").strip(),
        }

    def _normalize_schedule_break_boss_key(self, value: object) -> str:
        return re.sub(r"\s+", "", str(value or "")).strip().lower()

    def _is_schedule_break_ignored_boss_text(self, boss_text: object) -> bool:
        normalized = self._normalize_schedule_break_boss_key(boss_text)
        if not normalized:
            return False
        return "발할라" in normalized and "대전" in normalized

    def _get_schedule_break_row_sort_priority(self, row_kind: str) -> int:
        normalized_kind = str(row_kind or "").strip().lower()
        if normalized_kind == "break":
            return 9
        return 0

    def _get_schedule_visible_row_sort_key(
        self,
        row: tuple[datetime, str, str, str, str, str, str, str, str, dict[str, object], dict[str, object]],
    ) -> tuple[datetime, int, str]:
        return (
            row[0],
            self._get_schedule_break_row_sort_priority(str(row[8] or "")),
            str(row[1] or ""),
        )

    def _get_schedule_share_row_sort_key(self, entry: dict[str, object]) -> tuple[datetime, int, str]:
        scheduled_at = entry.get("scheduled_at")
        if not isinstance(scheduled_at, datetime):
            scheduled_at = datetime.max
        return (
            scheduled_at,
            self._get_schedule_break_row_sort_priority(str(entry.get("kind") or "")),
            str(entry.get("boss_text") or ""),
        )

    def _insert_schedule_break_rows_into_visible_rows(
        self,
        visible_rows: list[tuple[datetime, str, str, str, str, str, str, str, str, dict[str, object], dict[str, object]]],
    ) -> list[tuple[datetime, str, str, str, str, str, str, str, str, dict[str, object], dict[str, object]]]:
        if not bool(self.schedule_break_rows_enabled_var.get()) or not self.schedule_break_entries:
            return visible_rows
        sorted_rows = sorted(visible_rows, key=self._get_schedule_visible_row_sort_key)
        eligible_rows: list[tuple[int, tuple[datetime, str, str, str, str, str, str, str, str, dict[str, object], dict[str, object]]]] = [
            (index, row)
            for index, row in enumerate(sorted_rows)
            if str(row[8] or "") in {"event", "fixed"} and not self._is_schedule_break_ignored_boss_text(row[1])
        ]
        if len(eligible_rows) < 2:
            return visible_rows
        pending_breaks: dict[int, list[tuple[datetime, str, str, str, str, str, str, str, str, dict[str, object], dict[str, object]]]] = {}
        for (current_index, current_row), (next_index, next_row) in zip(eligible_rows, eligible_rows[1:]):
            current_item = current_row[9] if isinstance(current_row[9], dict) else {}
            next_scheduled_at = next_row[0]
            previous_end_at = self._get_schedule_item_effective_end_datetime(current_item)
            if not isinstance(previous_end_at, datetime) or not isinstance(next_scheduled_at, datetime):
                continue
            if next_scheduled_at <= previous_end_at:
                continue
            rule = self._get_schedule_break_rule_for_gap((next_scheduled_at - previous_end_at).total_seconds())
            if not isinstance(rule, dict):
                continue
            ignored_between = any(
                self._is_schedule_break_ignored_boss_text(sorted_rows[middle_index][1])
                for middle_index in range(current_index + 1, next_index)
                if str(sorted_rows[middle_index][8] or "") in {"event", "fixed"}
            )
            excluded_note_suffix = "(발할라 미포함)" if ignored_between else ""
            is_elapsed = bool(next_scheduled_at <= self._get_schedule_reference_datetime())
            break_item = self._build_schedule_break_row_payload(
                previous_end_at=previous_end_at,
                next_start_at=next_scheduled_at,
                rule=rule,
                excluded_note_suffix=excluded_note_suffix,
            )
            pending_breaks.setdefault(current_index, []).append(
                (
                    break_item["scheduled_at"],
                    str(break_item["label_text"]),
                    "경과" if is_elapsed else "휴식",
                    "-",
                    "",
                    "",
                    f"<{break_item['display_text']}>",
                    f"간격 {break_item['actual_text']}" + (f" {excluded_note_suffix}" if excluded_note_suffix else ""),
                    "break",
                    break_item,
                    {
                        "cut_available": False,
                        "cut_inline_visible": False,
                        "cut_disabled_reason": "",
                        "cut_anchor_datetime": break_item["scheduled_at"],
                        "elapsed": is_elapsed,
                    },
                )
            )
        rebuilt_rows: list[tuple[datetime, str, str, str, str, str, str, str, str, dict[str, object], dict[str, object]]] = []
        for index, row in enumerate(sorted_rows):
            rebuilt_rows.append(row)
            if index in pending_breaks:
                rebuilt_rows.extend(pending_breaks[index])
        return rebuilt_rows

    def _insert_schedule_break_rows_into_share_rows(
        self,
        rows: list[dict[str, object]],
    ) -> list[dict[str, object]]:
        if not self.schedule_break_entries:
            return rows
        sorted_rows = sorted(rows, key=self._get_schedule_share_row_sort_key)
        eligible_rows: list[tuple[int, dict[str, object]]] = [
            (index, dict(entry))
            for index, entry in enumerate(sorted_rows)
            if str(entry.get("kind") or "") == "event" and not self._is_schedule_break_ignored_boss_text(entry.get("boss_text"))
        ]
        if len(eligible_rows) < 2:
            return rows
        pending_breaks: dict[int, list[dict[str, object]]] = {}
        for (current_index, current_entry), (next_index, next_entry) in zip(eligible_rows, eligible_rows[1:]):
            current_item = {
                "scheduled_at": current_entry.get("scheduled_at"),
                "explicit_end_at": current_entry.get("effective_end_at"),
            }
            previous_end_at = self._get_schedule_item_effective_end_datetime(current_item)
            next_scheduled_at = next_entry.get("scheduled_at")
            if not isinstance(previous_end_at, datetime) or not isinstance(next_scheduled_at, datetime):
                continue
            if next_scheduled_at <= previous_end_at:
                continue
            rule = self._get_schedule_break_rule_for_gap((next_scheduled_at - previous_end_at).total_seconds())
            if not isinstance(rule, dict):
                continue
            ignored_between = any(
                self._is_schedule_break_ignored_boss_text(sorted_rows[middle_index].get("boss_text"))
                for middle_index in range(current_index + 1, next_index)
                if str(sorted_rows[middle_index].get("kind") or "") == "event"
            )
            excluded_note_suffix = "(발할라 미포함)" if ignored_between else ""
            is_elapsed = bool(next_scheduled_at <= self._get_schedule_reference_datetime())
            break_item = self._build_schedule_break_row_payload(
                previous_end_at=previous_end_at,
                next_start_at=next_scheduled_at,
                rule=rule,
                excluded_note_suffix=excluded_note_suffix,
            )
            pending_breaks.setdefault(current_index, []).append(
                {
                    "kind": "break",
                    "scheduled_at": break_item["scheduled_at"],
                    "time_text": break_item["scheduled_at"].strftime("%H:%M:%S"),
                    "boss_text": str(break_item["label_text"]) + (f" {excluded_note_suffix}" if excluded_note_suffix else ""),
                    "state_text": "경과" if is_elapsed else "휴식",
                    "break_display_text": str(break_item["display_text"]),
                    "is_elapsed": is_elapsed,
                    "is_invasion": False,
                    "is_fixed": False,
                    "has_star": False,
                    "text_color": str(break_item["text_color"]),
                    "bg_color": str(break_item["bg_color"]),
                    "row_scale": float(break_item["row_scale"]),
                    "font_size": 0 if int(break_item["font_size"] or 0) == 10 else int(break_item["font_size"] or 0),
                    "bold": bool(break_item["bold"]),
                }
            )
        rebuilt_rows: list[dict[str, object]] = []
        for index, row in enumerate(sorted_rows):
            rebuilt_rows.append(row)
            if index in pending_breaks:
                rebuilt_rows.extend(pending_breaks[index])
        return rebuilt_rows

    def _format_schedule_remaining_parts(self, total_seconds: float) -> tuple[str, str]:
        seconds_value = max(0, int(total_seconds))
        days, remainder = divmod(seconds_value, 86400)
        hours, remainder = divmod(remainder, 3600)
        minutes, seconds = divmod(remainder, 60)
        if days > 0:
            return f"{days}일 {hours:02d}:{minutes:02d}", f":{seconds:02d}"
        return f"{hours:02d}:{minutes:02d}", f":{seconds:02d}"

    def _get_schedule_item_identity(self, kind: str, item: dict[str, object]) -> tuple[str, str, str, str]:
        scheduled_at = item.get("scheduled_at")
        created_at = item.get("created_at")
        return (
            kind,
            str(item.get("raw_key") or item.get("display_name") or item.get("control_type") or ""),
            scheduled_at.isoformat() if isinstance(scheduled_at, datetime) else "",
            created_at.isoformat() if isinstance(created_at, datetime) else "",
        )

    def _get_schedule_cut_match_key(
        self,
        identity: tuple[str, str, str, str] | None = None,
        item: dict[str, object] | None = None,
        kind: str | None = None,
    ) -> tuple[str, str, str] | None:
        if isinstance(identity, tuple) and len(identity) >= 3:
            return (str(identity[0] or ""), str(identity[1] or ""), str(identity[2] or ""))
        if not isinstance(item, dict):
            return None
        scheduled_at = item.get("scheduled_at")
        scheduled_key = scheduled_at.isoformat() if isinstance(scheduled_at, datetime) else ""
        resolved_kind = str(kind or item.get("state") or "")
        raw_key = str(item.get("raw_key") or item.get("display_name") or item.get("control_type") or "")
        return (resolved_kind, raw_key, scheduled_key)

    def _set_schedule_tree_item_meta(self, item_id: str, kind: str, item: dict[str, object], **extra: object) -> None:
        meta = {
            "kind": kind,
            "identity": self._get_schedule_item_identity(kind, item),
            "item": dict(item),
        }
        meta.update(extra)
        self.schedule_tree_item_meta[item_id] = meta

    def _create_schedule_state_snapshot(self) -> dict[str, object]:
        return {
            "schedule_events": [dict(item) for item in self.schedule_events],
            "schedule_active_entries": [dict(item) for item in self.schedule_active_entries],
            "schedule_control_events": [dict(item) for item in self.schedule_control_events],
            "previous_meta": dict(self.schedule_last_import_meta) if isinstance(self.schedule_last_import_meta, dict) else None,
        }

    def _restore_schedule_state_snapshot(self, snapshot: dict[str, object]) -> None:
        self.schedule_events = self._normalize_schedule_event_items([dict(item) for item in snapshot.get("schedule_events", []) if isinstance(item, dict)])
        self.schedule_active_entries = self._normalize_schedule_active_items([dict(item) for item in snapshot.get("schedule_active_entries", []) if isinstance(item, dict)])
        self.schedule_control_events = [dict(item) for item in snapshot.get("schedule_control_events", []) if isinstance(item, dict)]
        previous_meta = snapshot.get("previous_meta")
        self.schedule_last_import_meta = dict(previous_meta) if isinstance(previous_meta, dict) else None

    def _restore_schedule_state_for_raw_key(self, snapshot: dict[str, object], raw_key: str) -> bool:
        normalized_raw_key = str(raw_key or "").strip()
        if not normalized_raw_key or not isinstance(snapshot, dict):
            return False
        backup_events = [
            dict(item)
            for item in snapshot.get("schedule_events", [])
            if isinstance(item, dict) and str(item.get("raw_key") or "").strip() == normalized_raw_key
        ]
        backup_active_entries = [
            dict(item)
            for item in snapshot.get("schedule_active_entries", [])
            if isinstance(item, dict) and str(item.get("raw_key") or "").strip() == normalized_raw_key
        ]
        current_events = [
            dict(item)
            for item in self.schedule_events
            if isinstance(item, dict) and str(item.get("raw_key") or "").strip() != normalized_raw_key
        ]
        current_active_entries = [
            dict(item)
            for item in self.schedule_active_entries
            if isinstance(item, dict) and str(item.get("raw_key") or "").strip() != normalized_raw_key
        ]
        self.schedule_events = self._normalize_schedule_event_items(current_events + backup_events)
        self.schedule_active_entries = self._normalize_schedule_active_items(current_active_entries + backup_active_entries)
        return True

    def _create_schedule_full_state_snapshot(self) -> dict[str, object]:
        return {
            "base_datetime": self._get_schedule_base_datetime(),
            "view_date": self._get_schedule_view_datetime(),
            "maintenance_weekday": self.schedule_maintenance_weekday_var.get(),
            "maintenance_hour": self.schedule_maintenance_hour_var.get(),
            "maintenance_minute": self.schedule_maintenance_minute_var.get(),
            "schedule_input_past_enabled": bool(self.schedule_input_past_enabled),
            "schedule_delete_active_cutoff_datetime": self.schedule_delete_active_cutoff_datetime,
            "schedule_events": [dict(item) for item in self.schedule_events],
            "schedule_active_entries": [dict(item) for item in self.schedule_active_entries],
            "schedule_control_events": [dict(item) for item in self.schedule_control_events],
            "schedule_last_import_meta": dict(self.schedule_last_import_meta) if isinstance(self.schedule_last_import_meta, dict) else None,
            "schedule_tree_quick_cut_history": [dict(entry) for entry in self.schedule_tree_quick_cut_history if isinstance(entry, dict)],
            "schedule_active_quick_cut_history": [dict(entry) for entry in self.schedule_active_quick_cut_history if isinstance(entry, dict)],
        }

    def _restore_schedule_full_state_snapshot(self, snapshot: dict[str, object]) -> bool:
        if not isinstance(snapshot, dict):
            return False
        base_datetime_value = snapshot.get("base_datetime")
        if isinstance(base_datetime_value, datetime):
            self.schedule_base_year_var.set(base_datetime_value.strftime("%Y년"))
            self.schedule_base_month_var.set(base_datetime_value.strftime("%m월"))
            self.schedule_base_day_var.set(base_datetime_value.strftime("%d일"))
            self.schedule_base_hour_var.set(base_datetime_value.strftime("%H시"))
            self.schedule_base_minute_var.set(base_datetime_value.strftime("%M분"))
        view_date_value = snapshot.get("view_date")
        if isinstance(view_date_value, datetime):
            self.schedule_view_year_var.set(view_date_value.strftime("%Y년"))
            self.schedule_view_month_var.set(view_date_value.strftime("%m월"))
            self.schedule_view_day_var.set(view_date_value.strftime("%d일"))
            self.schedule_view_weekday_var.set(f"({self._get_weekday_label(view_date_value)})")
            self._refresh_schedule_view_weekday_style(view_date_value)
        maintenance_weekday = str(snapshot.get("maintenance_weekday") or "").strip()
        if maintenance_weekday in {"월", "화", "수", "목", "금", "토", "일"}:
            self.schedule_maintenance_weekday_var.set(maintenance_weekday)
        maintenance_hour = str(snapshot.get("maintenance_hour") or "").strip()
        maintenance_hour_digits = re.sub(r"[^0-9]", "", maintenance_hour)
        if maintenance_hour_digits:
            self.schedule_maintenance_hour_var.set(f"{int(maintenance_hour_digits):02d}시")
        maintenance_minute = str(snapshot.get("maintenance_minute") or "").strip()
        maintenance_minute_digits = re.sub(r"[^0-9]", "", maintenance_minute)
        if maintenance_minute_digits:
            self.schedule_maintenance_minute_var.set(f"{int(maintenance_minute_digits):02d}분")
        self.schedule_input_past_enabled = bool(snapshot.get("schedule_input_past_enabled", self.schedule_input_past_enabled))
        self.schedule_input_past_var.set(self.schedule_input_past_enabled)
        schedule_delete_active_cutoff_datetime = snapshot.get("schedule_delete_active_cutoff_datetime")
        if isinstance(schedule_delete_active_cutoff_datetime, datetime):
            self.schedule_delete_active_cutoff_datetime = schedule_delete_active_cutoff_datetime.replace(microsecond=0)
        else:
            self.schedule_delete_active_cutoff_datetime = None
        schedule_events = snapshot.get("schedule_events")
        if isinstance(schedule_events, list):
            self.schedule_events = self._normalize_schedule_event_items([item for item in schedule_events if isinstance(item, dict)])
        schedule_active_entries = snapshot.get("schedule_active_entries")
        if isinstance(schedule_active_entries, list):
            self.schedule_active_entries = self._normalize_schedule_active_items([item for item in schedule_active_entries if isinstance(item, dict)])
        schedule_control_events = snapshot.get("schedule_control_events")
        if isinstance(schedule_control_events, list):
            self.schedule_control_events = [item for item in schedule_control_events if isinstance(item, dict)]
        schedule_last_import_meta = snapshot.get("schedule_last_import_meta")
        self.schedule_last_import_meta = dict(schedule_last_import_meta) if isinstance(schedule_last_import_meta, dict) else None
        tree_quick_cut_history = snapshot.get("schedule_tree_quick_cut_history")
        if isinstance(tree_quick_cut_history, list):
            self.schedule_tree_quick_cut_history = self._normalize_schedule_quick_cut_history_entries(tree_quick_cut_history)
        active_quick_cut_history = snapshot.get("schedule_active_quick_cut_history")
        if isinstance(active_quick_cut_history, list):
            self.schedule_active_quick_cut_history = self._normalize_schedule_quick_cut_history_entries(active_quick_cut_history)
        self._reset_schedule_delete_runtime_state()
        self._prune_schedule_quick_cut_histories()
        return True

    def _reset_schedule_delete_runtime_state(self) -> None:
        self.schedule_tree_deleted_backup = None
        self.schedule_tree_pending_restore_identities = []
        self.schedule_tree_quick_cut_backup = None
        self.schedule_tree_quick_cut_identity = None
        self.schedule_tree_quick_cut_item = None
        self.schedule_tree_quick_cut_text = ""
        self.schedule_tree_quick_cut_time_text = ""
        self.schedule_tree_overlay_cooldowns = {}
        self.schedule_active_overlay_cooldowns = {}
        self.schedule_cut_request_cooldowns = {}
        self.schedule_cut_interaction_cooldowns = {}
        self.schedule_cut_interaction_locks = set()
        self.schedule_tree_click_debounce_until = 0.0
        self.schedule_last_import_backup = None
        self.schedule_alarm_fired_keys = {}
        self.schedule_tree_overlay_signature = None
        self.schedule_tree_elapsed_overlay_signature = None

    def _get_schedule_delete_default_cutoff_datetime(self, reference_datetime: datetime | None = None) -> datetime:
        if isinstance(self.schedule_delete_default_cutoff_datetime, datetime):
            return self.schedule_delete_default_cutoff_datetime.replace(microsecond=0)
        return self._get_schedule_default_server_open_datetime(reference_datetime)

    def _set_schedule_delete_default_cutoff_datetime(self, cutoff_datetime: datetime) -> None:
        if not isinstance(cutoff_datetime, datetime):
            return
        self.schedule_delete_default_cutoff_datetime = cutoff_datetime.replace(microsecond=0)

    def _get_schedule_season_started_datetime(self) -> datetime | None:
        started_at_text = str(self.current_season_started_at or "").strip()
        if not started_at_text:
            return None
        try:
            return datetime.strptime(started_at_text, "%Y-%m-%d %H:%M:%S")
        except ValueError:
            return None

    def _normalize_schedule_delete_history_entry(self, entry: object) -> dict[str, object] | None:
        if not isinstance(entry, dict):
            return None
        normalized = dict(entry)
        cutoff_datetime = normalized.get("cutoff_datetime")
        deleted_at = normalized.get("deleted_at")
        snapshot = normalized.get("snapshot")
        if not isinstance(cutoff_datetime, datetime) or not isinstance(deleted_at, datetime) or not isinstance(snapshot, dict):
            return None
        normalized["cutoff_datetime"] = cutoff_datetime.replace(microsecond=0)
        normalized["deleted_at"] = deleted_at.replace(microsecond=0)
        normalized["snapshot"] = snapshot
        deleted_count = normalized.get("deleted_count")
        try:
            normalized["deleted_count"] = max(0, int(deleted_count))
        except (TypeError, ValueError):
            normalized["deleted_count"] = 0
        summary = normalized.get("summary")
        if isinstance(summary, dict):
            normalized["summary"] = {
                "events": max(0, int(summary.get("events", 0) or 0)),
                "active": max(0, int(summary.get("active", 0) or 0)),
                "controls": max(0, int(summary.get("controls", 0) or 0)),
                "quick_cut": max(0, int(summary.get("quick_cut", 0) or 0)),
                "total": max(0, int(summary.get("total", 0) or 0)),
            }
        else:
            normalized["summary"] = {
                "events": 0,
                "active": 0,
                "controls": 0,
                "quick_cut": 0,
                "total": normalized["deleted_count"],
            }
        return normalized

    def _load_schedule_delete_history(self) -> None:
        self.schedule_delete_history = []
        self.schedule_delete_default_cutoff_datetime = self._get_schedule_default_server_open_datetime()
        if not os.path.exists(SCHEDULE_DELETE_HISTORY_PATH):
            return
        try:
            with open(SCHEDULE_DELETE_HISTORY_PATH, "r", encoding="utf-8") as file:
                payload = json.load(file)
        except (OSError, json.JSONDecodeError):
            return
        restored = self._deserialize_schedule_state_value(payload)
        if not isinstance(restored, dict):
            return
        default_cutoff = restored.get("default_cutoff_datetime")
        if isinstance(default_cutoff, datetime):
            self.schedule_delete_default_cutoff_datetime = default_cutoff.replace(microsecond=0)
        entries = restored.get("entries")
        if isinstance(entries, list):
            normalized_entries = [
                item
                for item in (
                    self._normalize_schedule_delete_history_entry(entry)
                    for entry in entries
                )
                if isinstance(item, dict)
            ]
            normalized_entries.sort(key=lambda entry: entry.get("deleted_at") or datetime.min, reverse=True)
            self.schedule_delete_history = normalized_entries[:5]
        self._clear_stale_schedule_delete_cutoff_if_needed()

    def _save_schedule_delete_history(self) -> None:
        payload = {
            "version": 1,
            "default_cutoff_datetime": self._get_schedule_delete_default_cutoff_datetime(),
            "active_cutoff_datetime": self.schedule_delete_active_cutoff_datetime.replace(microsecond=0) if isinstance(self.schedule_delete_active_cutoff_datetime, datetime) else None,
            "entries": self.schedule_delete_history[:5],
        }
        try:
            with open(SCHEDULE_DELETE_HISTORY_PATH, "w", encoding="utf-8") as file:
                json.dump(self._serialize_schedule_state_value(payload), file, ensure_ascii=False, indent=2)
        except OSError:
            return

    def _clear_stale_schedule_delete_cutoff_if_needed(self) -> bool:
        active_cutoff = self.schedule_delete_active_cutoff_datetime
        if not isinstance(active_cutoff, datetime):
            return False
        latest_deleted_at: datetime | None = None
        for entry in self.schedule_delete_history:
            deleted_at = entry.get("deleted_at")
            if isinstance(deleted_at, datetime):
                latest_deleted_at = deleted_at
                break
        if not isinstance(latest_deleted_at, datetime):
            return False
        if not isinstance(self.schedule_last_import_meta, dict):
            return False
        imported_at = self.schedule_last_import_meta.get("imported_at")
        if not isinstance(imported_at, datetime):
            return False
        if imported_at <= latest_deleted_at:
            return False
        self.schedule_delete_active_cutoff_datetime = None
        self._save_schedule_state()
        self._save_schedule_delete_history()
        return True

    def _set_schedule_event_cut_state(
        self,
        identity: tuple[str, str, str, str] | None,
        cut_datetime: datetime | None,
    ) -> bool:
        current_item = self._get_schedule_event_item_by_identity(identity)
        if current_item is None:
            return False
        if isinstance(cut_datetime, datetime):
            current_item["cut_at"] = cut_datetime.replace(microsecond=0)
        else:
            current_item.pop("cut_at", None)
        current_item.pop("last_cut_time_text", None)
        current_item.pop("last_cut_datetime", None)
        return True

    def _find_schedule_cut_target_event_identity(
        self,
        raw_key: str,
        cut_datetime: datetime | None,
    ) -> tuple[str, str, str, str] | None:
        normalized_raw_key = str(raw_key or "").strip()
        if not normalized_raw_key or not isinstance(cut_datetime, datetime):
            return None
        target_identity: tuple[str, str, str, str] | None = None
        target_scheduled_at: datetime | None = None
        for event_item in self.schedule_events:
            if str(event_item.get("raw_key") or "").strip() != normalized_raw_key:
                continue
            scheduled_at = event_item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime) or scheduled_at > cut_datetime:
                continue
            if target_scheduled_at is None or scheduled_at > target_scheduled_at:
                target_scheduled_at = scheduled_at
                target_identity = self._get_schedule_item_identity("event", event_item)
        return target_identity

    def _find_schedule_event_identity_by_raw_key_and_scheduled_at(
        self,
        raw_key: str,
        scheduled_at: datetime | None,
    ) -> tuple[str, str, str, str] | None:
        normalized_raw_key = str(raw_key or "").strip()
        if not normalized_raw_key or not isinstance(scheduled_at, datetime):
            return None
        target_scheduled_at = scheduled_at.replace(microsecond=0)
        for event_item in self.schedule_events:
            if str(event_item.get("raw_key") or "").strip() != normalized_raw_key:
                continue
            current_scheduled_at = event_item.get("scheduled_at")
            if not isinstance(current_scheduled_at, datetime):
                continue
            if current_scheduled_at.replace(microsecond=0) == target_scheduled_at:
                return self._get_schedule_item_identity("event", event_item)
        return None

    def _get_schedule_event_item_by_identity(self, identity: tuple[str, str, str, str] | None) -> dict[str, object] | None:
        if not isinstance(identity, tuple) or str(identity[0] or "") != "event":
            return None
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        for item in self.schedule_events:
            current_identity = self._get_schedule_item_identity("event", item)
            current_match_key = self._get_schedule_cut_match_key(identity=current_identity)
            if current_identity == identity or (target_match_key is not None and current_match_key == target_match_key):
                return item
        return None

    def _apply_schedule_parsed_cut_states(
        self,
        parsed_items: list[dict[str, object]],
        reference_datetime: datetime,
    ) -> None:
        for item in parsed_items:
            if not isinstance(item, dict) or not bool(item.get("cut_applied")):
                continue
            raw_key = str(item.get("raw_key") or "").strip()
            if not raw_key:
                continue
            cut_datetime = self._resolve_schedule_seed_datetime(item, reference_datetime)
            if not isinstance(cut_datetime, datetime):
                continue
            preserve_scheduled_at = item.get("edit_cut_preserve_scheduled_at")
            if isinstance(preserve_scheduled_at, datetime):
                target_identity = self._find_schedule_event_identity_by_raw_key_and_scheduled_at(raw_key, preserve_scheduled_at)
            else:
                target_identity = self._find_schedule_cut_target_event_identity(raw_key, cut_datetime)
            if target_identity is None:
                continue
            self._set_schedule_event_cut_state(target_identity, cut_datetime)

    def _get_schedule_tree_quick_cut_entry(
        self,
        identity: tuple[str, str, str, str] | None,
        item: dict[str, object] | None = None,
    ) -> dict[str, object] | None:
        if not isinstance(identity, tuple):
            item = item if isinstance(item, dict) else None
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        for entry in reversed(self.schedule_tree_quick_cut_history):
            if entry.get("identity") == identity:
                return entry
            entry_match_key = entry.get("match_key")
            if target_match_key is not None and isinstance(entry_match_key, tuple) and entry_match_key == target_match_key:
                return entry
        # Cut applies can regenerate the row with a new scheduled_at, so keep
        # the quick-cut history attached by matching raw_key + cut_at as well.
        source_item = item if isinstance(item, dict) else self._get_schedule_event_item_by_identity(identity)
        if not isinstance(source_item, dict):
            return None
        raw_key = str(source_item.get("raw_key") or "").strip()
        cut_datetime = self._get_schedule_event_cut_datetime(source_item)
        if not raw_key or not isinstance(cut_datetime, datetime):
            return None
        target_cut_key = cut_datetime.replace(microsecond=0)
        for entry in reversed(self.schedule_tree_quick_cut_history):
            entry_item = entry.get("item")
            if not isinstance(entry_item, dict):
                continue
            if str(entry_item.get("raw_key") or "").strip() != raw_key:
                continue
            entry_cut_datetime = entry.get("cut_datetime")
            if not isinstance(entry_cut_datetime, datetime):
                entry_cut_text = str(entry.get("cut_time_text") or "").strip()
                if entry_cut_text != target_cut_key.strftime("%H:%M:%S"):
                    continue
            elif entry_cut_datetime.replace(microsecond=0) != target_cut_key:
                continue
            return entry
        return None

    def _get_schedule_active_quick_cut_entry_by_tree_identity(
        self,
        tree_identity: tuple[str, str, str, str] | None,
        item: dict[str, object] | None = None,
    ) -> dict[str, object] | None:
        if not isinstance(tree_identity, tuple):
            item = item if isinstance(item, dict) else None
        target_match_key = self._get_schedule_cut_match_key(identity=tree_identity)
        for entry in reversed(self.schedule_active_quick_cut_history):
            entry_tree_identity = entry.get("tree_identity")
            if entry_tree_identity == tree_identity:
                return entry
            entry_match_key = self._get_schedule_cut_match_key(
                identity=entry_tree_identity if isinstance(entry_tree_identity, tuple) else None,
            )
            if target_match_key is not None and entry_match_key == target_match_key:
                return entry
        # Tree identity can change after a cut, so match the restored row by
        # raw_key + cut_at when the direct tree identity no longer matches.
        source_item = item if isinstance(item, dict) else None
        if not isinstance(source_item, dict):
            return None
        raw_key = str(source_item.get("raw_key") or "").strip()
        cut_datetime = self._get_schedule_event_cut_datetime(source_item)
        if not raw_key or not isinstance(cut_datetime, datetime):
            return None
        target_cut_key = cut_datetime.replace(microsecond=0)
        for entry in reversed(self.schedule_active_quick_cut_history):
            entry_item = entry.get("item")
            if not isinstance(entry_item, dict):
                continue
            if str(entry_item.get("raw_key") or "").strip() != raw_key:
                continue
            entry_cut_datetime = entry.get("cut_datetime")
            if not isinstance(entry_cut_datetime, datetime):
                entry_cut_text = str(entry.get("cut_time_text") or "").strip()
                if entry_cut_text != target_cut_key.strftime("%H:%M:%S"):
                    continue
            elif entry_cut_datetime.replace(microsecond=0) != target_cut_key:
                continue
            return entry
        # Direct cut-time input on active rows can regenerate the event row with
        # a cut_at value that does not exactly round-trip to the history entry.
        # In that case, prefer the latest active quick-cut history for the same
        # boss raw_key so tree cancel still restores the original active state.
        for entry in reversed(self.schedule_active_quick_cut_history):
            entry_item = entry.get("item")
            if not isinstance(entry_item, dict):
                continue
            if str(entry_item.get("raw_key") or "").strip() != raw_key:
                continue
            return entry
        return None

    def _get_schedule_active_quick_cut_entry(self, identity: tuple[str, str, str, str] | None) -> dict[str, object] | None:
        if not isinstance(identity, tuple):
            return None
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        for entry in reversed(self.schedule_active_quick_cut_history):
            if entry.get("identity") == identity:
                return entry
            entry_match_key = entry.get("match_key")
            if target_match_key is not None and isinstance(entry_match_key, tuple) and entry_match_key == target_match_key:
                return entry
        return None

    def _purge_schedule_cut_state(
        self,
        *,
        identities: set[tuple[str, str, str, str]] | None = None,
        raw_keys: set[str] | None = None,
    ) -> None:
        target_identities = {
            identity
            for identity in (identities or set())
            if isinstance(identity, tuple) and len(identity) == 4
        }
        target_raw_keys = {str(raw_key or "").strip() for raw_key in (raw_keys or set()) if str(raw_key or "").strip()}
        target_match_keys = {
            match_key
            for match_key in (
                self._get_schedule_cut_match_key(identity=identity)
                for identity in target_identities
            )
            if isinstance(match_key, tuple) and len(match_key) == 3
        }
        if not target_identities and not target_raw_keys and not target_match_keys:
            return

        def matches_tuple_key(value: object) -> bool:
            if not isinstance(value, tuple) or len(value) < 2:
                return False
            if value in target_identities or value in target_match_keys:
                return True
            return str(value[1] or "").strip() in target_raw_keys

        def should_drop_history_entry(entry: dict[str, object]) -> bool:
            if not isinstance(entry, dict):
                return False
            if matches_tuple_key(entry.get("identity")):
                return True
            if matches_tuple_key(entry.get("tree_identity")):
                return True
            if matches_tuple_key(entry.get("match_key")):
                return True
            item = entry.get("item")
            if isinstance(item, dict) and str(item.get("raw_key") or "").strip() in target_raw_keys:
                return True
            return False

        self.schedule_tree_quick_cut_history = [
            dict(entry)
            for entry in self.schedule_tree_quick_cut_history
            if isinstance(entry, dict) and not should_drop_history_entry(entry)
        ]
        self.schedule_active_quick_cut_history = [
            dict(entry)
            for entry in self.schedule_active_quick_cut_history
            if isinstance(entry, dict) and not should_drop_history_entry(entry)
        ]
        for cooldown_map in (
            self.schedule_tree_overlay_cooldowns,
            self.schedule_active_overlay_cooldowns,
            self.schedule_cut_request_cooldowns,
        ):
            for key in list(cooldown_map.keys()):
                if matches_tuple_key(key):
                    cooldown_map.pop(key, None)

    def _is_schedule_tree_overlay_cooldown_active(self, identity: tuple[str, str, str, str] | None) -> bool:
        if not isinstance(identity, tuple):
            return False
        cooldown_key = self._get_schedule_cut_match_key(identity=identity) or identity
        cooldown_until = self.schedule_tree_overlay_cooldowns.get(cooldown_key)
        if not isinstance(cooldown_until, (int, float)):
            return False
        if time.monotonic() >= float(cooldown_until):
            self.schedule_tree_overlay_cooldowns.pop(cooldown_key, None)
            return False
        return True

    def _is_schedule_active_overlay_cooldown_active(self, identity: tuple[str, str, str, str] | None) -> bool:
        if not isinstance(identity, tuple):
            return False
        cooldown_key = self._get_schedule_cut_match_key(identity=identity) or identity
        cooldown_until = self.schedule_active_overlay_cooldowns.get(cooldown_key)
        if not isinstance(cooldown_until, (int, float)):
            return False
        if time.monotonic() >= float(cooldown_until):
            self.schedule_active_overlay_cooldowns.pop(cooldown_key, None)
            return False
        return True

    def _get_schedule_active_row_slot_index(self, identity: tuple[str, str, str, str] | None) -> int | None:
        if not isinstance(identity, tuple):
            return None
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        target_meta = self.schedule_active_row_meta.get(identity)
        if not isinstance(target_meta, dict) and target_match_key is not None:
            for current_identity, current_meta in self.schedule_active_row_meta.items():
                if self._get_schedule_cut_match_key(identity=current_identity) == target_match_key:
                    target_meta = current_meta
                    break
        if not isinstance(target_meta, dict):
            return None
        slot_index = target_meta.get("slot_index")
        return slot_index if isinstance(slot_index, int) and slot_index >= 0 else None

    def _has_schedule_tree_pending_overlay_state(self) -> bool:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return False
        try:
            for meta in self.schedule_tree_item_meta.values():
                if str(meta.get("kind") or "") != "event":
                    continue
                identity = meta.get("identity")
                if not isinstance(identity, tuple):
                    continue
                if self._is_schedule_tree_overlay_cooldown_active(identity):
                    return True
                current_item = meta.get("item") if isinstance(meta.get("item"), dict) else None
                tree_quick_cut_entry = self._get_schedule_tree_quick_cut_entry(identity, current_item)
                active_quick_cut_entry = self._get_schedule_active_quick_cut_entry_by_tree_identity(identity, current_item)
                quick_cut_entry = (
                    tree_quick_cut_entry
                    if isinstance(tree_quick_cut_entry, dict)
                    else active_quick_cut_entry
                )
                active_after = quick_cut_entry.get("active_after") if isinstance(quick_cut_entry, dict) else None
                if isinstance(active_after, (int, float)) and time.monotonic() < float(active_after):
                    return True
        except tk.TclError:
            return False
        return False

    def _schedule_active_rows_after_delay(self, delay_ms: int = 80) -> None:
        if self.schedule_active_rows_frame is None or not self.schedule_active_rows_frame.winfo_exists():
            return
        retry_job = self.schedule_active_overlay_retry_job
        if retry_job is not None:
            try:
                self.schedule_active_rows_frame.after_cancel(retry_job)
            except tk.TclError:
                pass
        try:
            self.schedule_active_overlay_retry_job = self.schedule_active_rows_frame.after(delay_ms, self._refresh_schedule_active_rows)
        except tk.TclError:
            self.schedule_active_overlay_retry_job = None

    def _is_schedule_tree_click_debounce_active(self) -> bool:
        debounce_until = getattr(self, "schedule_tree_click_debounce_until", 0.0)
        if not isinstance(debounce_until, (int, float)):
            return False
        now_monotonic = time.monotonic()
        if now_monotonic >= float(debounce_until):
            self.schedule_tree_click_debounce_until = 0.0
            return False
        return True

    def _arm_schedule_tree_click_debounce(self, cooldown_seconds: float = SCHEDULE_TREE_CLICK_DEBOUNCE_SECONDS) -> None:
        self.schedule_tree_click_debounce_until = time.monotonic() + max(0.0, float(cooldown_seconds))

    def _begin_schedule_cut_request(self, identity: tuple[str, str, str, str] | None, cooldown_seconds: float = SCHEDULE_TREE_CLICK_DEBOUNCE_SECONDS) -> bool:
        if not isinstance(identity, tuple):
            return True
        cooldown_key = self._get_schedule_cut_match_key(identity=identity) or identity
        active_until = self.schedule_cut_request_cooldowns.get(cooldown_key)
        now_monotonic = time.monotonic()
        if isinstance(active_until, (int, float)) and now_monotonic < float(active_until):
            return False
        self.schedule_cut_request_cooldowns[cooldown_key] = now_monotonic + cooldown_seconds
        return True

    def _begin_schedule_cut_interaction(
        self,
        identity: tuple[str, str, str, str] | None,
        cooldown_seconds: float = 0.6,
    ) -> object | None:
        interaction_key: object = self._get_schedule_cut_match_key(identity=identity) if isinstance(identity, tuple) else None
        if interaction_key is None:
            interaction_key = ("anonymous", "schedule_cut")
        now_monotonic = time.monotonic()
        active_until = self.schedule_cut_interaction_cooldowns.get(interaction_key)
        if interaction_key in self.schedule_cut_interaction_locks:
            return None
        if isinstance(active_until, (int, float)) and now_monotonic < float(active_until):
            return None
        self.schedule_cut_interaction_locks.add(interaction_key)
        return interaction_key

    def _end_schedule_cut_interaction(
        self,
        interaction_key: object | None,
        *,
        cooldown_seconds: float = 0.6,
        keep_cooldown: bool = True,
    ) -> None:
        if interaction_key is None:
            return
        self.schedule_cut_interaction_locks.discard(interaction_key)
        if keep_cooldown:
            self.schedule_cut_interaction_cooldowns[interaction_key] = time.monotonic() + max(0.0, float(cooldown_seconds))
        else:
            self.schedule_cut_interaction_cooldowns.pop(interaction_key, None)

    def _can_schedule_event_accept_cut(self, item: dict[str, object], reference_now: datetime) -> bool:
        scheduled_at = item.get("scheduled_at")
        if not isinstance(scheduled_at, datetime):
            return False
        if scheduled_at > reference_now:
            return False
        return self._get_schedule_item_respawn_seconds(item) > 0

    def _can_schedule_event_show_inline_cut(self, item: dict[str, object], reference_now: datetime) -> bool:
        return self._can_schedule_event_accept_cut(item, reference_now)

    def _can_schedule_active_entry_accept_cut(self, item: dict[str, object], reference_now: datetime | None = None) -> bool:
        if self._get_schedule_item_respawn_seconds(item) <= 0:
            return False
        if str(item.get("state") or "") == "active":
            return True
        precision = str(item.get("precision") or "")
        if precision in {"hour", "day"}:
            return True
        scheduled_at = item.get("scheduled_at")
        if scheduled_at is None:
            return True
        if isinstance(scheduled_at, datetime):
            reference_value = reference_now or self._get_schedule_reference_datetime()
            return scheduled_at <= reference_value
        return self._can_schedule_event_accept_cut(item, reference_now or self._get_schedule_reference_datetime())

