    def _show_schedule_delete_boss_dialog(self, *, parent: tk.Widget | None = None) -> str | None:
        owner = parent if self._widget_available(parent) else (self.schedule_window if self._widget_available(self.schedule_window) else self.root)
        delete_candidates = self._get_schedule_delete_candidate_map()
        candidate_names = [str(item.get("display_name") or item.get("boss_name") or "") for item in delete_candidates.values()]
        candidate_text = ", ".join(candidate_names) if candidate_names else "현재 출현 중 / 1일 이상 목록에 삭제할 보스가 없습니다."
        dialog = tk.Toplevel(owner)
        dialog.title("보스 삭제")
        dialog.resizable(False, False)
        dialog.transient(owner)
        dialog.configure(bg="#fee2e2")
        self._center_window_over_parent(dialog, owner, 420, 304)
        result = {"value": None}
        entry_var = tk.StringVar()
        status_var = tk.StringVar(value="예: 안나, 이미르 / 안나 이미르 / 안나,이미르")

        def close_with(value: str | None) -> None:
            result["value"] = value
            try:
                dialog.grab_release()
            except tk.TclError:
                pass
            dialog.destroy()

        def submit() -> None:
            if not delete_candidates:
                status_var.set("현재 출현 중 / 1일 이상 목록에 삭제할 보스가 없습니다.")
                return
            raw_value = (entry_var.get() or "").strip()
            if not raw_value:
                status_var.set("삭제할 보스이름을 입력하세요.")
                return
            boss_names = self._parse_schedule_boss_name_list(raw_value)
            if not boss_names:
                status_var.set("삭제할 보스이름을 확인하세요.")
                return
            missing_names: list[str] = []
            for boss_name in boss_names:
                boss_info = self._normalize_schedule_input_boss_name(boss_name)
                target_key = str(boss_info.get("raw_key") or "").strip()
                if target_key not in delete_candidates:
                    missing_names.append(self._get_schedule_boss_display_name(boss_info, prefer_alias=True) or boss_name)
            if missing_names:
                missing_text = ", ".join(missing_names[:3])
                if len(missing_names) > 3:
                    missing_text += " 외"
                status_var.set(f"{missing_text}: 아래 목록에 없는 보스입니다.")
                return
            close_with(raw_value)

        def append_candidate(candidate_info: dict[str, str]) -> None:
            display_name = str(candidate_info.get("display_name") or candidate_info.get("boss_name") or "").strip()
            raw_key = str(candidate_info.get("raw_key") or "").strip()
            if not display_name or not raw_key:
                return
            current_names = self._parse_schedule_boss_name_list(entry_var.get())
            current_keys = {
                str(self._normalize_schedule_input_boss_name(name).get("raw_key") or "").strip()
                for name in current_names
            }
            if raw_key in current_keys:
                status_var.set(f"{display_name}: 이미 입력되어 있습니다.")
                return
            current_names.append(display_name)
            entry_var.set(", ".join(current_names))
            status_var.set(f"{display_name}: 삭제 목록에 추가했습니다.")
            try:
                entry.focus_force()
                entry.icursor("end")
            except tk.TclError:
                pass

        dialog.protocol("WM_DELETE_WINDOW", lambda: close_with(None))
        tk.Label(dialog, text="삭제할 보스이름", font=self.header_font, bg="#fecaca", fg="#7f1d1d").place(x=0, y=0, width=420, height=40)
        tk.Label(dialog, text="보스이름 입력", font=self.label_font, bg="#fee2e2", fg="#7f1d1d").place(x=18, y=58)
        entry = tk.Entry(dialog, textvariable=entry_var, font=(self.current_font_family, 12, "bold"), relief="solid", bd=1)
        entry.place(x=18, y=84, width=250, height=30)
        tk.Label(
            dialog,
            text="현재 삭제 가능 목록",
            font=self.label_font,
            bg="#fee2e2",
            fg="#7f1d1d",
            anchor="w",
        ).place(x=18, y=122, width=126, height=18)
        candidate_frame = tk.Frame(dialog, bg="#fff1f2", relief="solid", bd=1)
        candidate_frame.place(x=18, y=144, width=384, height=100)
        if delete_candidates:
            candidate_textbox = tk.Text(
                candidate_frame,
                font=self.percent_font,
                bg="#fff1f2",
                fg="#7f1d1d",
                relief="flat",
                bd=0,
                wrap="word",
                padx=6,
                pady=6,
                cursor="arrow",
                highlightthickness=0,
            )
            candidate_textbox.place(x=0, y=0, width=382, height=98)
            candidate_textbox.insert("end", "목록을 클릭하면 입력란에 추가됩니다.\n")
            for index, candidate_info in enumerate(delete_candidates.values()):
                display_name = str(candidate_info.get("display_name") or candidate_info.get("boss_name") or "").strip()
                tag_name = f"delete_candidate_{index}"
                candidate_textbox.insert("end", display_name, (tag_name,))
                if index < len(delete_candidates) - 1:
                    candidate_textbox.insert("end", ", ")
                candidate_textbox.tag_configure(tag_name, foreground="#7f1d1d", underline=True)
                candidate_textbox.tag_bind(tag_name, "<Button-1>", lambda _event, info=dict(candidate_info): append_candidate(info))
                candidate_textbox.tag_bind(tag_name, "<Enter>", lambda _event, widget=candidate_textbox: widget.config(cursor="hand2"))
                candidate_textbox.tag_bind(tag_name, "<Leave>", lambda _event, widget=candidate_textbox: widget.config(cursor="arrow"))
            candidate_textbox.config(state="disabled")
        else:
            tk.Label(
                candidate_frame,
                text=candidate_text,
                font=self.percent_font,
                bg="#fff1f2",
                fg="#7f1d1d",
                anchor="nw",
                justify="left",
                wraplength=372,
                padx=6,
                pady=6,
            ).place(x=0, y=0, width=382, height=98)
        tk.Label(dialog, textvariable=status_var, font=self.percent_font, bg="#fee2e2", fg="#991b1b", anchor="w", justify="left", wraplength=384).place(x=18, y=250, width=384, height=20)
        delete_button = tk.Button(dialog, text="삭제", font=self.button_font, bg="#dc2626", fg="#ffffff", activebackground="#b91c1c", activeforeground="#ffffff", relief="raised", bd=1, highlightthickness=0, command=submit, cursor="hand2")
        delete_button.place(x=234, y=274, width=72, height=28)
        tk.Button(dialog, text="취소", font=self.button_font, bg="#e2e8f0", fg="#334155", activebackground="#cbd5e1", activeforeground="#334155", relief="raised", bd=1, highlightthickness=0, command=lambda: close_with(None), cursor="hand2").place(x=316, y=274, width=72, height=28)
        if not delete_candidates:
            try:
                entry.config(state="disabled")
                delete_button.config(state="disabled", cursor="arrow", bg="#cbd5e1", fg="#f8fafc", activebackground="#cbd5e1", activeforeground="#f8fafc")
            except tk.TclError:
                pass
        dialog.bind("<Return>", lambda _event: submit())
        dialog.bind("<Escape>", lambda _event: close_with(None))
        dialog.grab_set()
        try:
            (entry if delete_candidates else delete_button).focus_force()
        except tk.TclError:
            pass
        dialog.wait_window()
        return result["value"]

    def _get_schedule_delete_candidate_map(self, reference_datetime: datetime | None = None) -> dict[str, dict[str, str]]:
        reference_now = reference_datetime if isinstance(reference_datetime, datetime) else self._get_schedule_reference_datetime()
        candidates: dict[str, dict[str, str]] = {}
        for row_info in self._get_schedule_active_panel_rows(reference_now):
            if str(row_info.get("kind") or "") not in {"active", "long"}:
                continue
            item = row_info.get("item")
            if not isinstance(item, dict):
                continue
            raw_key = str(item.get("raw_key") or "").strip()
            boss_name = str(item.get("boss_name") or "").strip()
            display_name = self._get_schedule_boss_display_name(item, prefer_alias=True)
            if not raw_key or raw_key in candidates:
                continue
            candidates[raw_key] = {
                "raw_key": raw_key,
                "boss_name": boss_name,
                "display_name": display_name or boss_name or raw_key,
            }
        return candidates

