    def _parse_schedule_boss_name_list(self, raw_text: str) -> list[str]:
        cleaned = re.sub(r"[\r\n\t]+", " ", (raw_text or "").strip())
        if not cleaned:
            return []
        if "," in cleaned:
            parts = [part.strip() for part in cleaned.split(",") if part.strip()]
        else:
            tokens = [token for token in cleaned.split(" ") if token]
            parts = []
            index = 0
            while index < len(tokens):
                if tokens[index] == "침공" and index + 1 < len(tokens):
                    parts.append(f"침공 {tokens[index + 1]}")
                    index += 2
                    continue
                parts.append(tokens[index])
                index += 1
        deduped: list[str] = []
        seen: set[str] = set()
        for part in parts:
            normalized = self._normalize_schedule_boss_lookup_key(part)
            if not normalized or normalized in seen:
                continue
            seen.add(normalized)
            deduped.append(part)
        return deduped

    def _normalize_schedule_add_duration_text(self, text: str) -> str:
        compact = re.sub(r"\s+", "", (text or "").strip())
        if not compact:
            return ""
        compact = compact.replace("시", "시간")
        if re.fullmatch(r"\d+일\d+$", compact):
            match = re.fullmatch(r"(\d+)일(\d+)$", compact)
            if match:
                return f"{match.group(1)}일 {match.group(2)}시간"
        if re.fullmatch(r"\d+$", compact):
            return f"{compact}시간"
        compact = re.sub(r"(\d+일)(\d+시간)", r"\1 \2", compact)
        compact = re.sub(r"(\d+일)(\d+분)", r"\1 \2", compact)
        compact = re.sub(r"(\d+일)(\d+초)", r"\1 \2", compact)
        return compact

    def _get_schedule_add_candidate_names(self) -> list[str]:
        candidates: set[str] = set()
        for boss_name, item in self.schedule_boss_definitions.items():
            canonical = str(item.get("boss_name") or boss_name).strip()
            if not canonical:
                continue
            candidates.add(canonical)
            alias = str(item.get("alias") or "").strip()
            if alias:
                candidates.add(alias)
                candidates.add(f"침공 {alias}")
            candidates.add(f"침공 {canonical}")
        for source_name in RECORD_BOOK_ABBREV_MAP.keys():
            source = str(source_name or "").strip()
            if source:
                candidates.add(source)
                candidates.add(f"침공 {source}")
        return sorted(candidates, key=lambda value: len(self._normalize_schedule_boss_lookup_key(value)), reverse=True)

    def _normalize_schedule_active_add_line(self, raw_line: str) -> str | None:
        cleaned = re.sub(r"\s+", " ", (raw_line or "").strip())
        if not cleaned:
            return None
        direct = self._parse_schedule_input_line(cleaned)
        if isinstance(direct, dict) and str(direct.get("state") or "") in {"active", "scheduled"} and str(direct.get("control_type") or "") == "":
            return cleaned
        if not re.search(r"\d", cleaned) and self._normalize_schedule_presence_text(cleaned) is None and ":" not in cleaned and not cleaned.endswith("컷"):
            return f"{cleaned} 출현 중"
        normalized_input = self._normalize_schedule_boss_lookup_key(cleaned)
        for candidate in self._get_schedule_add_candidate_names():
            candidate_key = self._normalize_schedule_boss_lookup_key(candidate)
            if not candidate_key or not normalized_input.startswith(candidate_key):
                continue
            remainder = normalized_input[len(candidate_key):]
            if not remainder:
                return f"{candidate} 출현 중"
            duration_text = self._normalize_schedule_add_duration_text(remainder)
            if not duration_text:
                continue
            if self._parse_schedule_remaining_value(duration_text) is None:
                continue
            boss_info = self._normalize_schedule_input_boss_name(candidate)
            return f"{str(boss_info.get('display_name') or candidate)}: {duration_text}"
        return None

    def _add_schedule_active_entries_by_text(self, raw_text: str) -> None:
        lines = [line for line in re.split(r"[\r\n]+", raw_text or "") if line.strip()]
        normalized_lines: list[str] = []
        for line in lines:
            normalized_line = self._normalize_schedule_active_add_line(line)
            if normalized_line:
                normalized_lines.append(normalized_line)
        if not normalized_lines:
            self.schedule_status_var.set("추가할 보스 입력을 확인할 수 없습니다.")
            return
        normalized_text = "\n".join(normalized_lines)
        parsed_items, ignored_count = self._parse_schedule_input_lines(normalized_text)
        parsed_items = [
            item for item in parsed_items
            if str(item.get("state") or "") in {"active", "scheduled"} and str(item.get("control_type") or "") == ""
        ]
        if not parsed_items:
            self.schedule_status_var.set("추가할 보스 입력을 파싱하지 못했습니다.")
            return
        reference_datetime = self._get_schedule_reference_datetime()
        self._apply_schedule_parsed_batch(
            normalized_text,
            parsed_items,
            ignored_count,
            reference_datetime,
            reference_datetime,
            source_label="출현 중 추가",
            skip_overwrite_confirm=True,
            ignore_delete_cutoff=True,
        )

    def _delete_schedule_boss_by_name(self, boss_text: str, *, refresh: bool = True) -> int:
        reference_datetime = self._get_schedule_reference_datetime()
        delete_candidates = self._get_schedule_delete_candidate_map(reference_datetime)
        boss_info = self._normalize_schedule_input_boss_name(boss_text)
        target_key = str(boss_info.get("raw_key") or "")
        if not target_key:
            if refresh:
                self.schedule_status_var.set("삭제할 보스이름을 확인할 수 없습니다.")
            return 0
        candidate_info = delete_candidates.get(target_key)
        if not isinstance(candidate_info, dict):
            if refresh:
                self.schedule_status_var.set(f"{self._get_schedule_boss_display_name(boss_info, prefer_alias=True) or boss_text}: 출현 중 / 1일 이상 목록에 없는 보스입니다.")
            return 0

        before_events = len(self.schedule_events)
        before_active = len(self.schedule_active_entries)
        removed_event_items = [
            dict(item)
            for item in self.schedule_events
            if str(item.get("raw_key") or "") == target_key
        ]

        self.schedule_events = [
            item
            for item in self.schedule_events
            if str(item.get("raw_key") or "") != target_key
        ]
        self.schedule_active_entries = [item for item in self.schedule_active_entries if str(item.get("raw_key") or "") != target_key]
        self._purge_schedule_cut_state(
            identities={
                identity
                for identity in (
                    self._get_schedule_item_identity("event", item)
                    for item in removed_event_items
                )
                if isinstance(identity, tuple)
            },
            raw_keys={target_key},
        )

        removed_count = (
            (before_events - len(self.schedule_events))
            + (before_active - len(self.schedule_active_entries))
        )
        if removed_count <= 0:
            if refresh:
                self.schedule_status_var.set(f"{str(candidate_info.get('display_name') or boss_text)}: 삭제할 관리 데이터가 없습니다.")
            return 0

        if refresh:
            self._save_schedule_state()
            self._refresh_schedule_view()
            self.schedule_status_var.set(f"{str(candidate_info.get('display_name') or boss_text)}: 출현 중 / 1일 이상 관리 목록에서 삭제했습니다.")
        return removed_count

    def _open_schedule_delete_boss_dialog(self) -> None:
        raw_text = self._show_schedule_delete_boss_dialog(parent=self.schedule_window)
        if not raw_text:
            return
        boss_names = self._parse_schedule_boss_name_list(raw_text)
        if not boss_names:
            self.schedule_status_var.set("삭제할 보스이름을 확인할 수 없습니다.")
            return
        deleted_total = 0
        deleted_names: list[str] = []
        for boss_name in boss_names:
            removed_count = self._delete_schedule_boss_by_name(boss_name, refresh=False)
            if removed_count > 0:
                deleted_total += removed_count
                deleted_names.append(boss_name)
        if deleted_total <= 0:
            self.schedule_status_var.set("삭제할 데이터가 없습니다.")
            return
        self._save_schedule_state()
        self._refresh_schedule_view()
        self.schedule_status_var.set(f"{len(deleted_names)}개 보스를 출현 중 / 1일 이상 관리 목록에서 삭제했습니다.")

    def _open_schedule_add_boss_dialog(self) -> None:
        raw_text = self._show_schedule_add_boss_dialog(parent=self.schedule_window)
        if not raw_text:
            return
        self._add_schedule_active_entries_by_text(raw_text)

    def _apply_schedule_cut_action(
        self,
        item: dict[str, object],
        *,
        cut_token: str | None = None,
        overwrite_start_datetime: datetime | None = None,
        cut_preserve_scheduled_at: datetime | None = None,
        source_label: str = "컷 적용",
        suppress_schedule_view_refresh: bool = False,
        refresh_tree_on_suppress: bool = True,
        refresh_active_rows_on_suppress: bool = True,
    ) -> bool:
        reference_datetime = self._get_schedule_reference_datetime()
        raw_text = self._get_schedule_cut_input_text(item, cut_token)
        parsed_items, ignored_count = self._parse_schedule_input_lines(raw_text)
        if not parsed_items:
            self.schedule_status_var.set(f"{source_label}에 사용할 스케쥴 데이터를 만들지 못했습니다.")
            return False
        if isinstance(cut_preserve_scheduled_at, datetime):
            preserve_scheduled_at = cut_preserve_scheduled_at.replace(microsecond=0)
            target_raw_key = str(item.get("raw_key") or "").strip()
            for parsed_item in parsed_items:
                if target_raw_key and str(parsed_item.get("raw_key") or "").strip() != target_raw_key:
                    continue
                parsed_item["edit_cut_preserve_scheduled_at"] = preserve_scheduled_at
        start_datetime = overwrite_start_datetime
        if start_datetime is None:
            first_item = parsed_items[0]
            resolved = self._resolve_schedule_seed_datetime(first_item, reference_datetime)
            start_datetime = resolved if isinstance(resolved, datetime) else reference_datetime
        success = self._apply_schedule_parsed_batch(
            raw_text,
            parsed_items,
            ignored_count,
            reference_datetime,
            start_datetime,
            overwrite_cutoff_datetime=overwrite_start_datetime or start_datetime,
            edit_mode=False,
            force_past_update_keys={str(item.get("raw_key") or "")} if str(item.get("raw_key") or "") else set(),
            source_label=source_label,
            skip_overwrite_confirm=True,
            suppress_schedule_view_refresh=suppress_schedule_view_refresh,
            store_input_undo_backup=False,
            refresh_tree_on_suppress=refresh_tree_on_suppress,
            refresh_active_rows_on_suppress=refresh_active_rows_on_suppress,
        )
        return success

    def _update_schedule_next_boss_summary(self) -> None:
        reference_now = self._get_schedule_reference_datetime()
        self.schedule_current_time_var.set(reference_now.strftime("%H:%M:%S"))
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        next_maintenance_datetime = self._get_schedule_maintenance_cutoff_datetime(reference_now)
        previous_rows: list[tuple[datetime, str]] = []
        future_rows: list[tuple[datetime, str]] = []
        for item in self.schedule_events:
            scheduled_at = item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime):
                continue
            if self._is_schedule_invasion_item(item) and not self._is_schedule_invasion_datetime_visible(scheduled_at):
                continue
            if scheduled_at < reference_now:
                previous_rows.append((scheduled_at, self._get_schedule_boss_display_name(item, prefer_alias=True, include_star=True)))
                continue
            if cutoff_datetime is not None and scheduled_at >= cutoff_datetime:
                continue
            future_rows.append((scheduled_at, self._get_schedule_boss_display_name(item, prefer_alias=True, include_star=True)))
        for scheduled_at, boss_name, *_rest in self._get_fixed_boss_schedule_rows():
            if scheduled_at < reference_now:
                previous_rows.append((scheduled_at, boss_name))
                continue
            if cutoff_datetime is not None and scheduled_at >= cutoff_datetime:
                continue
            future_rows.append((scheduled_at, boss_name))
        previous_rows.sort(key=lambda row: (row[0], row[1]))
        if previous_rows:
            previous_time, previous_boss = previous_rows[-1]
            self.schedule_previous_boss_var.set(f"[{previous_time.strftime('%H:%M:%S')}] {previous_boss}")
        else:
            self.schedule_previous_boss_var.set("지나간 보스 없음")
        future_rows.sort(key=lambda row: (row[0], row[1]))
        maintenance_row = (
            (next_maintenance_datetime, "정기점검")
            if isinstance(next_maintenance_datetime, datetime) and next_maintenance_datetime >= reference_now
            else None
        )
        next_row: tuple[datetime, str] | None = future_rows[0] if future_rows else None
        following_row: tuple[datetime, str] | None = future_rows[1] if len(future_rows) >= 2 else None
        if next_row is None and maintenance_row is not None:
            next_row = maintenance_row
            following_row = None
        elif next_row is not None and following_row is None and maintenance_row is not None and maintenance_row[0] >= next_row[0]:
            following_row = maintenance_row
        if next_row is None:
            self.schedule_next_boss_var.set("다음 보스 없음")
            self.schedule_next_boss_remaining_var.set("--:--")
            self.schedule_next_boss_seconds_var.set(":--")
            self.schedule_following_boss_var.set("")
            self.schedule_following_boss_remaining_var.set("")
            self.schedule_following_boss_seconds_var.set("")
            self._update_schedule_summary_label_styles()
            self._layout_schedule_summary_labels()
            return
        next_time, next_boss = next_row
        self.schedule_next_boss_var.set(f"[{next_time.strftime('%H:%M:%S')}] {next_boss}:")
        next_main, next_seconds = self._format_schedule_remaining_parts((next_time - reference_now).total_seconds())
        self.schedule_next_boss_remaining_var.set(next_main)
        self.schedule_next_boss_seconds_var.set(next_seconds)
        if following_row is not None and next_boss != "정기점검":
            following_time, following_boss = following_row
            self.schedule_following_boss_var.set(f"[{following_time.strftime('%H:%M:%S')}] {following_boss}:")
            following_main, following_seconds = self._format_schedule_remaining_parts((following_time - reference_now).total_seconds())
            self.schedule_following_boss_remaining_var.set(f"{following_main}{following_seconds}")
            self.schedule_following_boss_seconds_var.set("")
        else:
            self.schedule_following_boss_var.set("")
            self.schedule_following_boss_remaining_var.set("")
            self.schedule_following_boss_seconds_var.set("")
        self._update_schedule_summary_label_styles()
        self._layout_schedule_summary_labels()

    def _update_schedule_summary_label_styles(self) -> None:
        next_name_label = getattr(self, "schedule_next_boss_label", None)
        next_main_label = getattr(self, "schedule_next_boss_remaining_label", None)
        next_seconds_label = getattr(self, "schedule_next_boss_seconds_label", None)
        following_name_label = getattr(self, "schedule_following_boss_label", None)
        following_main_label = getattr(self, "schedule_following_boss_remaining_label", None)
        following_seconds_label = getattr(self, "schedule_following_boss_seconds_label", None)
        if not all(
            (
                next_name_label,
                next_main_label,
                next_seconds_label,
                following_name_label,
                following_main_label,
                following_seconds_label,
            )
        ):
            return
        next_is_maintenance = "정기점검" in str(self.schedule_next_boss_var.get() or "")
        following_is_maintenance = "정기점검" in str(self.schedule_following_boss_var.get() or "")
        try:
            next_name_label.config(fg="#b91c1c" if next_is_maintenance else "#0f172a")
            next_main_label.config(fg="#b91c1c" if next_is_maintenance else "#dc2626")
            next_seconds_label.config(fg="#b91c1c" if next_is_maintenance else "#dc2626")
            following_name_label.config(fg="#b91c1c" if following_is_maintenance else "#334155")
            following_main_label.config(fg="#b91c1c" if following_is_maintenance else "#475569")
            following_seconds_label.config(fg="#b91c1c" if following_is_maintenance else "#475569")
        except tk.TclError:
            return

    def _layout_schedule_summary_labels(self) -> None:
        next_name_label = getattr(self, "schedule_next_boss_label", None)
        next_main_label = getattr(self, "schedule_next_boss_remaining_label", None)
        next_seconds_label = getattr(self, "schedule_next_boss_seconds_label", None)
        following_name_label = getattr(self, "schedule_following_boss_label", None)
        following_main_label = getattr(self, "schedule_following_boss_remaining_label", None)
        following_seconds_label = getattr(self, "schedule_following_boss_seconds_label", None)
        if not all(
            (
                getattr(self, "schedule_previous_boss_label", None),
                next_name_label,
                next_main_label,
                next_seconds_label,
                following_name_label,
                following_main_label,
                following_seconds_label,
            )
        ):
            return

        name_x = 136
        time_gap = 0
        next_seconds_gap = 0

        def measure_width(widget: tk.Widget, text: str, padding: int = 6) -> int:
            font = tkfont.Font(font=widget.cget("font"))
            return max(20, font.measure(text) + padding)

        next_name_text = self.schedule_next_boss_var.get()
        next_main_text = self.schedule_next_boss_remaining_var.get()
        next_seconds_text = self.schedule_next_boss_seconds_var.get()
        next_name_width = measure_width(next_name_label, next_name_text, 8)
        next_main_width = measure_width(next_main_label, next_main_text, 2)
        next_seconds_width = measure_width(next_seconds_label, next_seconds_text, 5)
        next_main_x = name_x + next_name_width + time_gap
        next_seconds_x = next_main_x + next_main_width + next_seconds_gap
        next_name_label.place_configure(x=name_x, width=next_name_width)
        next_main_label.place_configure(x=next_main_x, width=next_main_width)
        next_seconds_label.place_configure(x=next_seconds_x, width=next_seconds_width)

        following_name_text = self.schedule_following_boss_var.get()
        following_main_text = self.schedule_following_boss_remaining_var.get()
        following_seconds_text = self.schedule_following_boss_seconds_var.get()
        if not following_name_text and not following_main_text and not following_seconds_text:
            following_name_label.place_forget()
            following_main_label.place_forget()
            following_seconds_label.place_forget()
            return
        following_name_width = measure_width(following_name_label, following_name_text, 8)
        following_main_width = measure_width(following_main_label, following_main_text, 6)
        following_main_x = name_x + following_name_width + time_gap
        following_name_label.place(x=name_x, y=50, width=following_name_width, height=18)
        following_main_label.place(x=following_main_x, y=50, width=following_main_width, height=18)
        following_seconds_label.place_forget()

    def _on_schedule_active_cut_time(self, item: dict[str, object], boss_text: str, identity: tuple[str, str, str, str] | None = None) -> None:
        interaction_key = self._begin_schedule_cut_interaction(identity if isinstance(identity, tuple) else None)
        if interaction_key is None:
            return
        resolved_identity = identity if isinstance(identity, tuple) else self._get_schedule_item_identity("active", item)
        try:
            existing_entry = self._get_schedule_active_quick_cut_entry(resolved_identity)
            source_item = (
                dict(existing_entry.get("item"))
                if isinstance(existing_entry, dict) and isinstance(existing_entry.get("item"), dict)
                else dict(item)
            )
            if existing_entry is None and not self._can_schedule_active_entry_accept_cut(item, self._get_schedule_reference_datetime()):
                self.schedule_status_var.set("현재 출현 중 / 1일 이상 목록에서는 컷시간을 적용할 수 없습니다.")
                return
            dialog_boss_text = self._get_schedule_boss_display_name(source_item, prefer_alias=True) or boss_text
            cut_token = self._show_schedule_cut_time_dialog(dialog_boss_text, parent=self.schedule_window)
            if not cut_token:
                return
            presence_text = self._normalize_schedule_presence_text(cut_token)
            if presence_text:
                if isinstance(existing_entry, dict):
                    self._undo_schedule_active_quick_cut(resolved_identity)
                self._add_schedule_active_entries_by_text(f"{dialog_boss_text} {presence_text}")
                return
            if cut_token == "0":
                return
            if isinstance(existing_entry, dict):
                self._undo_schedule_active_quick_cut(resolved_identity)
            if not self._begin_schedule_cut_request(resolved_identity):
                return
            self._apply_schedule_active_quick_cut_with_history(
                source_item,
                resolved_identity,
                cut_token=cut_token,
                overwrite_start_datetime=None,
                source_label="출현 중 컷시간 적용",
            )
        finally:
            self._end_schedule_cut_interaction(interaction_key)

    def _apply_schedule_active_quick_cut(self, item: dict[str, object], identity: tuple[str, str, str, str] | None = None) -> None:
        interaction_key = self._begin_schedule_cut_interaction(identity if isinstance(identity, tuple) else None)
        if interaction_key is None:
            return
        try:
            if not self._can_schedule_active_entry_accept_cut(item, self._get_schedule_reference_datetime()):
                self.schedule_status_var.set("현재 출현 중 / 1일 이상 목록에서는 컷을 적용할 수 없습니다.")
                return
            resolved_identity = identity if isinstance(identity, tuple) else self._get_schedule_item_identity("active", item)
            if not self._begin_schedule_cut_request(resolved_identity):
                return
            cut_token = self._get_schedule_reference_datetime().strftime("%H%M%S")
            self._apply_schedule_active_quick_cut_with_history(
                dict(item),
                resolved_identity,
                cut_token=cut_token,
                overwrite_start_datetime=None,
                source_label="출현 중 컷 적용",
            )
        finally:
            self._end_schedule_cut_interaction(interaction_key)

    def _get_schedule_active_panel_chapter_sort_key(self, item: dict[str, object] | None) -> tuple[int, str]:
        if not isinstance(item, dict):
            return len(RECORD_BOOK_AREAS), ""
        boss_name = str(item.get("boss_name") or "").strip()
        if not boss_name:
            normalized = self._normalize_schedule_input_boss_name(str(item.get("display_name") or ""))
            boss_name = str(normalized.get("boss_name") or "").strip()
        definition = self.schedule_boss_definitions.get(boss_name, {})
        area_name = str(definition.get("area") or RECORD_BOOK_AREAS[0]).strip()
        area_index = RECORD_BOOK_AREAS.index(area_name) if area_name in RECORD_BOOK_AREAS else len(RECORD_BOOK_AREAS)
        return area_index, area_name

    def _get_schedule_active_panel_boss_definition_sort_key(self, item: dict[str, object] | None) -> tuple[int, str]:
        if not isinstance(item, dict):
            return 9999, ""
        boss_name = str(item.get("boss_name") or "").strip()
        if not boss_name:
            normalized = self._normalize_schedule_input_boss_name(str(item.get("display_name") or ""))
            boss_name = str(normalized.get("boss_name") or "").strip()
        definition = self.schedule_boss_definitions.get(boss_name, {})
        area_name = str(definition.get("area") or RECORD_BOOK_AREAS[0]).strip()
        area_order = RECORD_BOOK_BOSS_ORDER.get(area_name, [])
        try:
            return area_order.index(boss_name), boss_name
        except ValueError:
            return len(area_order), boss_name

    def _get_schedule_active_panel_time_sort_value(self, row_info: dict[str, object]) -> float:
        kind = str(row_info.get("kind") or "")
        if kind == "long":
            remaining_seconds = row_info.get("remaining_seconds")
            if isinstance(remaining_seconds, (int, float)):
                return float(remaining_seconds)
        cut_datetime = row_info.get("cut_datetime")
        if isinstance(cut_datetime, datetime):
            return cut_datetime.timestamp()
        item = row_info.get("item")
        if isinstance(item, dict):
            scheduled_at = item.get("scheduled_at")
            if isinstance(scheduled_at, datetime):
                return scheduled_at.timestamp()
            created_at = item.get("created_at")
            if isinstance(created_at, datetime):
                return created_at.timestamp()
        active_index = row_info.get("_active_index")
        if isinstance(active_index, int):
            return float(active_index)
        return float("inf")

    def _get_schedule_active_panel_sort_key(self, row_info: dict[str, object]) -> tuple[object, ...]:
        item = row_info.get("item")
        kind = str(row_info.get("kind") or "")
        chapter_order, area_name = self._get_schedule_active_panel_chapter_sort_key(item if isinstance(item, dict) else None)
        boss_order, boss_name = self._get_schedule_active_panel_boss_definition_sort_key(item if isinstance(item, dict) else None)
        time_sort = self._get_schedule_active_panel_time_sort_value(row_info)
        if kind == "active":
            return (
                0,
                chapter_order,
                boss_order,
                boss_name,
                area_name,
            )
        if kind == "cut" and not isinstance(row_info.get("remaining_seconds"), (int, float)):
            return (
                1,
                chapter_order,
                boss_order,
                boss_name,
                area_name,
            )
        return (
            2,
            time_sort,
            chapter_order,
            boss_order,
            boss_name,
            area_name,
        )

    def _get_selected_schedule_tree_cut_target(self) -> dict[str, object] | None:
        if self.schedule_tree is None:
            return None
        try:
            selected_ids = [str(item_id) for item_id in self.schedule_tree.selection() if str(item_id)]
            focus_id = str(self.schedule_tree.focus() or "").strip()
        except tk.TclError:
            return None
        candidate_ids = list(selected_ids)
        if focus_id and focus_id not in candidate_ids:
            candidate_ids.append(focus_id)
        if not candidate_ids:
            return None
        eligible_targets: dict[str, dict[str, object]] = {}
        reference_datetime = self._get_schedule_reference_datetime()
        for item_id in candidate_ids:
            meta = self.schedule_tree_item_meta.get(item_id, {})
            if str(meta.get("kind") or "") != "event":
                continue
            item = meta.get("item")
            if not isinstance(item, dict):
                continue
            scheduled_at = item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime):
                continue
            if self._get_schedule_item_respawn_seconds(item) <= 0:
                continue
            identity = meta.get("identity")
            resolved_identity = identity if isinstance(identity, tuple) else None
            tree_quick_cut_entry = self._get_schedule_tree_quick_cut_entry(resolved_identity, item)
            active_quick_cut_entry = self._get_schedule_active_quick_cut_entry_by_tree_identity(resolved_identity, item)
            quick_cut_entry = (
                tree_quick_cut_entry
                if isinstance(tree_quick_cut_entry, dict)
                else active_quick_cut_entry
            )
            cooldown_active = self._is_schedule_tree_overlay_cooldown_active(resolved_identity)
            active_after = quick_cut_entry.get("active_after") if isinstance(quick_cut_entry, dict) else None
            show_cancel = bool(
                not cooldown_active
                and quick_cut_entry is not None
                and (not isinstance(active_after, (int, float)) or time.monotonic() >= float(active_after))
            )
            pending = bool(quick_cut_entry is not None and not show_cancel)
            cut_time_text = (
                str(quick_cut_entry.get("cut_time_text") or "")
                if isinstance(quick_cut_entry, dict)
                else self._get_schedule_event_cut_time_text(item)
            )
            cut_allowed = self._can_schedule_event_accept_cut(item, reference_datetime)
            if show_cancel:
                mode = "cancel"
            elif pending:
                mode = "cooldown"
            elif cut_time_text:
                mode = "cut_time_only" if cut_allowed else "cut_time_locked"
            elif not cut_allowed:
                continue
            else:
                mode = "cut_pair"
            eligible_targets[item_id] = {
                "item_id": item_id,
                "item": dict(item),
                "identity": resolved_identity,
                "mode": mode,
                "cut_time_text": cut_time_text,
            }
        if not eligible_targets:
            return None
        if focus_id and focus_id in eligible_targets:
            return eligible_targets[focus_id]
        for item_id in selected_ids:
            if item_id in eligible_targets:
                return eligible_targets[item_id]
        return next(iter(eligible_targets.values()))

    def _get_schedule_active_panel_rows(self, reference_now: datetime) -> list[dict[str, object]]:
        rows: list[dict[str, object]] = []
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        active_order_map: dict[str, int] = {}
        for index, item in enumerate(self.schedule_active_entries):
            panel_key = self._get_schedule_panel_dedupe_key(item)
            if panel_key and panel_key not in active_order_map:
                active_order_map[panel_key] = index

        row_map: dict[str, dict[str, object]] = {}
        long_candidates: dict[str, dict[str, object]] = {}

        for item in self.schedule_active_entries:
            if self._is_schedule_invasion_item(item) and reference_now.weekday() != self._get_schedule_invasion_weekday_index():
                continue
            panel_key = self._get_schedule_panel_dedupe_key(item)
            if not panel_key:
                continue
            respawn_available = self._get_schedule_item_respawn_seconds(item) > 0
            cut_available = self._can_schedule_active_entry_accept_cut(item, reference_now)
            row_map[panel_key] = {
                "kind": "active",
                "item": dict(item),
                "identity": self._get_schedule_item_identity("active", item),
                "label": f"{self._get_schedule_boss_display_name(item, prefer_alias=True, include_star=True)}: 출현 중",
                "action_mode": "cut_pair" if cut_available else ("no_respawn" if not respawn_available else ""),
                "action_cut_time_text": "",
                "needs_retry": False,
                "_active_index": active_order_map.get(panel_key, 9999),
            }

        for entry in self.schedule_active_quick_cut_history:
            item = entry.get("item")
            cut_datetime = entry.get("cut_datetime")
            if not isinstance(item, dict) or not isinstance(cut_datetime, datetime):
                continue
            if self._is_schedule_invasion_item(item) and reference_now.weekday() != self._get_schedule_invasion_weekday_index():
                continue
            action_at = self._get_schedule_quick_cut_action_at(entry)
            if not isinstance(action_at, datetime):
                action_at = cut_datetime
            if reference_now > action_at + timedelta(seconds=SCHEDULE_ACTIVE_QUICK_CUT_PANEL_RETENTION_SECONDS):
                continue
            panel_key = self._get_schedule_panel_dedupe_key(item)
            if not panel_key:
                continue
            identity = entry.get("identity")
            resolved_identity = identity if isinstance(identity, tuple) else self._get_schedule_item_identity("active", item)
            scheduled_at = item.get("scheduled_at")
            remaining_seconds = None
            if isinstance(scheduled_at, datetime):
                remaining_seconds = max(0, int((scheduled_at - reference_now).total_seconds()))
            active_after = entry.get("active_after")
            cancel_ready = not isinstance(active_after, (int, float)) or time.monotonic() >= float(active_after)
            row_map[panel_key] = {
                "kind": "cut",
                "item": dict(item),
                "identity": resolved_identity,
                "label": f"{self._get_schedule_boss_display_name(item, prefer_alias=True, include_star=True)}: 컷 완료",
                "action_mode": "cancel" if cancel_ready else "cooldown",
                "action_cut_time_text": str(entry.get("cut_time_text") or "--:--:--"),
                "remaining_seconds": remaining_seconds,
                "needs_retry": not cancel_ready,
                "cut_datetime": cut_datetime,
                "fixed_slot_index": entry.get("panel_slot_index"),
                "_active_index": active_order_map.get(panel_key, 9999),
            }

        for item in self.schedule_events:
            scheduled_at = item.get("scheduled_at")
            created_at = item.get("created_at")
            if not isinstance(scheduled_at, datetime):
                continue
            if not self._is_schedule_event_visible(
                scheduled_at,
                created_at if isinstance(created_at, datetime) else None,
                reference_now,
                cutoff_datetime,
                is_invasion=self._is_schedule_invasion_item(item),
            ):
                continue
            remaining_seconds = (scheduled_at - reference_now).total_seconds()
            if remaining_seconds < 0:
                continue
            panel_key = self._get_schedule_panel_dedupe_key(item)
            if not panel_key or panel_key in row_map:
                continue
            respawn_seconds = int(item.get("respawn_seconds") or self._get_schedule_respawn_seconds_for_boss(str(item.get("boss_name") or "")) or 0)
            if respawn_seconds <= 0 or respawn_seconds < 86400:
                continue
            precision = str(item.get("precision") or "")
            if precision not in {"hour", "day"}:
                continue
            existing = long_candidates.get(panel_key)
            if existing is None or scheduled_at < existing["scheduled_at"]:
                respawn_available = self._get_schedule_item_respawn_seconds(item) > 0
                long_candidates[panel_key] = {
                    "scheduled_at": scheduled_at,
                    "item": dict(item),
                    "remaining_seconds": int(remaining_seconds),
                    "remaining_text": self._format_schedule_long_remaining_text(int(remaining_seconds)),
                    # The active panel is a management view, so long-duration rows
                    # should still expose cut/cut-time as long as the boss can respawn.
                    "action_mode": "cut_pair" if respawn_available else "no_respawn",
                }
        for panel_key, info in sorted(long_candidates.items(), key=lambda pair: pair[1]["scheduled_at"]):
            item = info["item"]
            row_map[panel_key] = {
                "kind": "long",
                "item": dict(item),
                "identity": self._get_schedule_item_identity("event", item),
                "label": f"{self._get_schedule_boss_display_name(item, prefer_alias=True, include_star=True)}: {info['remaining_text']}",
                "action_mode": str(info.get("action_mode") or "cut_pair"),
                "action_cut_time_text": "",
                "remaining_seconds": int(info.get("remaining_seconds") or 0),
                "needs_retry": False,
            }
        occupied_slots: set[int] = set()
        assigned_rows: list[dict[str, object]] = []
        deferred_rows: list[dict[str, object]] = []
        for row_info in row_map.values():
            slot_index = row_info.get("fixed_slot_index")
            if str(row_info.get("kind") or "") == "cut" and isinstance(slot_index, int) and slot_index >= 0 and slot_index not in occupied_slots:
                row_info["slot_index"] = slot_index
                occupied_slots.add(slot_index)
                assigned_rows.append(row_info)
            else:
                deferred_rows.append(row_info)
        next_slot_index = 0
        for row_info in sorted(deferred_rows, key=self._get_schedule_active_panel_sort_key):
            while next_slot_index in occupied_slots:
                next_slot_index += 1
            row_info["slot_index"] = next_slot_index
            occupied_slots.add(next_slot_index)
            assigned_rows.append(row_info)
            next_slot_index += 1
        for row_info in sorted(assigned_rows, key=lambda item: int(item.get("slot_index") or 0)):
            row_info.pop("_active_index", None)
            rows.append(row_info)
        return rows

    def _get_schedule_active_panel_display_row_count(self, item_count: int) -> int:
        if item_count <= 0:
            return 0
        return math.ceil(item_count / 2)

    def _get_schedule_active_panel_cell_position(self, index: int) -> tuple[int, int]:
        return index // 2, index % 2

    def _format_schedule_long_remaining_text(self, total_seconds: int) -> str:
        whole_seconds = max(0, int(total_seconds))
        days, remainder = divmod(whole_seconds, 86400)
        hours, _ = divmod(remainder, 3600)
        if days > 0:
            return f"{days}일 {hours}시간"
        if hours > 0:
            return f"{hours}시간"
        return "1시간 이내"

    def _get_schedule_active_panel_row_palette(self, row_info: dict[str, object]) -> dict[str, str]:
        remaining_seconds = row_info.get("remaining_seconds")
        if isinstance(remaining_seconds, (int, float)):
            if float(remaining_seconds) <= 3600:
                return {
                    "row_bg": "#dcfce7",
                    "label_fg": "#166534",
                    "sub_fg": "#166534",
                }
            if float(remaining_seconds) < 86400:
                return {
                    "row_bg": "#dbeafe",
                    "label_fg": "#1e3a8a",
                    "sub_fg": "#1d4ed8",
                }
        return {
            "row_bg": "#fecaca",
            "label_fg": "#0f172a",
            "sub_fg": "#7f1d1d",
        }

    def _on_schedule_active_rows_mousewheel(self, event) -> str | None:
        if self.schedule_active_rows_canvas is None or not self.schedule_active_rows_canvas.winfo_exists():
            return None
        try:
            delta = int(getattr(event, "delta", 0))
        except (TypeError, ValueError):
            delta = 0
        if delta == 0:
            return "break"
        step = -1 if delta > 0 else 1
        try:
            self.schedule_active_rows_canvas.yview_scroll(step, "units")
        except tk.TclError:
            return None
        return "break"

    def _bind_schedule_active_rows_mousewheel(self, widget: tk.Widget | None) -> None:
        if widget is None:
            return
        try:
            widget.bind("<MouseWheel>", self._on_schedule_active_rows_mousewheel)
        except tk.TclError:
            return

    def _update_schedule_active_rows_scrollregion(self) -> None:
        if (
            self.schedule_active_rows_canvas is None
            or not self.schedule_active_rows_canvas.winfo_exists()
            or self.schedule_active_rows_frame is None
            or not self.schedule_active_rows_frame.winfo_exists()
            or self.schedule_active_rows_window is None
        ):
            return
        try:
            viewport_width = max(24, int(self.schedule_active_rows_canvas.winfo_width()))
            viewport_height = max(24, int(self.schedule_active_rows_canvas.winfo_height()))
        except tk.TclError:
            return
        content_width = 575
        content_height = max(viewport_height, int(self.schedule_active_panel_content_height or 24))
        try:
            self.schedule_active_rows_canvas.itemconfigure(
                self.schedule_active_rows_window,
                width=content_width,
                height=content_height,
            )
            self.schedule_active_rows_canvas.configure(
                scrollregion=(0, 0, content_width, content_height),
                yscrollincrement=14,
            )
            if self.schedule_active_rows_scrollbar is not None and self.schedule_active_rows_scrollbar.winfo_exists():
                if content_height > viewport_height:
                    self.schedule_active_rows_scrollbar.place(
                        x=590,
                        y=10,
                        width=12,
                        height=viewport_height,
                    )
                else:
                    self.schedule_active_rows_canvas.yview_moveto(0.0)
                    self.schedule_active_rows_scrollbar.place_forget()
        except tk.TclError:
            return

    def _layout_schedule_active_panel(self, row_count: int = 0) -> None:
        if self.schedule_active_frame is None or not self.schedule_active_frame.winfo_exists():
            return
        panel_width = 612
        option_width = 328
        option_height = 62
        display_row_count = self._get_schedule_active_panel_display_row_count(row_count)
        panel_height = 36 if display_row_count <= 0 else min(150, 20 + (display_row_count * 26) + ((display_row_count - 1) * 2))
        viewport_height = max(24, panel_height - 20)
        self.schedule_active_panel_content_height = max(24, display_row_count * 26 + max(0, display_row_count - 1) * 2)
        active_y = 138
        option_x = 646
        option_y = active_y + max(0, panel_height - option_height)
        active_bottom = active_y + panel_height
        option_bottom = option_y + option_height
        list_y = max(active_bottom, option_bottom) + 12
        try:
            self.schedule_active_frame.place_configure(x=18, y=active_y, width=panel_width, height=panel_height)
            if self.schedule_option_frame is not None and self.schedule_option_frame.winfo_exists():
                self.schedule_option_frame.place_configure(x=option_x, y=option_y, width=option_width, height=option_height)
            if self.schedule_active_rows_canvas is not None and self.schedule_active_rows_canvas.winfo_exists():
                self.schedule_active_rows_canvas.place_configure(x=10, y=10, width=576, height=viewport_height)
            if self.schedule_active_rows_scrollbar is not None and self.schedule_active_rows_scrollbar.winfo_exists():
                self.schedule_active_rows_scrollbar.place(x=590, y=10, width=12, height=viewport_height)
            self._update_schedule_active_rows_scrollregion()
            if self.schedule_list_frame is not None and self.schedule_list_frame.winfo_exists():
                list_height = max(420, SCHEDULE_WINDOW_HEIGHT - list_y - 18)
                self.schedule_list_frame.place_configure(x=18, y=list_y, width=SCHEDULE_WINDOW_WIDTH - 36, height=list_height)
                tree_y = 88
                footer_y = list_height - 26
                tree_height = max(220, footer_y - tree_y - 8)
                if self.schedule_tree is not None and self.schedule_tree.winfo_exists():
                    self.schedule_tree.place_configure(x=14, y=tree_y, width=SCHEDULE_WINDOW_WIDTH - 82, height=tree_height)
                if self.schedule_tree_scrollbar is not None and self.schedule_tree_scrollbar.winfo_exists():
                    self.schedule_tree_scrollbar.place_configure(x=SCHEDULE_WINDOW_WIDTH - 82, y=tree_y, width=18, height=tree_height)
                if self.schedule_tree_footer_label is not None and self.schedule_tree_footer_label.winfo_exists():
                    self.schedule_tree_footer_label.place_configure(x=14, y=footer_y, width=760, height=18)
        except tk.TclError:
            return

    def _apply_schedule_active_quick_cut_visual_state(
        self,
        identity: tuple[str, str, str, str] | None,
        *,
        cut_time_text: str,
    ) -> None:
        if not isinstance(identity, tuple):
            return
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        target_identity = identity
        target_meta = self.schedule_active_row_meta.get(target_identity)
        if target_meta is None and target_match_key is not None:
            for current_identity, current_meta in self.schedule_active_row_meta.items():
                if self._get_schedule_cut_match_key(identity=current_identity) == target_match_key:
                    target_identity = current_identity
                    target_meta = current_meta
                    break
        if not isinstance(target_meta, dict):
            return
        row = target_meta.get("row")
        label = target_meta.get("label")
        item = target_meta.get("item")
        if (
            not isinstance(row, tk.Widget)
            or not row.winfo_exists()
            or not isinstance(label, tk.Widget)
            or not label.winfo_exists()
            or not isinstance(item, dict)
        ):
            return
        try:
            label.config(text=f"{self._get_schedule_boss_display_name(item, prefer_alias=True, include_star=True)}: 컷 완료")
        except tk.TclError:
            return
        for key in ("cut_widget", "cut_time_widget", "status_widget"):
            widget = target_meta.get(key)
            if isinstance(widget, tk.Widget):
                try:
                    widget.destroy()
                except tk.TclError:
                    pass
            target_meta[key] = None
        try:
            current_meta = self.schedule_active_row_meta.get(target_identity)
            if not isinstance(current_meta, dict):
                return
            current_row = current_meta.get("row")
            row_bg = str(current_meta.get("row_bg") or "#fecaca")
            label_fg = str(current_meta.get("label_fg") or "#0f172a")
            if not isinstance(current_row, tk.Widget) or not current_row.winfo_exists():
                return
            undo_button = tk.Button(
                current_row,
                text="취소",
                font=self.percent_font,
                bg="#dc2626",
                fg="#ffffff",
                activebackground="#b91c1c",
                activeforeground="#ffffff",
                relief="raised",
                bd=1,
                highlightthickness=0,
                command=lambda current_identity=target_identity: self._undo_schedule_active_quick_cut(current_identity),
                cursor="hand2",
            )
            undo_button.place(x=154, y=1, width=44, height=22)
            self._bind_schedule_active_rows_mousewheel(undo_button)
            time_label = tk.Label(
                current_row,
                text=cut_time_text,
                font=self.percent_font,
                bg=row_bg,
                fg=label_fg,
                anchor="center",
            )
            time_label.place(x=202, y=1, width=58, height=24)
            self._bind_schedule_active_rows_mousewheel(time_label)
            current_meta["cut_widget"] = undo_button
            current_meta["cut_time_widget"] = time_label
        except tk.TclError:
            return

    def _restore_schedule_active_quick_cut_visual_state(
        self,
        identity: tuple[str, str, str, str] | None,
    ) -> None:
        if not isinstance(identity, tuple):
            return
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        target_identity = identity
        target_meta = self.schedule_active_row_meta.get(target_identity)
        if target_meta is None and target_match_key is not None:
            for current_identity, current_meta in self.schedule_active_row_meta.items():
                if self._get_schedule_cut_match_key(identity=current_identity) == target_match_key:
                    target_identity = current_identity
                    target_meta = current_meta
                    break
        if not isinstance(target_meta, dict):
            return
        row = target_meta.get("row")
        label = target_meta.get("label")
        item = target_meta.get("item")
        if (
            not isinstance(row, tk.Widget)
            or not row.winfo_exists()
            or not isinstance(label, tk.Widget)
            or not label.winfo_exists()
            or not isinstance(item, dict)
        ):
            return
        try:
            label.config(text=str(target_meta.get("base_label") or ""))
        except tk.TclError:
            return
        for key in ("cut_widget", "cut_time_widget", "status_widget"):
            widget = target_meta.get(key)
            if isinstance(widget, tk.Widget):
                try:
                    widget.destroy()
                except tk.TclError:
                    pass
            target_meta[key] = None
        if self._get_schedule_item_respawn_seconds(item) <= 0:
            row_bg = str(target_meta.get("row_bg") or "#fecaca")
            sub_fg = str(target_meta.get("sub_fg") or "#7f1d1d")
            status_widget = tk.Label(
                row,
                text="젠시간 없음",
                font=self.percent_font,
                bg=row_bg,
                fg=sub_fg,
                anchor="center",
            )
            status_widget.place(x=154, y=1, width=88, height=24)
            self._bind_schedule_active_rows_mousewheel(status_widget)
            target_meta["status_widget"] = status_widget
            return
        if not self._can_schedule_active_entry_accept_cut(item, self._get_schedule_reference_datetime()):
            return
        try:
            current_meta = self.schedule_active_row_meta.get(target_identity)
            if not isinstance(current_meta, dict):
                return
            current_row = current_meta.get("row")
            current_item = current_meta.get("item")
            if (
                not isinstance(current_row, tk.Widget)
                or not current_row.winfo_exists()
                or not isinstance(current_item, dict)
            ):
                return
            cut_button = tk.Button(
                current_row,
                text="컷",
                font=self.percent_font,
                bg="#0f766e",
                fg="#ffffff",
                activebackground="#115e59",
                activeforeground="#ffffff",
                relief="raised",
                bd=1,
                highlightthickness=0,
                command=lambda current_item=dict(current_item), current_identity=target_identity: self._apply_schedule_active_quick_cut(
                    current_item,
                    current_identity,
                ),
                cursor="hand2",
            )
            cut_button.place(x=154, y=1, width=44, height=22)
            self._bind_schedule_active_rows_mousewheel(cut_button)
            boss_text = self._get_schedule_boss_display_name(current_item, prefer_alias=True)
            cut_time_button = tk.Button(
                current_row,
                text="컷시간",
                font=self.percent_font,
                bg="#f8f1df",
                fg="#7c2d12",
                activebackground="#efe2c5",
                activeforeground="#7c2d12",
                relief="raised",
                bd=1,
                highlightthickness=0,
                command=lambda current_item=dict(current_item), current_boss_text=boss_text, current_identity=target_identity: self._on_schedule_active_cut_time(
                    current_item,
                    current_boss_text,
                    current_identity,
                ),
                cursor="hand2",
            )
            cut_time_button.place(x=202, y=1, width=72, height=22)
            self._bind_schedule_active_rows_mousewheel(cut_time_button)
            current_meta["cut_widget"] = cut_button
            current_meta["cut_time_widget"] = cut_time_button
        except tk.TclError:
            return

    def _refresh_schedule_active_rows(self) -> None:
        self.schedule_active_overlay_retry_job = None
        if self.schedule_active_rows_frame is None or not self.schedule_active_rows_frame.winfo_exists():
            return
        self.schedule_active_row_meta = {}
        for child in self.schedule_active_rows_frame.winfo_children():
            child.destroy()
        reference_now = self._get_schedule_reference_datetime()
        panel_rows = self._get_schedule_active_panel_rows(reference_now)
        self._layout_schedule_active_panel(len(panel_rows))
        retry_required = False
        if not panel_rows:
            self.schedule_active_panel_content_height = 24
            tk.Label(
                self.schedule_active_rows_frame,
                text="표시할 데이터가 없습니다.",
                font=(self.current_font_family, 9),
                bg="#fee2e2",
                fg="#7f1d1d",
                anchor="w",
                justify="left",
                padx=4,
            ).place(x=0, y=0, width=575, height=20)
            self._update_schedule_active_rows_scrollregion()
            return

        row_height = 26
        left_x = 0
        right_x = 289
        row_width = 286
        max_slot_index = max(
            (int(row_info.get("slot_index")) for row_info in panel_rows if isinstance(row_info.get("slot_index"), int)),
            default=len(panel_rows) - 1,
        )
        total_slot_count = max(len(panel_rows), max_slot_index + 1)
        total_row_count = self._get_schedule_active_panel_display_row_count(total_slot_count)
        self.schedule_active_panel_content_height = max(24, total_row_count * row_height + max(0, total_row_count - 1) * 2)
        label_width = 148
        button_x = 154
        cut_button_width = 44
        cut_time_x = button_x + 48
        cut_time_width = 72
        for index, row_info in enumerate(panel_rows):
            slot_index = int(row_info.get("slot_index")) if isinstance(row_info.get("slot_index"), int) else index
            row_index, column_index = self._get_schedule_active_panel_cell_position(slot_index)
            row_y = row_index * (row_height + 2)
            row_x = left_x if column_index == 0 else right_x
            palette = self._get_schedule_active_panel_row_palette(row_info)
            row_bg = palette["row_bg"]
            label_fg = palette["label_fg"]
            sub_fg = palette["sub_fg"]
            row = tk.Frame(self.schedule_active_rows_frame, bg=row_bg, bd=0, relief="flat", highlightthickness=0)
            row.place(x=row_x, y=row_y, width=row_width, height=row_height)
            self._bind_schedule_active_rows_mousewheel(row)
            item = row_info["item"]
            identity = row_info.get("identity")
            action_mode = str(row_info.get("action_mode") or "")
            if bool(row_info.get("needs_retry")):
                retry_required = True

            label_widget = tk.Label(
                row,
                text=str(row_info.get("label") or ""),
                font=(self.current_font_family, 9),
                bg=row_bg,
                fg=label_fg,
                anchor="w",
            )
            label_widget.place(x=2, y=1, width=label_width, height=row_height - 2)
            self._bind_schedule_active_rows_mousewheel(label_widget)
            if isinstance(identity, tuple):
                self.schedule_active_row_meta[identity] = {
                    "row": row,
                    "label": label_widget,
                    "base_label": str(row_info.get("label") or ""),
                    "item": dict(item),
                    "kind": str(row_info.get("kind") or ""),
                    "action_mode": action_mode,
                    "row_bg": row_bg,
                    "label_fg": label_fg,
                    "sub_fg": sub_fg,
                    "slot_index": slot_index,
                    "cut_widget": None,
                    "cut_time_widget": None,
                    "status_widget": None,
                }

            if action_mode == "cooldown":
                continue
            if action_mode == "no_respawn":
                status_widget = tk.Label(
                    row,
                    text="젠시간 없음",
                    font=self.percent_font,
                    bg=row_bg,
                    fg=sub_fg,
                    anchor="center",
                )
                status_widget.place(x=button_x, y=1, width=88, height=row_height - 2)
                self._bind_schedule_active_rows_mousewheel(status_widget)
                if isinstance(identity, tuple):
                    self.schedule_active_row_meta[identity]["status_widget"] = status_widget
                continue
            if action_mode == "cancel":
                undo_button = tk.Button(
                    row,
                    text="취소",
                    font=self.percent_font,
                    bg="#dc2626",
                    fg="#ffffff",
                    activebackground="#b91c1c",
                    activeforeground="#ffffff",
                    relief="raised",
                    bd=1,
                    highlightthickness=0,
                    command=lambda current_identity=identity: self._undo_schedule_active_quick_cut(current_identity if isinstance(current_identity, tuple) else None),
                    cursor="hand2",
                )
                undo_button.place(x=button_x, y=1, width=44, height=22)
                self._bind_schedule_active_rows_mousewheel(undo_button)
                time_label = tk.Label(
                    row,
                    text=str(row_info.get("action_cut_time_text") or "--:--:--"),
                    font=self.percent_font,
                    bg=row_bg,
                    fg=label_fg,
                    anchor="center",
                )
                time_label.place(x=button_x + 48, y=1, width=58, height=row_height - 2)
                self._bind_schedule_active_rows_mousewheel(time_label)
                if isinstance(identity, tuple):
                    self.schedule_active_row_meta[identity]["cut_widget"] = undo_button
                    self.schedule_active_row_meta[identity]["cut_time_widget"] = time_label
                continue
            if action_mode != "cut_pair":
                continue

            display_name = self._get_schedule_boss_display_name(item, prefer_alias=True)
            cut_button = tk.Button(
                row,
                text="컷",
                font=self.percent_font,
                bg="#0f766e",
                fg="#ffffff",
                activebackground="#115e59",
                activeforeground="#ffffff",
                relief="raised",
                bd=1,
                highlightthickness=0,
                command=lambda current_item=dict(item), current_identity=identity, row_kind=str(row_info.get("kind") or ""): self._apply_schedule_active_quick_cut(
                    current_item,
                    current_identity if isinstance(current_identity, tuple) else None,
                ) if row_kind in {"active", "long"} else None,
                cursor="hand2",
            )
            cut_button.place(x=button_x, y=1, width=cut_button_width, height=22)
            self._bind_schedule_active_rows_mousewheel(cut_button)
            cut_time_button = tk.Button(
                row,
                text="컷시간",
                font=self.percent_font,
                bg="#f8f1df",
                fg="#7c2d12",
                activebackground="#efe2c5",
                activeforeground="#7c2d12",
                relief="raised",
                bd=1,
                highlightthickness=0,
                command=lambda current_item=dict(item), boss_text=display_name, current_identity=identity: self._on_schedule_active_cut_time(
                    current_item,
                    boss_text,
                    current_identity if isinstance(current_identity, tuple) else None,
                ),
                cursor="hand2",
            )
            cut_time_button.place(x=cut_time_x, y=1, width=cut_time_width, height=22)
            self._bind_schedule_active_rows_mousewheel(cut_time_button)
            if isinstance(identity, tuple):
                self.schedule_active_row_meta[identity]["cut_widget"] = cut_button
                self.schedule_active_row_meta[identity]["cut_time_widget"] = cut_time_button
        self._update_schedule_active_rows_scrollregion()
        if retry_required:
            self._schedule_active_rows_after_delay(120)

    def _scroll_schedule_tree_to_focus_next_event(self) -> None:
        if self.schedule_tree is None:
            return
        try:
            item_ids = list(self.schedule_tree.get_children(""))
            if not item_ids:
                return
            target_index = 0
            for index, item_id in enumerate(item_ids):
                tags = set(self.schedule_tree.item(item_id, "tags"))
                if "date_header" in tags:
                    continue
                item_meta = self.schedule_tree_item_meta.get(item_id, {})
                if str(item_meta.get("kind") or "") == "break":
                    continue
                values = self.schedule_tree.item(item_id, "values")
                state_text = str(values[2]) if len(values) >= 3 else ""
                boss_text = str(values[1]) if len(values) >= 2 else ""
                if boss_text == "정기점검":
                    continue
                if state_text != "경과":
                    candidate_index = max(0, index - 1)
                    while candidate_index > 0:
                        candidate_tags = set(self.schedule_tree.item(item_ids[candidate_index], "tags"))
                        if "date_header" in candidate_tags:
                            break
                        candidate_values = self.schedule_tree.item(item_ids[candidate_index], "values")
                        candidate_state = str(candidate_values[2]) if len(candidate_values) >= 3 else ""
                        if candidate_state == "경과":
                            target_index = candidate_index
                        else:
                            target_index = index
                        break
                    else:
                        target_index = candidate_index
                    if index > 0:
                        previous_tags = set(self.schedule_tree.item(item_ids[index - 1], "tags"))
                        if "date_header" in previous_tags:
                            target_index = index - 1
                        else:
                            previous_values = self.schedule_tree.item(item_ids[index - 1], "values")
                            previous_state = str(previous_values[2]) if len(previous_values) >= 3 else ""
                            target_index = index - 1 if previous_state == "경과" else index
                    else:
                        target_index = index
                    break
            else:
                target_index = 0
            fraction = 0.0 if len(item_ids) <= 1 else target_index / max(1, len(item_ids) - 1)
            self.schedule_tree.yview_moveto(fraction)
        except tk.TclError:
            return

    def _refresh_schedule_view_live(self) -> None:
        if self.schedule_tree is None:
            self._refresh_schedule_view()
            return
        try:
            yview = self.schedule_tree.yview()
            selected_targets: list[tuple[tuple[str, str, str, str], tuple[str, str, str] | None]] = []
            for item_id in self.schedule_tree.selection():
                meta = self.schedule_tree_item_meta.get(item_id, {})
                identity = meta.get("identity")
                if isinstance(identity, tuple):
                    selected_targets.append((identity, self._get_schedule_cut_match_key(identity=identity)))
        except tk.TclError:
            yview = (0.0, 1.0)
            selected_targets = []
        self._refresh_schedule_view()
        if self.schedule_tree is None:
            return
        try:
            if selected_targets:
                selected_identities = {
                    identity
                    for identity, _match_key in selected_targets
                }
                selected_match_keys = {
                    match_key
                    for _identity, match_key in selected_targets
                    if isinstance(match_key, tuple)
                }
                selected_ids: list[str] = []
                for item_id, meta in self.schedule_tree_item_meta.items():
                    identity = meta.get("identity")
                    if isinstance(identity, tuple) and identity in selected_identities:
                        selected_ids.append(item_id)
                        continue
                    match_key = self._get_schedule_cut_match_key(identity=identity if isinstance(identity, tuple) else None)
                    if match_key is not None and match_key in selected_match_keys:
                        selected_ids.append(item_id)
                if selected_ids:
                    self.schedule_tree.selection_set(selected_ids)
                    self.schedule_tree.focus(selected_ids[0])
                    self.schedule_tree.see(selected_ids[0])
                    self._update_schedule_tree_action_buttons()
                    self.schedule_tree_overlay_signature = None
                    self.schedule_tree_elapsed_overlay_signature = None
            if yview:
                self.schedule_tree.yview_moveto(float(yview[0]))
            self._schedule_tree_overlay_after_idle()
        except (tk.TclError, ValueError, TypeError):
            return

    def _compute_schedule_tree_next_refresh_datetime(self, reference_now: datetime) -> datetime | None:
        view_datetime = self._get_schedule_view_datetime()
        if view_datetime is None:
            return None
        window_start = view_datetime.replace(hour=0, minute=0, second=0, microsecond=0)
        window_end = window_start + timedelta(days=2)
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        candidate_times: list[datetime] = []
        for item in self.schedule_events:
            scheduled_at = item.get("scheduled_at")
            created_at = item.get("created_at")
            if not isinstance(scheduled_at, datetime):
                continue
            if scheduled_at <= reference_now or scheduled_at < window_start or scheduled_at >= window_end:
                continue
            if not self._is_schedule_event_visible(
                scheduled_at,
                created_at if isinstance(created_at, datetime) else None,
                reference_now,
                cutoff_datetime,
                is_invasion=self._is_schedule_invasion_item(item),
            ):
                continue
            candidate_times.append(scheduled_at)
        for scheduled_at, *_rest in self._get_fixed_boss_schedule_rows():
            if reference_now < scheduled_at < window_end:
                candidate_times.append(scheduled_at)
        for item in self.schedule_control_events:
            scheduled_at = item.get("scheduled_at")
            if isinstance(scheduled_at, datetime) and reference_now < scheduled_at < window_end:
                candidate_times.append(scheduled_at)
        next_maintenance_datetime = self._get_schedule_maintenance_cutoff_datetime(reference_now)
        if next_maintenance_datetime is not None and reference_now < next_maintenance_datetime < window_end:
            candidate_times.append(next_maintenance_datetime)
        for entry in self.schedule_tree_quick_cut_history:
            cut_datetime = entry.get("cut_datetime")
            if not isinstance(cut_datetime, datetime):
                continue
            expiry_datetime = (cut_datetime + timedelta(seconds=SCHEDULE_TREE_QUICK_CUT_RETENTION_SECONDS)).replace(microsecond=0)
            if expiry_datetime > reference_now:
                candidate_times.append(expiry_datetime)
        for entry in self.schedule_active_quick_cut_history:
            cut_datetime = entry.get("cut_datetime")
            if not isinstance(cut_datetime, datetime):
                continue
            action_at = self._get_schedule_quick_cut_action_at(entry)
            if not isinstance(action_at, datetime):
                action_at = cut_datetime
            expiry_datetime = (action_at + timedelta(seconds=SCHEDULE_ACTIVE_QUICK_CUT_PANEL_RETENTION_SECONDS)).replace(microsecond=0)
            if expiry_datetime > reference_now:
                candidate_times.append(expiry_datetime)
        if not candidate_times:
            return None
        return min(candidate_times).replace(microsecond=0)

    def _apply_selected_schedule_tree_cut(self) -> None:
        target = self._get_selected_schedule_tree_cut_target()
        if not isinstance(target, dict):
            return
        if str(target.get("mode") or "") == "cancel":
            self._cancel_schedule_tree_cut_state(
                dict(target.get("item") or {}),
                target.get("identity") if isinstance(target.get("identity"), tuple) else None,
            )
            return
        if str(target.get("mode") or "") != "cut_pair":
            return
        self._apply_schedule_tree_quick_cut(
            dict(target.get("item") or {}),
            target.get("identity") if isinstance(target.get("identity"), tuple) else None,
        )

    def _apply_selected_schedule_tree_cut_time(self) -> None:
        target = self._get_selected_schedule_tree_cut_target()
        if not isinstance(target, dict):
            return
        if str(target.get("mode") or "") not in {"cut_pair", "cancel", "cut_time_only"}:
            return
        self._apply_schedule_tree_cut_time(
            dict(target.get("item") or {}),
            target.get("identity") if isinstance(target.get("identity"), tuple) else None,
        )

