    def _get_schedule_share_area_name(self, item: dict[str, object] | None) -> str:
        if not isinstance(item, dict):
            return ""
        boss_name = str(item.get("boss_name") or "").strip()
        if not boss_name:
            normalized = self._normalize_schedule_input_boss_name(str(item.get("display_name") or ""))
            boss_name = str(normalized.get("boss_name") or "").strip()
        definition = self.schedule_boss_definitions.get(boss_name, {})
        return str(definition.get("area") or "").strip()

    def _get_schedule_share_event_colors(self, item: dict[str, object]) -> tuple[str, str]:
        if self._is_schedule_invasion_item(item):
            return self._get_schedule_invasion_effective_colors()
        boss_name = self._get_schedule_boss_definition_name(item)
        definition = self.schedule_boss_definitions.get(boss_name, {})
        area_name = str(definition.get("area") or RECORD_BOOK_AREAS[0]).strip()
        area_item = self.schedule_area_definitions.get(self._get_schedule_area_color_group_key(area_name, absolute=bool(definition.get("absolute", False))), {})
        area_text_color = self._normalize_hex_color(str(area_item.get("text_color") or DEFAULT_SCHEDULE_TEXT_COLOR), DEFAULT_SCHEDULE_TEXT_COLOR)
        area_bg_color = self._normalize_hex_color(str(area_item.get("bg_color") or DEFAULT_SCHEDULE_BG_COLOR), DEFAULT_SCHEDULE_BG_COLOR)
        text_color = self._normalize_optional_hex_color(str(definition.get("text_color") or "")) or area_text_color
        bg_color = self._normalize_optional_hex_color(str(definition.get("bg_color") or "")) or area_bg_color
        return (
            self._normalize_hex_color(text_color, DEFAULT_SCHEDULE_TEXT_COLOR),
            self._normalize_hex_color(bg_color, DEFAULT_SCHEDULE_BG_COLOR),
        )

    def _schedule_share_item_has_star(self, item: dict[str, object] | None) -> bool:
        return self._schedule_boss_has_star(item)

    def _collect_schedule_share_rows(
        self,
        start_datetime: datetime,
        end_datetime: datetime,
        *,
        use_boss_colors: bool = False,
        use_fixed_boss_colors: bool = False,
        include_break_rows: bool = False,
        exclude_elapsed: bool = False,
    ) -> tuple[list[dict[str, object]], datetime, datetime]:
        reference_now = self._get_schedule_reference_datetime().replace(microsecond=0)
        share_start = start_datetime.replace(microsecond=0)
        share_end = end_datetime.replace(microsecond=0)
        future_cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        rows: list[dict[str, object]] = []
        for item in self.schedule_events:
            if not isinstance(item, dict):
                continue
            scheduled_at = item.get("scheduled_at")
            created_at = item.get("created_at")
            if not isinstance(scheduled_at, datetime):
                continue
            if scheduled_at < share_start or scheduled_at > share_end:
                continue
            if exclude_elapsed and scheduled_at < reference_now:
                continue
            if not self._is_schedule_event_visible(
                scheduled_at,
                created_at if isinstance(created_at, datetime) else None,
                reference_now,
                future_cutoff_datetime,
                is_invasion=self._is_schedule_invasion_item(item),
            ):
                continue
            rows.append(
                {
                    "kind": "event",
                    "scheduled_at": scheduled_at.replace(microsecond=0),
                    "effective_end_at": self._get_schedule_item_effective_end_datetime(item),
                    "time_text": scheduled_at.strftime("%H:%M:%S"),
                    "boss_text": self._get_schedule_boss_display_name(item, prefer_alias=True),
                    "state_text": "경과" if scheduled_at < reference_now else "예정",
                    "is_elapsed": bool(scheduled_at < reference_now),
                    "is_invasion": self._is_schedule_invasion_item(item),
                    "is_fixed": False,
                    "has_star": self._schedule_share_item_has_star(item),
                    "text_color": self._get_schedule_share_event_colors(item)[0] if use_boss_colors else "",
                    "bg_color": self._get_schedule_share_event_colors(item)[1] if use_boss_colors else "",
                }
            )
        for scheduled_at, boss_text, state_text, *_rest, text_color, bg_color in self._get_fixed_boss_schedule_rows_for_share_range(reference_now, share_start, share_end):
            if scheduled_at < share_start or scheduled_at > share_end:
                continue
            if exclude_elapsed and scheduled_at < reference_now:
                continue
            raw_boss_text = re.sub(r"\s*★\s*$", "", str(boss_text or "")).strip()
            rows.append(
                {
                    "kind": "event",
                    "scheduled_at": scheduled_at.replace(microsecond=0),
                    "effective_end_at": scheduled_at.replace(microsecond=0),
                    "time_text": scheduled_at.strftime("%H:%M:%S"),
                    "boss_text": raw_boss_text,
                    "state_text": state_text,
                    "is_elapsed": bool(scheduled_at < reference_now),
                    "is_invasion": False,
                    "is_fixed": True,
                    "has_star": self._schedule_boss_has_star(raw_boss_text),
                    "text_color": self._normalize_hex_color(str(text_color or DEFAULT_FIXED_BOSS_TEXT_COLOR), DEFAULT_FIXED_BOSS_TEXT_COLOR) if use_fixed_boss_colors else "",
                    "bg_color": self._normalize_hex_color(str(bg_color or DEFAULT_FIXED_BOSS_BG_COLOR), DEFAULT_FIXED_BOSS_BG_COLOR) if use_fixed_boss_colors else "",
                }
            )
        if include_break_rows:
            try:
                rows = self._insert_schedule_break_rows_into_share_rows(rows)
            except Exception:
                try:
                    log_path = os.path.join(get_app_root(), "boss_timer_runtime_error.log")
                    with open(log_path, "a", encoding="utf-8") as error_file:
                        error_file.write(f"\n[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}]\n")
                        error_file.write("schedule share break row insert failed\n")
                        error_file.write(traceback.format_exc())
                except OSError:
                    pass
        rows.sort(key=self._get_schedule_share_row_sort_key)
        grouped_rows: list[dict[str, object]] = []
        today_date = reference_now.date()
        next_day_date = (today_date + timedelta(days=1))
        current_date = None
        for entry in rows:
            scheduled_at = entry.get("scheduled_at")
            if not isinstance(scheduled_at, datetime):
                continue
            row_date = scheduled_at.date()
            if row_date != current_date:
                label_prefix = "오늘" if row_date == today_date else "다음날" if row_date == next_day_date else "날짜"
                grouped_rows.append(
                    {
                        "kind": "date_header",
                        "date_text": f"{label_prefix}  {scheduled_at.strftime('%Y-%m-%d')} ({self._get_weekday_label(scheduled_at)})",
                    }
                )
                current_date = row_date
            grouped_rows.append(entry)
        return grouped_rows, share_start, share_end

    def _copy_schedule_share_image_to_clipboard(self) -> None:
        try:
            selected_range = self._show_schedule_share_period_dialog()
            if not isinstance(selected_range, dict):
                return
            start_datetime = selected_range.get("start_datetime")
            end_datetime = selected_range.get("end_datetime")
            if not isinstance(start_datetime, datetime) or not isinstance(end_datetime, datetime):
                return
            rows, reference_now, share_end = self._collect_schedule_share_rows(
                start_datetime,
                end_datetime,
                use_boss_colors=bool(selected_range.get("use_boss_colors")),
                use_fixed_boss_colors=bool(selected_range.get("use_fixed_boss_colors")),
                include_break_rows=bool(selected_range.get("include_break_rows")),
                exclude_elapsed=bool(selected_range.get("exclude_elapsed", False)),
            )
            if not rows:
                self.schedule_status_var.set("공유할 예정 스케쥴이 없습니다.")
                return
            payload = {
                "title": "보스 스케쥴",
                "subtitle": f"기준 {reference_now.strftime('%Y-%m-%d %H:%M:%S')} ~ {share_end.strftime('%Y-%m-%d %H:%M:%S')}",
                "default_font_size": min(24, max(8, self._parse_int(str(selected_range.get("font_size") or "9"), 9))),
                "default_bold": bool(selected_range.get("bold")),
                "strike_elapsed": bool(selected_range.get("strike_elapsed")),
                "rows": [
                    {
                        "kind": str(entry.get("kind") or "event"),
                        "date_text": str(entry.get("date_text") or ""),
                        "time": str(entry.get("time_text") or ""),
                        "boss": str(entry.get("boss_text") or ""),
                        "state": str(entry.get("state_text") or ""),
                        "break_display_text": str(entry.get("break_display_text") or ""),
                        "is_elapsed": bool(entry.get("is_elapsed")),
                        "is_invasion": bool(entry.get("is_invasion")),
                        "is_fixed": bool(entry.get("is_fixed")),
                        "has_star": bool(entry.get("has_star")),
                        "text_color": str(entry.get("text_color") or ""),
                        "bg_color": str(entry.get("bg_color") or ""),
                        "row_scale": float(entry.get("row_scale") or 1.0),
                        "font_size": int(entry.get("font_size") or 0),
                        "bold": bool(entry.get("bold", False)),
                    }
                    for entry in rows
                ],
            }
            fd, payload_path = tempfile.mkstemp(prefix="schedule_share_", suffix=".json")
            try:
                with os.fdopen(fd, "w", encoding="utf-8-sig") as payload_file:
                    json.dump(payload, payload_file, ensure_ascii=False)
                script = (
                    "[Console]::OutputEncoding = [System.Text.Encoding]::UTF8\n"
                    "$ErrorActionPreference = 'Stop'\n"
                    "try {\n"
                    "  Add-Type -AssemblyName System.Drawing -ErrorAction Stop\n"
                    "  Add-Type -AssemblyName PresentationCore -ErrorAction Stop\n"
                    "  Add-Type -AssemblyName PresentationFramework -ErrorAction Stop\n"
                    f"  $payloadPath = '{self._quote_powershell_literal(payload_path)}'\n"
                    "  $payload = Get-Content -Raw -Encoding UTF8 -Path $payloadPath | ConvertFrom-Json\n"
                    "  $rows = @($payload.rows)\n"
                    "  $width = 520\n"
                    "  $headerHeight = 72\n"
                    "  $defaultFontSize = [Math]::Max(8, [int]$payload.default_font_size)\n"
                    "  $defaultBodyBold = [bool]$payload.default_bold\n"
                    "  $strikeElapsed = [bool]$payload.strike_elapsed\n"
                    "  $headerFontSize = [Math]::Max(10, $defaultFontSize + 2)\n"
                    "  $tableHeaderHeight = [Math]::Max(34, $headerFontSize + 20)\n"
                    "  $dateHeaderHeight = [Math]::Max(34, $defaultFontSize + 18)\n"
                    "  $eventRowHeight = [Math]::Max(36, $defaultFontSize + 24)\n"
                    "  $tableHeight = 0\n"
                    "  if ($rows.Count -eq 0) { $tableHeight = $eventRowHeight } else { foreach ($row in $rows) { if ([string]$row.kind -eq 'date_header') { $tableHeight += $dateHeaderHeight } else { $rowScale = if ([string]$row.kind -eq 'break') { [double]$row.row_scale } else { 1.0 }; if ($rowScale -le 0) { $rowScale = 1.0 }; $rowHeight = [Math]::Max($eventRowHeight, [int][Math]::Round($eventRowHeight * $rowScale)); $tableHeight += $rowHeight } } }\n"
                    "  $height = $headerHeight + $tableHeaderHeight + $tableHeight + 18\n"
                    "  $bmp = New-Object System.Drawing.Bitmap $width, $height\n"
                    "  $clipboardImagePath = [System.IO.Path]::ChangeExtension($payloadPath, '.png')\n"
                    "  $g = [System.Drawing.Graphics]::FromImage($bmp)\n"
                    "  $g.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::HighQuality\n"
                    "  $g.TextRenderingHint = [System.Drawing.Text.TextRenderingHint]::ClearTypeGridFit\n"
                    "  $g.Clear([System.Drawing.Color]::FromArgb(248,250,252))\n"
                    "  $titleFont = New-Object System.Drawing.Font('Malgun Gothic', 14, [System.Drawing.FontStyle]::Bold)\n"
                    "  $subFont = New-Object System.Drawing.Font('Malgun Gothic', 8)\n"
                    "  $headerFontStyle = if ($defaultBodyBold) { [System.Drawing.FontStyle]::Bold } else { [System.Drawing.FontStyle]::Regular }\n"
                    "  $headFont = New-Object System.Drawing.Font('Malgun Gothic', $headerFontSize, $headerFontStyle)\n"
                    "  $bodyFontStyle = if ($defaultBodyBold) { [System.Drawing.FontStyle]::Bold } else { [System.Drawing.FontStyle]::Regular }\n"
                    "  $bodyFont = New-Object System.Drawing.Font('Malgun Gothic', $defaultFontSize, $bodyFontStyle)\n"
                    "  $bodyStrikeStyle = $bodyFontStyle\n"
                    "  if ($strikeElapsed) { $bodyStrikeStyle = $bodyFontStyle -bor [System.Drawing.FontStyle]::Strikeout }\n"
                    "  $bodyStrikeFont = New-Object System.Drawing.Font('Malgun Gothic', $defaultFontSize, $bodyStrikeStyle)\n"
                    "  $starFont = New-Object System.Drawing.Font('Malgun Gothic', 10, [System.Drawing.FontStyle]::Bold)\n"
                    "  $dateFont = New-Object System.Drawing.Font('Malgun Gothic', [Math]::Max(9, $defaultFontSize), [System.Drawing.FontStyle]::Bold)\n"
                    "  $centerFormat = New-Object System.Drawing.StringFormat\n"
                    "  $centerFormat.Alignment = [System.Drawing.StringAlignment]::Center\n"
                    "  $centerFormat.LineAlignment = [System.Drawing.StringAlignment]::Center\n"
                    "  $headerBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(219,234,254))\n"
                    "  $tableHeaderBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(239,246,255))\n"
                    "  $dateHeaderBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(191,219,254))\n"
                    "  $eventBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(248,241,223))\n"
                    "  $invasionBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(254,226,226))\n"
                    "  $fixedBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(224,242,254))\n"
                    "  $textBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(15,23,42))\n"
                    "  $subBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(71,85,105))\n"
                    "  $dateTextBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(30,58,138))\n"
                    "  $starBrush = New-Object System.Drawing.SolidBrush([System.Drawing.Color]::FromArgb(217,119,6))\n"
                    "  $linePen = New-Object System.Drawing.Pen([System.Drawing.Color]::FromArgb(203,213,225))\n"
                    "  $dateLinePen = New-Object System.Drawing.Pen([System.Drawing.Color]::FromArgb(147,197,253))\n"
                    "  $g.FillRectangle($headerBrush, 0, 0, $width, $headerHeight)\n"
                    "  $g.DrawString([string]$payload.title, $titleFont, $textBrush, 16, 12)\n"
                    "  $g.DrawString([string]$payload.subtitle, $subFont, $subBrush, 16, 42)\n"
                    "  $g.FillRectangle($tableHeaderBrush, 0, $headerHeight, $width, $tableHeaderHeight)\n"
                    "  $g.DrawRectangle($linePen, 0, $headerHeight, $width - 1, $tableHeaderHeight + $tableHeight)\n"
                    "  $timeX = 28\n"
                    "  $starX = 144\n"
                    "  $bossX = 164\n"
                    "  $stateX = 404\n"
                    "  $headerTextY = $headerHeight + [Math]::Max(6, [int][Math]::Floor(($tableHeaderHeight - $headFont.GetHeight($g)) / 2))\n"
                    "  $g.DrawString('예정시각', $headFont, $textBrush, $timeX, $headerTextY)\n"
                    "  $g.DrawString('보스명', $headFont, $textBrush, $bossX, $headerTextY)\n"
                    "  $g.DrawString('상태', $headFont, $textBrush, $stateX, $headerTextY)\n"
                    "  $rowY = $headerHeight + $tableHeaderHeight\n"
                    "  if ($rows.Count -eq 0) {\n"
                    "    $g.FillRectangle($eventBrush, 0, $rowY, $width, $eventRowHeight)\n"
                    "    $g.DrawString('표시할 일정 없음', $bodyFont, $subBrush, $timeX, $rowY + 6)\n"
                    "    $g.DrawLine($linePen, 0, $rowY + $eventRowHeight, $width, $rowY + $eventRowHeight)\n"
                    "  } else {\n"
                    "    foreach ($row in $rows) {\n"
                    "      $kind = [string]$row.kind\n"
                    "      if ($kind -eq 'date_header') {\n"
                    "        $g.FillRectangle($dateHeaderBrush, 0, $rowY, $width, $dateHeaderHeight)\n"
                    "        $g.DrawString([string]$row.date_text, $dateFont, $dateTextBrush, 24, $rowY + 6)\n"
                    "        $g.DrawLine($dateLinePen, 0, $rowY, $width, $rowY)\n"
                    "        $g.DrawLine($dateLinePen, 0, $rowY + $dateHeaderHeight, $width, $rowY + $dateHeaderHeight)\n"
                    "        $rowY += $dateHeaderHeight\n"
                    "        continue\n"
                    "      }\n"
                    "      $rowBgColor = $null\n"
                    "      $rowTextColor = $null\n"
                    "      if ([string]$row.bg_color) { try { $rowBgColor = [System.Drawing.ColorTranslator]::FromHtml([string]$row.bg_color) } catch { $rowBgColor = $null } }\n"
                    "      if ([string]$row.text_color) { try { $rowTextColor = [System.Drawing.ColorTranslator]::FromHtml([string]$row.text_color) } catch { $rowTextColor = $null } }\n"
                    "      if ($null -eq $rowBgColor) {\n"
                    "        if ([bool]$row.is_fixed) { $rowBgColor = $fixedBrush.Color }\n"
                    "        elseif ([bool]$row.is_invasion) { $rowBgColor = $invasionBrush.Color }\n"
                    "        else { $rowBgColor = $eventBrush.Color }\n"
                    "      }\n"
                    "      if ($null -eq $rowTextColor) { $rowTextColor = $textBrush.Color }\n"
                    "      $rowBgBrush = New-Object System.Drawing.SolidBrush($rowBgColor)\n"
                    "      $rowTextBrush = New-Object System.Drawing.SolidBrush($rowTextColor)\n"
                    "      $rowScale = 1.0\n"
                    "      if ($kind -eq 'break') { try { $rowScale = [double]$row.row_scale } catch { $rowScale = 1.0 } }\n"
                    "      if ($rowScale -le 0) { $rowScale = 1.0 }\n"
                    "      $currentRowHeight = [Math]::Max($eventRowHeight, [int][Math]::Round($eventRowHeight * $rowScale))\n"
                    "      $g.FillRectangle($rowBgBrush, 0, $rowY, $width, $currentRowHeight)\n"
                    "      if ($kind -eq 'break') {\n"
                    "        try { $breakFontSize = [Math]::Max(8, [int]$row.font_size) } catch { $breakFontSize = 0 }\n"
                    "        if ($breakFontSize -le 0) { $breakFontSize = $defaultFontSize }\n"
                    "        $breakFontStyle = if ([bool]$row.bold) { [System.Drawing.FontStyle]::Bold } else { $bodyFontStyle }\n"
                    "        if ($strikeElapsed -and [bool]$row.is_elapsed) { $breakFontStyle = $breakFontStyle -bor [System.Drawing.FontStyle]::Strikeout }\n"
                    "        $breakFont = New-Object System.Drawing.Font('Malgun Gothic', $breakFontSize, $breakFontStyle)\n"
                    "        $breakText = [string]$row.boss\n"
                    "        $breakState = [string]$row.state\n"
                    "        $breakDisplay = [string]$row.break_display_text\n"
                    "        if (-not $breakDisplay) { $breakDisplay = $breakState }\n"
                    "        if ($breakDisplay) { $breakText += ('  <' + $breakDisplay + '>') }\n"
                    "        $breakY = $rowY + [Math]::Max(4, [int][Math]::Floor(($currentRowHeight - $breakFont.GetHeight($g)) / 2))\n"
                    "        $g.DrawString($breakText, $breakFont, $rowTextBrush, 24, $breakY)\n"
                    "        $breakFont.Dispose()\n"
                    "        $g.DrawLine($linePen, 0, $rowY + $currentRowHeight, $width, $rowY + $currentRowHeight)\n"
                    "        $rowBgBrush.Dispose()\n"
                    "        $rowTextBrush.Dispose()\n"
                    "        $rowY += $currentRowHeight\n"
                    "        continue\n"
                    "      }\n"
                    "      $currentBodyFont = if ($strikeElapsed -and [bool]$row.is_elapsed) { $bodyStrikeFont } else { $bodyFont }\n"
                    "      $bodyTextY = $rowY + [Math]::Max(4, [int][Math]::Floor(($currentRowHeight - $currentBodyFont.GetHeight($g)) / 2))\n"
                    "      $g.DrawString([string]$row.time, $currentBodyFont, $rowTextBrush, $timeX, $bodyTextY)\n"
                    "      if ([bool]$row.has_star) { $g.DrawString('★', $starFont, $starBrush, $starX, $rowY + 4) }\n"
                    "      $g.DrawString([string]$row.boss, $currentBodyFont, $rowTextBrush, $bossX, $bodyTextY)\n"
                    "      $g.DrawString([string]$row.state, $currentBodyFont, $rowTextBrush, $stateX, $bodyTextY)\n"
                    "      $g.DrawLine($linePen, 0, $rowY + $currentRowHeight, $width, $rowY + $currentRowHeight)\n"
                    "      $rowBgBrush.Dispose()\n"
                    "      $rowTextBrush.Dispose()\n"
                    "      $rowY += $currentRowHeight\n"
                    "    }\n"
                    "  }\n"
                    "  $bmp.Save($clipboardImagePath, [System.Drawing.Imaging.ImageFormat]::Png)\n"
                    "  $bitmapImage = New-Object System.Windows.Media.Imaging.BitmapImage\n"
                    "  $bitmapImage.BeginInit()\n"
                    "  $bitmapImage.CacheOption = [System.Windows.Media.Imaging.BitmapCacheOption]::OnLoad\n"
                    "  $bitmapImage.UriSource = [Uri]::new($clipboardImagePath)\n"
                    "  $bitmapImage.EndInit()\n"
                    "  $bitmapImage.Freeze()\n"
                    "  [System.Windows.Clipboard]::SetImage($bitmapImage)\n"
                    "  [PSCustomObject]@{ ok = $true; count = $rows.Count } | ConvertTo-Json -Compress\n"
                    "} catch {\n"
                    "  [PSCustomObject]@{ ok = $false; error = $_.Exception.Message } | ConvertTo-Json -Compress\n"
                    "} finally {\n"
                    "  if ($null -ne $g) { $g.Dispose() }\n"
                    "  if ($null -ne $bmp) { $bmp.Dispose() }\n"
                    "  if ($null -ne $linePen) { $linePen.Dispose() }\n"
                    "  if ($null -ne $dateLinePen) { $dateLinePen.Dispose() }\n"
                    "  if ($null -ne $headerBrush) { $headerBrush.Dispose() }\n"
                    "  if ($null -ne $tableHeaderBrush) { $tableHeaderBrush.Dispose() }\n"
                    "  if ($null -ne $dateHeaderBrush) { $dateHeaderBrush.Dispose() }\n"
                    "  if ($null -ne $eventBrush) { $eventBrush.Dispose() }\n"
                    "  if ($null -ne $invasionBrush) { $invasionBrush.Dispose() }\n"
                    "  if ($null -ne $fixedBrush) { $fixedBrush.Dispose() }\n"
                    "  if ($null -ne $textBrush) { $textBrush.Dispose() }\n"
                    "  if ($null -ne $subBrush) { $subBrush.Dispose() }\n"
                    "  if ($null -ne $dateTextBrush) { $dateTextBrush.Dispose() }\n"
                    "  if ($null -ne $starBrush) { $starBrush.Dispose() }\n"
                    "  if ($null -ne $titleFont) { $titleFont.Dispose() }\n"
                    "  if ($null -ne $subFont) { $subFont.Dispose() }\n"
                    "  if ($null -ne $headFont) { $headFont.Dispose() }\n"
                    "  if ($null -ne $bodyFont) { $bodyFont.Dispose() }\n"
                    "  if ($null -ne $bodyStrikeFont) { $bodyStrikeFont.Dispose() }\n"
                    "  if ($null -ne $starFont) { $starFont.Dispose() }\n"
                    "  if ($null -ne $dateFont) { $dateFont.Dispose() }\n"
                    "  if ($clipboardImagePath -and [System.IO.File]::Exists($clipboardImagePath)) { [System.IO.File]::Delete($clipboardImagePath) }\n"
                    "}\n"
                )
                ok, output = self._run_schedule_ocr_powershell(script, sta=True)
                if not ok or not output:
                    self.schedule_status_var.set("공유용 스케쥴을 클립보드에 저장하지 못했습니다.")
                    return
                try:
                    payload_result = json.loads(output)
                except json.JSONDecodeError:
                    payload_result = None
                if not isinstance(payload_result, dict) or not bool(payload_result.get("ok")):
                    error_message = str(payload_result.get("error") or "알 수 없는 오류") if isinstance(payload_result, dict) else "알 수 없는 오류"
                    try:
                        log_path = os.path.join(get_app_root(), "boss_timer_runtime_error.log")
                        with open(log_path, "a", encoding="utf-8") as error_file:
                            error_file.write(f"\n[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}]\n")
                            error_file.write("schedule share copy failed\n")
                            error_file.write(f"include_break_rows={bool(selected_range.get('include_break_rows'))}\n")
                            error_file.write(f"rows={len(rows)}\n")
                            error_file.write(f"error={error_message}\n")
                            error_file.write(f"output={output}\n")
                    except OSError:
                        pass
                    self.schedule_status_var.set(f"공유용 스케쥴 저장 실패: {error_message}")
                    return
                self.schedule_status_var.set(f"클립보드에 스케쥴이 저장됐습니다. ({len(rows)}건)")
            finally:
                try:
                    os.remove(payload_path)
                except OSError:
                    pass
        except Exception as exc:
            try:
                log_path = os.path.join(get_app_root(), "boss_timer_runtime_error.log")
                with open(log_path, "a", encoding="utf-8") as error_file:
                    error_file.write(f"\n[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}]\n")
                    error_file.write("".join(traceback.format_exception(type(exc), exc, exc.__traceback__)))
            except OSError:
                pass
            self.schedule_status_var.set(f"공유용 스케쥴 저장 실패: {exc}")

    def _get_schedule_input_placeholder_text(self) -> str:
        if self.schedule_input_add_mode:
            return (
                "- 기존 스케쥴에 몇 줄만 추가 입력\n"
                "1817 그로아\n"
                "18:17 그로아\n"
                "18:17:00 그로아\n"
                "그로아 출현 중\n"
                "그로아 1시간 20분\n"
                "1817 그로아 컷\n\n"
                "※ 추가 규칙\n"
                "입력한 보스만 현재 시각 이후 스케쥴에 반영합니다.\n"
                "서버오픈 기준 전체 생성은 일반 스케쥴 입력을 사용하세요."
            )
        return (
            "- 디코보탐매니저 텍스트 복사 또는 수동입력\n"
            "1817 그로아\n"
            "18:17 그로아\n"
            "181700 그로아\n"
            "18:17:00 그로아\n"
            "1817 그로아 컷  (이하 컷적용도 위와 같음)\n"
            "출현중 or 출현 중\n\n"
            "※ 생성 규칙\n"
            "그로아 컷  -> 현재시간 기준 컷 적용\n"
            "1815 그로아 컷  -> 해당 시각 컷 적용\n\n"
            "※ OCR 입력 방법\n"
            "1. 오딘 노른 시간표 스샷을 클립보드에 복사\n"
            "   - 중요: 좌측 상단 현재 시간이 꼭 포함되어야 함\n"
            "2. 이 창에서 Ctrl+V 로 이미지를 추가\n"
            "3. 여러 장을 붙여넣은 뒤 OCR 변환\n"
            "4. 검증 로그를 확인하고 필요하면 텍스트를 수정 후 적용"
        )

    def _ensure_schedule_input_placeholder(self, force: bool = False) -> None:
        if self.schedule_input_text is None or not self.schedule_input_text.winfo_exists() or self.schedule_input_edit_mode:
            return
        try:
            current_text = self.schedule_input_text.get("1.0", "end-1c")
        except tk.TclError:
            return
        if not force and current_text.strip() and not self.schedule_input_placeholder_active:
            return
        self.schedule_input_placeholder_active = True
        try:
            self.schedule_input_text.delete("1.0", "end")
            self.schedule_input_text.insert("1.0", self._get_schedule_input_placeholder_text())
            self.schedule_input_text.config(fg="#94a3b8")
            self.schedule_input_text.edit_modified(False)
        except tk.TclError:
            return

    def _clear_schedule_input_placeholder(self) -> None:
        if self.schedule_input_text is None or not self.schedule_input_text.winfo_exists() or not self.schedule_input_placeholder_active:
            return
        self.schedule_input_placeholder_active = False
        try:
            self.schedule_input_text.delete("1.0", "end")
            self.schedule_input_text.config(fg="#0f172a")
            self.schedule_input_text.edit_modified(False)
        except tk.TclError:
            return

    def _on_schedule_input_text_focus_in(self, _event=None) -> None:
        self._clear_schedule_input_placeholder()

    def _on_schedule_input_text_click(self, _event=None) -> None:
        self._clear_schedule_input_placeholder()
        return None

    def _get_schedule_input_raw_text(self) -> str:
        if self.schedule_input_text is None or self.schedule_input_placeholder_active:
            return ""
        try:
            return self.schedule_input_text.get("1.0", "end-1c")
        except tk.TclError:
            return ""

    def _get_schedule_ocr_cache_dir(self) -> str:
        cache_dir = os.path.join(get_app_root(), SCHEDULE_OCR_CACHE_DIRNAME)
        os.makedirs(cache_dir, exist_ok=True)
        return cache_dir

    def _prepare_schedule_input_ocr_runtime(self) -> tuple[bool, str]:
        try:
            self._get_schedule_ocr_cache_dir()
        except Exception as exc:
            return False, str(exc)
        script = (
            "[Console]::OutputEncoding = [System.Text.Encoding]::UTF8\n"
            "$ErrorActionPreference = 'Stop'\n"
            "try {\n"
            "  Add-Type -AssemblyName PresentationCore -ErrorAction Stop\n"
            "  Add-Type -AssemblyName PresentationFramework -ErrorAction Stop\n"
            "  [void][Windows.Graphics.Imaging.SoftwareBitmap, Windows.Foundation, ContentType=WindowsRuntime]\n"
            "  [void][Windows.Media.Ocr.OcrEngine, Windows.Foundation, ContentType=WindowsRuntime]\n"
            "  $engine = [Windows.Media.Ocr.OcrEngine]::TryCreateFromUserProfileLanguages()\n"
            "  if ($null -eq $engine) { throw 'ocr_engine_unavailable' }\n"
            "  [PSCustomObject]@{ ok = $true } | ConvertTo-Json -Compress\n"
            "} catch {\n"
            "  [PSCustomObject]@{ ok = $false; error = $_.Exception.Message } | ConvertTo-Json -Compress\n"
            "}\n"
        )
        ok, output = self._run_schedule_ocr_powershell(script, sta=True)
        if not ok or not output:
            return False, output or "ocr_runtime_prepare_failed"
        try:
            payload = json.loads(output)
        except json.JSONDecodeError:
            return False, output
        if not isinstance(payload, dict) or not bool(payload.get("ok")):
            return False, str(payload.get("error") or "ocr_runtime_prepare_failed") if isinstance(payload, dict) else "ocr_runtime_prepare_failed"
        return True, ""

    def _start_schedule_input_ocr_runtime_prewarm(self) -> None:
        if self.schedule_input_ocr_runtime_ready or self.schedule_input_ocr_runtime_warming:
            return
        self.schedule_input_ocr_runtime_warming = True
        self.schedule_input_ocr_runtime_error = ""

        def worker() -> None:
            ok, error_message = self._prepare_schedule_input_ocr_runtime()

            def finish() -> None:
                self.schedule_input_ocr_runtime_warming = False
                self.schedule_input_ocr_runtime_ready = bool(ok)
                self.schedule_input_ocr_runtime_error = "" if ok else str(error_message or "")

            if self.root is not None and self.root.winfo_exists():
                try:
                    self.root.after(0, finish)
                    return
                except tk.TclError:
                    pass
            self.schedule_input_ocr_runtime_warming = False
            self.schedule_input_ocr_runtime_ready = bool(ok)
            self.schedule_input_ocr_runtime_error = "" if ok else str(error_message or "")

        threading.Thread(target=worker, daemon=True).start()

    def _load_schedule_ocr_corrections(self) -> dict[str, dict[str, object]]:
        if not os.path.exists(SCHEDULE_OCR_CORRECTIONS_PATH):
            return {}
        try:
            with open(SCHEDULE_OCR_CORRECTIONS_PATH, "r", encoding="utf-8") as file:
                payload = json.load(file)
        except (OSError, json.JSONDecodeError):
            return {}
        raw_items = payload.get("items") if isinstance(payload, dict) else None
        if not isinstance(raw_items, list):
            return {}
        corrections: dict[str, dict[str, object]] = {}
        for raw_item in raw_items:
            if not isinstance(raw_item, dict):
                continue
            boss_name = str(raw_item.get("boss_name") or "").strip()
            observed_text = self._normalize_schedule_ocr_text(str(raw_item.get("observed_text") or ""))
            corrected_text = self._normalize_schedule_ocr_text(str(raw_item.get("corrected_text") or ""))
            if not boss_name or not observed_text or not corrected_text:
                continue
            if self._is_schedule_ocr_lossy_no_time_correction(observed_text, corrected_text):
                continue
            key = self._build_schedule_ocr_correction_key(boss_name, observed_text)
            corrections[key] = {
                "boss_name": boss_name,
                "observed_text": observed_text,
                "corrected_text": corrected_text,
                "count": max(1, int(raw_item.get("count") or 1)),
            }
        return corrections

    def _save_schedule_ocr_corrections(self) -> None:
        items = sorted(
            self.schedule_ocr_corrections.values(),
            key=lambda item: (
                str(item.get("boss_name") or ""),
                str(item.get("observed_text") or ""),
            ),
        )
        payload = {"version": 1, "items": items}
        try:
            with open(SCHEDULE_OCR_CORRECTIONS_PATH, "w", encoding="utf-8") as file:
                json.dump(payload, file, ensure_ascii=False, indent=2)
        except OSError:
            return

    def _build_schedule_ocr_correction_key(self, boss_name: str, observed_text: str) -> str:
        canonical_name = self._get_canonical_boss_name(boss_name) or str(boss_name or "").strip()
        normalized_name = self._normalize_schedule_boss_lookup_key(canonical_name)
        normalized_text = self._normalize_schedule_boss_lookup_key(self._normalize_schedule_ocr_text(observed_text))
        return f"{normalized_name}|{normalized_text}"

    def _is_schedule_ocr_lossy_no_time_correction(self, observed_text: str, corrected_text: str) -> bool:
        normalized_observed = self._normalize_schedule_ocr_text(observed_text)
        normalized_corrected = self._normalize_schedule_ocr_text(corrected_text)
        if normalized_corrected != "1일 이상" or normalized_observed in {"", "1일 이상"}:
            return False
        normalized_duration_text, _ = self._normalize_schedule_ocr_duration_prefix(normalized_observed)
        parsed_value = self._parse_schedule_remaining_value(normalized_duration_text or normalized_observed)
        if parsed_value is None:
            return False
        remaining_seconds, _ = parsed_value
        return int(remaining_seconds) >= 86400

    def _get_schedule_ocr_learned_correction(self, boss_name: str, observed_text: str) -> dict[str, object] | None:
        if not self._is_schedule_ocr_learning_enabled():
            return None
        key = self._build_schedule_ocr_correction_key(boss_name, observed_text)
        item = self.schedule_ocr_corrections.get(key)
        if not isinstance(item, dict):
            return None
        if self._is_schedule_ocr_lossy_no_time_correction(
            str(item.get("observed_text") or observed_text),
            str(item.get("corrected_text") or ""),
        ):
            return None
        if int(item.get("count") or 0) < int(self.schedule_ocr_correction_auto_threshold or 0):
            return None
        return item

    def _record_schedule_ocr_correction(self, boss_name: str, observed_text: str, corrected_text: str) -> int:
        if not self._is_schedule_ocr_learning_enabled():
            return 0
        normalized_observed = self._normalize_schedule_ocr_text(observed_text)
        normalized_corrected = self._normalize_schedule_ocr_text(corrected_text)
        if not boss_name or not normalized_observed or not normalized_corrected:
            return 0
        key = self._build_schedule_ocr_correction_key(boss_name, normalized_observed)
        if self._is_schedule_ocr_lossy_no_time_correction(normalized_observed, normalized_corrected):
            existing = self.schedule_ocr_corrections.get(key)
            if isinstance(existing, dict) and self._normalize_schedule_ocr_text(str(existing.get("corrected_text") or "")) == "1일 이상":
                self.schedule_ocr_corrections.pop(key, None)
                self._save_schedule_ocr_corrections()
            return 0
        existing = self.schedule_ocr_corrections.get(key)
        if isinstance(existing, dict) and self._normalize_schedule_ocr_text(str(existing.get("corrected_text") or "")) == normalized_corrected:
            count = max(1, int(existing.get("count") or 1) + 1)
        else:
            count = 1
        self.schedule_ocr_corrections[key] = {
            "boss_name": self._get_canonical_boss_name(boss_name) or str(boss_name or "").strip(),
            "observed_text": normalized_observed,
            "corrected_text": normalized_corrected,
            "count": count,
        }
        self._save_schedule_ocr_corrections()
        return count

    def _is_schedule_ocr_learning_enabled(self) -> bool:
        var = getattr(self, "schedule_ocr_learning_enabled_var", None)
        if var is not None:
            try:
                return bool(var.get())
            except tk.TclError:
                pass
        return bool(getattr(self, "schedule_ocr_learning_enabled_default", True))

    def _set_schedule_ocr_learning_enabled(self, enabled: bool, *, persist: bool = True) -> None:
        enabled = bool(enabled)
        self.schedule_ocr_learning_enabled_default = enabled
        var = getattr(self, "schedule_ocr_learning_enabled_var", None)
        if var is not None:
            try:
                var.set(enabled)
            except tk.TclError:
                pass
        if persist:
            self._save_settings()

    def _clear_schedule_ocr_corrections(self) -> int:
        cleared_count = len(self.schedule_ocr_corrections)
        self.schedule_ocr_corrections.clear()
        self._save_schedule_ocr_corrections()
        return cleared_count

    def _on_schedule_ocr_learning_toggle(self) -> None:
        self._set_schedule_ocr_learning_enabled(self._is_schedule_ocr_learning_enabled())
        if self.schedule_input_status_var is not None:
            status_text = "학습보정 사용" if self._is_schedule_ocr_learning_enabled() else "학습보정 사용 안 함"
            try:
                self.schedule_input_status_var.set(status_text)
            except tk.TclError:
                pass

    def _delete_schedule_ocr_learning_data(self, dialog: tk.Toplevel | None = None) -> None:
        parent = dialog if self._widget_available(dialog) else self.schedule_input_ocr_log_window if self._widget_available(self.schedule_input_ocr_log_window) else self.root
        if not self._ask_centered_yesno("검증로그 전체삭제", "학습보정 데이터를 모두 삭제하시겠습니까?", parent=parent):
            return
        cleared_count = self._clear_schedule_ocr_corrections()
        if self.schedule_input_status_var is not None:
            try:
                self.schedule_input_status_var.set(f"학습보정 데이터 {cleared_count}건 삭제")
            except tk.TclError:
                pass
        if dialog is not None and self._widget_available(dialog):
            try:
                dialog.lift()
            except tk.TclError:
                pass

    def _clear_schedule_input_ocr_rendered_text_if_unedited(self) -> None:
        if self.schedule_input_text is None or not self.schedule_input_text.winfo_exists():
            return
        if not self.schedule_input_ocr_last_render_text:
            return
        if self._schedule_input_has_manual_ocr_text_edits():
            return
        try:
            self.schedule_input_text.delete("1.0", "end")
            self.schedule_input_text.config(fg="#0f172a")
            self.schedule_input_text.edit_modified(False)
        except tk.TclError:
            return
        self.schedule_input_placeholder_active = False
        self._ensure_schedule_input_placeholder(force=True)

    def _invalidate_schedule_input_ocr_results(self, status_text: str = "") -> None:
        self.schedule_input_ocr_results = []
        self.schedule_input_ocr_log_lines = []
        self.schedule_input_ocr_line_severities = {}
        if self.schedule_input_ocr_log_window is not None and self.schedule_input_ocr_log_window.winfo_exists():
            try:
                self.schedule_input_ocr_log_window.destroy()
            except tk.TclError:
                pass
        self.schedule_input_ocr_log_window = None
        if self.schedule_input_ocr_log_button is not None and self.schedule_input_ocr_log_button.winfo_exists():
            try:
                self.schedule_input_ocr_log_button.config(
                    state="disabled",
                    bg="#cbd5e1",
                    fg="#f8fafc",
                    activebackground="#cbd5e1",
                    activeforeground="#f8fafc",
                    cursor="arrow",
                )
            except tk.TclError:
                pass
        self.schedule_input_ocr_results_stale = bool(self.schedule_input_ocr_last_render_text.strip())
        if status_text and self.schedule_input_status_var is not None:
            try:
                self.schedule_input_status_var.set(status_text)
            except tk.TclError:
                pass
        self._update_schedule_input_apply_state()

    def _clear_schedule_input_ocr_results(self) -> None:
        self._clear_schedule_input_ocr_rendered_text_if_unedited()
        self.schedule_input_ocr_results = []
        self.schedule_input_ocr_log_lines = []
        self.schedule_input_ocr_last_render_text = ""
        self.schedule_input_ocr_last_render_text_normal = ""
        self.schedule_input_ocr_last_render_text_invasion = ""
        self.schedule_input_ocr_line_severities = {}
        self.schedule_input_ocr_results_stale = False
        if self.schedule_input_ocr_log_window is not None and self.schedule_input_ocr_log_window.winfo_exists():
            try:
                self.schedule_input_ocr_log_window.destroy()
            except tk.TclError:
                pass
        self.schedule_input_ocr_log_window = None
        if self.schedule_input_ocr_log_button is not None and self.schedule_input_ocr_log_button.winfo_exists():
            try:
                self.schedule_input_ocr_log_button.config(
                    state="disabled",
                    bg="#cbd5e1",
                    fg="#f8fafc",
                    activebackground="#cbd5e1",
                    activeforeground="#f8fafc",
                    cursor="arrow",
                )
            except tk.TclError:
                pass

    def _set_schedule_input_ocr_loading_lock(self, locked: bool) -> None:
        self.schedule_input_ocr_loading_lock_active = bool(locked)
        text_widget = getattr(self, "schedule_input_text", None)
        if text_widget is not None and text_widget.winfo_exists():
            try:
                text_widget.config(state="disabled" if locked else "normal")
            except tk.TclError:
                pass
        widgets = [
            getattr(self, "schedule_input_undo_button", None),
            getattr(self, "schedule_input_edit_undo_button", None),
            getattr(self, "schedule_input_invasion_check", None),
            getattr(self, "schedule_input_past_button", None),
            getattr(self, "schedule_input_ocr_addon_button", None),
            getattr(self, "schedule_input_close_button", None),
        ]
        for widget in widgets:
            if widget is None or not widget.winfo_exists():
                continue
            try:
                widget.config(
                    state="disabled" if locked else "normal",
                    cursor="arrow" if locked else "hand2",
                )
            except tk.TclError:
                continue
        for widget in getattr(self, "schedule_input_base_widgets", []):
            if widget is None or not widget.winfo_exists():
                continue
            try:
                widget.config(state="disabled" if locked else "normal")
            except tk.TclError:
                continue
        self._update_schedule_input_ocr_addon_controls()
        if not locked:
            self._configure_schedule_input_window_mode(prefill=False)
            self._refresh_schedule_input_ocr_queue_widgets()
            self._update_schedule_input_apply_state()

    def _show_schedule_input_ocr_loading_dialog(self, total_count: int) -> None:
        owner = self.schedule_input_window if self.schedule_input_window is not None and self.schedule_input_window.winfo_exists() else self.root
        if owner is None or not owner.winfo_exists():
            return
        dialog = self.schedule_input_ocr_loading_window
        if dialog is None or not dialog.winfo_exists():
            dialog = tk.Toplevel(owner)
            self.schedule_input_ocr_loading_window = dialog
            dialog.title("OCR 변환 중")
            dialog.resizable(False, False)
            dialog.transient(owner)
            dialog.configure(bg="#0f172a")
            dialog.protocol("WM_DELETE_WINDOW", lambda: None)
            try:
                dialog.attributes("-topmost", True)
            except tk.TclError:
                pass
            tk.Label(
                dialog,
                text="OCR 변환 중",
                font=self.header_font,
                bg="#0f172a",
                fg="#f8fafc",
            ).place(x=0, y=14, width=360, height=24)
            tk.Label(
                dialog,
                textvariable=self.schedule_input_ocr_loading_title_var,
                font=(self.current_font_family, 10, "bold"),
                bg="#0f172a",
                fg="#93c5fd",
            ).place(x=24, y=52, width=312, height=22)
            tk.Label(
                dialog,
                textvariable=self.schedule_input_ocr_loading_detail_var,
                font=(self.current_font_family, 9),
                bg="#0f172a",
                fg="#cbd5e1",
                justify="center",
            ).place(x=24, y=80, width=312, height=20)
            progressbar = ttk.Progressbar(dialog, mode="indeterminate", length=280)
            progressbar.place(x=40, y=114, width=280, height=14)
            self.schedule_input_ocr_loading_progressbar = progressbar
            tk.Label(
                dialog,
                text="변환 중에는 입력과 버튼이 잠시 비활성화됩니다.",
                font=(self.current_font_family, 8),
                bg="#0f172a",
                fg="#64748b",
            ).place(x=24, y=138, width=312, height=18)
        self.schedule_input_ocr_loading_title_var.set(f"이미지 0/{max(1, int(total_count or 0))} 준비 중")
        self.schedule_input_ocr_loading_detail_var.set("시간표를 읽고 검증 로그를 만드는 중입니다.")
        self._center_window_over_parent(dialog, owner, 360, 176)
        self._set_schedule_input_ocr_loading_lock(True)
        progressbar = self.schedule_input_ocr_loading_progressbar
        if progressbar is not None:
            try:
                progressbar.start(10)
            except tk.TclError:
                pass
        try:
            dialog.deiconify()
            dialog.lift()
            dialog.grab_set()
            dialog.focus_force()
        except tk.TclError:
            pass

    def _update_schedule_input_ocr_loading_dialog(
        self,
        *,
        index: int,
        total: int,
        area: str = "",
        warning_count: int = 0,
    ) -> None:
        dialog = self.schedule_input_ocr_loading_window
        if dialog is None or not dialog.winfo_exists():
            return
        area_text = str(area or "").strip()
        detail_parts = [f"이미지 {max(0, int(index))}/{max(1, int(total or 0))} 분석 중"]
        if area_text:
            detail_parts.append(f"지역 추정: {area_text}")
        if int(warning_count or 0) > 0:
            detail_parts.append(f"경고 {int(warning_count)}건")
        self.schedule_input_ocr_loading_title_var.set("OCR 결과를 정리하고 있습니다.")
        self.schedule_input_ocr_loading_detail_var.set(" / ".join(detail_parts))
        try:
            dialog.lift()
        except tk.TclError:
            pass

    def _hide_schedule_input_ocr_loading_dialog(self) -> None:
        progressbar = self.schedule_input_ocr_loading_progressbar
        if progressbar is not None:
            try:
                progressbar.stop()
            except tk.TclError:
                pass
        dialog = self.schedule_input_ocr_loading_window
        if dialog is not None and dialog.winfo_exists():
            try:
                dialog.grab_release()
            except tk.TclError:
                pass
            try:
                dialog.destroy()
            except tk.TclError:
                pass
        self.schedule_input_ocr_loading_window = None
        self.schedule_input_ocr_loading_progressbar = None
        self._set_schedule_input_ocr_loading_lock(False)

    def _clear_schedule_input_ocr_queue(self) -> None:
        for item in list(self.schedule_input_ocr_items):
            image_path = str(item.get("path") or "").strip()
            if image_path and os.path.exists(image_path):
                try:
                    os.remove(image_path)
                except OSError:
                    pass
        self.schedule_input_ocr_items = []
        self._clear_schedule_input_ocr_recent_hashes()
        self._clear_schedule_input_ocr_results()
        if self.schedule_input_ocr_addon_window is not None and self.schedule_input_ocr_addon_window.winfo_exists():
            self._refresh_schedule_input_ocr_addon_stack_widgets()
        self._save_schedule_state()

    def _stash_schedule_input_ocr_queue(self) -> None:
        if self.schedule_input_ocr_items:
            self.schedule_input_ocr_saved_items = [dict(item) for item in self.schedule_input_ocr_items]
            self.schedule_input_ocr_saved_results = [dict(item) for item in self.schedule_input_ocr_results]
            self.schedule_input_ocr_saved_invasion_mode = bool(self.schedule_input_invasion_var.get())
        self.schedule_input_ocr_items = []
        self._clear_schedule_input_ocr_recent_hashes()
        self._clear_schedule_input_ocr_results()
        self._refresh_schedule_input_ocr_queue_widgets()
        if self.schedule_input_ocr_addon_window is not None and self.schedule_input_ocr_addon_window.winfo_exists():
            self._refresh_schedule_input_ocr_addon_stack_widgets()
        self._save_schedule_state()

    def _restore_saved_schedule_input_ocr_queue(self) -> None:
        if self.schedule_input_ocr_worker_active:
            self.schedule_input_status_var.set("OCR 변환 중에는 이전 스샷을 복구할 수 없습니다.")
            return
        if self.schedule_input_ocr_items:
            self.schedule_input_status_var.set("현재 대기열을 먼저 비운 뒤 이전 스샷을 복구하세요.")
            return
        if not self.schedule_input_ocr_saved_items:
            self.schedule_input_status_var.set("복구할 이전 스샷이 없습니다.")
            return
        restored_results = [dict(item) for item in self.schedule_input_ocr_saved_results]
        self.schedule_input_ocr_items = [dict(item) for item in self.schedule_input_ocr_saved_items]
        self.schedule_input_ocr_saved_items = []
        self.schedule_input_ocr_saved_results = []
        self._clear_schedule_input_ocr_recent_hashes()
        if isinstance(self.schedule_input_ocr_saved_invasion_mode, bool):
            self.schedule_input_invasion_var.set(self.schedule_input_ocr_saved_invasion_mode)
        self.schedule_input_ocr_saved_invasion_mode = None
        self._clear_schedule_input_ocr_results()
        self.schedule_input_ocr_results = restored_results
        self._refresh_schedule_input_ocr_queue_widgets()
        if self.schedule_input_ocr_addon_window is not None and self.schedule_input_ocr_addon_window.winfo_exists():
            self._refresh_schedule_input_ocr_addon_stack_widgets()
        if self.schedule_input_ocr_results:
            self._refresh_schedule_input_ocr_warning_summary()
            self._render_schedule_input_ocr_text()
        if self.schedule_input_ocr_queue_canvas is not None and self.schedule_input_ocr_queue_canvas.winfo_exists():
            try:
                self.schedule_input_ocr_queue_canvas.xview_moveto(0.0)
            except tk.TclError:
                pass
        if self.schedule_input_ocr_results:
            self.schedule_input_status_var.set(
                f"이전 스샷 {len(self.schedule_input_ocr_items)}장과 OCR 텍스트를 복구했습니다. 필요하면 OCR 검증만 다시 확인하세요."
            )
        else:
            self.schedule_input_status_var.set(f"이전 스샷 {len(self.schedule_input_ocr_items)}장을 복구했습니다. OCR 변환을 눌러 다시 분석하세요.")
        self._save_schedule_state()

    def _open_schedule_input_ocr_preview(self, item_id: str) -> None:
        owner = self.schedule_input_window if self.schedule_input_window is not None and self.schedule_input_window.winfo_exists() else self.root
        if owner is None:
            return
        target_item = next((item for item in self.schedule_input_ocr_items if str(item.get("id") or "") == str(item_id or "")), None)
        if not isinstance(target_item, dict):
            target_item = next((item for item in self.schedule_input_ocr_saved_items if str(item.get("id") or "") == str(item_id or "")), None)
        if not isinstance(target_item, dict):
            self.schedule_input_status_var.set("미리볼 스샷을 찾지 못했습니다.")
            return
        image_path = str(target_item.get("path") or "").strip()
        if not image_path or not os.path.exists(image_path):
            self.schedule_input_status_var.set("미리볼 스샷 파일이 없습니다.")
            return
        try:
            preview_image = tk.PhotoImage(file=image_path)
        except tk.TclError:
            self.schedule_input_status_var.set("스샷 미리보기를 불러오지 못했습니다.")
            return
        if self.schedule_input_ocr_preview_window is not None and self.schedule_input_ocr_preview_window.winfo_exists():
            try:
                self.schedule_input_ocr_preview_window.destroy()
            except tk.TclError:
                pass
        image_width = max(1, int(preview_image.width() or 1))
        image_height = max(1, int(preview_image.height() or 1))
        dialog = tk.Toplevel(owner)
        self.schedule_input_ocr_preview_window = dialog
        dialog.title("OCR 스샷 미리보기")
        dialog.transient(owner)
        dialog.configure(bg="#eff6ff")
        screen_width = max(640, int(dialog.winfo_screenwidth() or owner.winfo_screenwidth() or 1280))
        screen_height = max(480, int(dialog.winfo_screenheight() or owner.winfo_screenheight() or 900))
        available_width = max(420, screen_width - 80)
        available_height = max(320, screen_height - 120)
        window_width = min(available_width, max(420, image_width + 54))
        window_height = min(available_height, max(320, image_height + 98))
        self._center_window_over_parent(dialog, owner, window_width, window_height)
        tk.Label(dialog, text="OCR 스샷 미리보기", font=self.header_font, bg="#dbeafe", fg="#0f172a").place(x=0, y=0, width=window_width, height=40)
        canvas_width = max(120, window_width - 40)
        canvas_height = max(120, window_height - 96)
        canvas = tk.Canvas(dialog, bg="#0f172a", highlightthickness=1, highlightbackground="#94a3b8")
        canvas.place(x=18, y=52, width=canvas_width, height=canvas_height)
        x_scrollbar = tk.Scrollbar(dialog, orient="horizontal", command=canvas.xview)
        x_scrollbar.place(x=18, y=window_height - 28, width=canvas_width, height=14)
        y_scrollbar = tk.Scrollbar(dialog, orient="vertical", command=canvas.yview)
        y_scrollbar.place(x=window_width - 20, y=52, width=14, height=canvas_height)
        canvas.configure(xscrollcommand=x_scrollbar.set, yscrollcommand=y_scrollbar.set, scrollregion=(0, 0, image_width, image_height))
        canvas.create_image(0, 0, image=preview_image, anchor="nw")
        canvas.image = preview_image

        def _close_preview() -> None:
            self.schedule_input_ocr_preview_window = None
            try:
                dialog.destroy()
            except tk.TclError:
                return

        dialog.protocol("WM_DELETE_WINDOW", _close_preview)
        dialog.bind("<Escape>", lambda _event: _close_preview())
        dialog.focus_force()

    def _is_schedule_input_ocr_addon_target_title(self, title: str) -> bool:
        normalized = str(title or "").strip().lower()
        if not normalized:
            return False
        if any(blocked in normalized for blocked in ("boss timer", "노른의 시간표", "스샷 애드온", "ocr", "record book", "보스 기록")):
            return False
        return "오딘" in normalized or "odin" in normalized

    def _get_window_text(self, hwnd: int) -> str:
        if sys.platform != "win32" or not hwnd:
            return ""
        try:
            user32 = ctypes.windll.user32
            length = int(user32.GetWindowTextLengthW(hwnd) or 0)
            buffer = ctypes.create_unicode_buffer(length + 1)
            user32.GetWindowTextW(hwnd, buffer, len(buffer))
            return str(buffer.value or "").strip()
        except Exception:
            return ""

    def _get_window_rect(self, hwnd: int) -> dict[str, int] | None:
        if sys.platform != "win32" or not hwnd:
            return None
        try:
            user32 = ctypes.windll.user32
            rect = WIN32_RECT()
            if not user32.GetWindowRect(int(hwnd), ctypes.byref(rect)):
                return None
            width = max(1, int(rect.right - rect.left))
            height = max(1, int(rect.bottom - rect.top))
            return {
                "left": int(rect.left),
                "top": int(rect.top),
                "right": int(rect.right),
                "bottom": int(rect.bottom),
                "width": width,
                "height": height,
            }
        except Exception:
            return None

    def _get_window_class_name(self, hwnd: int) -> str:
        if sys.platform != "win32" or not hwnd:
            return ""
        try:
            user32 = ctypes.windll.user32
            buffer = ctypes.create_unicode_buffer(256)
            user32.GetClassNameW(int(hwnd), buffer, len(buffer))
            return str(buffer.value or "").strip()
        except Exception:
            return ""

    def _get_window_dpi(self, hwnd: int) -> int:
        if sys.platform != "win32" or not hwnd:
            return 96
        try:
            user32 = ctypes.windll.user32
            get_dpi_for_window = getattr(user32, "GetDpiForWindow", None)
            if callable(get_dpi_for_window):
                dpi_value = int(get_dpi_for_window(int(hwnd)) or 96)
                return max(96, dpi_value)
        except Exception:
            pass
        return 96

    def _wait_for_odin_client_size(self, hwnd: int, client_width: int, client_height: int, *, attempts: int = 10, sleep_seconds: float = 0.05) -> bool:
        for _ in range(max(1, int(attempts))):
            rect = self._get_odin_client_screen_rect(hwnd)
            if isinstance(rect, dict):
                if int(rect.get("width") or 0) == int(client_width) and int(rect.get("height") or 0) == int(client_height):
                    return True
            time.sleep(max(0.0, float(sleep_seconds)))
        return False

    def _get_foreground_window_handle(self) -> int:
        if sys.platform != "win32":
            return 0
        try:
            return int(ctypes.windll.user32.GetForegroundWindow() or 0)
        except Exception:
            return 0

    def _get_root_window_handle(self, hwnd: int) -> int:
        if sys.platform != "win32" or not hwnd:
            return 0
        try:
            return int(ctypes.windll.user32.GetAncestor(int(hwnd), 2) or int(hwnd))
        except Exception:
            return int(hwnd)

    def _is_valid_window_handle(self, hwnd: int) -> bool:
        if sys.platform != "win32" or not hwnd:
            return False
        try:
            return bool(ctypes.windll.user32.IsWindow(int(hwnd)))
        except Exception:
            return False

    def _get_cursor_screen_pos(self) -> tuple[int, int] | None:
        if sys.platform != "win32":
            return None
        try:
            user32 = ctypes.windll.user32
            pt = WIN32_POINT()
            if not user32.GetCursorPos(ctypes.byref(pt)):
                return None
            return int(pt.x), int(pt.y)
        except Exception:
            return None

    def _get_window_from_screen_point(self, x: int, y: int) -> int:
        if sys.platform != "win32":
            return 0
        try:
            hwnd = int(ctypes.windll.user32.WindowFromPoint(WIN32_POINT(int(x), int(y))) or 0)
            if hwnd:
                root_hwnd = self._get_root_window_handle(hwnd)
                if root_hwnd:
                    return int(root_hwnd)
            return hwnd
        except Exception:
            return 0

    def _get_window_nchit_test(self, hwnd: int, x: int, y: int) -> int:
        if sys.platform != "win32" or not hwnd:
            return 0
        try:
            lparam = ctypes.c_long((int(y) & 0xFFFF) << 16 | (int(x) & 0xFFFF))
            return int(ctypes.windll.user32.SendMessageW(int(hwnd), WINDOW_MESSAGE_NCHITTEST, 0, lparam) or 0)
        except Exception:
            return 0

    def _get_window_close_button_rect(self, hwnd: int) -> dict[str, int] | None:
        window_rect = self._get_window_rect(hwnd)
        if not isinstance(window_rect, dict):
            return None
        window_width = max(1, int(window_rect.get("width") or 0))
        window_height = max(1, int(window_rect.get("height") or 0))
        try:
            user32 = ctypes.windll.user32
            dpi_scale = max(1.0, self._get_window_dpi(hwnd) / 96.0)
            sys_close_width = int(round(user32.GetSystemMetrics(30) * dpi_scale))
            sys_caption_height = int(round(user32.GetSystemMetrics(4) * dpi_scale))
            close_width = max(56, min(144, sys_close_width + 24, int(round(window_width * 0.12))))
            close_height = max(30, min(72, max(sys_caption_height, int(round(window_height * 0.07)))))
        except Exception:
            close_width = max(56, min(144, int(round(window_width * 0.12))))
            close_height = max(30, min(72, int(round(window_height * 0.07))))
        left = max(0, int(window_rect.get("right") or 0) - close_width)
        top = max(0, int(window_rect.get("top") or 0))
        right = max(left + 1, int(window_rect.get("right") or 0))
        bottom = min(int(window_rect.get("bottom") or 0), top + close_height)
        if right <= left or bottom <= top:
            return None
        return {
            "left": left,
            "top": top,
            "right": right,
            "bottom": bottom,
        }

    def _point_in_rect(self, x: int, y: int, rect: dict[str, int] | None) -> bool:
        if not isinstance(rect, dict):
            return False
        left = int(rect.get("left") or 0)
        top = int(rect.get("top") or 0)
        right = int(rect.get("right") or 0)
        bottom = int(rect.get("bottom") or 0)
        return left <= int(x) < right and top <= int(y) < bottom

    def _is_cursor_in_window_resize_hotzone(self, hwnd: int, x: int, y: int) -> bool:
        window_rect = self._get_window_rect(hwnd)
        if not isinstance(window_rect, dict):
            return False
        close_rect = self._get_window_close_button_rect(hwnd)
        if self._point_in_rect(x, y, close_rect):
            return True
        left = int(window_rect.get("left") or 0)
        top = int(window_rect.get("top") or 0)
        right = int(window_rect.get("right") or 0)
        width = max(1, int(window_rect.get("width") or 0))
        height = max(1, int(window_rect.get("height") or 0))
        hot_width = max(64, min(180, int(round(width * 0.14))))
        hot_height = max(28, min(80, int(round(height * 0.08))))
        hot_rect = {
            "left": max(left, right - hot_width),
            "top": top,
            "right": right,
            "bottom": min(int(window_rect.get("bottom") or 0), top + hot_height),
        }
        return self._point_in_rect(x, y, hot_rect)

    def _apply_window_resize_style_fallback(self, hwnd: int) -> bool:
        if sys.platform != "win32" or not hwnd:
            return False
        try:
            user32 = ctypes.windll.user32
            hwnd = int(hwnd)
            style = int(user32.GetWindowLongW(hwnd, WINDOW_GWL_STYLE) or 0)
            desired_style = style | WINDOW_WS_CAPTION | WINDOW_WS_THICKFRAME | WINDOW_WS_SYSMENU | WINDOW_WS_MINIMIZEBOX | WINDOW_WS_MAXIMIZEBOX
            if style & WINDOW_WS_POPUP:
                desired_style = (style & ~WINDOW_WS_POPUP) | WINDOW_WS_OVERLAPPEDWINDOW
            changed = False
            try:
                if desired_style != style:
                    user32.SetWindowLongW(hwnd, WINDOW_GWL_STYLE, desired_style)
                    changed = True
            except Exception:
                return False
            if changed:
                try:
                    user32.ShowWindow(hwnd, 9)
                except Exception:
                    pass
                try:
                    user32.SetWindowPos(
                        hwnd,
                        None,
                        0,
                        0,
                        0,
                        0,
                        WINDOW_SWP_NOMOVE | WINDOW_SWP_NOSIZE | WINDOW_SWP_NOZORDER | WINDOW_SWP_NOACTIVATE | WINDOW_SWP_FRAMECHANGED,
                    )
                except Exception:
                    pass
            return changed
        except Exception:
            return False

    def _apply_window_placement_resize_fallback(self, hwnd: int, left: int, top: int, target_width: int, target_height: int) -> bool:
        if sys.platform != "win32" or not hwnd:
            return False
        try:
            user32 = ctypes.windll.user32
            placement = WINDOWPLACEMENT()
            placement.length = ctypes.sizeof(WINDOWPLACEMENT)
            placement.flags = 0
            placement.showCmd = 1
            placement.ptMinPosition = WIN32_POINT(0, 0)
            placement.ptMaxPosition = WIN32_POINT(0, 0)
            placement.rcNormalPosition = WIN32_RECT(int(left), int(top), int(left) + int(target_width), int(top) + int(target_height))
            if not bool(user32.SetWindowPlacement(int(hwnd), ctypes.byref(placement))):
                return False
            try:
                user32.ShowWindow(int(hwnd), 9)
            except Exception:
                pass
            return True
        except Exception:
            return False

    def _simulate_window_drag_resize_fallback(self, hwnd: int, target_width: int, target_height: int) -> bool:
        if sys.platform != "win32" or not hwnd:
            return False
        try:
            user32 = ctypes.windll.user32
            kernel32 = ctypes.windll.kernel32
            window_rect = self._get_window_rect(hwnd)
            if not isinstance(window_rect, dict):
                return False
            left = int(window_rect.get("left") or 0)
            top = int(window_rect.get("top") or 0)
            right = int(window_rect.get("right") or 0)
            bottom = int(window_rect.get("bottom") or 0)
            start_x = max(left + 2, right - 4)
            start_y = max(top + 2, bottom - 4)
            end_x = max(left + 2, left + int(target_width) - 4)
            end_y = max(top + 2, top + int(target_height) - 4)
            before_cursor = self._get_cursor_screen_pos()
            start_point_hwnd = self._get_window_from_screen_point(start_x, start_y)
            end_point_hwnd = self._get_window_from_screen_point(end_x, end_y)
            start_hit_test = self._get_window_nchit_test(hwnd, start_x, start_y)
            end_hit_test = self._get_window_nchit_test(hwnd, end_x, end_y)
            try:
                capture_hwnd = int(user32.GetCapture() or 0)
            except Exception:
                capture_hwnd = 0
            self._append_debug_log(
                f"drag_begin hwnd={int(hwnd):#x} window={self._format_window_rect_text(window_rect)} "
                f"start=({int(start_x)},{int(start_y)}) end=({int(end_x)},{int(end_y)}) target={int(target_width)}x{int(target_height)} "
                f"before_cursor={before_cursor} capture={capture_hwnd:#x} clip={self._format_window_rect_text(self._get_clip_cursor_rect())} "
                f"start_point_hwnd={int(start_point_hwnd):#x} end_point_hwnd={int(end_point_hwnd):#x} "
                f"start_hit={start_hit_test} end_hit={end_hit_test}"
            )
            self._force_window_foreground(hwnd)
            time.sleep(0.05)
            start_ok = bool(user32.SetCursorPos(int(start_x), int(start_y)))
            start_last_error = int(kernel32.GetLastError() or 0)
            after_start_cursor = self._get_cursor_screen_pos()
            after_start_point_hwnd = self._get_window_from_screen_point(start_x, start_y)
            time.sleep(0.03)
            user32.mouse_event(WINDOW_MOUSEEVENTF_LEFTDOWN, 0, 0, 0, 0)
            try:
                capture_after_down = int(user32.GetCapture() or 0)
            except Exception:
                capture_after_down = 0
            steps = 12
            for step in range(1, steps + 1):
                intermediate_x = int(round(start_x + ((end_x - start_x) * step / steps)))
                intermediate_y = int(round(start_y + ((end_y - start_y) * step / steps)))
                user32.SetCursorPos(intermediate_x, intermediate_y)
                time.sleep(0.015)
            user32.mouse_event(WINDOW_MOUSEEVENTF_LEFTUP, 0, 0, 0, 0)
            time.sleep(0.08)
            self._append_debug_log(
                f"drag_end hwnd={int(hwnd):#x} start_ok={int(start_ok)} start_last_error={start_last_error} "
                f"before_cursor={before_cursor} after_start_cursor={after_start_cursor} "
                f"start_point_hwnd={int(start_point_hwnd):#x} after_start_point_hwnd={int(after_start_point_hwnd):#x} "
                f"capture_after_down={capture_after_down:#x} final_cursor={self._get_cursor_screen_pos()} "
                f"window={self._format_window_rect_text(self._get_window_rect(hwnd))} "
                f"client={self._format_odin_client_rect_text(self._get_odin_client_screen_rect(hwnd))} "
                f"clip={self._format_window_rect_text(self._get_clip_cursor_rect())}"
            )
            return True
        except Exception:
            self._append_debug_log(f"drag_exception hwnd={int(hwnd):#x}")
            return False

    def _get_schedule_input_ocr_addon_resize_target_window_handle(self) -> int:
        candidate = int(self.schedule_input_ocr_addon_resize_target_hwnd or 0)
        if candidate and self._is_valid_window_handle(candidate):
            return candidate
        return int(self._get_preferred_odin_window_handle() or 0)

    def _register_schedule_input_ocr_addon_hotkeys(self) -> None:
        if sys.platform != "win32" or self.schedule_input_ocr_addon_hotkey_registered:
            return
        try:
            user32 = ctypes.windll.user32
            mod_norepeat = 0x4000
            self.schedule_input_ocr_addon_hotkey_registered = bool(
                user32.RegisterHotKey(
                    None,
                    SCHEDULE_INPUT_OCR_ADDON_GLOBAL_HOTKEY_ID_F2,
                    mod_norepeat,
                    SCHEDULE_INPUT_OCR_ADDON_HOTKEY_F2,
                )
            )
        except Exception:
            self.schedule_input_ocr_addon_hotkey_registered = False

    def _unregister_schedule_input_ocr_addon_hotkeys(self) -> None:
        if sys.platform != "win32":
            return
        if self.schedule_input_ocr_addon_hotkey_registered:
            try:
                ctypes.windll.user32.UnregisterHotKey(None, SCHEDULE_INPUT_OCR_ADDON_GLOBAL_HOTKEY_ID_F2)
            except Exception:
                pass
        self.schedule_input_ocr_addon_hotkey_registered = False
        self.schedule_input_ocr_addon_hotkey_pending_f2 = False

    def _poll_schedule_input_ocr_addon_hotkeys(self) -> None:
        if sys.platform != "win32" or not self.schedule_input_ocr_addon_hotkey_registered:
            return
        try:
            user32 = ctypes.windll.user32
            msg = WIN32_MSG()
            while bool(user32.PeekMessageW(ctypes.byref(msg), None, 0x0312, 0x0312, 0x0001)):
                if int(msg.message) == 0x0312 and int(msg.wParam) == SCHEDULE_INPUT_OCR_ADDON_GLOBAL_HOTKEY_ID_F2:
                    self.schedule_input_ocr_addon_hotkey_pending_f2 = True
        except Exception:
            self.schedule_input_ocr_addon_hotkey_pending_f2 = False

    def _force_window_foreground(self, hwnd: int) -> bool:
        if sys.platform != "win32" or not hwnd:
            return False
        try:
            user32 = ctypes.windll.user32
            kernel32 = ctypes.windll.kernel32
            hwnd = int(hwnd)
            foreground_hwnd = int(user32.GetForegroundWindow() or 0)
            foreground_thread = int(user32.GetWindowThreadProcessId(foreground_hwnd, None) or 0) if foreground_hwnd else 0
            target_thread = int(user32.GetWindowThreadProcessId(hwnd, None) or 0)
            current_thread = int(kernel32.GetCurrentThreadId() or 0)
            attached_to_foreground = False
            attached_to_target = False
            if foreground_thread and foreground_thread != current_thread:
                attached_to_foreground = bool(user32.AttachThreadInput(current_thread, foreground_thread, True))
            if target_thread and target_thread != current_thread:
                attached_to_target = bool(user32.AttachThreadInput(current_thread, target_thread, True))
            try:
                user32.ShowWindow(hwnd, 9)
                user32.BringWindowToTop(hwnd)
                user32.SetActiveWindow(hwnd)
                user32.SetFocus(hwnd)
                return bool(user32.SetForegroundWindow(hwnd))
            finally:
                if attached_to_foreground:
                    user32.AttachThreadInput(current_thread, foreground_thread, False)
                if attached_to_target:
                    user32.AttachThreadInput(current_thread, target_thread, False)
        except Exception:
            return False

    def _get_preferred_odin_window_handle(self) -> int:
        foreground = int(self._get_foreground_window_handle() or 0)
        foreground_root = int(self._get_root_window_handle(foreground) or 0)
        if foreground_root and self._is_valid_window_handle(foreground_root):
            foreground_title = self._get_window_text(foreground_root)
            if self._is_schedule_input_ocr_addon_target_title(foreground_title):
                return foreground_root
        for candidate in (
            int(self.schedule_input_ocr_addon_active_hwnd or 0),
            int(self.schedule_input_ocr_addon_last_odin_hwnd or 0),
        ):
            if candidate and self._is_valid_window_handle(candidate):
                return candidate
        found_handle = int(self._find_odin_window_handle() or 0)
        if found_handle and self._is_valid_window_handle(found_handle):
            return found_handle
        return 0

    def _find_odin_window_handle(self) -> int:
        if sys.platform != "win32":
            return 0
        user32 = ctypes.windll.user32
        foreground = self._get_foreground_window_handle()
        if foreground and self._is_schedule_input_ocr_addon_target_title(self._get_window_text(foreground)):
            return foreground
        found_candidates: list[tuple[int, int, int]] = []

        @ctypes.WINFUNCTYPE(wintypes.BOOL, wintypes.HWND, wintypes.LPARAM)
        def _enum_proc(hwnd, _lparam):
            try:
                if not user32.IsWindowVisible(hwnd):
                    return True
                hwnd_int = int(hwnd)
                title = self._get_window_text(hwnd_int)
                if self._is_schedule_input_ocr_addon_target_title(title):
                    client_rect = self._get_odin_client_screen_rect(hwnd_int)
                    client_area = 0
                    if isinstance(client_rect, dict):
                        client_area = int(client_rect.get("width") or 0) * int(client_rect.get("height") or 0)
                    window_rect = self._get_window_rect(hwnd_int)
                    window_area = 0
                    if isinstance(window_rect, dict):
                        window_area = int(window_rect.get("width") or 0) * int(window_rect.get("height") or 0)
                    found_candidates.append((client_area, window_area, hwnd_int))
            except Exception:
                return True
            return True

        try:
            user32.EnumWindows(_enum_proc, 0)
        except Exception:
            return 0
        if not found_candidates:
            return 0
        found_candidates.sort(key=lambda entry: (entry[0], entry[1], entry[2]), reverse=True)
        return int(found_candidates[0][2])

    def _get_odin_client_screen_rect(self, hwnd: int) -> dict[str, int] | None:
        if sys.platform != "win32" or not hwnd:
            return None
        try:
            user32 = ctypes.windll.user32
            client_rect = WIN32_RECT()
            if not user32.GetClientRect(hwnd, ctypes.byref(client_rect)):
                return None
            origin = WIN32_POINT(0, 0)
            if not user32.ClientToScreen(hwnd, ctypes.byref(origin)):
                return None
            width = max(1, int(client_rect.right - client_rect.left))
            height = max(1, int(client_rect.bottom - client_rect.top))
            return {
                "left": int(origin.x),
                "top": int(origin.y),
                "right": int(origin.x + width),
                "bottom": int(origin.y + height),
                "width": width,
                "height": height,
            }
        except Exception:
            return None

    def _format_odin_client_rect_text(self, rect: dict[str, int] | None) -> str:
        if not isinstance(rect, dict):
            return "-"
        width = int(rect.get("width") or 0)
        height = int(rect.get("height") or 0)
        left = int(rect.get("left") or 0)
        top = int(rect.get("top") or 0)
        if width <= 0 or height <= 0:
            return "-"
        return f"{width}x{height}@{left},{top}"

    def _format_window_rect_text(self, rect: dict[str, int] | None) -> str:
        if not isinstance(rect, dict):
            return "-"
        width = int(rect.get("width") or 0)
        height = int(rect.get("height") or 0)
        left = int(rect.get("left") or 0)
        top = int(rect.get("top") or 0)
        if width <= 0 or height <= 0:
            return "-"
        return f"{width}x{height}@{left},{top}"

    def _format_window_resize_debug_text(self, hwnd: int) -> str:
        if not hwnd or not self._is_valid_window_handle(hwnd):
            return "hwnd=0"
        title = self._get_window_text(hwnd) or "-"
        class_name = self._get_window_class_name(hwnd) or "-"
        window_rect = self._get_window_rect(hwnd)
        client_rect = self._get_odin_client_screen_rect(hwnd)
        hit_test = int(getattr(self, "schedule_input_ocr_addon_resize_target_hit_test", 0) or 0)
        path = str(getattr(self, "schedule_input_ocr_addon_resize_last_path", "") or "-")
        return (
            f"hwnd={int(hwnd):#x} title={title} class={class_name} hit={hit_test} "
            f"window={self._format_window_rect_text(window_rect)} "
            f"client={self._format_odin_client_rect_text(client_rect)} path={path}"
        )

    def _get_clip_cursor_rect(self) -> dict[str, int] | None:
        if sys.platform != "win32":
            return None
        try:
            user32 = ctypes.windll.user32
            rect = WIN32_RECT()
            if not user32.GetClipCursor(ctypes.byref(rect)):
                return None
            left = int(rect.left)
            top = int(rect.top)
            right = int(rect.right)
            bottom = int(rect.bottom)
            return {
                "left": left,
                "top": top,
                "right": right,
                "bottom": bottom,
                "width": max(1, right - left),
                "height": max(1, bottom - top),
            }
        except Exception:
            return None

    def _cancel_schedule_input_ocr_addon_resize_verify(self) -> None:
        after_id = self.schedule_input_ocr_addon_resize_verify_after_id
        self.schedule_input_ocr_addon_resize_verify_after_id = None
        if after_id is None or self.root is None:
            return
        try:
            self.root.after_cancel(after_id)
        except Exception:
            pass

    def _append_debug_log(self, message: str) -> None:
        try:
            log_path = os.path.join(get_app_root(), "boss_timer_debug.log")
            with open(log_path, "a", encoding="utf-8") as debug_file:
                debug_file.write(f"[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] {message}\n")
        except Exception:
            pass

    def _verify_schedule_input_ocr_addon_resize(self, hwnd: int, client_width: int, client_height: int, before_text: str, target_text: str) -> None:
        self.schedule_input_ocr_addon_resize_verify_after_id = None
        if self.schedule_input_ocr_addon_window is None or not self.schedule_input_ocr_addon_window.winfo_exists():
            return
        current_rect = self._get_odin_client_screen_rect(hwnd)
        current_text = self._format_odin_client_rect_text(current_rect)
        debug_text = self._format_window_resize_debug_text(hwnd)
        if not isinstance(current_rect, dict):
            self.schedule_input_ocr_addon_status_var.set(
                f"{target_text} 재확인 실패: 현재 창 정보를 읽지 못했습니다. (시도 {before_text} -> {target_text}) [{debug_text}]"
            )
            return
        current_width = int(current_rect.get("width") or 0)
        current_height = int(current_rect.get("height") or 0)
        if current_width == int(client_width) and current_height == int(client_height):
            self.schedule_input_ocr_addon_status_var.set(
                f"{target_text} 유지 확인 ({before_text} -> {target_text} -> {current_text}) [{debug_text}]"
            )
            return
        self.schedule_input_ocr_addon_status_var.set(
            f"{target_text} 원복 감지 ({before_text} -> {target_text} -> {current_text}) [{debug_text}]"
        )

    def _resize_odin_client_window(self, hwnd: int, client_width: int = 1600, client_height: int = 900) -> bool:
        if sys.platform != "win32" or not hwnd:
            return False
        try:
            user32 = ctypes.windll.user32
            kernel32 = ctypes.windll.kernel32
            self.schedule_input_ocr_addon_resize_last_error = 0
            self.schedule_input_ocr_addon_resize_last_path = "start"
            current_rect = self._get_odin_client_screen_rect(hwnd)
            if isinstance(current_rect, dict):
                current_width = int(current_rect.get("width") or 0)
                current_height = int(current_rect.get("height") or 0)
                if current_width == int(client_width) and current_height == int(client_height):
                    self.schedule_input_ocr_addon_resize_last_path = "already-matched"
                    return True
            try:
                if bool(user32.IsIconic(hwnd)):
                    user32.ShowWindow(hwnd, 9)
                elif bool(user32.IsZoomed(hwnd)):
                    user32.ShowWindow(hwnd, 9)
            except Exception:
                pass
            rect = WIN32_RECT(0, 0, int(client_width), int(client_height))
            style = int(user32.GetWindowLongW(hwnd, -16) or 0)
            ex_style = int(user32.GetWindowLongW(hwnd, -20) or 0)
            adjusted = False
            try:
                adjust_for_dpi = getattr(user32, "AdjustWindowRectExForDpi", None)
                if callable(adjust_for_dpi):
                    adjusted = bool(adjust_for_dpi(ctypes.byref(rect), style, False, ex_style, self._get_window_dpi(hwnd)))
            except Exception:
                adjusted = False
            if not adjusted:
                if not user32.AdjustWindowRectEx(ctypes.byref(rect), style, False, ex_style):
                    return False
            target_width = max(1, int(rect.right - rect.left))
            target_height = max(1, int(rect.bottom - rect.top))
            window_rect = self._get_window_rect(hwnd)
            if not isinstance(window_rect, dict):
                return False
            left = int(window_rect.get("left") or 0)
            top = int(window_rect.get("top") or 0)
            flags = 0x0004 | 0x0010 | 0x0020 | 0x0040
            self.schedule_input_ocr_addon_resize_last_path = "SetWindowPos"
            if bool(user32.SetWindowPos(hwnd, None, left, top, target_width, target_height, flags)):
                if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                    self.schedule_input_ocr_addon_resize_last_error = 0
                    self.schedule_input_ocr_addon_resize_last_path = "SetWindowPos"
                    return True
            self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
            try:
                self.schedule_input_ocr_addon_resize_last_path = "MoveWindow"
                if bool(user32.MoveWindow(hwnd, left, top, target_width, target_height, True)):
                    if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                        self.schedule_input_ocr_addon_resize_last_error = 0
                        self.schedule_input_ocr_addon_resize_last_path = "MoveWindow"
                        return True
            except Exception:
                pass
            self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
            current_client_rect = self._get_odin_client_screen_rect(hwnd)
            latest_window_rect = self._get_window_rect(hwnd)
            if isinstance(current_client_rect, dict) and isinstance(latest_window_rect, dict):
                frame_width = max(0, int(latest_window_rect.get("width") or 0) - int(current_client_rect.get("width") or 0))
                frame_height = max(0, int(latest_window_rect.get("height") or 0) - int(current_client_rect.get("height") or 0))
                fallback_width = max(1, int(client_width) + frame_width)
                fallback_height = max(1, int(client_height) + frame_height)
                self.schedule_input_ocr_addon_resize_last_path = "SetWindowPos+frame"
                if bool(user32.SetWindowPos(hwnd, None, int(latest_window_rect.get("left") or 0), int(latest_window_rect.get("top") or 0), fallback_width, fallback_height, flags)):
                    if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                        self.schedule_input_ocr_addon_resize_last_error = 0
                        self.schedule_input_ocr_addon_resize_last_path = "SetWindowPos+frame"
                        return True
                self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
            if self._apply_window_resize_style_fallback(hwnd):
                window_rect = self._get_window_rect(hwnd)
                left = int(window_rect.get("left") or 0) if isinstance(window_rect, dict) else 0
                top = int(window_rect.get("top") or 0) if isinstance(window_rect, dict) else 0
                self.schedule_input_ocr_addon_resize_last_path = "style+SetWindowPos"
                if bool(user32.SetWindowPos(hwnd, None, left, top, target_width, target_height, flags)):
                    if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                        self.schedule_input_ocr_addon_resize_last_error = 0
                        self.schedule_input_ocr_addon_resize_last_path = "style+SetWindowPos"
                        return True
                self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
                try:
                    self.schedule_input_ocr_addon_resize_last_path = "style+MoveWindow"
                    if bool(user32.MoveWindow(hwnd, left, top, target_width, target_height, True)):
                        if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                            self.schedule_input_ocr_addon_resize_last_error = 0
                            self.schedule_input_ocr_addon_resize_last_path = "style+MoveWindow"
                            return True
                except Exception:
                    pass
                self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
            if self._apply_window_placement_resize_fallback(hwnd, left, top, target_width, target_height):
                self.schedule_input_ocr_addon_resize_last_path = "placement"
                if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                    self.schedule_input_ocr_addon_resize_last_error = 0
                    return True
                self.schedule_input_ocr_addon_resize_last_path = "placement+SetWindowPos"
                if bool(user32.SetWindowPos(hwnd, None, left, top, target_width, target_height, flags)):
                    if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                        self.schedule_input_ocr_addon_resize_last_error = 0
                        return True
                self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
            if self._simulate_window_drag_resize_fallback(hwnd, target_width, target_height):
                self.schedule_input_ocr_addon_resize_last_path = "drag"
                if self._wait_for_odin_client_size(hwnd, client_width, client_height):
                    self.schedule_input_ocr_addon_resize_last_error = 0
                    return True
            self.schedule_input_ocr_addon_resize_last_error = int(kernel32.GetLastError() or 0)
            return False
        except Exception:
            try:
                self.schedule_input_ocr_addon_resize_last_error = int(ctypes.windll.kernel32.GetLastError() or 0)
            except Exception:
                self.schedule_input_ocr_addon_resize_last_error = 0
            return False

    def _capture_screen_rect_to_png(self, left: int, top: int, width: int, height: int, target_path: str) -> bool:
        if width <= 0 or height <= 0 or not target_path:
            return False
        script = (
            "[Console]::OutputEncoding = [System.Text.Encoding]::UTF8\n"
            "$ErrorActionPreference = 'Stop'\n"
            "Add-Type -AssemblyName System.Drawing -ErrorAction Stop\n"
            f"$left = [int]{int(left)}\n"
            f"$top = [int]{int(top)}\n"
            f"$width = [int]{int(width)}\n"
            f"$height = [int]{int(height)}\n"
            f"$targetPath = '{self._quote_powershell_literal(target_path)}'\n"
            "$bitmap = New-Object System.Drawing.Bitmap($width, $height)\n"
            "$graphics = [System.Drawing.Graphics]::FromImage($bitmap)\n"
            "try {\n"
            "  $graphics.CopyFromScreen($left, $top, 0, 0, $bitmap.Size)\n"
            "  $bitmap.Save($targetPath, [System.Drawing.Imaging.ImageFormat]::Png)\n"
            "  [PSCustomObject]@{ ok = $true; path = $targetPath } | ConvertTo-Json -Compress\n"
            "} catch {\n"
            "  [PSCustomObject]@{ ok = $false; error = $_.Exception.Message } | ConvertTo-Json -Compress\n"
            "} finally {\n"
            "  $graphics.Dispose()\n"
            "  $bitmap.Dispose()\n"
            "}\n"
        )
        ok, output = self._run_schedule_ocr_powershell(script, sta=True)
        if not ok or not output:
            return False
        try:
            payload = json.loads(output)
        except json.JSONDecodeError:
            return False
        return isinstance(payload, dict) and bool(payload.get("ok"))

    def _normalize_captured_png_size(self, image_path: str, target_width: int, target_height: int) -> bool:
        safe_path = str(image_path or "").strip()
        if not safe_path or target_width <= 0 or target_height <= 0 or not os.path.exists(safe_path):
            return False
        actual_size = get_png_image_size(safe_path)
        if actual_size == (int(target_width), int(target_height)):
            return True
        temp_path = os.path.join(
            os.path.dirname(safe_path),
            f"{Path(safe_path).stem}_normalized_{uuid.uuid4().hex}.png",
        )
        script = (
            "[Console]::OutputEncoding = [System.Text.Encoding]::UTF8\n"
            "$ErrorActionPreference = 'Stop'\n"
            "Add-Type -AssemblyName System.Drawing -ErrorAction Stop\n"
            f"$sourcePath = '{self._quote_powershell_literal(safe_path)}'\n"
            f"$tempPath = '{self._quote_powershell_literal(temp_path)}'\n"
            f"$targetWidth = [int]{int(target_width)}\n"
            f"$targetHeight = [int]{int(target_height)}\n"
            "$sourceBitmap = [System.Drawing.Bitmap]::FromFile($sourcePath)\n"
            "$targetBitmap = New-Object System.Drawing.Bitmap($targetWidth, $targetHeight)\n"
            "$graphics = [System.Drawing.Graphics]::FromImage($targetBitmap)\n"
            "try {\n"
            "  $graphics.InterpolationMode = [System.Drawing.Drawing2D.InterpolationMode]::HighQualityBicubic\n"
            "  $graphics.PixelOffsetMode = [System.Drawing.Drawing2D.PixelOffsetMode]::HighQuality\n"
            "  $graphics.SmoothingMode = [System.Drawing.Drawing2D.SmoothingMode]::HighQuality\n"
            "  $graphics.DrawImage($sourceBitmap, 0, 0, $targetWidth, $targetHeight)\n"
            "  $targetBitmap.Save($tempPath, [System.Drawing.Imaging.ImageFormat]::Png)\n"
            "  [PSCustomObject]@{ ok = $true; path = $tempPath } | ConvertTo-Json -Compress\n"
            "} catch {\n"
            "  [PSCustomObject]@{ ok = $false; error = $_.Exception.Message } | ConvertTo-Json -Compress\n"
            "} finally {\n"
            "  $graphics.Dispose()\n"
            "  $targetBitmap.Dispose()\n"
            "  $sourceBitmap.Dispose()\n"
            "}\n"
        )
        ok, output = self._run_schedule_ocr_powershell(script, sta=True)
        if not ok or not output:
            if os.path.exists(temp_path):
                try:
                    os.remove(temp_path)
                except OSError:
                    pass
            return False
        try:
            payload = json.loads(output)
        except json.JSONDecodeError:
            payload = {}
        if not isinstance(payload, dict) or not bool(payload.get("ok")) or not os.path.exists(temp_path):
            if os.path.exists(temp_path):
                try:
                    os.remove(temp_path)
                except OSError:
                    pass
            return False
        try:
            os.replace(temp_path, safe_path)
        except OSError:
            try:
                if os.path.exists(temp_path):
                    os.remove(temp_path)
            except OSError:
                pass
            return False
        return get_png_image_size(safe_path) == (int(target_width), int(target_height))

    def _create_schedule_input_ocr_item_from_path(
        self,
        image_path: str,
        *,
        width: int,
        height: int,
        source: str,
    ) -> dict[str, object] | None:
        safe_path = str(image_path or "").strip()
        if not safe_path or not os.path.exists(safe_path):
            return None
        return {
            "id": uuid.uuid4().hex,
            "path": safe_path,
            "width": int(width or 0),
            "height": int(height or 0),
            "thumbnail": None,
            "area_guess": "",
            "warning_count": 0,
            "source": str(source or ""),
            "captured_at": datetime.now(),
        }

    def _append_schedule_input_ocr_item_to_queue(
        self,
        item: dict[str, object],
        *,
        announce: bool = True,
        allow_internal_move: bool = False,
    ) -> bool:
        if not isinstance(item, dict):
            return False
        if self.schedule_input_ocr_worker_active:
            self.schedule_input_status_var.set("OCR 변환 중에는 이미지를 추가할 수 없습니다.")
            return False
        item_copy = dict(item)
        content_hash = self._get_schedule_input_ocr_item_content_hash(item_copy)
        is_duplicate = False
        if content_hash:
            if allow_internal_move:
                for existing_item in self.schedule_input_ocr_items:
                    if self._get_schedule_input_ocr_item_content_hash(existing_item) == content_hash:
                        is_duplicate = True
                        break
            else:
                is_duplicate = self._schedule_input_ocr_is_duplicate_content_hash(content_hash)
        if content_hash and is_duplicate:
            image_path = str(item_copy.get("path") or "").strip()
            if image_path and not self._schedule_input_ocr_path_in_use(image_path) and os.path.exists(image_path):
                try:
                    os.remove(image_path)
                except OSError:
                    pass
            if announce:
                self.schedule_input_status_var.set("같은 스샷은 이미 대기열에 있습니다.")
            return False
        if content_hash:
            item_copy["content_hash"] = content_hash
            self._schedule_input_ocr_register_content_hash(content_hash)
        self.schedule_input_ocr_items.append(item_copy)
        self._invalidate_schedule_input_ocr_results("새 스샷이 추가되었습니다. OCR 변환을 눌러 결과를 갱신하세요.")
        self._refresh_schedule_input_ocr_queue_widgets()
        if self.schedule_input_ocr_addon_window is not None and self.schedule_input_ocr_addon_window.winfo_exists():
            self._refresh_schedule_input_ocr_addon_stack_widgets()
        if announce:
            self.schedule_input_status_var.set(f"OCR 대기열에 이미지 {len(self.schedule_input_ocr_items)}장을 추가했습니다.")
        if self.schedule_input_ocr_queue_canvas is not None and self.schedule_input_ocr_queue_canvas.winfo_exists():
            try:
                self.schedule_input_ocr_queue_canvas.xview_moveto(1.0)
            except tk.TclError:
                pass
        return True

    def _append_schedule_input_ocr_item_to_addon_stack(self, item: dict[str, object], *, announce: bool = True) -> bool:
        if not isinstance(item, dict):
            return False
        if self.schedule_input_ocr_worker_active:
            self.schedule_input_status_var.set("OCR 변환 중에는 스택에 이미지를 추가할 수 없습니다.")
            return False
        item_copy = dict(item)
        content_hash = self._get_schedule_input_ocr_item_content_hash(item_copy)
        if content_hash and self._schedule_input_ocr_is_duplicate_content_hash(content_hash):
            image_path = str(item_copy.get("path") or "").strip()
            if image_path and not self._schedule_input_ocr_path_in_use(image_path) and os.path.exists(image_path):
                try:
                    os.remove(image_path)
                except OSError:
                    pass
            if announce:
                self.schedule_input_ocr_addon_status_var.set("같은 스샷은 이미 스택/대기열에 있습니다.")
            return False
        if content_hash:
            item_copy["content_hash"] = content_hash
            self._schedule_input_ocr_register_content_hash(content_hash)
        self.schedule_input_ocr_addon_stack_items.append(item_copy)
        self._refresh_schedule_input_ocr_addon_stack_widgets()
        if announce:
            self.schedule_input_ocr_addon_status_var.set(f"스택에 이미지 {len(self.schedule_input_ocr_addon_stack_items)}장을 쌓았습니다.")
        return True

    def _flush_schedule_input_ocr_addon_stack_to_queue(self, *, announce: bool = False, close_after: bool = False) -> int:
        if self.schedule_input_ocr_worker_active:
            return 0
        if not self.schedule_input_ocr_addon_stack_items:
            return 0
        moved_items = [dict(item) for item in self.schedule_input_ocr_addon_stack_items]
        self.schedule_input_ocr_addon_stack_items = []
        moved_count = 0
        for item in moved_items:
            if self._append_schedule_input_ocr_item_to_queue(item, announce=False, allow_internal_move=True):
                moved_count += 1
        self._refresh_schedule_input_ocr_addon_stack_widgets()
        if announce and moved_count > 0:
            self.schedule_input_status_var.set(f"캡처 스택 {moved_count}장을 OCR 대기열로 옮겼습니다.")
        if close_after and moved_count > 0:
            self._close_schedule_input_ocr_addon_window()
        return moved_count

    def _capture_active_odin_window_image(self, hwnd: int | None = None) -> dict[str, object] | None:
        hwnd = int(hwnd or 0)
        if not self._is_valid_window_handle(hwnd):
            hwnd = self._get_preferred_odin_window_handle()
        if not hwnd:
            return None
        self.schedule_input_ocr_addon_active_hwnd = hwnd
        rect = self._get_odin_client_screen_rect(hwnd)
        if not isinstance(rect, dict):
            return None
        target_path = os.path.join(self._get_schedule_ocr_cache_dir(), f"odin_{uuid.uuid4().hex}.png")
        if not self._capture_screen_rect_to_png(int(rect["left"]), int(rect["top"]), int(rect["width"]), int(rect["height"]), target_path):
            if os.path.exists(target_path):
                try:
                    os.remove(target_path)
                except OSError:
                    pass
            return None
        expected_width = int(rect["width"] or 0)
        expected_height = int(rect["height"] or 0)
        actual_size = get_png_image_size(target_path)
        if actual_size is not None and actual_size != (expected_width, expected_height):
            self._append_debug_log(
                f"capture_size_mismatch hwnd={int(hwnd):#x} expected={expected_width}x{expected_height} "
                f"actual={int(actual_size[0])}x{int(actual_size[1])}"
            )
            if self._normalize_captured_png_size(target_path, expected_width, expected_height):
                self._append_debug_log(
                    f"capture_size_normalized hwnd={int(hwnd):#x} size={expected_width}x{expected_height}"
                )
            else:
                normalized_size = get_png_image_size(target_path)
                if normalized_size is not None:
                    expected_width = int(normalized_size[0])
                    expected_height = int(normalized_size[1])
                    self._append_debug_log(
                        f"capture_size_normalize_failed hwnd={int(hwnd):#x} fallback={expected_width}x{expected_height}"
                    )
        return {
            "path": target_path,
            "width": int(expected_width),
            "height": int(expected_height),
            "hwnd": int(hwnd),
            "title": self._get_window_text(hwnd),
        }

    def _capture_schedule_input_ocr_from_odin(self, *, announce: bool = True) -> None:
        if self.schedule_input_ocr_worker_active:
            self.schedule_input_status_var.set("OCR 변환 중에는 스샷을 추가할 수 없습니다.")
            return
        if self.schedule_input_ocr_addon_busy:
            return
        hwnd = self._get_preferred_odin_window_handle()
        if not hwnd:
            self.schedule_input_status_var.set("오딘 창을 찾지 못했습니다.")
            self.schedule_input_ocr_addon_status_var.set("오딘 창을 찾지 못했습니다.")
            return
        self.schedule_input_ocr_addon_active_hwnd = hwnd
        self.schedule_input_ocr_addon_last_odin_hwnd = hwnd
        if not self.schedule_input_ocr_addon_open:
            self._open_schedule_input_ocr_addon()
        self.schedule_input_ocr_addon_busy = True
        self._update_schedule_input_ocr_addon_controls()
        session_id = int(self.schedule_input_ocr_addon_session_id or 0)
        def worker(current_hwnd: int) -> None:
            target_hwnd = int(current_hwnd or 0)
            if not self._is_valid_window_handle(target_hwnd):
                target_hwnd = self._get_preferred_odin_window_handle()
            if not target_hwnd:
                if self.root is not None and self.root.winfo_exists():
                    self.root.after(0, lambda: self._finish_schedule_input_ocr_addon_capture("오딘 창을 찾지 못했습니다."))
                return
            capture = self._capture_active_odin_window_image(target_hwnd)
            if capture is None:
                if self.root is not None and self.root.winfo_exists():
                    self.root.after(0, lambda: self._finish_schedule_input_ocr_addon_capture("오딘 스샷을 캡처하지 못했습니다."))
                return
            prepared_item = self._create_schedule_input_ocr_item_from_path(
                str(capture.get("path") or ""),
                width=int(capture.get("width") or 0),
                height=int(capture.get("height") or 0),
                source="odin_fast",
            )
            if prepared_item is None:
                image_path = str(capture.get("path") or "").strip()
                if image_path and os.path.exists(image_path):
                    try:
                        os.remove(image_path)
                    except OSError:
                        pass
                if self.root is not None and self.root.winfo_exists():
                    self.root.after(0, lambda: self._finish_schedule_input_ocr_addon_capture("오딘 스샷을 준비하지 못했습니다."))
                return
            content_hash = self._compute_schedule_input_ocr_content_hash(str(prepared_item.get("path") or ""))
            if content_hash:
                prepared_item["content_hash"] = content_hash
            def finish() -> None:
                if session_id != int(self.schedule_input_ocr_addon_session_id or 0):
                    image_path = str(capture.get("path") or "").strip()
                    if image_path and os.path.exists(image_path):
                        try:
                            os.remove(image_path)
                        except OSError:
                            pass
                    return
                if self._append_schedule_input_ocr_item_to_queue(prepared_item, announce=announce):
                    self._finish_schedule_input_ocr_addon_capture(
                        f"OCR 대기열에 이미지 1장을 추가했습니다. (총 {len(self.schedule_input_ocr_items)}장)"
                    )
                else:
                    image_path = str(capture.get("path") or "").strip()
                    if image_path and not self._schedule_input_ocr_path_in_use(image_path) and os.path.exists(image_path):
                        try:
                            os.remove(image_path)
                        except OSError:
                            pass
                    self._finish_schedule_input_ocr_addon_capture("같은 스샷은 이미 대기열에 있습니다.")
            if self.root is not None and self.root.winfo_exists():
                self.root.after(0, finish)
        threading.Thread(target=worker, args=(hwnd,), daemon=True).start()

    def _request_schedule_input_ocr_capture_from_odin(self, *, announce: bool = True) -> None:
        if self.schedule_input_ocr_addon_busy:
            return
        now_monotonic = time.monotonic()
        last_capture_at = float(getattr(self, "schedule_input_ocr_addon_last_capture_at", 0.0) or 0.0)
        if now_monotonic - last_capture_at < SCHEDULE_INPUT_OCR_ADDON_CAPTURE_DEBOUNCE_SECONDS:
            return
        self.schedule_input_ocr_addon_last_capture_at = now_monotonic
        self._capture_schedule_input_ocr_from_odin(announce=announce)

    def _finish_schedule_input_ocr_addon_capture(self, status_text: str = "") -> None:
        self.schedule_input_ocr_addon_busy = False
        if status_text:
            try:
                self.schedule_input_ocr_addon_status_var.set(status_text)
            except tk.TclError:
                pass
        self._update_schedule_input_ocr_addon_controls()

    def _resize_schedule_input_ocr_addon_odin_window(self, client_width: int = 1600, client_height: int = 900) -> None:
        if self.schedule_input_ocr_worker_active:
            self.schedule_input_ocr_addon_status_var.set("OCR 변환 중에는 창 크기를 바꿀 수 없습니다.")
            self._append_debug_log("resize_blocked:ocr_worker_active")
            return
        hwnd = self._get_schedule_input_ocr_addon_resize_target_window_handle()
        if not hwnd:
            self.schedule_input_ocr_addon_status_var.set("대상 창을 찾지 못했습니다.")
            self._append_debug_log("resize_failed:no_target_hwnd")
            return
        title_text = self._get_window_text(hwnd) or self._get_window_class_name(hwnd) or f"hwnd={int(hwnd)}"
        if self._is_schedule_input_ocr_addon_target_title(title_text):
            self.schedule_input_ocr_addon_active_hwnd = hwnd
            self.schedule_input_ocr_addon_last_odin_hwnd = hwnd
        before_rect = self._get_odin_client_screen_rect(hwnd)
        before_text = self._format_odin_client_rect_text(before_rect)
        debug_text = self._format_window_resize_debug_text(hwnd)
        self._append_debug_log(f"resize_begin size={int(client_width)}x{int(client_height)} {debug_text}")
        try:
            user32 = ctypes.windll.user32
            style_value = int(user32.GetWindowLongW(hwnd, WINDOW_GWL_STYLE) or 0)
            ex_style_value = int(user32.GetWindowLongW(hwnd, WINDOW_GWL_EXSTYLE) or 0)
        except Exception:
            style_value = 0
            ex_style_value = 0
        ok = self._resize_odin_client_window(hwnd, int(client_width), int(client_height))
        after_rect = self._get_odin_client_screen_rect(hwnd)
        after_text = self._format_odin_client_rect_text(after_rect)
        target_size_text = f"{int(client_width)}x{int(client_height)}"
        if ok:
            self.schedule_input_ocr_addon_status_var.set(f"{title_text}: {target_size_text} 적용 시도 ({before_text} -> {after_text}) [{debug_text}]")
            self._append_debug_log(f"resize_ok size={target_size_text} before={before_text} after={after_text} path={getattr(self, 'schedule_input_ocr_addon_resize_last_path', '')} {debug_text}")
            self._cancel_schedule_input_ocr_addon_resize_verify()
            if self.root is not None and self.root.winfo_exists():
                self.schedule_input_ocr_addon_resize_verify_after_id = self.root.after(
                    250,
                    lambda hwnd=hwnd, client_width=int(client_width), client_height=int(client_height), before_text=before_text, target_text=target_size_text: self._verify_schedule_input_ocr_addon_resize(
                        hwnd,
                        client_width,
                        client_height,
                        before_text,
                        target_text,
                    ),
                )
        else:
            last_error = int(getattr(self, "schedule_input_ocr_addon_resize_last_error", 0) or 0)
            error_text = f", last_error={last_error}" if last_error else ""
            self.schedule_input_ocr_addon_status_var.set(
                f"{title_text}: {target_size_text} 적용 실패 ({before_text} -> {after_text}){error_text}, "
                f"style={style_value:#x}, exstyle={ex_style_value:#x}, [{debug_text}]"
            )
            self._append_debug_log(f"resize_fail size={target_size_text} before={before_text} after={after_text} last_error={last_error} style={style_value:#x} exstyle={ex_style_value:#x} path={getattr(self, 'schedule_input_ocr_addon_resize_last_path', '')} {debug_text}")
        self._position_schedule_input_ocr_addon_window()
        self._update_schedule_input_ocr_addon_controls()

    def _on_schedule_input_ocr_addon_resize_menu_choice(self, client_width: int, client_height: int) -> None:
        target_hwnd = self._get_schedule_input_ocr_addon_resize_target_window_handle()
        size_text = f"{int(client_width)}x{int(client_height)}"
        if not target_hwnd:
            self.schedule_input_ocr_addon_status_var.set(f"{size_text} 메뉴는 눌렸지만 대상 창을 찾지 못했습니다.")
            self._append_debug_log(f"menu_choice size={size_text} target=NONE")
            return
        self.schedule_input_ocr_addon_resize_last_path = f"menu:{size_text}"
        self.schedule_input_ocr_addon_status_var.set(f"{size_text} 메뉴를 선택했습니다. 대상 창을 바꾸는 중...")
        self._append_debug_log(f"menu_choice size={size_text} target={self._format_window_resize_debug_text(target_hwnd)}")
        self._resize_schedule_input_ocr_addon_odin_window(int(client_width), int(client_height))

    def _show_schedule_input_ocr_addon_resize_menu(self, event=None, *, target_hwnd: int = 0) -> str | None:
        menu = self.schedule_input_ocr_addon_resize_menu
        if menu is None:
            return None
        if target_hwnd and self._is_valid_window_handle(target_hwnd):
            self.schedule_input_ocr_addon_resize_target_hwnd = int(target_hwnd)
        if event is None:
            return None
        try:
            x_root = int(event.x_root)
            y_root = int(event.y_root)
        except (TypeError, ValueError, tk.TclError):
            return None
        try:
            menu.tk_popup(x_root, y_root)
        except tk.TclError:
            return None
        finally:
            try:
                menu.grab_release()
            except tk.TclError:
                pass
        return "break"

    def _show_schedule_input_ocr_addon_resize_menu_at(self, target_hwnd: int, x_root: int, y_root: int) -> bool:
        menu = self.schedule_input_ocr_addon_resize_menu
        if menu is None:
            return False
        if target_hwnd and self._is_valid_window_handle(target_hwnd):
            self.schedule_input_ocr_addon_resize_target_hwnd = int(target_hwnd)
        try:
            menu.tk_popup(int(x_root), int(y_root))
        except tk.TclError:
            return False
        finally:
            try:
                menu.grab_release()
            except tk.TclError:
                pass
        return True

    def _is_schedule_input_ocr_addon_resize_menu_open(self) -> bool:
        menu = self.schedule_input_ocr_addon_resize_menu
        if menu is None:
            return False
        try:
            return bool(menu.winfo_exists() and menu.winfo_ismapped())
        except tk.TclError:
            return False

    def _maybe_show_schedule_input_ocr_addon_resize_menu_from_cursor(self) -> bool:
        if not self.schedule_input_ocr_addon_open or self.schedule_input_ocr_worker_active:
            return False
        cursor_pos = self._get_cursor_screen_pos()
        if cursor_pos is None:
            return False
        cursor_x, cursor_y = cursor_pos
        hwnd = self._get_window_from_screen_point(cursor_x, cursor_y)
        if not hwnd:
            return False
        hit_test = self._get_window_nchit_test(hwnd, cursor_x, cursor_y)
        self.schedule_input_ocr_addon_resize_target_hit_test = int(hit_test)
        if hit_test != WINDOW_HITTEST_CLOSE and not self._is_cursor_in_window_resize_hotzone(hwnd, cursor_x, cursor_y):
            return False
        return self._show_schedule_input_ocr_addon_resize_menu_at(hwnd, cursor_x, cursor_y)

    def _transfer_schedule_input_ocr_addon_stack_to_queue(self) -> None:
        if self.schedule_input_ocr_worker_active:
            self.schedule_input_ocr_addon_status_var.set("OCR 변환 중에는 스택을 넘길 수 없습니다.")
            return
        if not self.schedule_input_ocr_addon_stack_items:
            self.schedule_input_ocr_addon_status_var.set("넘길 스택이 없습니다.")
            return
        moved_count = self._flush_schedule_input_ocr_addon_stack_to_queue(announce=False, close_after=False)
        self.schedule_input_status_var.set(f"애드온 스택 {moved_count}장을 대기열로 넘겼습니다.")
        self.schedule_input_ocr_addon_status_var.set(f"대기열로 {moved_count}장을 전송했습니다.")
        self._refresh_schedule_input_ocr_queue_widgets()

    def _toggle_schedule_input_ocr_addon_fast_input(self) -> None:
        self.schedule_input_ocr_addon_fast_input_enabled = bool(self.schedule_input_ocr_addon_fast_input_var.get())
        self._save_settings()

    def _on_schedule_input_ocr_addon_f2_keypress(self, _event=None) -> str | None:
        if not self.schedule_input_ocr_addon_open or self.schedule_input_ocr_worker_active or self.schedule_input_ocr_addon_busy:
            return "break"
        self.schedule_input_ocr_addon_f2_down = True
        self._request_schedule_input_ocr_capture_from_odin()
        return "break"

    def _is_schedule_input_ocr_addon_hotkey_pressed(self, vk_code: int) -> bool:
        if sys.platform != "win32":
            return False
        try:
            state = int(ctypes.windll.user32.GetAsyncKeyState(int(vk_code)) or 0)
        except Exception:
            return False
        return bool(state & 0x8000 or state & 0x0001)

    def _refresh_schedule_input_ocr_addon_stack_widgets(self) -> None:
        frame = self.schedule_input_ocr_addon_stack_inner_frame
        self._update_schedule_input_ocr_addon_controls()
        if self.schedule_input_ocr_addon_count_label is not None and self.schedule_input_ocr_addon_count_label.winfo_exists():
            try:
                self.schedule_input_ocr_addon_count_label.config(text=f"총 {len(self.schedule_input_ocr_items)}장")
            except tk.TclError:
                pass
        if frame is None or not frame.winfo_exists():
            return
        for child in frame.winfo_children():
            try:
                child.destroy()
            except tk.TclError:
                continue
        if not self.schedule_input_ocr_addon_stack_items:
            hint_label = tk.Label(
                frame,
                text="스샷찍기 또는 F2로 캡처하면 여기에 쌓입니다.\n전송을 눌러 대기열로 넘기세요.",
                font=self.percent_font,
                bg="#dff8fb",
                fg="#0f766e",
                anchor="w",
                justify="left",
                wraplength=284,
            )
            hint_label.place(x=10, y=28, width=284, height=48)
            self.schedule_input_ocr_addon_stack_hint_label = hint_label
            self._sync_schedule_input_ocr_addon_stack_scrollregion()
            return
        frame_width = 12 + (len(self.schedule_input_ocr_addon_stack_items) * 102)
        frame.configure(width=max(300, frame_width), height=116)
        for index, item in enumerate(self.schedule_input_ocr_addon_stack_items):
            item_frame = tk.Frame(frame, bg="#ccfbf1", relief="solid", bd=1, highlightthickness=0)
            item_frame.place(x=10 + (index * 102), y=10, width=94, height=92)
            preview_item_id = str(item.get("id") or "")
            thumbnail = item.get("thumbnail")
            if isinstance(thumbnail, tk.PhotoImage):
                thumb_label = tk.Label(item_frame, image=thumbnail, bg="#ccfbf1")
                thumb_label.image = thumbnail
                thumb_label.place(x=3, y=3, width=88, height=56)
                thumb_label.bind("<Button-1>", lambda _event, current_id=preview_item_id: self._open_schedule_input_ocr_preview(current_id))
            else:
                width_text = int(item.get("width") or 0)
                height_text = int(item.get("height") or 0)
                placeholder_text = "스샷"
                if width_text > 0 and height_text > 0:
                    placeholder_text = f"{width_text}x{height_text}"
                thumb_label = tk.Label(
                    item_frame,
                    text=placeholder_text,
                    font=(self.current_font_family, 8, "bold"),
                    bg="#99f6e4",
                    fg="#115e59",
                    relief="flat",
                    anchor="center",
                    justify="center",
                )
                thumb_label.place(x=3, y=3, width=88, height=56)
                thumb_label.bind("<Button-1>", lambda _event, current_id=preview_item_id: self._open_schedule_input_ocr_preview(current_id))
            info_text = f"{index + 1}"
            source_label = str(item.get("source") or "").strip()
            if source_label:
                info_text += f" {source_label}"
            info_label = tk.Label(item_frame, text=info_text, font=(self.current_font_family, 8, "bold"), bg="#ccfbf1", fg="#115e59", anchor="w")
            info_label.place(x=6, y=62, width=72, height=12)
            tk.Button(
                item_frame,
                text="X",
                font=(self.current_font_family, 7, "bold"),
                bg="#dc2626",
                fg="#ffffff",
                activebackground="#b91c1c",
                activeforeground="#ffffff",
                relief="raised",
                bd=1,
                highlightthickness=0,
                cursor="hand2",
                command=lambda current_id=preview_item_id: self._delete_schedule_input_ocr_addon_item(current_id),
            ).place(x=74, y=0, width=18, height=18)
        self._sync_schedule_input_ocr_addon_stack_scrollregion()

    def _sync_schedule_input_ocr_addon_stack_scrollregion(self) -> None:
        canvas = self.schedule_input_ocr_addon_stack_canvas
        inner_frame = self.schedule_input_ocr_addon_stack_inner_frame
        window_id = self.schedule_input_ocr_addon_stack_window_id
        if canvas is None or inner_frame is None or window_id is None:
            return
        try:
            canvas.update_idletasks()
            canvas.configure(scrollregion=canvas.bbox("all"))
            inner_width = max(300, 12 + (len(self.schedule_input_ocr_addon_stack_items) * 102))
            canvas.itemconfigure(window_id, width=inner_width)
        except tk.TclError:
            return

    def _update_schedule_input_ocr_addon_controls(self) -> None:
        controls_enabled = bool(self.schedule_input_ocr_addon_open) and not self._is_schedule_input_compact_mode() and not self.schedule_input_ocr_worker_active
        for widget in (
            self.schedule_input_ocr_addon_capture_button,
            self.schedule_input_ocr_addon_close_button,
        ):
            if widget is None or not widget.winfo_exists():
                continue
            try:
                if widget is self.schedule_input_ocr_addon_capture_button:
                    enabled = controls_enabled and not self.schedule_input_ocr_addon_busy
                else:
                    enabled = controls_enabled
                widget.config(
                    state="normal" if enabled else "disabled",
                    cursor="hand2" if enabled else "arrow",
                )
            except tk.TclError:
                continue

    def _delete_schedule_input_ocr_addon_item(self, item_id: str) -> None:
        target_id = str(item_id or "").strip()
        if not target_id:
            return
        before_count = len(self.schedule_input_ocr_addon_stack_items)
        retained_items: list[dict[str, object]] = []
        for item in self.schedule_input_ocr_addon_stack_items:
            if str(item.get("id") or "") != target_id:
                retained_items.append(item)
                continue
            image_path = str(item.get("path") or "").strip()
            if image_path and os.path.exists(image_path):
                try:
                    os.remove(image_path)
                except OSError:
                    pass
        self.schedule_input_ocr_addon_stack_items = retained_items
        if len(self.schedule_input_ocr_addon_stack_items) != before_count:
            self.schedule_input_ocr_addon_status_var.set(f"스택에서 1장을 삭제했습니다. ({len(self.schedule_input_ocr_addon_stack_items)}장 남음)")
            self._refresh_schedule_input_ocr_addon_stack_widgets()

    def _schedule_input_ocr_addon_tick(self) -> None:
        if not self.schedule_input_ocr_addon_open:
            self.schedule_input_ocr_addon_poll_after_id = None
            return
        window = self.schedule_input_ocr_addon_window
        if window is None or not window.winfo_exists():
            self._close_schedule_input_ocr_addon_window()
            return
        foreground_hwnd = self._get_foreground_window_handle()
        foreground_root_hwnd = self._get_root_window_handle(foreground_hwnd)
        current_title = self._get_window_text(foreground_root_hwnd)
        is_odin_active = bool(
            foreground_root_hwnd
            and (
                foreground_root_hwnd == int(self.schedule_input_ocr_addon_last_odin_hwnd or 0)
                or self._is_schedule_input_ocr_addon_target_title(current_title)
            )
        )
        addon_root_hwnd = self._get_root_window_handle(int(window.winfo_id() or 0))
        is_addon_active = False
        try:
            is_addon_active = bool(addon_root_hwnd and addon_root_hwnd == foreground_root_hwnd)
        except tk.TclError:
            is_addon_active = False
        resize_menu_open = self._is_schedule_input_ocr_addon_resize_menu_open()
        rbutton_down = self._is_schedule_input_ocr_addon_hotkey_pressed(SCHEDULE_INPUT_OCR_ADDON_MOUSE_RIGHT_BUTTON)
        f2_down = self._is_schedule_input_ocr_addon_hotkey_pressed(SCHEDULE_INPUT_OCR_ADDON_HOTKEY_F2)
        if is_odin_active:
            self.schedule_input_ocr_addon_last_odin_hwnd = foreground_root_hwnd
            self.schedule_input_ocr_addon_active_hwnd = foreground_root_hwnd
            self._position_schedule_input_ocr_addon_window()
            if window.state() == "withdrawn":
                try:
                    window.deiconify()
                except tk.TclError:
                    pass
        else:
            try:
                if window.state() == "withdrawn":
                    window.deiconify()
            except tk.TclError:
                pass
        self._poll_schedule_input_ocr_addon_hotkeys()
        if self.schedule_input_ocr_addon_hotkey_pending_f2:
            self.schedule_input_ocr_addon_hotkey_pending_f2 = False
            self._request_schedule_input_ocr_capture_from_odin()
        if rbutton_down and not self.schedule_input_ocr_addon_rbutton_down:
            self._maybe_show_schedule_input_ocr_addon_resize_menu_from_cursor()
        self.schedule_input_ocr_addon_rbutton_down = rbutton_down
        if f2_down and not self.schedule_input_ocr_addon_f2_down:
            self._request_schedule_input_ocr_capture_from_odin()
        self.schedule_input_ocr_addon_f2_down = f2_down
        self.schedule_input_ocr_addon_f3_down = False
        if self.schedule_input_ocr_addon_open and self.root is not None and self.root.winfo_exists():
            try:
                self.schedule_input_ocr_addon_poll_after_id = self.root.after(
                    SCHEDULE_INPUT_OCR_ADDON_POLL_INTERVAL_MS,
                    self._schedule_input_ocr_addon_tick,
                )
            except tk.TclError:
                self.schedule_input_ocr_addon_poll_after_id = None

    def _position_schedule_input_ocr_addon_window(self) -> None:
        window = self.schedule_input_ocr_addon_window
        if window is None or not window.winfo_exists() or not self.schedule_input_ocr_addon_open:
            return
        hwnd = self.schedule_input_ocr_addon_last_odin_hwnd or self.schedule_input_ocr_addon_active_hwnd or self._find_odin_window_handle()
        rect = self._get_odin_client_screen_rect(hwnd) if hwnd else None
        if not isinstance(rect, dict):
            try:
                screen_width = int(window.winfo_screenwidth() or 1920)
                screen_height = int(window.winfo_screenheight() or 1080)
            except tk.TclError:
                screen_width = 1920
                screen_height = 1080
            x = max(0, screen_width - SCHEDULE_INPUT_OCR_ADDON_WIDTH - 24)
            y = 24
        else:
            left = int(rect.get("left") or 0)
            top = int(rect.get("top") or 0)
            right = int(rect.get("right") or 0)
            screen_width = max(1, int(window.winfo_screenwidth() or 1920))
            right_side_x = right + 12
            left_side_x = left - SCHEDULE_INPUT_OCR_ADDON_WIDTH - 12
            if right_side_x + SCHEDULE_INPUT_OCR_ADDON_WIDTH <= screen_width - 10:
                x = right_side_x
            elif left_side_x >= 10:
                x = left_side_x
            else:
                x = max(10, screen_width - SCHEDULE_INPUT_OCR_ADDON_WIDTH - 10)
            y = max(10, top)
        try:
            window.geometry(f"{SCHEDULE_INPUT_OCR_ADDON_WIDTH}x{SCHEDULE_INPUT_OCR_ADDON_HEIGHT}+{x}+{y}")
        except tk.TclError:
            return

    def _ensure_schedule_input_ocr_addon_window(self) -> None:
        if self.schedule_input_ocr_addon_window is not None and self.schedule_input_ocr_addon_window.winfo_exists():
            return
