    def _get_schedule_elapsed_overlay_colors(self, row_kind: str, row_item: dict[str, object], boss_text: str) -> tuple[str, str]:
        return SCHEDULE_ELAPSED_DISABLED_TEXT_COLOR, SCHEDULE_ELAPSED_DISABLED_BG_COLOR

    def _format_schedule_alarm_offset_text(self, total_seconds: int) -> str:
        seconds = max(1, int(total_seconds))
        hours, remainder = divmod(seconds, 3600)
        minutes, remainder_seconds = divmod(remainder, 60)
        parts: list[str] = []
        if hours > 0:
            parts.append(f"{hours}시간")
        if minutes > 0 or hours > 0:
            parts.append(f"{minutes}분")
        if remainder_seconds > 0 or not parts:
            if minutes > 0 or hours > 0:
                parts.append(f"{remainder_seconds:02d}초")
            else:
                parts.append(f"{remainder_seconds}초")
        return " ".join(parts)

    def _format_schedule_alarm_offsets_summary(self, offsets: list[int]) -> str:
        normalized = self._normalize_schedule_alarm_offsets(offsets)
        if not normalized:
            return "-"
        return ", ".join(self._format_schedule_alarm_offset_text(seconds) for seconds in normalized)

    def _build_schedule_alarm_minutes_seconds(self, minute_text: str, second_text: str) -> int | None:
        minute_value = self._parse_int(re.sub(r"[^0-9]", "", minute_text or ""), -1)
        second_value = self._parse_int(re.sub(r"[^0-9]", "", second_text or ""), -1)
        if minute_value < 0 or second_value < 0 or second_value >= 60:
            return None
        total_seconds = (minute_value * 60) + second_value
        return total_seconds if total_seconds > 0 else None

    def _get_schedule_boss_alarm_entry(self, boss_name: str) -> dict[str, object]:
        canonical_name = self._get_canonical_boss_name(str(boss_name or "").strip()) or str(boss_name or "").strip()
        if not canonical_name:
            return {"enabled": False, "offsets": []}
        current = self.schedule_boss_alarm_settings.get(canonical_name)
        if not isinstance(current, dict):
            current = {"enabled": False, "offsets": []}
            self.schedule_boss_alarm_settings[canonical_name] = current
        normalized = self._normalize_schedule_boss_alarm_entry(current)
        self.schedule_boss_alarm_settings[canonical_name] = normalized
        return normalized

    def _get_schedule_alarm_display_text_for_boss(self, boss_name: str) -> str:
        entry = self._get_schedule_boss_alarm_entry(boss_name)
        return "ON" if bool(entry.get("enabled")) and bool(entry.get("offsets")) else "OFF"

    def _get_schedule_alarm_display_text_for_item(self, item: dict[str, object] | None, *, row_kind: str) -> str:
        if row_kind == "fixed":
            return "ON" if bool(self.schedule_fixed_boss_alarm_enabled_var.get()) else "OFF"
        if not isinstance(item, dict):
            return "OFF"
        return self._get_schedule_alarm_display_text_for_boss(str(item.get("boss_name") or ""))

    def _update_schedule_alarm_master_button(self) -> None:
        button = getattr(self, "schedule_alarm_master_button", None)
        is_enabled = bool(self.schedule_alarm_master_var.get()) if hasattr(self, "schedule_alarm_master_var") else False
        if button is None:
            return
        normal_bg = "#16a34a" if is_enabled else "#dc2626"
        hover_bg = "#15803d" if is_enabled else "#b91c1c"
        try:
            button.config(
                text="알람 ON" if is_enabled else "알람 OFF",
                bg=normal_bg,
                fg="#ffffff",
                activebackground=hover_bg,
                activeforeground="#ffffff",
                cursor="hand2",
            )
        except tk.TclError:
            return
        self._bind_hover_button(button, normal_bg, hover_bg, "#ffffff", "#ffffff")

    def _toggle_schedule_alarm_master(self) -> None:
        self.schedule_alarm_master_var.set(not bool(self.schedule_alarm_master_var.get()))

    def _on_schedule_alarm_master_changed(self, *_args) -> None:
        self.schedule_alarm_master_enabled_default = bool(self.schedule_alarm_master_var.get())
        self._update_schedule_alarm_master_button()
        if hasattr(self, "schedule_alarm_status_var") and self.schedule_alarm_status_var is not None:
            self.schedule_alarm_status_var.set("전체 알람을 켰습니다." if self.schedule_alarm_master_enabled_default else "전체 알람을 껐습니다.")
        self._save_schedule_alarm_settings()
        if self.schedule_tree is not None and self.schedule_tree.winfo_exists():
            self._refresh_schedule_tree_scope()

    def _play_schedule_alarm_signal(self) -> None:
        for frequency in SCHEDULE_ALARM_SIGNAL_FREQUENCIES:
            try:
                winsound.Beep(int(frequency), 90)
            except RuntimeError:
                try:
                    winsound.MessageBeep(winsound.MB_ICONASTERISK)
                except RuntimeError:
                    pass
            time.sleep(0.03)

    def _build_schedule_alarm_tts_command(self, text: str) -> list[str]:
        voice_name = str(self.schedule_alarm_voice_name or SCHEDULE_ALARM_FEMALE_VOICE_NAME).strip() or SCHEDULE_ALARM_FEMALE_VOICE_NAME
        script = (
            "$voice = New-Object -ComObject SAPI.SpVoice\n"
            f"$preferredVoice = {json.dumps(voice_name, ensure_ascii=False)}\n"
            "$selected = $voice.GetVoices() | Where-Object { $_.GetDescription() -eq $preferredVoice } | Select-Object -First 1\n"
            "if ($selected) { $voice.Voice = $selected }\n"
            "$voice.Rate = 0\n"
            f"[void]$voice.Speak({json.dumps(text, ensure_ascii=False)})\n"
        )
        encoded = base64.b64encode(script.encode("utf-16le")).decode("ascii")
        return ["powershell", "-NoProfile", "-EncodedCommand", encoded]

    def _build_schedule_alarm_tts_host_command(self) -> list[str]:
        voice_name = str(self.schedule_alarm_voice_name or SCHEDULE_ALARM_FEMALE_VOICE_NAME).strip() or SCHEDULE_ALARM_FEMALE_VOICE_NAME
        script = (
            "[Console]::InputEncoding = [System.Text.Encoding]::UTF8\n"
            "$voice = New-Object -ComObject SAPI.SpVoice\n"
            f"$preferredVoice = {json.dumps(voice_name, ensure_ascii=False)}\n"
            "$selected = $voice.GetVoices() | Where-Object { $_.GetDescription() -eq $preferredVoice } | Select-Object -First 1\n"
            "if ($selected) { $voice.Voice = $selected }\n"
            "while (($line = [Console]::In.ReadLine()) -ne $null) {\n"
            "  if ($line -eq '__EXIT__') { break }\n"
            "  if ([string]::IsNullOrWhiteSpace($line)) { continue }\n"
            "  $parts = $line.Split('|', 4)\n"
            "  if ($parts.Length -lt 4 -or $parts[0] -ne '__SPEAK__') { continue }\n"
            "  try { $rate = [int]$parts[1] } catch { $rate = 0 }\n"
            "  try { $flags = [int]$parts[2] } catch { $flags = 0 }\n"
            "  try { $text = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String($parts[3])) } catch { $text = '' }\n"
            "  if ([string]::IsNullOrWhiteSpace($text)) { continue }\n"
            "  $voice.Rate = [Math]::Max(-10, [Math]::Min(10, $rate))\n"
            "  [void]$voice.Speak($text, $flags)\n"
            "}\n"
        )
        encoded = base64.b64encode(script.encode("utf-16le")).decode("ascii")
        return ["powershell", "-NoProfile", "-EncodedCommand", encoded]

    def _ensure_schedule_alarm_tts_process(self) -> subprocess.Popen | None:
        voice_name = str(self.schedule_alarm_voice_name or SCHEDULE_ALARM_FEMALE_VOICE_NAME).strip() or SCHEDULE_ALARM_FEMALE_VOICE_NAME
        existing = self.schedule_alarm_tts_process
        if (
            existing is not None
            and existing.poll() is None
            and self.schedule_alarm_tts_process_voice_name == voice_name
            and existing.stdin is not None
        ):
            return existing
        if existing is not None:
            try:
                if existing.stdin is not None:
                    existing.stdin.write("__EXIT__\n")
                    existing.stdin.flush()
            except OSError:
                pass
            try:
                existing.terminate()
            except OSError:
                pass
        creationflags = getattr(subprocess, "CREATE_NO_WINDOW", 0)
        try:
            process = subprocess.Popen(
                self._build_schedule_alarm_tts_host_command(),
                stdin=subprocess.PIPE,
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL,
                text=True,
                encoding="utf-8",
                creationflags=creationflags,
            )
        except OSError:
            self.schedule_alarm_tts_process = None
            self.schedule_alarm_tts_process_voice_name = ""
            return None
        self.schedule_alarm_tts_process = process
        self.schedule_alarm_tts_process_voice_name = voice_name
        return process

    def _speak_schedule_alarm_text(self, text: str, *, rate: int = 0, purge: bool = False) -> None:
        speech_text = str(text or "").strip()
        if not speech_text:
            return
        process = self._ensure_schedule_alarm_tts_process()
        if process is None or process.stdin is None:
            return
        flags = 2 if purge else 0
        payload_text = base64.b64encode(speech_text.encode("utf-8")).decode("ascii")
        payload = f"__SPEAK__|{max(-10, min(10, int(rate)))}|{flags}|{payload_text}\n"
        try:
            process.stdin.write(payload)
            process.stdin.flush()
        except OSError:
            self.schedule_alarm_tts_process = None
            self.schedule_alarm_tts_process_voice_name = ""

    def _drop_pending_schedule_alarm_queue_items(self, *, category: str) -> None:
        with self.schedule_alarm_tts_queue.mutex:
            retained = []
            for item in list(self.schedule_alarm_tts_queue.queue):
                if item is None:
                    retained.append(item)
                    continue
                if isinstance(item, dict) and str(item.get("category") or "") == category:
                    continue
                retained.append(item)
            self.schedule_alarm_tts_queue.queue.clear()
            self.schedule_alarm_tts_queue.queue.extend(retained)

    def _schedule_alarm_tts_worker_loop(self) -> None:
        while not self.schedule_alarm_tts_stop_event.is_set():
            try:
                payload = self.schedule_alarm_tts_queue.get(timeout=0.2)
            except queue.Empty:
                continue
            if payload is None:
                self.schedule_alarm_tts_queue.task_done()
                break
            try:
                text = str(payload.get("text") or "").strip() if isinstance(payload, dict) else ""
                if not text:
                    continue
                expires_at = payload.get("expires_at") if isinstance(payload, dict) else None
                if isinstance(expires_at, datetime) and datetime.now() > expires_at:
                    continue
                if bool(payload.get("beep")):
                    self._play_schedule_alarm_signal()
                self._speak_schedule_alarm_text(
                    text,
                    rate=int(payload.get("rate", 0)) if isinstance(payload, dict) else 0,
                    purge=bool(payload.get("purge", False)) if isinstance(payload, dict) else False,
                )
            finally:
                self.schedule_alarm_tts_queue.task_done()

    def _shutdown_schedule_alarm_tts_worker(self) -> None:
        if self.schedule_alarm_tts_stop_event.is_set():
            return
        self.schedule_alarm_tts_stop_event.set()
        try:
            self.schedule_alarm_tts_queue.put_nowait(None)
        except queue.Full:
            pass
        if self.schedule_alarm_tts_process is not None:
            try:
                if self.schedule_alarm_tts_process.stdin is not None:
                    self.schedule_alarm_tts_process.stdin.write("__EXIT__\n")
                    self.schedule_alarm_tts_process.stdin.flush()
            except OSError:
                pass
            try:
                self.schedule_alarm_tts_process.terminate()
            except OSError:
                pass
        self.schedule_alarm_tts_process = None
        self.schedule_alarm_tts_process_voice_name = ""
        if self.schedule_alarm_tts_thread.is_alive():
            self.schedule_alarm_tts_thread.join(timeout=0.8)

    def _queue_schedule_alarm_speech(
        self,
        text: str,
        *,
        beep: bool = True,
        category: str = "general",
        rate: int = 0,
        purge: bool = False,
        expires_at: datetime | None = None,
    ) -> None:
        if self.schedule_alarm_tts_stop_event.is_set():
            return
        speech_text = str(text or "").strip()
        if not speech_text:
            return
        normalized_category = str(category or "general").strip() or "general"
        if normalized_category == "countdown":
            self._drop_pending_schedule_alarm_queue_items(category="countdown")
        self.schedule_alarm_tts_queue.put(
            {
                "text": speech_text,
                "beep": bool(beep),
                "category": normalized_category,
                "rate": int(rate),
                "purge": bool(purge),
                "expires_at": expires_at if isinstance(expires_at, datetime) else None,
            }
        )

    def _format_schedule_alarm_remaining_speech(self, total_seconds: int) -> str:
        seconds = max(1, int(total_seconds))
        hours, remainder = divmod(seconds, 3600)
        minutes, remainder_seconds = divmod(remainder, 60)
        parts: list[str] = []
        if hours > 0:
            parts.append(f"{hours}시간")
        if minutes > 0:
            parts.append(f"{minutes}분")
        if remainder_seconds > 0 and hours == 0:
            parts.append(f"{remainder_seconds}초")
        if not parts:
            parts.append("1초")
        return " ".join(parts)

    def _build_schedule_alarm_due_key(self, category: str, identity: str, anchor_datetime: datetime, seconds: int) -> str:
        return f"{category}:{identity}:{anchor_datetime.isoformat()}:{int(seconds)}"

    def _should_fire_schedule_alarm_key(self, key: str, reference_now: datetime) -> bool:
        last_fired = self.schedule_alarm_fired_keys.get(key)
        if isinstance(last_fired, datetime) and last_fired >= reference_now - timedelta(days=1):
            return False
        self.schedule_alarm_fired_keys[key] = reference_now
        return True

    def _prune_schedule_alarm_fired_keys(self, reference_now: datetime) -> None:
        self.schedule_alarm_fired_keys = {
            key: value
            for key, value in self.schedule_alarm_fired_keys.items()
            if isinstance(value, datetime) and value >= reference_now - timedelta(days=2)
        }

    def _get_next_schedule_alarm_target_after(self, reference_now: datetime, after_datetime: datetime) -> tuple[datetime, str] | None:
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        candidates: list[tuple[datetime, str]] = []
        for item in self.schedule_events:
            scheduled_at = item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime) or scheduled_at <= after_datetime or scheduled_at < reference_now:
                continue
            if cutoff_datetime is not None and scheduled_at >= cutoff_datetime:
                continue
            if self._is_schedule_invasion_item(item) and not self._is_schedule_invasion_datetime_visible(scheduled_at):
                continue
            candidates.append((scheduled_at, self._get_schedule_boss_display_name(item, prefer_alias=True)))
        for scheduled_at, boss_name, *_rest in self._get_fixed_boss_schedule_rows_for_alarm(reference_now):
            if scheduled_at <= after_datetime or scheduled_at < reference_now:
                continue
            if cutoff_datetime is not None and scheduled_at >= cutoff_datetime:
                continue
            candidates.append((scheduled_at, boss_name))
        if not candidates:
            return None
        candidates.sort(key=lambda row: (row[0], row[1]))
        return candidates[0]

    def _build_schedule_fixed_alarm_message(self, reference_now: datetime, scheduled_at: datetime, boss_name: str) -> str:
        message = f"고정보스 {boss_name}이 끝나기 1분 전입니다."
        next_target = self._get_next_schedule_alarm_target_after(reference_now, scheduled_at)
        if next_target is not None:
            next_time, next_boss = next_target
            next_remaining = int((next_time - scheduled_at).total_seconds())
            if next_remaining > 0:
                message += f" 다음 보스는 {next_boss}, {self._format_schedule_alarm_remaining_speech(next_remaining)} 남았습니다."
        return message

    def _process_schedule_alarm_tick(self, reference_now: datetime) -> None:
        if not bool(self.schedule_alarm_master_var.get()):
            return
        current_second = reference_now.replace(microsecond=0)
        if self.schedule_alarm_last_tick_second == current_second:
            return
        self.schedule_alarm_last_tick_second = current_second
        self._prune_schedule_alarm_fired_keys(current_second)
        cutoff_datetime = self._get_schedule_visible_cutoff_datetime()
        countdown_candidates: list[tuple[datetime, str, int]] = []

        for item in self.schedule_events:
            scheduled_at = item.get("scheduled_at")
            if not isinstance(scheduled_at, datetime) or scheduled_at <= current_second:
                continue
            if cutoff_datetime is not None and scheduled_at >= cutoff_datetime:
                continue
            if self._is_schedule_invasion_item(item) and not self._is_schedule_invasion_datetime_visible(scheduled_at):
                continue
            boss_name = str(item.get("boss_name") or "").strip()
            if not boss_name:
                continue
            entry = self._get_schedule_boss_alarm_entry(boss_name)
            offsets = self._normalize_schedule_alarm_offsets(entry.get("offsets", []))
            if not bool(entry.get("enabled")) or not offsets:
                continue
            remaining_seconds = int((scheduled_at - current_second).total_seconds())
            display_name = self._get_schedule_boss_display_name(item, prefer_alias=True)
            fired_phrase_this_second = False
            for offset_seconds in offsets:
                alert_message = f"{display_name} {self._format_schedule_alarm_remaining_speech(offset_seconds)} 남았습니다."
                if remaining_seconds != offset_seconds:
                    continue
                alert_key = self._build_schedule_alarm_due_key("event", boss_name, scheduled_at, offset_seconds)
                if not self._should_fire_schedule_alarm_key(alert_key, current_second):
                    continue
                self._queue_schedule_alarm_speech(
                    alert_message,
                    beep=True,
                    category="general",
                    rate=1,
                )
                fired_phrase_this_second = True
            if bool(self.schedule_alarm_countdown_enabled_var.get()):
                countdown_start = min(60, max(1, self._parse_int(self.schedule_alarm_countdown_start_var.get(), 10)))
                if 1 <= remaining_seconds <= countdown_start and not fired_phrase_this_second:
                    countdown_candidates.append((scheduled_at, boss_name, remaining_seconds))

        if countdown_candidates:
            countdown_candidates.sort(key=lambda item: (item[0], item[1]))
            scheduled_at, boss_name, remaining_seconds = countdown_candidates[0]
            countdown_key = self._build_schedule_alarm_due_key("countdown", boss_name, scheduled_at, remaining_seconds)
            if self._should_fire_schedule_alarm_key(countdown_key, current_second):
                self._queue_schedule_alarm_speech(
                    str(remaining_seconds),
                    beep=False,
                    category="countdown",
                    rate=6,
                    purge=True,
                    expires_at=current_second + timedelta(milliseconds=850),
                )

        if bool(self.schedule_fixed_boss_alarm_enabled_var.get()):
            for scheduled_at, boss_name, *_rest in self._get_fixed_boss_schedule_rows_for_alarm(current_second):
                remaining_seconds = int((scheduled_at - current_second).total_seconds())
                if remaining_seconds != SCHEDULE_FIXED_BOSS_SPECIAL_ALERT_SECONDS:
                    continue
                alert_key = self._build_schedule_alarm_due_key("fixed", boss_name, scheduled_at, remaining_seconds)
                if not self._should_fire_schedule_alarm_key(alert_key, current_second):
                    continue
                message = self._build_schedule_fixed_alarm_message(current_second, scheduled_at, boss_name)
                self._queue_schedule_alarm_speech(message, beep=True, category="fixed", rate=1)

    def _blend_hex_color(self, base_color: str, target_color: str, ratio: float) -> str:
        normalized_base = self._normalize_hex_color(base_color, "#FFFFFF")
        normalized_target = self._normalize_hex_color(target_color, "#FFFFFF")
        mix_ratio = max(0.0, min(1.0, float(ratio)))
        try:
            base_red = int(normalized_base[1:3], 16)
            base_green = int(normalized_base[3:5], 16)
            base_blue = int(normalized_base[5:7], 16)
            target_red = int(normalized_target[1:3], 16)
            target_green = int(normalized_target[3:5], 16)
            target_blue = int(normalized_target[5:7], 16)
        except ValueError:
            return normalized_base
        mixed_red = round(base_red + ((target_red - base_red) * mix_ratio))
        mixed_green = round(base_green + ((target_green - base_green) * mix_ratio))
        mixed_blue = round(base_blue + ((target_blue - base_blue) * mix_ratio))
        return f"#{mixed_red:02X}{mixed_green:02X}{mixed_blue:02X}"

    def _on_schedule_tree_select(self, _event=None) -> None:
        self._update_schedule_tree_action_buttons()
        self.schedule_tree_overlay_signature = None
        self.schedule_tree_elapsed_overlay_signature = None
        self._schedule_tree_overlay_after_idle()

    def _select_schedule_tree_item(self, item_id: str) -> None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists() or not item_id:
            return
        try:
            self.schedule_tree.selection_set((item_id,))
            self.schedule_tree.focus(item_id)
            self.schedule_tree.see(item_id)
            self.schedule_tree_drag_anchor = item_id
        except tk.TclError:
            return
        self._update_schedule_tree_action_buttons()
        self.schedule_tree_overlay_signature = None
        self.schedule_tree_elapsed_overlay_signature = None
        self._schedule_tree_overlay_after_idle()

    def _on_schedule_tree_overlay_press(self, item_id: str, _event=None) -> str:
        if self._is_schedule_tree_click_debounce_active():
            return "break"
        self._arm_schedule_tree_click_debounce()
        self._select_schedule_tree_item(item_id)
        return "break"

    def _on_schedule_tree_press(self, event) -> None:
        if self.schedule_tree is None:
            return
        try:
            item_id = self.schedule_tree.identify_row(event.y) or None
        except tk.TclError:
            item_id = None
        self.schedule_tree_drag_anchor = item_id
        if item_id is None:
            return
        if self._is_schedule_tree_click_debounce_active():
            return "break"
        self._arm_schedule_tree_click_debounce()

    def _on_schedule_tree_button_release(self, event) -> None:
        if self.schedule_tree is None:
            return
        try:
            item_id = self.schedule_tree.identify_row(event.y) or ""
            column_id = self.schedule_tree.identify_column(event.x) or ""
            if not item_id or column_id not in {"#5", "#6"}:
                return
            meta = self.schedule_tree_item_meta.get(item_id, {})
            if str(meta.get("kind") or "") != "event":
                return
            item = meta.get("item")
            identity = meta.get("identity")
            if not isinstance(item, dict) or not isinstance(identity, tuple):
                return
            values = self.schedule_tree.item(item_id, "values")
            cut_text = str(values[4]) if len(values) >= 5 else ""
            cut_time_text = str(values[5]) if len(values) >= 6 else ""
            if column_id == "#5":
                if cut_text == "컷":
                    self._apply_schedule_tree_quick_cut(dict(item), identity)
                elif cut_text == "취소":
                    self._cancel_schedule_tree_cut_state(dict(item), identity)
            elif column_id == "#6" and cut_time_text == "컷시간":
                self._apply_schedule_tree_cut_time(dict(item), identity)
        except tk.TclError:
            return

    def _on_schedule_tree_mousewheel(self, event) -> str | None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return None
        delta = int(getattr(event, "delta", 0) or 0)
        if delta == 0:
            return "break"
        steps = int(-delta / 120)
        if steps == 0:
            steps = -1 if delta > 0 else 1
        if steps > 3:
            steps = 3
        elif steps < -3:
            steps = -3
        try:
            self.schedule_tree.yview_scroll(steps, "units")
        except tk.TclError:
            return None
        self._hide_schedule_tree_elapsed_overlays()
        self._schedule_tree_overlay_after_idle()
        return "break"

    def _block_combobox_mousewheel(self, _event=None) -> str:
        return "break"

    def _clear_schedule_tree_overlays(self) -> None:
        for widget in list(self.schedule_tree_overlay_cache.values()):
            try:
                widget.destroy()
            except tk.TclError:
                continue
        self.schedule_tree_overlay_cache = {}
        self.schedule_tree_overlay_widgets = []
        self.schedule_tree_overlay_signature = None
        self.schedule_tree_elapsed_overlay_signature = None

    def _hide_schedule_tree_overlays(self, *, invalidate_signatures: bool = True) -> None:
        for widget in list(self.schedule_tree_overlay_cache.values()):
            try:
                if widget.winfo_exists():
                    widget.place_forget()
            except tk.TclError:
                continue
        self.schedule_tree_overlay_widgets = []
        if invalidate_signatures:
            self.schedule_tree_overlay_signature = None
            self.schedule_tree_elapsed_overlay_signature = None

    def _hide_schedule_tree_elapsed_overlays(self) -> None:
        for cache_key, widget in list(self.schedule_tree_overlay_cache.items()):
            if not str(cache_key[1]).startswith("elapsed_"):
                continue
            try:
                if widget.winfo_exists():
                    widget.place_forget()
            except tk.TclError:
                continue
        self.schedule_tree_elapsed_overlay_signature = None

    def _on_schedule_tree_scrollbar(self, *args) -> None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return
        try:
            self.schedule_tree.yview(*args)
        except tk.TclError:
            return
        self._hide_schedule_tree_elapsed_overlays()
        self._schedule_tree_overlay_after_idle()

    def _get_schedule_tree_overlay_button(self, cache_key: tuple[str, str], parent: tk.Misc) -> tk.Button | None:
        button = self.schedule_tree_overlay_cache.get(cache_key)
        if button is not None:
            try:
                if button.winfo_exists() and isinstance(button, tk.Button):
                    return button
                button.destroy()
            except tk.TclError:
                pass
        button = tk.Button(parent, relief="raised", bd=1, highlightthickness=0, cursor="hand2")
        button.bind("<MouseWheel>", self._on_schedule_tree_mousewheel)
        self.schedule_tree_overlay_cache[cache_key] = button
        return button

    def _get_schedule_tree_overlay_label(self, cache_key: tuple[str, str], parent: tk.Misc) -> tk.Label | None:
        label = self.schedule_tree_overlay_cache.get(cache_key)
        if label is not None:
            try:
                if label.winfo_exists() and isinstance(label, tk.Label):
                    return label
                label.destroy()
            except tk.TclError:
                pass
        label = tk.Label(parent, bd=0, highlightthickness=0, anchor="center")
        label.bind("<MouseWheel>", self._on_schedule_tree_mousewheel)
        label.bind("<Button-1>", lambda event, current_item_id=cache_key[0]: self._on_schedule_tree_overlay_press(current_item_id, event))
        self.schedule_tree_overlay_cache[cache_key] = label
        return label

    def _get_schedule_tree_elapsed_overlay_specs(self, item_id: str, meta: dict[str, object]) -> tuple[tuple[str, tuple[int, int, int, int], str], ...]:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return ()
        overlay_values = meta.get("elapsed_overlay_values")
        if not isinstance(overlay_values, (list, tuple)):
            return ()
        specs: list[tuple[str, tuple[int, int, int, int], str]] = []
        for column_index, raw_value in enumerate(overlay_values[:4], start=1):
            try:
                bbox = self.schedule_tree.bbox(item_id, f"#{column_index}")
            except tk.TclError:
                bbox = ()
            if not bbox:
                continue
            specs.append((f"#{column_index}", tuple(bbox), str(raw_value or "")))
        return tuple(specs)

    def _get_schedule_tree_row_cut_overlay_state(
        self,
        item: dict[str, object],
        identity: tuple[str, str, str, str] | None,
        meta: dict[str, object],
        *,
        selected: bool = False,
    ) -> tuple[str, str]:
        tree_quick_cut_entry = self._get_schedule_tree_quick_cut_entry(identity, item)
        active_quick_cut_entry = self._get_schedule_active_quick_cut_entry_by_tree_identity(identity, item)
        quick_cut_entry = (
            tree_quick_cut_entry
            if isinstance(tree_quick_cut_entry, dict)
            else active_quick_cut_entry
        )
        cut_time_text = (
            str(quick_cut_entry.get("cut_time_text") or "")
            if isinstance(quick_cut_entry, dict)
            else self._get_schedule_event_cut_time_text(item)
        )
        has_cut_state = bool(cut_time_text) or isinstance(quick_cut_entry, dict)
        if not bool(meta.get("cut_inline_visible", True)) and not has_cut_state:
            return "hidden", ""
        if not selected and not has_cut_state:
            return "hidden", ""
        cooldown_active = self._is_schedule_tree_overlay_cooldown_active(identity)
        active_after = quick_cut_entry.get("active_after") if isinstance(quick_cut_entry, dict) else None
        show_cancel = bool(
            not cooldown_active
            and quick_cut_entry is not None
            and (not isinstance(active_after, (int, float)) or time.monotonic() >= float(active_after))
        )
        if cut_time_text and not show_cancel and not isinstance(quick_cut_entry, dict):
            show_cancel = True
        pending = bool(quick_cut_entry is not None and not show_cancel)
        cut_available = bool(meta.get("cut_available"))
        if cooldown_active and not has_cut_state:
            return "hidden", cut_time_text
        if show_cancel:
            return "cancel", cut_time_text
        if pending:
            return "cooldown", cut_time_text
        if cut_time_text:
            return ("cut_time_only" if cut_available else "cut_time_locked"), cut_time_text
        if cut_available:
            return "cut_pair", ""
        return "none", ""

    def _build_schedule_tree_action_overlay_signature(self) -> tuple:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return ()
        entries: list[tuple[object, ...]] = []
        try:
            selected_item_ids = set(self.schedule_tree.selection())
        except tk.TclError:
            selected_item_ids = set()
        try:
            for item_id, meta in self.schedule_tree_item_meta.items():
                item = meta.get("item")
                if str(meta.get("kind") or "") != "event" or not isinstance(item, dict):
                    continue
                identity = meta.get("identity")
                mode, cut_time_text = self._get_schedule_tree_row_cut_overlay_state(
                    item,
                    identity if isinstance(identity, tuple) else None,
                    meta,
                    selected=item_id in selected_item_ids,
                )
                if mode in {"hidden", "none"} and not cut_time_text:
                    continue
                cut_bbox = self.schedule_tree.bbox(item_id, "#5")
                cut_time_bbox = self.schedule_tree.bbox(item_id, "#6")
                if not cut_bbox and not cut_time_bbox:
                    continue
                entries.append(
                    (
                        item_id,
                        mode,
                        tuple(cut_bbox) if cut_bbox else (),
                        tuple(cut_time_bbox) if cut_time_bbox else (),
                        cut_time_text,
                        item_id in selected_item_ids,
                    )
                )
        except tk.TclError:
            return ()
        return tuple(entries)

    def _build_schedule_tree_elapsed_overlay_signature(self) -> tuple:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return ()
        entries: list[tuple[object, ...]] = []
        try:
            selected_item_ids = set(self.schedule_tree.selection())
        except tk.TclError:
            selected_item_ids = set()
        try:
            for item_id, meta in self.schedule_tree_item_meta.items():
                elapsed_specs = self._get_schedule_tree_elapsed_overlay_specs(item_id, meta)
                if not elapsed_specs:
                    continue
                entries.append((item_id, item_id in selected_item_ids, elapsed_specs))
        except tk.TclError:
            return ()
        return tuple(entries)

    def _refresh_schedule_tree_overlays(self) -> None:
        self.schedule_tree_overlay_retry_job = None
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            self._clear_schedule_tree_overlays()
            return
        try:
            self.schedule_tree.update_idletasks()
        except tk.TclError:
            return
        retry_required = self._has_schedule_tree_pending_overlay_state()
        new_action_signature = self._build_schedule_tree_action_overlay_signature()
        new_elapsed_signature = self._build_schedule_tree_elapsed_overlay_signature()
        action_changed = new_action_signature != self.schedule_tree_overlay_signature
        elapsed_changed = new_elapsed_signature != self.schedule_tree_elapsed_overlay_signature
        if not action_changed and not elapsed_changed:
            if retry_required:
                self._schedule_tree_overlay_after_delay(120)
            return
        self.schedule_tree_overlay_signature = new_action_signature
        self.schedule_tree_elapsed_overlay_signature = new_elapsed_signature
        overlay_parent = self.schedule_window if self.schedule_window is not None and self.schedule_window.winfo_exists() else self.schedule_tree
        try:
            list_offset_x = self.schedule_list_frame.winfo_x() if self.schedule_list_frame is not None and self.schedule_list_frame.winfo_exists() else 0
            list_offset_y = self.schedule_list_frame.winfo_y() if self.schedule_list_frame is not None and self.schedule_list_frame.winfo_exists() else 0
            tree_offset_x = list_offset_x + self.schedule_tree.winfo_x()
            tree_offset_y = list_offset_y + self.schedule_tree.winfo_y()
        except tk.TclError:
            tree_offset_x = 0
            tree_offset_y = 0
        try:
            selected_item_ids = set(self.schedule_tree.selection())
        except tk.TclError:
            selected_item_ids = set()
        try:
            if action_changed:
                used_action_cache_keys: set[tuple[str, str]] = set()
                for item_id, meta in self.schedule_tree_item_meta.items():
                    item = meta.get("item")
                    kind = str(meta.get("kind") or "")
                    is_selected = item_id in selected_item_ids
                    if kind != "event" or not isinstance(item, dict):
                        continue
                    identity = meta.get("identity")
                    mode, overlay_cut_time_text = self._get_schedule_tree_row_cut_overlay_state(
                        item,
                        identity if isinstance(identity, tuple) else None,
                        meta,
                        selected=is_selected,
                    )
                    cut_bbox = self.schedule_tree.bbox(item_id, "#5")
                    cut_time_bbox = self.schedule_tree.bbox(item_id, "#6")
                    if mode == "cancel" and cut_bbox:
                            cache_key = (item_id, "cancel")
                            button = self._get_schedule_tree_overlay_button(cache_key, overlay_parent)
                            if button is not None:
                                button.config(
                                    text="취소",
                                    font=self.percent_font,
                                    bg="#dc2626",
                                    fg="#ffffff",
                                    activebackground="#b91c1c",
                                    activeforeground="#ffffff",
                                    command=lambda current_item=dict(item), current_identity=identity: self._cancel_schedule_tree_cut_state(
                                        current_item,
                                        current_identity if isinstance(current_identity, tuple) else None,
                                    ),
                                )
                                button.place(x=tree_offset_x + cut_bbox[0], y=tree_offset_y + cut_bbox[1] + 1, width=cut_bbox[2], height=max(20, cut_bbox[3] - 2))
                                button.lift()
                                used_action_cache_keys.add(cache_key)
                    elif mode == "cut_pair" and cut_bbox:
                            cut_cache_key = (item_id, "cut")
                            cut_button = self._get_schedule_tree_overlay_button(cut_cache_key, overlay_parent)
                            if cut_button is not None:
                                cut_button.config(
                                    text="컷",
                                    font=self.percent_font,
                                    bg="#0f766e",
                                    fg="#ffffff",
                                    activebackground="#115e59",
                                    activeforeground="#ffffff",
                                    command=lambda current_item=dict(item), current_identity=identity: self._apply_schedule_tree_quick_cut(current_item, current_identity),
                                )
                                cut_button.place(x=tree_offset_x + cut_bbox[0], y=tree_offset_y + cut_bbox[1] + 1, width=cut_bbox[2], height=max(20, cut_bbox[3] - 2))
                                cut_button.lift()
                                used_action_cache_keys.add(cut_cache_key)
                    if mode == "cut_pair" and cut_time_bbox:
                        cut_time_cache_key = (item_id, "cut_time")
                        cut_time_button = self._get_schedule_tree_overlay_button(cut_time_cache_key, overlay_parent)
                        if cut_time_button is not None:
                            cut_time_button.config(
                                text="컷시간",
                                font=self.percent_font,
                                bg="#f8f1df",
                                fg="#7c2d12",
                                activebackground="#efe2c5",
                                activeforeground="#7c2d12",
                                command=lambda current_item=dict(item), current_identity=identity: self._apply_schedule_tree_cut_time(current_item, current_identity),
                            )
                            cut_time_button.place(x=tree_offset_x + cut_time_bbox[0], y=tree_offset_y + cut_time_bbox[1] + 1, width=cut_time_bbox[2], height=max(20, cut_time_bbox[3] - 2))
                            cut_time_button.lift()
                            used_action_cache_keys.add(cut_time_cache_key)
                    if cut_time_bbox and overlay_cut_time_text:
                        cut_time_text_cache_key = (item_id, "cut_time_text")
                        cut_time_text_label = self._get_schedule_tree_overlay_label(cut_time_text_cache_key, overlay_parent)
                        if cut_time_text_label is not None:
                            cut_time_text_label.config(
                                text=overlay_cut_time_text,
                                font=self.percent_font,
                                bg="#bfdbfe" if is_selected else "#f8fafc",
                                fg="#0f172a",
                            )
                            cut_time_text_label.place(x=tree_offset_x + cut_time_bbox[0], y=tree_offset_y + cut_time_bbox[1] + 1, width=cut_time_bbox[2], height=max(20, cut_time_bbox[3] - 2))
                            cut_time_text_label.lift()
                            used_action_cache_keys.add(cut_time_text_cache_key)
                for cache_key, widget in list(self.schedule_tree_overlay_cache.items()):
                    if cache_key[1].startswith("elapsed_"):
                        continue
                    if cache_key in used_action_cache_keys:
                        continue
                    try:
                        widget.place_forget()
                    except tk.TclError:
                        pass

            if elapsed_changed:
                used_elapsed_cache_keys: set[tuple[str, str]] = set()
                for item_id, meta in self.schedule_tree_item_meta.items():
                    is_selected = item_id in selected_item_ids
                    elapsed_specs = self._get_schedule_tree_elapsed_overlay_specs(item_id, meta)
                    overlay_fg = self._normalize_hex_color(str(meta.get("elapsed_overlay_fg") or DEFAULT_SCHEDULE_TEXT_COLOR), DEFAULT_SCHEDULE_TEXT_COLOR)
                    overlay_bg = self._normalize_hex_color(str(meta.get("elapsed_overlay_bg") or DEFAULT_SCHEDULE_BG_COLOR), DEFAULT_SCHEDULE_BG_COLOR)
                    for column_id, bbox, overlay_text in elapsed_specs:
                        elapsed_cache_key = (item_id, f"elapsed_{column_id}")
                        elapsed_label = self._get_schedule_tree_overlay_label(elapsed_cache_key, overlay_parent)
                        if elapsed_label is None:
                            continue
                        elapsed_label.config(
                            text=overlay_text,
                            font=self.schedule_tree_elapsed_font,
                            bg="#bfdbfe" if is_selected else overlay_bg,
                            fg="#0f172a" if is_selected else overlay_fg,
                            anchor="center",
                        )
                        elapsed_label.place(x=tree_offset_x + bbox[0], y=tree_offset_y + bbox[1] + 1, width=bbox[2], height=max(20, bbox[3] - 2))
                        elapsed_label.lift()
                        used_elapsed_cache_keys.add(elapsed_cache_key)
                for cache_key, widget in list(self.schedule_tree_overlay_cache.items()):
                    if not cache_key[1].startswith("elapsed_"):
                        continue
                    if cache_key in used_elapsed_cache_keys:
                        continue
                    try:
                        widget.place_forget()
                    except tk.TclError:
                        pass

            self.schedule_tree_overlay_widgets = [
                widget
                for widget in self.schedule_tree_overlay_cache.values()
                if isinstance(widget, tk.Widget) and widget.winfo_exists()
            ]
            if retry_required:
                self._schedule_tree_overlay_after_delay(120)
        except tk.TclError:
            self._clear_schedule_tree_overlays()

    def _schedule_tree_overlay_after_delay(self, delay_ms: int = 80) -> None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return
        retry_job = self.schedule_tree_overlay_retry_job
        if retry_job is not None:
            try:
                self.schedule_tree.after_cancel(retry_job)
            except tk.TclError:
                pass
        try:
            self.schedule_tree_overlay_retry_job = self.schedule_tree.after(delay_ms, self._refresh_schedule_tree_overlays)
        except tk.TclError:
            self.schedule_tree_overlay_retry_job = None

    def _schedule_tree_overlay_after_idle(self, _event=None) -> None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
            return
        retry_job = self.schedule_tree_overlay_retry_job
        if retry_job is not None:
            try:
                self.schedule_tree.after_cancel(retry_job)
            except tk.TclError:
                pass
            self.schedule_tree_overlay_retry_job = None
        try:
            self.schedule_tree.after_idle(self._refresh_schedule_tree_overlays)
        except tk.TclError:
            return

    def _apply_schedule_tree_quick_cut_visual_state(
        self,
        identity: tuple[str, str, str, str] | None,
        *,
        cut_time_text: str,
    ) -> None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists() or not isinstance(identity, tuple):
            return
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        target_item_id = ""
        target_meta: dict[str, object] | None = None
        for item_id, meta in self.schedule_tree_item_meta.items():
            current_identity = meta.get("identity")
            if current_identity == identity:
                target_item_id = item_id
                target_meta = meta
                break
            if target_match_key is not None and self._get_schedule_cut_match_key(identity=current_identity if isinstance(current_identity, tuple) else None) == target_match_key:
                target_item_id = item_id
                target_meta = meta
                break
        if not target_item_id:
            self._schedule_tree_overlay_after_idle()
            return
        try:
            values = list(self.schedule_tree.item(target_item_id, "values"))
            while len(values) < 8:
                values.append("")
            current_item = self._get_schedule_event_item_by_identity(identity)
            if not isinstance(current_item, dict) and isinstance(target_meta, dict):
                fallback_item = target_meta.get("item")
                if isinstance(fallback_item, dict):
                    current_item = fallback_item
            quick_cut_entry = self._get_schedule_tree_quick_cut_entry(identity, current_item if isinstance(current_item, dict) else None)
            inline_visible = bool(
                quick_cut_entry is not None
                or (
                    isinstance(current_item, dict)
                    and self._can_schedule_event_show_inline_cut(current_item, self._get_schedule_reference_datetime())
                )
            )
            if isinstance(target_meta, dict):
                target_meta["cut_available"] = inline_visible
                target_meta["cut_inline_visible"] = inline_visible
                if isinstance(current_item, dict):
                    target_meta["item"] = dict(current_item)
            values[4] = ""
            values[5] = ""
            self.schedule_tree.item(target_item_id, values=tuple(values))
            self._update_schedule_tree_action_buttons()
            self._schedule_tree_overlay_after_idle()
            if self.root is not None and self.root.winfo_exists():
                def finalize_row() -> None:
                    if self.schedule_tree is None or not self.schedule_tree.winfo_exists():
                        return
                    try:
                        row_values = list(self.schedule_tree.item(target_item_id, "values"))
                        while len(row_values) < 8:
                            row_values.append("")
                        row_values[4] = ""
                        row_values[5] = ""
                        self.schedule_tree.item(target_item_id, values=tuple(row_values))
                        self._update_schedule_tree_action_buttons()
                        self._schedule_tree_overlay_after_idle()
                    except tk.TclError:
                        return
                self.root.after(320, finalize_row)
        except tk.TclError:
            return

    def _restore_schedule_tree_quick_cut_visual_state(
        self,
        identity: tuple[str, str, str, str] | None,
    ) -> None:
        if self.schedule_tree is None or not self.schedule_tree.winfo_exists() or not isinstance(identity, tuple):
            return
        target_match_key = self._get_schedule_cut_match_key(identity=identity)
        target_item_id = ""
        target_meta: dict[str, object] | None = None
        for item_id, meta in self.schedule_tree_item_meta.items():
            current_identity = meta.get("identity")
            if current_identity == identity:
                target_item_id = item_id
                target_meta = meta
                break
            if target_match_key is not None and self._get_schedule_cut_match_key(identity=current_identity if isinstance(current_identity, tuple) else None) == target_match_key:
                target_item_id = item_id
                target_meta = meta
                break
        if not target_item_id or not isinstance(target_meta, dict):
            self._schedule_tree_overlay_after_idle()
            return
        try:
            values = list(self.schedule_tree.item(target_item_id, "values"))
            while len(values) < 8:
                values.append("")
            current_item = self._get_schedule_event_item_by_identity(identity)
            if isinstance(current_item, dict):
                target_meta["item"] = dict(current_item)
                respawn_available = self._get_schedule_item_respawn_seconds(current_item) > 0
                target_meta["cut_disabled_reason"] = "" if respawn_available else "no_respawn"
                target_meta["cut_available"] = bool(respawn_available and self._can_schedule_event_show_inline_cut(current_item, self._get_schedule_reference_datetime()))
                target_meta["cut_inline_visible"] = bool(respawn_available and self._can_schedule_event_show_inline_cut(current_item, self._get_schedule_reference_datetime()))
            values[4] = ""
            values[5] = ""
            self.schedule_tree.item(target_item_id, values=tuple(values))
            self._update_schedule_tree_action_buttons()
            if self.root is not None and self.root.winfo_exists():
                self.root.after(320, self._schedule_tree_overlay_after_idle)
        except tk.TclError:
            return

    def _apply_schedule_tree_quick_cut(self, item: dict[str, object], identity: tuple[str, str, str, str] | None) -> None:
        interaction_key = self._begin_schedule_cut_interaction(identity if isinstance(identity, tuple) else None)
        if interaction_key is None:
            return
        if self._is_schedule_tree_click_debounce_active():
            self._end_schedule_cut_interaction(interaction_key, keep_cooldown=False)
            return
        self._arm_schedule_tree_click_debounce()
        try:
            if not self._can_schedule_event_accept_cut(item, self._get_schedule_reference_datetime()):
                self.schedule_status_var.set("예정 상태에서는 컷을 적용할 수 없습니다. 수정 또는 스케쥴 입력을 사용하세요.")
                return
            if not self._begin_schedule_cut_request(identity):
                return
            cut_token = self._get_schedule_reference_datetime().strftime("%H%M%S")
            anchor_datetime = item.get("scheduled_at")
            # Preserve the selected row's scheduled_at, and rebuild the future chain
            # from the actual cut time instead of shifting the original schedule.
            overwrite_start = anchor_datetime.replace(microsecond=0) if isinstance(anchor_datetime, datetime) else None
            self._apply_schedule_quick_cut_with_history(
                dict(item),
                identity,
                cut_token=cut_token,
                overwrite_start_datetime=overwrite_start,
                cut_preserve_scheduled_at=anchor_datetime if isinstance(anchor_datetime, datetime) else None,
                source_label="스케쥴 컷 적용",
            )
        finally:
            self._end_schedule_cut_interaction(interaction_key)

    def _apply_schedule_tree_cut_time(self, item: dict[str, object], identity: tuple[str, str, str, str] | None) -> None:
        interaction_key = self._begin_schedule_cut_interaction(identity if isinstance(identity, tuple) else None)
        if interaction_key is None:
            return
        if self._is_schedule_tree_click_debounce_active():
            self._end_schedule_cut_interaction(interaction_key, keep_cooldown=False)
            return
        self._arm_schedule_tree_click_debounce()
        try:
            resolved_identity = identity if isinstance(identity, tuple) else self._get_schedule_item_identity("event", item)
            tree_quick_cut_entry = self._get_schedule_tree_quick_cut_entry(resolved_identity, item)
            active_quick_cut_entry = self._get_schedule_active_quick_cut_entry_by_tree_identity(resolved_identity, item)
            existing_entry = tree_quick_cut_entry if isinstance(tree_quick_cut_entry, dict) else active_quick_cut_entry
            source_item = (
                dict(existing_entry.get("item"))
                if isinstance(existing_entry, dict) and isinstance(existing_entry.get("item"), dict)
                else dict(item)
            )
            if existing_entry is None and not self._can_schedule_event_accept_cut(item, self._get_schedule_reference_datetime()):
                self.schedule_status_var.set("예정 상태에서는 컷시간을 적용할 수 없습니다. 수정 또는 스케쥴 입력을 사용하세요.")
                return
            boss_text = self._get_schedule_boss_display_name(source_item, prefer_alias=True)
            cut_token = self._show_schedule_cut_time_dialog(boss_text, parent=self.schedule_window)
            if not cut_token:
                return
            presence_text = self._normalize_schedule_presence_text(cut_token)
            if presence_text:
                if isinstance(existing_entry, dict):
                    self._clear_schedule_tree_cut_time(dict(item), resolved_identity)
                self._add_schedule_active_entries_by_text(f"{boss_text} {presence_text}")
                return
            if cut_token == "0":
                self._clear_schedule_tree_cut_time(dict(item), resolved_identity)
                return
            if isinstance(existing_entry, dict):
                self._clear_schedule_tree_cut_time(dict(item), resolved_identity)
            if not self._begin_schedule_cut_request(resolved_identity):
                return
            anchor_datetime = source_item.get("scheduled_at")
            overwrite_start = anchor_datetime.replace(microsecond=0) if isinstance(anchor_datetime, datetime) else None
            self._apply_schedule_quick_cut_with_history(
                source_item,
                resolved_identity,
                cut_token=cut_token,
                overwrite_start_datetime=overwrite_start,
                cut_preserve_scheduled_at=anchor_datetime if isinstance(anchor_datetime, datetime) else None,
                source_label="스케쥴 컷시간 적용",
            )
        finally:
            self._end_schedule_cut_interaction(interaction_key)

    def _cancel_schedule_tree_cut_state(self, item: dict[str, object], identity: tuple[str, str, str, str] | None) -> None:
        if self._is_schedule_tree_click_debounce_active():
            return
        self._arm_schedule_tree_click_debounce()
        self._clear_schedule_tree_cut_time(dict(item), identity if isinstance(identity, tuple) else None)

    def _clear_schedule_tree_cut_time(self, item: dict[str, object], identity: tuple[str, str, str, str] | None) -> None:
        resolved_identity = identity if isinstance(identity, tuple) else None
        if isinstance(resolved_identity, tuple):
            tree_quick_cut_entry = self._get_schedule_tree_quick_cut_entry(resolved_identity, item)
            if isinstance(tree_quick_cut_entry, dict):
                self._undo_schedule_tree_quick_cut_impl(resolved_identity)
                return
            active_quick_cut_entry = self._get_schedule_active_quick_cut_entry_by_tree_identity(resolved_identity, item)
            if isinstance(active_quick_cut_entry, dict):
                active_identity = active_quick_cut_entry.get("identity")
                self._undo_schedule_active_quick_cut(active_identity if isinstance(active_identity, tuple) else None)
                return
        scheduled_at = item.get("scheduled_at")
        raw_key = str(item.get("raw_key") or "").strip()
        if not isinstance(scheduled_at, datetime) or not raw_key:
            self.schedule_status_var.set("삭제할 컷시간 대상을 찾지 못했습니다.")
            return
        boss_text = self._get_schedule_boss_display_name(item, prefer_alias=False) or str(item.get("display_name") or item.get("boss_name") or "").strip()
        if not boss_text:
            self.schedule_status_var.set("삭제할 컷시간 대상을 찾지 못했습니다.")
            return
        parsed_item = {
            **self._normalize_schedule_input_boss_name(boss_text),
            "state": "scheduled",
            "mode": "clock",
            "day_offset": 0,
            "day_offset_explicit": False,
            "clock_hours": scheduled_at.hour,
            "clock_minutes": scheduled_at.minute,
            "clock_seconds": scheduled_at.second,
            "precision": "second" if scheduled_at.second else "minute",
            "source_text": f"{scheduled_at.strftime('%H:%M:%S')} {boss_text}",
        }
        applied = self._apply_schedule_parsed_batch(
            parsed_item["source_text"],
            [parsed_item],
            0,
            self._get_schedule_reference_datetime(),
            scheduled_at.replace(microsecond=0),
            overwrite_cutoff_datetime=scheduled_at.replace(microsecond=0),
            edit_mode=False,
            force_past_update_keys={raw_key},
            source_label="스케쥴 컷시간 삭제",
            skip_overwrite_confirm=True,
            suppress_schedule_view_refresh=True,
            store_input_undo_backup=False,
            refresh_tree_on_suppress=False,
            refresh_active_rows_on_suppress=False,
            suppress_auto_cut_raw_keys={raw_key},
        )
        if not applied:
            return
        self._refresh_schedule_view_live()
        self._save_schedule_state()
        self.schedule_status_var.set("선택한 스케쥴의 컷시간을 삭제했습니다.")

    def _undo_schedule_tree_quick_cut_impl(self, identity: tuple[str, str, str, str] | None = None) -> None:
        if not self.schedule_tree_quick_cut_history:
            return
        target_identity = identity if isinstance(identity, tuple) else None
        target_match_key = self._get_schedule_cut_match_key(identity=target_identity) if target_identity is not None else None
        target_index = -1
        if target_identity is not None:
            for index in range(len(self.schedule_tree_quick_cut_history) - 1, -1, -1):
                entry = self.schedule_tree_quick_cut_history[index]
                if entry.get("identity") == target_identity or (
                    target_match_key is not None and entry.get("match_key") == target_match_key
                ):
                    target_index = index
                    break
        if target_index < 0:
            target_index = len(self.schedule_tree_quick_cut_history) - 1
        target_entry = self.schedule_tree_quick_cut_history[target_index]
        if target_identity is None:
            resolved_identity = target_entry.get("identity")
            target_identity = resolved_identity if isinstance(resolved_identity, tuple) else None
            target_match_key = self._get_schedule_cut_match_key(identity=target_identity) if target_identity is not None else None
        target_item = target_entry.get("item")
        target_raw_key = ""
        if isinstance(target_item, dict):
            target_raw_key = str(target_item.get("raw_key") or "").strip()
        if not target_raw_key and isinstance(target_identity, tuple) and len(target_identity) >= 2:
            target_raw_key = str(target_identity[1] or "").strip()
        backup = target_entry.get("backup")
        if not isinstance(backup, dict) or not target_raw_key:
            return
        preserved_history: list[dict[str, object]] = []
        for history_index, entry in enumerate(self.schedule_tree_quick_cut_history):
            if history_index == target_index:
                continue
            if entry.get("identity") == target_identity or (
                target_match_key is not None and entry.get("match_key") == target_match_key
            ):
                continue
            preserved_history.append(entry)
        self._restore_schedule_state_for_raw_key(backup, target_raw_key)
        self.schedule_tree_quick_cut_history = list(preserved_history)
        if target_identity is not None:
            self.schedule_tree_overlay_cooldowns[target_match_key or target_identity] = time.monotonic() + 0.3
        self._save_schedule_state()
        self._refresh_schedule_view_live()
        self.schedule_status_var.set("최근 컷 적용을 취소했습니다.")
        self._update_schedule_input_undo_state()

    def _undo_schedule_tree_quick_cut(self, identity: tuple[str, str, str, str] | None = None) -> None:
        if self._is_schedule_tree_click_debounce_active():
            return
        self._arm_schedule_tree_click_debounce()
        self._undo_schedule_tree_quick_cut_impl(identity)

    def _undo_schedule_active_quick_cut(self, identity: tuple[str, str, str, str] | None = None) -> None:
        if not self.schedule_active_quick_cut_history:
            return
        target_identity = identity if isinstance(identity, tuple) else None
        target_match_key = self._get_schedule_cut_match_key(identity=target_identity) if target_identity is not None else None
        target_index = -1
        if target_identity is not None:
            for index in range(len(self.schedule_active_quick_cut_history) - 1, -1, -1):
                entry = self.schedule_active_quick_cut_history[index]
                if entry.get("identity") == target_identity or (
                    target_match_key is not None and entry.get("match_key") == target_match_key
                ):
                    target_index = index
                    break
        if target_index < 0:
            target_index = len(self.schedule_active_quick_cut_history) - 1
        target_entry = self.schedule_active_quick_cut_history[target_index]
        if target_identity is None:
            resolved_identity = target_entry.get("identity")
            target_identity = resolved_identity if isinstance(resolved_identity, tuple) else None
            target_match_key = self._get_schedule_cut_match_key(identity=target_identity) if target_identity is not None else None
        target_tree_identity = target_entry.get("tree_identity")
        if not isinstance(target_tree_identity, tuple):
            target_item = target_entry.get("item")
            target_cut_datetime = target_entry.get("cut_datetime")
            if isinstance(target_item, dict):
                target_tree_identity = self._find_schedule_cut_target_event_identity(
                    str(target_item.get("raw_key") or ""),
                    target_cut_datetime if isinstance(target_cut_datetime, datetime) else None,
                )
        target_item = target_entry.get("item")
        target_raw_key = ""
        if isinstance(target_item, dict):
            target_raw_key = str(target_item.get("raw_key") or "").strip()
        if not target_raw_key and isinstance(target_identity, tuple) and len(target_identity) >= 2:
            target_raw_key = str(target_identity[1] or "").strip()
        backup = target_entry.get("backup")
        if not isinstance(backup, dict) or not target_raw_key:
            return
        preserved_history: list[dict[str, object]] = []
        for history_index, entry in enumerate(self.schedule_active_quick_cut_history):
            if history_index == target_index:
                continue
            if entry.get("identity") == target_identity or (
                target_match_key is not None and entry.get("match_key") == target_match_key
            ):
                continue
            preserved_history.append(entry)
        self._restore_schedule_state_for_raw_key(backup, target_raw_key)
        self.schedule_active_quick_cut_history = list(preserved_history)
        if target_identity is not None:
            self.schedule_active_overlay_cooldowns[target_match_key or target_identity] = time.monotonic() + 0.3
        self._refresh_schedule_view_live()
        self._save_schedule_state()
        self.schedule_status_var.set("최근 출현 중 컷 적용을 취소했습니다.")
        self._update_schedule_input_undo_state()

    def _on_schedule_tree_drag(self, event) -> None:
        if self.schedule_tree is None or not self.schedule_tree_drag_anchor:
            return
        try:
            current_item = self.schedule_tree.identify_row(event.y) or None
            if not current_item:
                return
            item_ids = list(self.schedule_tree.get_children(""))
            if self.schedule_tree_drag_anchor not in item_ids or current_item not in item_ids:
                return
            start_index = item_ids.index(self.schedule_tree_drag_anchor)
            end_index = item_ids.index(current_item)
            selected_ids: list[str] = []
            for item_id in item_ids[min(start_index, end_index):max(start_index, end_index) + 1]:
                if "date_header" in set(self.schedule_tree.item(item_id, "tags")):
                    continue
                selected_ids.append(item_id)
            self.schedule_tree.selection_set(selected_ids)
            self._update_schedule_tree_action_buttons()
        except tk.TclError:
            return

    def _get_selected_schedule_edit_keys(self) -> set[str]:
        keys: set[str] = set()
        if self.schedule_tree is None:
            return keys
        try:
            for item_id in self.schedule_tree.selection():
                meta = self.schedule_tree_item_meta.get(item_id, {})
                kind = str(meta.get("kind") or "")
                identity = meta.get("identity")
                if kind != "event" or not isinstance(identity, tuple):
                    continue
                for item in self.schedule_events:
                    if self._get_schedule_item_identity("event", item) == identity:
                        raw_key = str(item.get("raw_key") or "")
                        if raw_key:
                            keys.add(raw_key)
                        break
        except tk.TclError:
            return set()
        return keys

    def _get_selected_schedule_event_items(self) -> list[dict[str, object]]:
        items: list[dict[str, object]] = []
        if self.schedule_tree is None:
            return items
        try:
            selected_identities = []
            for item_id in self.schedule_tree.selection():
                meta = self.schedule_tree_item_meta.get(item_id, {})
                kind = str(meta.get("kind") or "")
                identity = meta.get("identity")
                if kind == "event" and isinstance(identity, tuple):
                    selected_identities.append(identity)
            for identity in selected_identities:
                for item in self.schedule_events:
                    if self._get_schedule_item_identity("event", item) == identity:
                        items.append(dict(item))
                        break
        except tk.TclError:
            return []
        items.sort(key=lambda item: (item.get("scheduled_at") or datetime.max, str(item.get("display_name") or item.get("boss_name") or "")))
        return items

    def _is_schedule_input_compact_mode(self) -> bool:
        return bool(self.schedule_input_edit_mode or self.schedule_input_add_mode)

    def _get_schedule_input_mode_label(self) -> str:
        if self.schedule_input_edit_mode:
            return "수정"
        if self.schedule_input_add_mode:
            return "추가"
        return "입력"

    def _reset_schedule_input_mode_state(self) -> None:
        self.schedule_input_add_mode = False
        self.schedule_input_edit_mode = False
        self.schedule_input_edit_keys = set()
        self.schedule_input_edit_identities = []
        self.schedule_input_edit_anchor_datetime = None
        self.schedule_input_edit_selected_map = {}

    def _configure_schedule_input_window_mode(self, prefill: bool = False) -> None:
        if self.schedule_input_window is not None and self.schedule_input_window.winfo_exists():
            try:
                self.schedule_input_window.title(f"스케쥴 {self._get_schedule_input_mode_label()}")
            except tk.TclError:
                pass
