    def _delete_selected_schedule_rows(self) -> None:
        if self.schedule_tree is None:
            return
        selected_event_items: list[dict[str, object]] = []
        selected_control_items: list[dict[str, object]] = []
        selected_labels: list[str] = []
        try:
            for item_id in self.schedule_tree.selection():
                meta = self.schedule_tree_item_meta.get(item_id, {})
                kind = str(meta.get("kind") or "")
                identity = meta.get("identity")
                if not isinstance(identity, tuple):
                    continue
                values = self.schedule_tree.item(item_id, "values")
                label = f"{values[0]}  {values[1]}" if len(values) >= 2 else item_id
                if kind == "event":
                    for item in self.schedule_events:
                        if self._get_schedule_item_identity("event", item) == identity:
                            selected_event_items.append(dict(item))
                            selected_labels.append(label)
                            break
                elif kind == "control":
                    for item in self.schedule_control_events:
                        if self._get_schedule_item_identity("control", item) == identity:
                            selected_control_items.append(dict(item))
                            selected_labels.append(label)
                            break
        except tk.TclError:
            return
        if not selected_event_items and not selected_control_items:
            return
        future_delete_event_items = self._get_schedule_future_delete_event_items(selected_event_items)
        selected_event_identities = {self._get_schedule_item_identity("event", item) for item in selected_event_items}
        future_delete_count = sum(
            1
            for item in future_delete_event_items
            if self._get_schedule_item_identity("event", item) not in selected_event_identities
        )
        delete_mode = self._show_schedule_delete_confirm(selected_labels, future_delete_count=future_delete_count)
        if delete_mode is None:
            return
        if delete_mode == "future_all":
            selected_event_items = future_delete_event_items
        event_identities = {self._get_schedule_item_identity("event", item) for item in selected_event_items}
        event_raw_keys = {
            str(item.get("raw_key") or "").strip()
            for item in selected_event_items
            if str(item.get("raw_key") or "").strip()
        }
        control_identities = {self._get_schedule_item_identity("control", item) for item in selected_control_items}
        self.schedule_tree_deleted_backup = {
            "events": [dict(item) for item in selected_event_items],
            "controls": [dict(item) for item in selected_control_items],
        }
        self.schedule_events = [
            item for item in self.schedule_events
            if self._get_schedule_item_identity("event", item) not in event_identities
        ]
        self.schedule_control_events = [
            item for item in self.schedule_control_events
            if self._get_schedule_item_identity("control", item) not in control_identities
        ]
        self._purge_schedule_cut_state(identities=event_identities, raw_keys=event_raw_keys)
        deleted_count = len(selected_event_items) + len(selected_control_items)
        if delete_mode == "future_all" and future_delete_count > 0:
            self.schedule_status_var.set(f"선택 일정과 이후 같은 보스 스케쥴을 포함해 {deleted_count}건을 삭제했습니다.")
        else:
            self.schedule_status_var.set(f"{deleted_count}건의 스케쥴을 삭제했습니다.")
        self._save_schedule_state()
        self._refresh_schedule_view()
        self._update_schedule_tree_action_buttons()

    def _restore_deleted_schedule_rows(self) -> None:
        if not self.schedule_tree_deleted_backup:
            return
        restored_events = [dict(item) for item in self.schedule_tree_deleted_backup.get("events", []) if isinstance(item, dict)]
        restored_controls = [dict(item) for item in self.schedule_tree_deleted_backup.get("controls", []) if isinstance(item, dict)]
        existing_event_identities = {self._get_schedule_item_identity("event", item) for item in self.schedule_events}
        existing_control_identities = {self._get_schedule_item_identity("control", item) for item in self.schedule_control_events}
        self.schedule_tree_pending_restore_identities = []
        for item in restored_events:
            identity = self._get_schedule_item_identity("event", item)
            if identity not in existing_event_identities:
                self.schedule_events.append(item)
                self.schedule_tree_pending_restore_identities.append(identity)
        for item in restored_controls:
            identity = self._get_schedule_item_identity("control", item)
            if identity not in existing_control_identities:
                self.schedule_control_events.append(item)
                self.schedule_tree_pending_restore_identities.append(identity)
        self.schedule_events.sort(key=lambda item: (item.get("scheduled_at") or datetime.max, str(item.get("display_name") or item.get("boss_name") or "")))
        self.schedule_control_events.sort(key=lambda item: item.get("scheduled_at") or datetime.max)
        self.schedule_tree_deleted_backup = None
        self.schedule_status_var.set(f"{len(self.schedule_tree_pending_restore_identities)}건의 스케쥴을 복구했습니다.")
        self._save_schedule_state()
        self._refresh_schedule_view()

    def _schedule_delete_item_matches_cutoff(self, item: dict[str, object] | None, cutoff_datetime: datetime) -> bool:
        if not isinstance(item, dict) or not isinstance(cutoff_datetime, datetime):
            return False
        scheduled_at = item.get("scheduled_at")
        if isinstance(scheduled_at, datetime) and scheduled_at.replace(microsecond=0) >= cutoff_datetime.replace(microsecond=0):
            return True
        created_at = item.get("created_at")
        if isinstance(created_at, datetime) and created_at.replace(microsecond=0) >= cutoff_datetime.replace(microsecond=0):
            return True
        return False

    def _schedule_delete_history_entry_matches_cutoff(self, entry: dict[str, object], cutoff_datetime: datetime) -> bool:
        if not isinstance(entry, dict) or not isinstance(cutoff_datetime, datetime):
            return False
        cutoff_key = cutoff_datetime.replace(microsecond=0)
        for field_name in ("cut_datetime", "action_at", "deleted_at"):
            field_value = entry.get(field_name)
            if isinstance(field_value, datetime) and field_value.replace(microsecond=0) >= cutoff_key:
                return True
        item = entry.get("item")
        if self._schedule_delete_item_matches_cutoff(item if isinstance(item, dict) else None, cutoff_key):
            return True
        return False

    def _get_schedule_delete_scope_counts(self, cutoff_datetime: datetime) -> dict[str, int]:
        cutoff_key = cutoff_datetime.replace(microsecond=0)
        event_count = sum(1 for item in self.schedule_events if self._schedule_delete_item_matches_cutoff(item, cutoff_key))
        active_count = sum(1 for item in self.schedule_active_entries if self._schedule_delete_item_matches_cutoff(item, cutoff_key))
        control_count = sum(1 for item in self.schedule_control_events if self._schedule_delete_item_matches_cutoff(item, cutoff_key))
        quick_cut_count = sum(
            1
            for entry in self.schedule_tree_quick_cut_history
            if isinstance(entry, dict) and self._schedule_delete_history_entry_matches_cutoff(entry, cutoff_key)
        )
        quick_cut_count += sum(
            1
            for entry in self.schedule_active_quick_cut_history
            if isinstance(entry, dict) and self._schedule_delete_history_entry_matches_cutoff(entry, cutoff_key)
        )
        imported_count = 0
        if isinstance(self.schedule_last_import_meta, dict):
            imported_at = self.schedule_last_import_meta.get("imported_at")
            if isinstance(imported_at, datetime) and imported_at.replace(microsecond=0) >= cutoff_key:
                imported_count = 1
        total = event_count + active_count + control_count + quick_cut_count
        return {
            "events": event_count,
            "active": active_count,
            "controls": control_count,
            "quick_cut": quick_cut_count,
            "import_meta": imported_count,
            "total": total,
        }

    def _show_schedule_delete_period_dialog(self, *, parent: tk.Widget | None = None) -> datetime | None:
        host = parent if self._widget_available(parent) else (self.schedule_window if self._widget_available(self.schedule_window) else self.root)
        dialog = tk.Toplevel(host)
        dialog.title("스케쥴 전체삭제")
        dialog.resizable(False, False)
        dialog.configure(bg="#fff7ed")
        dialog.transient(host)
        dialog.grab_set()
        width = 540
        height = 324
        self._center_window_over_parent(dialog, host, width, height)

        result = {"cutoff": None}
        now = self._get_schedule_reference_datetime()
        default_cutoff = self._get_schedule_delete_default_cutoff_datetime(now)
        season_start = self._get_schedule_season_started_datetime()

        year_values = [f"{year}년" for year in range(now.year - 2, now.year + 3)]
        month_values = [f"{month:02d}월" for month in range(1, 13)]
        day_values = [f"{day:02d}일" for day in range(1, 32)]
        hour_values = [f"{hour:02d}시" for hour in range(0, 24)]
        minute_values = [f"{minute:02d}분" for minute in range(0, 60)]

        cutoff_year_var = tk.StringVar()
        cutoff_month_var = tk.StringVar()
        cutoff_day_var = tk.StringVar()
        cutoff_hour_var = tk.StringVar()
        cutoff_minute_var = tk.StringVar()
        status_var = tk.StringVar()

        def set_cutoff_fields(target_datetime: datetime | None) -> None:
            resolved = target_datetime if isinstance(target_datetime, datetime) else default_cutoff
            resolved = resolved.replace(microsecond=0)
            for var, value in (
                (cutoff_year_var, resolved.strftime("%Y년")),
                (cutoff_month_var, resolved.strftime("%m월")),
                (cutoff_day_var, resolved.strftime("%d일")),
                (cutoff_hour_var, resolved.strftime("%H시")),
                (cutoff_minute_var, resolved.strftime("%M분")),
            ):
                var.set(value)
            update_preview()

        def read_cutoff_datetime() -> datetime | None:
            try:
                year = int(re.sub(r"[^0-9]", "", cutoff_year_var.get() or ""))
                month = int(re.sub(r"[^0-9]", "", cutoff_month_var.get() or ""))
                day = int(re.sub(r"[^0-9]", "", cutoff_day_var.get() or ""))
                hour = int(re.sub(r"[^0-9]", "", cutoff_hour_var.get() or ""))
                minute = int(re.sub(r"[^0-9]", "", cutoff_minute_var.get() or ""))
                return datetime(year, month, day, hour, minute, 0).replace(microsecond=0)
            except ValueError:
                return None

        def update_preview(*_args) -> None:
            cutoff_datetime = read_cutoff_datetime()
            if not isinstance(cutoff_datetime, datetime):
                status_var.set("삭제 기준 시각을 정확히 입력하세요.")
                return
            counts = self._get_schedule_delete_scope_counts(cutoff_datetime)
            cutoff_text = cutoff_datetime.strftime("%Y-%m-%d %H:%M")
            status_var.set(
                f"{cutoff_text} 이후 삭제 예정: 스케쥴 {counts['events']}건 / 활성 {counts['active']}건 / 제어 {counts['controls']}건 / 상태 {counts['quick_cut']}건"
            )

        def close_with(value: datetime | None) -> None:
            result["cutoff"] = value
            try:
                dialog.grab_release()
            except tk.TclError:
                pass
            dialog.destroy()

        def confirm_delete() -> None:
            cutoff_datetime = read_cutoff_datetime()
            if not isinstance(cutoff_datetime, datetime):
                status_var.set("삭제 기준 시각을 정확히 입력하세요.")
                return
            close_with(cutoff_datetime)

        def apply_preset(target_datetime: datetime | None) -> None:
            if not isinstance(target_datetime, datetime):
                status_var.set("적용할 기준 시각을 찾지 못했습니다.")
                return
            set_cutoff_fields(target_datetime)

        tk.Label(dialog, text="스케쥴 전체삭제", font=self.header_font, bg="#ffedd5", fg="#9a3412").place(x=0, y=0, width=width, height=40)
        tk.Label(dialog, text="삭제 기준 시각", font=self.button_font, bg="#fff7ed", fg="#7c2d12", anchor="w").place(x=20, y=56, width=100, height=22)
        ttk.Combobox(dialog, textvariable=cutoff_year_var, values=year_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=20, y=82, width=74, height=28)
        ttk.Combobox(dialog, textvariable=cutoff_month_var, values=month_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=102, y=82, width=58, height=28)
        ttk.Combobox(dialog, textvariable=cutoff_day_var, values=day_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=168, y=82, width=58, height=28)
        ttk.Combobox(dialog, textvariable=cutoff_hour_var, values=hour_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=234, y=82, width=58, height=28)
        ttk.Combobox(dialog, textvariable=cutoff_minute_var, values=minute_values, font=(self.current_font_family, 10, "bold"), state="normal").place(x=300, y=82, width=58, height=28)
        tk.Button(
            dialog,
            text="이번주 서버오픈",
            font=self.percent_font,
            bg="#f8f1df",
            fg="#7c2d12",
            activebackground="#efe2c5",
            activeforeground="#7c2d12",
            relief="raised",
            bd=1,
            highlightthickness=0,
            command=lambda: apply_preset(self._get_schedule_default_server_open_datetime(now)),
            cursor="hand2",
        ).place(x=20, y=126, width=110, height=28)
        tk.Button(
            dialog,
            text="시즌오픈",
            font=self.percent_font,
            bg="#dbeafe",
            fg="#1e3a8a",
            activebackground="#bfdbfe",
            activeforeground="#1e3a8a",
            relief="raised",
            bd=1,
            highlightthickness=0,
            command=lambda: apply_preset(season_start if isinstance(season_start, datetime) else self._get_schedule_default_server_open_datetime(now)),
            cursor="hand2",
        ).place(x=138, y=126, width=78, height=28)
        tk.Button(
            dialog,
            text="최근값",
            font=self.percent_font,
            bg="#e0f2fe",
            fg="#075985",
            activebackground="#bae6fd",
            activeforeground="#075985",
            relief="raised",
            bd=1,
            highlightthickness=0,
            command=lambda: apply_preset(default_cutoff),
            cursor="hand2",
        ).place(x=224, y=126, width=78, height=28)
        tk.Label(
            dialog,
            text="기준 시각 이후의 스케쥴, 활성 상태, 컷 상태를 모두 삭제합니다.",
            font=self.percent_font,
            bg="#fff7ed",
            fg="#9a3412",
            justify="left",
            wraplength=480,
        ).place(x=20, y=166, width=500, height=34)
        tk.Label(
            dialog,
            textvariable=status_var,
            font=self.percent_font,
            bg="#ffffff",
            fg="#0f172a",
            anchor="w",
            relief="solid",
            bd=1,
            justify="left",
            wraplength=500,
        ).place(x=20, y=206, width=500, height=48)
        tk.Button(
            dialog,
            text="삭제",
            font=self.button_font,
            bg="#dc2626",
            fg="#ffffff",
            activebackground="#b91c1c",
            activeforeground="#ffffff",
            relief="raised",
            bd=1,
            highlightthickness=0,
            command=confirm_delete,
            cursor="hand2",
        ).place(x=320, y=266, width=88, height=30)
        tk.Button(
            dialog,
            text="취소",
            font=self.button_font,
            bg="#e2e8f0",
            fg="#334155",
            activebackground="#cbd5e1",
            activeforeground="#334155",
            relief="raised",
            bd=1,
            highlightthickness=0,
            command=lambda: close_with(None),
            cursor="hand2",
        ).place(x=416, y=266, width=88, height=30)
        for variable in (cutoff_year_var, cutoff_month_var, cutoff_day_var, cutoff_hour_var, cutoff_minute_var):
            variable.trace_add("write", update_preview)
        dialog.protocol("WM_DELETE_WINDOW", lambda: close_with(None))
        dialog.bind("<Escape>", lambda _event: close_with(None))
        dialog.bind("<Return>", lambda _event: confirm_delete())
        set_cutoff_fields(default_cutoff)
        if isinstance(season_start, datetime):
            dialog.bind("<Control-s>", lambda _event: apply_preset(season_start))
        dialog.focus_force()
        dialog.wait_window()
        return result["cutoff"]

