    def _delete_selected_schedule_boss_definitions(self) -> None:
        if self.schedule_boss_tree is None:
            return
        default_boss_names = set(self._build_schedule_boss_definitions())
        try:
            selected_ids = list(self.schedule_boss_tree.selection())
        except tk.TclError:
            selected_ids = []
        if not selected_ids:
            self.schedule_boss_config_status_var.set("삭제할 보스를 선택하세요.")
            return
        count = len(selected_ids)
        if not self._show_schedule_boss_delete_confirm(count):
            return
        self.schedule_boss_deleted_backup = []
        for boss_name in selected_ids:
            item = self.schedule_boss_definitions.pop(boss_name, None)
            if item is not None:
                self.schedule_boss_deleted_backup.append(dict(item))
                self._discard_schedule_boss_draft(boss_name)
                if boss_name in default_boss_names:
                    self.schedule_boss_deleted_builtin_names.add(boss_name)
        if not self.schedule_boss_deleted_backup:
            self.schedule_boss_config_status_var.set("삭제할 보스를 찾지 못했습니다.")
            return
        if self.schedule_boss_selected_name in selected_ids:
            self._clear_schedule_boss_definition_form("선택한 보스를 삭제했습니다.")
        self._populate_schedule_boss_definition_tree()
        self._save_schedule_definition_files(f"{len(self.schedule_boss_deleted_backup)}개 보스 정의를 삭제하고 init 텍스트 파일에 저장했습니다.")
        self._set_schedule_boss_definition_dirty(False)
        self._refresh_schedule_boss_config_aux_buttons()

    def _restore_deleted_schedule_boss_definitions(self) -> None:
        if not self.schedule_boss_deleted_backup:
            self.schedule_boss_config_status_var.set("복구할 최근 삭제 보스가 없습니다.")
            return
        restored_ids: list[str] = []
        for item in self.schedule_boss_deleted_backup:
            boss_name = str(item.get("boss_name") or "")
            if not boss_name:
                continue
            self.schedule_boss_definitions[boss_name] = dict(item)
            self.schedule_boss_deleted_builtin_names.discard(boss_name)
            restored_ids.append(boss_name)
        self.schedule_boss_deleted_backup = None
        self._populate_schedule_boss_definition_tree()
        if self.schedule_boss_tree is not None and restored_ids:
            try:
                self.schedule_boss_tree.selection_set(restored_ids)
                self.schedule_boss_tree.focus(restored_ids[0])
                self.schedule_boss_tree.see(restored_ids[0])
            except tk.TclError:
                pass
        self._save_schedule_definition_files(f"{len(restored_ids)}개 보스 정의를 복구하고 init 텍스트 파일에 저장했습니다.")
        self._set_schedule_boss_definition_dirty(False)
        self._refresh_schedule_boss_config_aux_buttons()

