    def close_schedule_break_window(self) -> None:
        try:
            self._save_schedule_break_apply_all_preferences()
            if self.schedule_break_window is not None and self.schedule_break_window.winfo_exists():
                self.schedule_break_window.withdraw()
            self.schedule_break_window_open = False
        except tk.TclError:
            self.schedule_break_window_open = False

    def _schedule_break_display_mode_options(self) -> dict[str, str]:
        return {
            "실제간격": "actual",
            "고정텍스트": "fixed",
            "30분 반올림": "rounded_30m",
        }

    def _get_schedule_break_display_mode_label(self, mode: str) -> str:
        reverse_map = {value: key for key, value in self._schedule_break_display_mode_options().items()}
        return reverse_map.get(str(mode or "").strip(), "실제간격")

    def _normalize_schedule_break_display_mode_value(self, raw_value: str) -> str:
        options = self._schedule_break_display_mode_options()
        stripped = str(raw_value or "").strip()
        if stripped in options:
            return options[stripped]
        if stripped in options.values():
            return stripped
        return "actual"

    def _format_schedule_break_rule_summary(self, item: dict[str, object]) -> str:
        min_gap = self._parse_int(str(item.get("min_gap_minutes") or "0"), 0)
        max_gap = self._parse_int(str(item.get("max_gap_minutes") or str(min_gap)), min_gap)
        label_text = str(item.get("label_text") or "휴식").strip() or "휴식"
        display_mode = self._get_schedule_break_display_mode_label(str(item.get("display_mode") or "actual"))
        display_text = str(item.get("display_text") or "").strip()
        if display_text:
            display_text = f" | {display_text}"
        return (
            f"[{'ON' if bool(item.get('enabled', True)) else 'OFF'}] "
            f"{min_gap}~{max_gap}분 | {label_text} | {display_mode}{display_text} | "
            f"행수 {float(item.get('row_scale') or 1.0):g}"
        )

    def _save_schedule_break_apply_all_preferences(self) -> None:
        self.schedule_break_apply_all_text_default = bool(self.schedule_break_apply_all_text_var.get())
        self.schedule_break_apply_all_display_mode_default = bool(self.schedule_break_apply_all_display_mode_var.get())
        self.schedule_break_apply_all_row_scale_default = bool(self.schedule_break_apply_all_row_scale_var.get())
        self.schedule_break_apply_all_font_size_default = bool(self.schedule_break_apply_all_font_size_var.get())
        self.schedule_break_apply_all_bold_default = bool(self.schedule_break_apply_all_bold_var.get())
        self.schedule_break_apply_all_enabled_default = bool(self.schedule_break_apply_all_enabled_var.get())
        self.schedule_break_apply_all_text_color_default = bool(self.schedule_break_apply_all_text_color_var.get())
        self.schedule_break_apply_all_bg_color_default = bool(self.schedule_break_apply_all_bg_color_var.get())
        self._save_settings()

    def _refresh_schedule_break_color_button_styles(self) -> None:
        self._apply_color_preview_button_style(self.schedule_break_text_color_button, self.schedule_break_text_color_var.get(), "글자색")
        self._apply_color_preview_button_style(self.schedule_break_bg_color_button, self.schedule_break_bg_color_var.get(), "배경색")

    def _choose_schedule_break_color(self, variable: tk.StringVar, button: tk.Widget | None, title: str, default: str) -> None:
        parent = self.schedule_break_window if self.schedule_break_window is not None and self.schedule_break_window.winfo_exists() else self.root
        initial_color = self._normalize_hex_color(variable.get(), default)
        try:
            _rgb, selected = colorchooser.askcolor(color=initial_color, title=title, parent=parent)
        except tk.TclError:
            return
        if not selected:
            return
        normalized = self._normalize_hex_color(selected, default)
        variable.set(normalized)
        if variable is self.schedule_break_text_color_var:
            self.schedule_break_last_text_color = normalized
        elif variable is self.schedule_break_bg_color_var:
            self.schedule_break_last_bg_color = normalized
        self._refresh_schedule_break_color_button_styles()
        self._save_settings()

    def _refresh_schedule_break_list(self) -> None:
        if self.schedule_break_listbox is None or not self.schedule_break_listbox.winfo_exists():
            return
        try:
            self.schedule_break_listbox.delete(0, "end")
        except tk.TclError:
            return
        for item in self.schedule_break_entries:
            try:
                self.schedule_break_listbox.insert("end", self._format_schedule_break_rule_summary(item))
            except tk.TclError:
                return
        if self.schedule_break_restore_button is not None and self.schedule_break_restore_button.winfo_exists():
            enabled = bool(self.schedule_break_entries_deleted_backup)
            self.schedule_break_restore_button.config(
                state="normal" if enabled else "disabled",
                bg="#2563eb" if enabled else "#cbd5e1",
                activebackground="#1d4ed8" if enabled else "#cbd5e1",
                fg="#ffffff" if enabled else "#e2e8f0",
                activeforeground="#ffffff" if enabled else "#e2e8f0",
                cursor="hand2" if enabled else "arrow",
            )
        if self.schedule_break_selected_index is not None and 0 <= self.schedule_break_selected_index < len(self.schedule_break_entries):
            try:
                self.schedule_break_listbox.selection_clear(0, "end")
                self.schedule_break_listbox.selection_set(self.schedule_break_selected_index)
                self.schedule_break_listbox.see(self.schedule_break_selected_index)
            except tk.TclError:
                pass

    def _load_schedule_break_entry_to_form(self, index: int) -> None:
        if not (0 <= index < len(self.schedule_break_entries)):
            return
        self.schedule_break_form_syncing = True
        item = self.schedule_break_entries[index]
        self.schedule_break_selected_index = index
        self.schedule_break_min_gap_var.set(str(self._parse_int(str(item.get("min_gap_minutes") or "0"), 0)))
        self.schedule_break_max_gap_var.set(str(self._parse_int(str(item.get("max_gap_minutes") or "0"), 0)))
        self.schedule_break_label_var.set(str(item.get("label_text") or "휴식"))
        self.schedule_break_display_mode_var.set(self._get_schedule_break_display_mode_label(str(item.get("display_mode") or "actual")))
        self.schedule_break_display_text_var.set(str(item.get("display_text") or ""))
        self.schedule_break_row_scale_var.set(f"{float(item.get('row_scale') or 1.0):g}")
        self.schedule_break_font_size_var.set(str(int(item.get("font_size") or 10)))
        self.schedule_break_bold_var.set(bool(item.get("bold", False)))
        self.schedule_break_enabled_var.set(bool(item.get("enabled", True)))
        self.schedule_break_text_color_var.set(self._normalize_hex_color(str(item.get("text_color") or DEFAULT_SCHEDULE_BREAK_TEXT_COLOR), DEFAULT_SCHEDULE_BREAK_TEXT_COLOR))
        self.schedule_break_bg_color_var.set(self._normalize_hex_color(str(item.get("bg_color") or DEFAULT_SCHEDULE_BREAK_BG_COLOR), DEFAULT_SCHEDULE_BREAK_BG_COLOR))
        self.schedule_break_form_syncing = False
        self._refresh_schedule_break_color_button_styles()
        self.schedule_break_inline_status_var.set("")
        self.schedule_break_status_var.set("선택한 휴식시간 규칙을 수정할 수 있습니다.")

    def _reset_schedule_break_form(self) -> None:
        self.schedule_break_form_syncing = True
        self.schedule_break_selected_index = None
        self.schedule_break_min_gap_var.set("50")
        self.schedule_break_max_gap_var.set("79")
        self.schedule_break_label_var.set("휴식")
        self.schedule_break_display_mode_var.set("실제간격")
        self.schedule_break_display_text_var.set("")
        self.schedule_break_row_scale_var.set("1.0")
        self.schedule_break_font_size_var.set("10")
        self.schedule_break_bold_var.set(False)
        self.schedule_break_enabled_var.set(True)
        self.schedule_break_text_color_var.set(self.schedule_break_last_text_color)
        self.schedule_break_bg_color_var.set(self.schedule_break_last_bg_color)
        self.schedule_break_form_syncing = False
        self._refresh_schedule_break_color_button_styles()
        self.schedule_break_inline_status_var.set("")

    def _on_schedule_break_listbox_select(self, _event=None) -> None:
        if self.schedule_break_listbox is None or not self.schedule_break_listbox.winfo_exists():
            return
        selection = self.schedule_break_listbox.curselection()
        if not selection:
            return
        self._load_schedule_break_entry_to_form(int(selection[0]))

    def _apply_schedule_break_rule(self) -> None:
        try:
            min_gap = max(0, int(re.sub(r"[^0-9]", "", self.schedule_break_min_gap_var.get() or "0") or "0"))
            max_gap = max(min_gap, int(re.sub(r"[^0-9]", "", self.schedule_break_max_gap_var.get() or str(min_gap)) or str(min_gap)))
            row_scale = float(self.schedule_break_row_scale_var.get() or "1.0")
            font_size = int(re.sub(r"[^0-9]", "", self.schedule_break_font_size_var.get() or "10") or "10")
        except ValueError:
            self.schedule_break_inline_status_var.set("숫자 형식을 확인하세요.")
            return
        label_text = str(self.schedule_break_label_var.get() or "").strip() or "휴식"
        entry = self._normalize_schedule_break_rule_entry(
            {
                "min_gap_minutes": min_gap,
                "max_gap_minutes": max_gap,
                "label_text": label_text,
                "display_mode": self._normalize_schedule_break_display_mode_value(self.schedule_break_display_mode_var.get()),
                "display_text": str(self.schedule_break_display_text_var.get() or "").strip(),
                "row_scale": row_scale,
                "font_size": font_size,
                "bold": bool(self.schedule_break_bold_var.get()),
                "enabled": bool(self.schedule_break_enabled_var.get()),
                "text_color": self.schedule_break_text_color_var.get(),
                "bg_color": self.schedule_break_bg_color_var.get(),
            }
        )
        if not isinstance(entry, dict):
            self.schedule_break_inline_status_var.set("규칙을 저장할 수 없습니다.")
            return
        if isinstance(self.schedule_break_selected_index, int) and 0 <= self.schedule_break_selected_index < len(self.schedule_break_entries):
            self.schedule_break_entries[self.schedule_break_selected_index] = entry
            self.schedule_break_status_var.set(f"{label_text} 휴식시간 규칙을 수정했습니다.")
        else:
            self.schedule_break_entries.append(entry)
            self.schedule_break_selected_index = len(self.schedule_break_entries) - 1
            self.schedule_break_status_var.set(f"{label_text} 휴식시간 규칙을 추가했습니다.")
        self.schedule_break_last_text_color = str(entry.get("text_color") or DEFAULT_SCHEDULE_BREAK_TEXT_COLOR)
        self.schedule_break_last_bg_color = str(entry.get("bg_color") or DEFAULT_SCHEDULE_BREAK_BG_COLOR)
        self._save_schedule_break_rules()
        self._save_settings()
        self._refresh_schedule_break_list()
        self._refresh_schedule_view()

    def _apply_schedule_break_style_to_all(self) -> None:
        if not self.schedule_break_entries:
            self.schedule_break_status_var.set("적용할 휴식시간 규칙이 없습니다.")
            return
        try:
            row_scale = float(self.schedule_break_row_scale_var.get() or "1.0")
            font_size = int(re.sub(r"[^0-9]", "", self.schedule_break_font_size_var.get() or "10") or "10")
        except ValueError:
            self.schedule_break_inline_status_var.set("행수/폰트 숫자 형식을 확인하세요.")
            return
        label_text = str(self.schedule_break_label_var.get() or "").strip() or "휴식"
        display_mode = self._normalize_schedule_break_display_mode_value(self.schedule_break_display_mode_var.get())
        bold = bool(self.schedule_break_bold_var.get())
        enabled = bool(self.schedule_break_enabled_var.get())
        text_color = self._normalize_hex_color(self.schedule_break_text_color_var.get(), DEFAULT_SCHEDULE_BREAK_TEXT_COLOR)
        bg_color = self._normalize_hex_color(self.schedule_break_bg_color_var.get(), DEFAULT_SCHEDULE_BREAK_BG_COLOR)
        updated_entries: list[dict[str, object]] = []
        for item in self.schedule_break_entries:
            updated_entry = self._normalize_schedule_break_rule_entry(
                {
                    **item,
                    "label_text": label_text if bool(self.schedule_break_apply_all_text_var.get()) else item.get("label_text"),
                    "display_mode": display_mode if bool(self.schedule_break_apply_all_display_mode_var.get()) else item.get("display_mode"),
                    "row_scale": row_scale if bool(self.schedule_break_apply_all_row_scale_var.get()) else item.get("row_scale"),
                    "font_size": font_size if bool(self.schedule_break_apply_all_font_size_var.get()) else item.get("font_size"),
                    "bold": bold if bool(self.schedule_break_apply_all_bold_var.get()) else item.get("bold"),
                    "enabled": enabled if bool(self.schedule_break_apply_all_enabled_var.get()) else item.get("enabled"),
                    "text_color": text_color if bool(self.schedule_break_apply_all_text_color_var.get()) else item.get("text_color"),
                    "bg_color": bg_color if bool(self.schedule_break_apply_all_bg_color_var.get()) else item.get("bg_color"),
                }
            )
            if isinstance(updated_entry, dict):
                updated_entries.append(updated_entry)
        if not updated_entries:
            self.schedule_break_status_var.set("전체 적용에 실패했습니다.")
            return
        self.schedule_break_entries = updated_entries
        if bool(self.schedule_break_apply_all_text_color_var.get()):
            self.schedule_break_last_text_color = text_color
        if bool(self.schedule_break_apply_all_bg_color_var.get()):
            self.schedule_break_last_bg_color = bg_color
        self._save_schedule_break_rules()
        self._save_schedule_break_apply_all_preferences()
        self._refresh_schedule_break_list()
        self._refresh_schedule_view()
        self.schedule_break_status_var.set("선택한 전체적용 항목을 모든 휴식시간 규칙에 적용했습니다.")

    def _delete_schedule_break_entry(self) -> None:
        index = self.schedule_break_selected_index
        if not isinstance(index, int) or not (0 <= index < len(self.schedule_break_entries)):
            self.schedule_break_status_var.set("삭제할 휴식시간 규칙을 선택하세요.")
            return
        deleted_entry = dict(self.schedule_break_entries[index])
        self.schedule_break_entries_deleted_backup = [deleted_entry]
        del self.schedule_break_entries[index]
        self.schedule_break_selected_index = None
        self._save_schedule_break_rules()
        self._refresh_schedule_break_list()
        self._refresh_schedule_view()
        self._reset_schedule_break_form()
        self.schedule_break_status_var.set("선택한 휴식시간 규칙을 삭제했습니다.")

    def _delete_all_schedule_break_entries(self) -> None:
        if not self.schedule_break_entries:
            self.schedule_break_status_var.set("삭제할 휴식시간 규칙이 없습니다.")
            return
        if not self._ask_centered_yesno("전체 삭제", "등록된 휴식시간 규칙을 모두 삭제할까요?", parent=self.schedule_break_window):
            return
        self.schedule_break_entries_deleted_backup = [dict(item) for item in self.schedule_break_entries]
        self.schedule_break_entries.clear()
        self.schedule_break_selected_index = None
        self._save_schedule_break_rules()
        self._refresh_schedule_break_list()
        self._refresh_schedule_view()
        self._reset_schedule_break_form()
        self.schedule_break_status_var.set("등록된 휴식시간 규칙을 모두 삭제했습니다.")

    def _restore_deleted_schedule_break_entries(self) -> None:
        if not self.schedule_break_entries_deleted_backup:
            self.schedule_break_status_var.set("복구할 최근 삭제 규칙이 없습니다.")
            return
        for item in self.schedule_break_entries_deleted_backup:
            self.schedule_break_entries.append(dict(item))
        self.schedule_break_entries_deleted_backup = None
        self._save_schedule_break_rules()
        self._refresh_schedule_break_list()
        self._refresh_schedule_view()
        self.schedule_break_status_var.set("최근 삭제한 휴식시간 규칙을 복구했습니다.")

    def _move_schedule_break_entry(self, direction: int) -> None:
        index = self.schedule_break_selected_index
        if not isinstance(index, int) or not (0 <= index < len(self.schedule_break_entries)):
            self.schedule_break_status_var.set("순서를 바꿀 휴식시간 규칙을 선택하세요.")
            return
        target_index = index + direction
        if not (0 <= target_index < len(self.schedule_break_entries)):
            return
        self.schedule_break_entries[index], self.schedule_break_entries[target_index] = (
            self.schedule_break_entries[target_index],
            self.schedule_break_entries[index],
        )
        self.schedule_break_selected_index = target_index
        self._save_schedule_break_rules()
        self._refresh_schedule_break_list()
        self._refresh_schedule_view()
        self.schedule_break_status_var.set("휴식시간 규칙 순서를 변경했습니다. 위에서부터 먼저 매칭됩니다.")

    def _on_schedule_break_rows_enabled_changed(self) -> None:
        self.schedule_break_rows_enabled_default = bool(self.schedule_break_rows_enabled_var.get())
        self._save_settings()
        self._refresh_schedule_view()

    def _on_schedule_boss_metric_duration_enabled_changed(self) -> None:
        self.schedule_boss_metric_duration_enabled_default = bool(self.schedule_boss_metric_duration_enabled_var.get())
        self._save_settings()
        self._refresh_schedule_view()

    def _on_schedule_boss_metric_schedule_duration_enabled_changed(self) -> None:
        self.schedule_boss_metric_schedule_duration_enabled_default = bool(self.schedule_boss_metric_schedule_duration_enabled_var.get())
        if self._reapply_schedule_boss_metric_schedule_times():
            self._save_schedule_state()
        self._save_settings()
        self._refresh_schedule_view_live() if self._widget_available(getattr(self, "schedule_tree", None)) else self._refresh_schedule_view()

    def _ensure_schedule_break_window(self) -> None:
        if self.schedule_break_window is not None and self.schedule_break_window.winfo_exists():
            return
        parent = self.schedule_window if self.schedule_window is not None and self.schedule_window.winfo_exists() else self.root
        self.schedule_break_window = tk.Toplevel(parent)
        self.schedule_break_window.title("휴식시간 설정")
        self.schedule_break_window.resizable(False, False)
