        tk.Label(self.schedule_break_window, text="행수/폰트/굵기는 스케쥴 복사에서만 사용됩니다.", font=self.percent_font, bg="#eef2ff", fg="#475569", anchor="w").place(x=18, y=48, width=420, height=18)

