    def _toggle_fixed_boss_everyday(self) -> None:
        target_value = not all(variable.get() for variable in self.fixed_boss_day_vars.values())
        for variable in self.fixed_boss_day_vars.values():
            variable.set(target_value)
        self._refresh_fixed_boss_day_button_styles()

    def _set_fixed_boss_add_button_active(self, active: bool) -> None:
        self.fixed_boss_add_button_active = bool(active)
        if self.fixed_boss_add_button is None or not self.fixed_boss_add_button.winfo_exists():
            return
        if active:
            self.fixed_boss_add_button.config(
                bg="#0f766e",
                fg="#ffffff",
                activebackground="#115e59",
                activeforeground="#ffffff",
                cursor="hand2",
            )
        else:
            self.fixed_boss_add_button.config(
                bg="#dbeafe",
                fg="#64748b",
                activebackground="#dbeafe",
                activeforeground="#64748b",
                cursor="arrow",
            )

    def _bind_fixed_boss_add_button_hover(self) -> None:
        if self.fixed_boss_add_button is None or not self.fixed_boss_add_button.winfo_exists():
            return

        def on_enter(_event=None) -> None:
            if not self.fixed_boss_add_button_active:
                return
            try:
                self.fixed_boss_add_button.config(bg="#115e59", activebackground="#115e59", fg="#ffffff", activeforeground="#ffffff")
            except tk.TclError:
                return

        def on_leave(_event=None) -> None:
            try:
                self._set_fixed_boss_add_button_active(self.fixed_boss_add_button_active)
            except tk.TclError:
                return

        self.fixed_boss_add_button.bind("<Enter>", on_enter)
        self.fixed_boss_add_button.bind("<Leave>", on_leave)

    def _refresh_fixed_boss_day_button_styles(self) -> None:
        all_selected = all(variable.get() for variable in self.fixed_boss_day_vars.values())
        if self.fixed_boss_everyday_button is not None and self.fixed_boss_everyday_button.winfo_exists():
            everyday_bg = "#0f766e" if all_selected else "#dbeafe"
            everyday_fg = "#ffffff" if all_selected else "#1e3a8a"
            self.fixed_boss_everyday_button.config(
                bg=everyday_bg,
                fg=everyday_fg,
                activebackground=everyday_bg,
                activeforeground=everyday_fg,
                relief="sunken" if all_selected else "raised",
            )
        for day, button in self.fixed_boss_day_buttons.items():
            if button is None or not button.winfo_exists():
                continue
            selected = bool(self.fixed_boss_day_vars[day].get())
            weekend = day in {"토", "일"}
            normal_bg = "#fee2e2" if weekend else "#dcfce7"
            normal_fg = "#7f1d1d" if weekend else "#166534"
            selected_bg = "#dc2626" if weekend else "#16a34a"
            selected_fg = "#ffffff"
            button.config(
                bg=selected_bg if selected else normal_bg,
                fg=selected_fg if selected else normal_fg,
                activebackground=selected_bg if selected else normal_bg,
                activeforeground=selected_fg if selected else normal_fg,
                relief="sunken" if selected else "raised",
                selectcolor=selected_bg if selected else normal_bg,
            )
        repeat_palette = {
            "weekly": ("#dbeafe", "#1e3a8a", "#2563eb"),
            "biweekly_current": ("#ede9fe", "#6d28d9", "#7c3aed"),
            "biweekly_next": ("#fef3c7", "#92400e", "#d97706"),
        }
        selected_mode = self.fixed_boss_repeat_mode_var.get()
        for mode, button in self.fixed_boss_repeat_buttons.items():
            if button is None or not button.winfo_exists():
                continue
            base_bg, base_fg, active_bg = repeat_palette.get(mode, ("#e2e8f0", "#334155", "#94a3b8"))
            chosen = mode == selected_mode
            button.config(
                bg=active_bg if chosen else base_bg,
                fg="#ffffff" if chosen else base_fg,
                activebackground=active_bg if chosen else base_bg,
                activeforeground="#ffffff" if chosen else base_fg,
                relief="sunken" if chosen else "raised",
                selectcolor=active_bg if chosen else base_bg,
            )

    def _on_fixed_boss_form_changed(self, *_args) -> None:
        if self.fixed_boss_form_syncing:
            return
        self.fixed_boss_inline_status_var.set("")
        self._set_fixed_boss_add_button_active(True)

    def _mark_fixed_boss_form_dirty(self, _event=None) -> None:
        if self.fixed_boss_form_syncing:
            return
        self.fixed_boss_inline_status_var.set("")
        self._set_fixed_boss_add_button_active(True)

    def _load_fixed_boss_entry_to_form(self, index: int) -> None:
        if not (0 <= index < len(self.fixed_boss_entries)):
            return
        self.fixed_boss_form_syncing = True
        item = self.fixed_boss_entries[index]
        self.fixed_boss_name_var.set(str(item.get("boss_name") or ""))
        self.fixed_boss_time_var.set(self._normalize_fixed_boss_time_text(str(item.get("time_text") or "00:00:00")))
        self.fixed_boss_use_var.set(bool(item.get("enabled", True)))
        self.fixed_boss_text_color_var.set(self._normalize_hex_color(str(item.get("text_color") or DEFAULT_FIXED_BOSS_TEXT_COLOR), DEFAULT_FIXED_BOSS_TEXT_COLOR))
        self.fixed_boss_bg_color_var.set(self._normalize_hex_color(str(item.get("bg_color") or DEFAULT_FIXED_BOSS_BG_COLOR), DEFAULT_FIXED_BOSS_BG_COLOR))
        self.fixed_boss_repeat_mode_var.set(
            str(item.get("repeat_mode") or "weekly")
            if str(item.get("repeat_mode") or "weekly") in {"weekly", "biweekly_current", "biweekly_next"}
            else "weekly"
        )
        for day, variable in self.fixed_boss_day_vars.items():
            variable.set(day in item.get("days", []))
        self.fixed_boss_form_syncing = False
        self._refresh_fixed_boss_day_button_styles()
        self._refresh_fixed_boss_color_button_styles()
        self._set_fixed_boss_add_button_active(False)
        self.fixed_boss_inline_status_var.set("")
        self.fixed_boss_status_var.set(f"{str(item.get('boss_name') or '')} 고정보스를 수정할 수 있습니다.")
        if self.fixed_boss_name_entry is not None and self.fixed_boss_name_entry.winfo_exists():
            self.fixed_boss_name_entry.focus_set()
            self.fixed_boss_name_entry.selection_range(0, "end")

    def _on_fixed_boss_name_changed(self, *_args) -> None:
        boss_name = (self.fixed_boss_name_var.get() or "").strip()
        if not self.fixed_boss_form_syncing:
            self._set_fixed_boss_add_button_active(True)
        if not boss_name:
            return
        for item in self.fixed_boss_entries:
            if str(item.get("boss_name") or "").strip() != boss_name:
                continue
            self.fixed_boss_text_color_var.set(self._normalize_hex_color(str(item.get("text_color") or DEFAULT_FIXED_BOSS_TEXT_COLOR), DEFAULT_FIXED_BOSS_TEXT_COLOR))
            self.fixed_boss_bg_color_var.set(self._normalize_hex_color(str(item.get("bg_color") or DEFAULT_FIXED_BOSS_BG_COLOR), DEFAULT_FIXED_BOSS_BG_COLOR))
            self._refresh_fixed_boss_color_button_styles()
            return

    def _reset_fixed_boss_form(self) -> None:
        self.fixed_boss_form_syncing = True
        self.fixed_boss_name_var.set("")
        self.fixed_boss_time_var.set("00:00:00")
        self.fixed_boss_use_var.set(True)
        self.fixed_boss_text_color_var.set(self.fixed_boss_last_text_color)
        self.fixed_boss_bg_color_var.set(self.fixed_boss_last_bg_color)
        self.fixed_boss_repeat_mode_var.set("weekly")
        for variable in self.fixed_boss_day_vars.values():
            variable.set(False)
        self.fixed_boss_form_syncing = False
        self._refresh_fixed_boss_day_button_styles()
        self._refresh_fixed_boss_color_button_styles()
        self._set_fixed_boss_add_button_active(False)
        self.fixed_boss_inline_status_var.set("")
        if self.fixed_boss_name_entry is not None and self.fixed_boss_name_entry.winfo_exists():
            self.fixed_boss_name_entry.focus_set()
            self.fixed_boss_name_entry.selection_range(0, "end")

    def _toggle_fixed_boss_use(self, index: int, enabled: bool | None = None) -> None:
        if not (0 <= index < len(self.fixed_boss_entries)):
            return
        if enabled is None:
            self.fixed_boss_entries[index]["enabled"] = not bool(self.fixed_boss_entries[index].get("enabled", True))
        else:
            self.fixed_boss_entries[index]["enabled"] = bool(enabled)
        self._save_fixed_boss_definitions()
        self._refresh_fixed_boss_list()
        self._refresh_schedule_view()
        self._set_fixed_boss_add_button_active(True)

    def _delete_fixed_boss_entry(self, index: int) -> None:
        if not (0 <= index < len(self.fixed_boss_entries)):
            return
        deleted_item = dict(self.fixed_boss_entries[index])
        self.fixed_boss_deleted_backup = [deleted_item]
        del self.fixed_boss_entries[index]
        self._save_fixed_boss_definitions()
        self._sync_schedule_boss_metrics_with_definitions()
        if self.schedule_boss_metrics_window_open:
            self._populate_schedule_boss_metrics_tree()
        self._refresh_fixed_boss_list()
        self._refresh_schedule_view()
        self.fixed_boss_status_var.set(f"{str(deleted_item.get('boss_name') or '')} 고정보스를 삭제했습니다.")
        self._set_fixed_boss_add_button_active(True)

    def _delete_all_fixed_boss_entries(self) -> None:
        if not self.fixed_boss_entries:
            self.fixed_boss_status_var.set("삭제할 고정보스가 없습니다.")
            return
        if not self._ask_centered_yesno("전체 삭제", "등록된 고정보스를 모두 삭제할까요?", parent=self.fixed_boss_window):
            return
        self.fixed_boss_deleted_backup = [dict(item) for item in self.fixed_boss_entries]
        self.fixed_boss_entries.clear()
        self._save_fixed_boss_definitions()
        self._sync_schedule_boss_metrics_with_definitions()
        if self.schedule_boss_metrics_window_open:
            self._populate_schedule_boss_metrics_tree()
        self._refresh_fixed_boss_list()
        self._refresh_schedule_view()
        self.fixed_boss_status_var.set("등록된 고정보스를 모두 삭제했습니다.")
        self._set_fixed_boss_add_button_active(True)

    def _restore_deleted_fixed_boss_entries(self) -> None:
        if not self.fixed_boss_deleted_backup:
            self.fixed_boss_status_var.set("복구할 최근 삭제 내역이 없습니다.")
            return
        existing_keys = {
            (
                str(item.get("boss_name") or "").strip(),
                self._normalize_fixed_boss_time_text(str(item.get("time_text") or "00:00:00")),
            )
            for item in self.fixed_boss_entries
        }
        restored_count = 0
        for item in self.fixed_boss_deleted_backup:
            key = (
                str(item.get("boss_name") or "").strip(),
                self._normalize_fixed_boss_time_text(str(item.get("time_text") or "00:00:00")),
            )
            if key in existing_keys:
                continue
            self.fixed_boss_entries.append(dict(item))
            existing_keys.add(key)
            restored_count += 1
        self.fixed_boss_entries.sort(key=lambda item: (str(item.get("time_text") or ""), str(item.get("boss_name") or "")))
        self.fixed_boss_deleted_backup = None
        self._save_fixed_boss_definitions()
        self._sync_schedule_boss_metrics_with_definitions()
        if self.schedule_boss_metrics_window_open:
            self._populate_schedule_boss_metrics_tree()
        self._refresh_fixed_boss_list()
        self._refresh_schedule_view()
        self.fixed_boss_status_var.set("최근 삭제한 고정보스를 복구했습니다." if restored_count else "복구할 새 항목이 없습니다.")
        if restored_count:
            self._set_fixed_boss_add_button_active(True)

    def _on_fixed_boss_mousewheel(self, event) -> str | None:
        if not self._widget_available(self.fixed_boss_canvas):
            return None
        delta = getattr(event, "delta", 0)
        if delta == 0:
            return "break"
        steps = int(-delta / 120)
        if steps == 0:
            steps = -1 if delta > 0 else 1
        try:
            self.fixed_boss_canvas.yview_scroll(steps, "units")
        except tk.TclError:
            return None
        return "break"

    def _bind_fixed_boss_scroll_recursive(self, widget: tk.Widget) -> None:
        try:
            widget.bind("<MouseWheel>", self._on_fixed_boss_mousewheel)
        except tk.TclError:
            return
        for child in widget.winfo_children():
            self._bind_fixed_boss_scroll_recursive(child)

    def _refresh_fixed_boss_list(self) -> None:
        if self.fixed_boss_rows_frame is None:
            return
        self.fixed_boss_list_use_vars = []
        try:
            for child in self.fixed_boss_rows_frame.winfo_children():
                child.destroy()
        except tk.TclError:
            return
        if self.fixed_boss_restore_button is not None and self.fixed_boss_restore_button.winfo_exists():
            self.fixed_boss_restore_button.config(
                state="normal" if self.fixed_boss_deleted_backup else "disabled",
                bg="#2563eb" if self.fixed_boss_deleted_backup else "#bfdbfe",
                activebackground="#1d4ed8" if self.fixed_boss_deleted_backup else "#bfdbfe",
                fg="#ffffff" if self.fixed_boss_deleted_backup else "#e2e8f0",
                activeforeground="#ffffff" if self.fixed_boss_deleted_backup else "#e2e8f0",
                cursor="hand2" if self.fixed_boss_deleted_backup else "arrow",
            )
        if not self.fixed_boss_entries:
            self.fixed_boss_rows_frame.configure(height=44)
            tk.Label(
                self.fixed_boss_rows_frame,
                text="아직 등록된 고정보스가 없습니다.",
                font=(self.current_font_family, 10),
                bg="#f8fafc",
                fg="#475569",
                anchor="w",
            ).place(x=10, y=10, width=700, height=24)
            return
