    def _position_fixed_boss_window(self) -> None:
        if self.fixed_boss_window is None or not self.fixed_boss_window.winfo_exists() or not self.fixed_boss_window_open:
            return
        parent = self.schedule_input_window if self.schedule_input_window is not None and self.schedule_input_window.winfo_exists() else self.schedule_window
        if parent is None or not parent.winfo_exists():
            parent = self.root
        self._center_window_over_parent(self.fixed_boss_window, parent, 820, 560)

    def _normalize_hex_color(self, raw_value: str | None, default: str) -> str:
        value = str(raw_value or "").strip()
        if re.fullmatch(r"#[0-9a-fA-F]{6}", value):
            return value.upper()
        return default.upper()

    def _get_contrast_text_color(self, hex_color: str) -> str:
        color = self._normalize_hex_color(hex_color, "#FFFFFF")
        try:
            red = int(color[1:3], 16)
            green = int(color[3:5], 16)
            blue = int(color[5:7], 16)
        except ValueError:
            return "#0F172A"
        luminance = (0.299 * red) + (0.587 * green) + (0.114 * blue)
        return "#0F172A" if luminance >= 160 else "#F8FAFC"

    def _apply_color_preview_button_style(self, button: tk.Widget | None, color_value: str, label_text: str) -> None:
        if button is None or not button.winfo_exists():
            return
        normalized = self._normalize_hex_color(color_value, DEFAULT_FIXED_BOSS_BG_COLOR)
        foreground = self._get_contrast_text_color(normalized)
        border_color = "#94a3b8" if self._is_light_preview_color(normalized) else normalized
        try:
            button.config(
                text=label_text,
                bg=normalized,
                fg=foreground,
                activebackground=normalized,
                activeforeground=foreground,
                highlightbackground=border_color,
                highlightcolor=border_color,
                highlightthickness=1,
                bd=1,
                relief="solid",
            )
        except tk.TclError:
            return

    def _is_light_preview_color(self, color: str) -> bool:
        try:
            normalized = self._normalize_hex_color(color, "#FFFFFF")
            red = int(normalized[1:3], 16)
            green = int(normalized[3:5], 16)
            blue = int(normalized[5:7], 16)
        except Exception:
            return False
        luminance = (0.299 * red) + (0.587 * green) + (0.114 * blue)
        return luminance >= 235

    def _refresh_fixed_boss_color_button_styles(self) -> None:
        self._apply_color_preview_button_style(self.fixed_boss_text_color_button, self.fixed_boss_text_color_var.get(), "글자색")
        self._apply_color_preview_button_style(self.fixed_boss_bg_color_button, self.fixed_boss_bg_color_var.get(), "배경색")

    def _choose_fixed_boss_color(self, variable: tk.StringVar, button: tk.Widget | None, title: str, default: str) -> None:
        parent = self.fixed_boss_window if self.fixed_boss_window is not None and self.fixed_boss_window.winfo_exists() else self.root
        initial_color = self._normalize_hex_color(variable.get(), default)
        try:
            _rgb, selected = colorchooser.askcolor(color=initial_color, title=title, parent=parent)
        except tk.TclError:
            return
        if not selected:
            return
        normalized = self._normalize_hex_color(selected, default)
        if normalized == self._normalize_hex_color(variable.get(), default):
            return
        variable.set(normalized)
        if variable is self.fixed_boss_text_color_var:
            self.fixed_boss_last_text_color = normalized
        elif variable is self.fixed_boss_bg_color_var:
            self.fixed_boss_last_bg_color = normalized
        self._refresh_fixed_boss_color_button_styles()
        self._set_fixed_boss_add_button_active(True)
        self._save_settings()

