    def open_record_book_window(self) -> None:
        if self.record_book_window_busy:
            return
        self.record_book_window_busy = True
        try:
            self._ensure_record_book_window()
            if self.record_book_window_open and self.record_book_window is not None and self.record_book_window.winfo_exists():
                self.record_book_window.deiconify()
                self.record_book_window.lift()
                return
            self.record_book_window_open = True
            self._position_record_book_window()
            self.record_book_window.deiconify()
            self.record_book_window.lift()
            self._set_record_book_date_fields(datetime.now().strftime(RECORD_BOOK_DATE_FORMAT))
            self._load_record_book_date()
        except tk.TclError:
            return
        finally:
            self.record_book_window_busy = False

    def close_record_book_window(self) -> None:
        try:
            if not self._confirm_record_book_pending_changes("보스 기록표를 닫기 전에 변경사항을 저장하시겠습니까?", save_date_key=self.record_book_loaded_date_key):
                return
            if self.record_book_search_window is not None and self.record_book_search_window.winfo_exists():
                self.record_book_search_window.destroy()
            if self.record_book_file_window is not None and self.record_book_file_window.winfo_exists():
                self.record_book_file_window.withdraw()
            self.record_book_file_window_open = False
            if self.record_book_window is not None and self.record_book_window.winfo_exists():
                self.record_book_window.withdraw()
            self.record_book_window_open = False
        except tk.TclError:
            self.record_book_window_open = False

    def open_record_book_file_window(self) -> None:
        if self.record_book_file_window_busy:
            return
        self.record_book_file_window_busy = True
        try:
            self._ensure_record_book_file_window()
            if self.record_book_file_window is not None and self.record_book_file_window.winfo_exists():
                self.record_book_file_window_open = True
                self.record_book_file_window.deiconify()
                self.record_book_file_window.lift()
                self.record_book_file_search_result_var.set("기간을 선택한 뒤 검색하면 아군/적군 횟수를 보여줍니다.")
                self._set_record_book_file_result_style("neutral")
                self.record_book_file_status_var.set("기간 검색과 보관 관리를 사용할 수 있습니다.")
                return
        finally:
            self.record_book_file_window_busy = False

    def close_record_book_file_window(self) -> None:
        try:
            if self.record_book_search_window is not None and self.record_book_search_window.winfo_exists():
                self.record_book_search_window.destroy()
            if self.record_book_file_window is not None and self.record_book_file_window.winfo_exists():
                self.record_book_file_window.withdraw()
            self.record_book_file_window_open = False
        except tk.TclError:
            self.record_book_file_window_open = False

    def _ensure_record_book_file_window(self) -> None:
        if self.record_book_file_window is not None and self.record_book_file_window.winfo_exists():
            return
        parent = self.record_book_window if self.record_book_window is not None and self.record_book_window.winfo_exists() else self.root
        self.record_book_file_window = tk.Toplevel(parent)
        self.record_book_file_window.title("파일관리")
        self.record_book_file_window.resizable(False, False)
        self.record_book_file_window.protocol("WM_DELETE_WINDOW", self.close_record_book_file_window)
