    def _get_record_book_file_search_range(self) -> tuple[datetime | None, datetime | None]:
        start_date = self._parse_record_book_date_input(
            self.record_book_file_start_year_var.get(),
            self.record_book_file_start_month_var.get(),
            self.record_book_file_start_day_var.get(),
        )
        end_date = self._parse_record_book_date_input(
            self.record_book_file_end_year_var.get(),
            self.record_book_file_end_month_var.get(),
            self.record_book_file_end_day_var.get(),
        )
        return start_date, end_date

    def _run_record_book_file_search(self) -> None:
        start_date, end_date = self._get_record_book_file_search_range()
        if start_date is None or end_date is None:
            self._set_record_book_file_result_style("neutral")
            self.record_book_file_search_result_var.set("날짜 형식을 다시 확인하세요.")
            return
        if end_date < start_date:
            self._set_record_book_file_result_style("neutral")
            self.record_book_file_search_result_var.set("끝 날짜는 시작 날짜보다 빠를 수 없습니다.")
            return
        self._show_record_book_file_search_summary(start_date, end_date)

    def _run_record_book_file_delete(self) -> None:
        start_date, end_date = self._get_record_book_file_search_range()
        if start_date is None or end_date is None:
            self._set_record_book_file_result_style("neutral")
            self.record_book_file_search_result_var.set("날짜 형식을 다시 확인하세요.")
            return
        if end_date < start_date:
            self._set_record_book_file_result_style("neutral")
            self.record_book_file_search_result_var.set("끝 날짜는 시작 날짜보다 빠를 수 없습니다.")
            return
        _, _, date_total, boss_entry_total = self._show_record_book_file_search_summary(
            start_date,
            end_date,
            empty_message="삭제할 데이터가 없습니다.",
        )
        if date_total == 0 and boss_entry_total == 0:
            return
        parent = self.record_book_file_window if self.record_book_file_window is not None and self.record_book_file_window.winfo_exists() else self.root
        delete_message = (
            f"{start_date.strftime(RECORD_BOOK_DATE_FORMAT)}부터\n"
            f"{end_date.strftime(RECORD_BOOK_DATE_FORMAT)}까지의 기록을 삭제하시겠습니까?"
        )
        if not self._show_record_book_delete_confirm_dialog(parent, delete_message):
            return
        deleted_dates, deleted_records, deleted_ally, deleted_enemy = self._delete_record_book_range(start_date, end_date)
        remain_ally, remain_enemy, remain_dates, remain_entries = self._calculate_record_book_range_summary(start_date, end_date)
        self._set_record_book_file_result_style("delete")
        self.record_book_file_search_result_var.set(
            "삭제 완료: "
            f"날짜 {deleted_dates}일 / 보스 기록 {deleted_records}건 / 아군 {deleted_ally}개 / 적군 {deleted_enemy}개 삭제\n"
            f"남은 결과: 날짜 {remain_dates}일 / 보스 기록 {remain_entries}건 / 아군 {remain_ally}개 / 적군 {remain_enemy}개"
        )
        self.record_book_file_status_var.set("기간 삭제를 적용했습니다.")

    def _show_record_book_file_search_summary(
        self,
        start_date: datetime,
        end_date: datetime,
        *,
        empty_message: str = "검색 데이터가 없습니다.",
    ) -> tuple[int, int, int, int]:
        ally_total, enemy_total, date_total, boss_entry_total = self._calculate_record_book_range_summary(start_date, end_date)
        if date_total == 0 and boss_entry_total == 0:
            self._set_record_book_file_result_style("neutral")
            self.record_book_file_search_result_var.set(empty_message)
        else:
            self._set_record_book_file_result_style("search")
            self.record_book_file_search_result_var.set(
                f"날짜 {date_total}일 / 보스 기록 {boss_entry_total}건 / 아군 {ally_total}개 / 적군 {enemy_total}개"
            )
        return ally_total, enemy_total, date_total, boss_entry_total

    def _on_record_book_retention_change(self, _event=None) -> None:
        if self.record_book_retention_var.get() not in RECORD_BOOK_RETENTION_OPTIONS:
            self.record_book_retention_var.set(RECORD_BOOK_DEFAULT_RETENTION)
        self._update_record_book_retention_run_button_state()
        self._save_settings()
        self.record_book_file_status_var.set(f"보관 기간을 {self.record_book_retention_var.get()}로 저장했습니다.")

    def _run_record_book_retention_cleanup(self) -> None:
        retention_days = self._get_record_book_retention_days()
        if retention_days is None:
            return
        target_dates, target_records = self._calculate_record_book_retention_summary()
        if target_dates == 0 and target_records == 0:
            self.record_book_file_status_var.set("정리할 보관 대상 기록이 없습니다.")
            return
        deleted_dates, deleted_records = self._apply_record_book_retention_policy()
        self.record_book_file_status_var.set(
            f"보관 정리 완료: 날짜 {deleted_dates}개, 기록 {deleted_records}건을 정리했습니다."
        )

    def _update_record_book_retention_run_button_state(self) -> None:
        if self.record_book_retention_run_button is None:
            return
        try:
            if self.record_book_retention_var.get() == "영구":
                self.record_book_retention_run_button.config(
                    state="disabled",
                    bg="#cbd5e1",
                    fg="#eff6ff",
                    activebackground="#cbd5e1",
                    activeforeground="#eff6ff",
                    disabledforeground="#eff6ff",
                    cursor="arrow",
                )
            else:
                self.record_book_retention_run_button.config(
                    state="normal",
                    bg="#0f766e",
                    fg="#ffffff",
                    activebackground="#115e59",
                    activeforeground="#ffffff",
                    disabledforeground="#ffffff",
                    cursor="hand2",
                )
        except tk.TclError:
            return

    def _set_record_book_file_result_style(self, mode: str = "neutral") -> None:
        if self.record_book_file_search_result_label is None:
            return
        try:
            if mode == "search":
                self.record_book_file_search_result_label.config(bg="#dcfce7", fg="#166534")
            elif mode == "delete":
                self.record_book_file_search_result_label.config(bg="#fee2e2", fg="#991b1b")
            else:
                self.record_book_file_search_result_label.config(bg="#f8fafc", fg="#0f172a")
        except tk.TclError:
            return

    def _position_record_book_window(self) -> None:
        if self.record_book_window is None or not self.record_book_window.winfo_exists() or not self.record_book_window_open:
            return
        x = self.root.winfo_x() + WINDOW_WIDTH + 16
        y = self.root.winfo_y()
        self.record_book_window.geometry(f"{RECORD_BOOK_WINDOW_WIDTH}x{RECORD_BOOK_WINDOW_HEIGHT}+{x}+{y}")

    def _on_record_book_canvas_configure(self, _event=None) -> None:
        if not self._widget_available(getattr(self, "record_book_canvas", None)):
            return
        self.record_book_canvas.configure(scrollregion=self.record_book_canvas.bbox("all"))
        canvas_width = self.record_book_canvas.winfo_width()
        if hasattr(self, "record_book_canvas_window_id"):
            self.record_book_canvas.itemconfig(self.record_book_canvas_window_id, width=max(960, canvas_width))

    def _bind_record_book_scroll_target(self, widget: tk.Widget) -> None:
        return

    def _is_pointer_inside_record_book_window(self) -> bool:
        if self.record_book_window is None or not self.record_book_window.winfo_exists() or not self.record_book_window_open:
            return False
        try:
            pointer_x = self.root.winfo_pointerx()
            pointer_y = self.root.winfo_pointery()
            left = self.record_book_window.winfo_rootx()
            top = self.record_book_window.winfo_rooty()
            right = left + self.record_book_window.winfo_width()
            bottom = top + self.record_book_window.winfo_height()
            return left <= pointer_x <= right and top <= pointer_y <= bottom
        except tk.TclError:
            return False

    def _on_record_book_mousewheel(self, event) -> str | None:
        if not self._widget_available(getattr(self, "record_book_canvas", None)):
            return None
        if not self._is_pointer_inside_record_book_window():
            return None
        try:
            delta = getattr(event, "delta", 0)
            if delta == 0:
                return "break"
            steps = int(-delta / 120)
            if steps == 0:
                steps = -1 if delta > 0 else 1
            self.record_book_canvas.yview_scroll(steps, "units")
            return "break"
        except (tk.TclError, KeyError):
            return "break"

    def _bind_record_book_move_button_hover(self, button: tk.Button) -> None:
        def apply_current_style() -> None:
            enabled = bool(getattr(button, "_record_book_move_enabled", False))
            state = str(button.cget("state"))
            if state == "disabled":
                button.config(bg="#e2e8f0", fg="#94a3b8", activebackground="#e2e8f0", activeforeground="#94a3b8")
            elif enabled:
                button.config(bg="#ffffff", fg="#1e3a8a", activebackground="#dbeafe", activeforeground="#1e3a8a")
            else:
                button.config(bg="#e2e8f0", fg="#94a3b8", activebackground="#e2e8f0", activeforeground="#94a3b8")

        def on_enter(_event=None) -> None:
            enabled = bool(getattr(button, "_record_book_move_enabled", False))
            if str(button.cget("state")) == "disabled" or not enabled:
                apply_current_style()
                return
            try:
                button.config(bg="#dbeafe", fg="#1e3a8a", activebackground="#bfdbfe", activeforeground="#1e3a8a")
            except tk.TclError:
                return

        def on_leave(_event=None) -> None:
            try:
                apply_current_style()
            except tk.TclError:
                return

        button.bind("<Enter>", on_enter)
        button.bind("<Leave>", on_leave)
        apply_current_style()

    def _bind_record_book_header_action_hover(self, widget: tk.Widget, normal_bg: str, hover_bg: str, normal_fg: str, hover_fg: str) -> None:
        widget._record_book_action_normal_bg = normal_bg
        widget._record_book_action_hover_bg = hover_bg
        widget._record_book_action_normal_fg = normal_fg
        widget._record_book_action_hover_fg = hover_fg

        def on_enter(_event=None) -> None:
            if getattr(widget, "_record_book_state", "normal") == "disabled":
                return
            try:
                widget.config(bg=hover_bg, fg=hover_fg)
            except tk.TclError:
                return

        def on_leave(_event=None) -> None:
            try:
                fg = getattr(widget, "_record_book_disabled_fg", normal_fg) if getattr(widget, "_record_book_state", "normal") == "disabled" else normal_fg
                widget.config(bg=normal_bg, fg=fg)
            except tk.TclError:
                return

        def on_click(_event=None) -> None:
            if getattr(widget, "_record_book_state", "normal") == "disabled":
                return
            callback = getattr(widget, "_record_book_command", None)
            if callback is None:
                return
            try:
                callback()
            except tk.TclError:
                return

        widget.bind("<Enter>", on_enter)
        widget.bind("<Leave>", on_leave)
        widget.bind("<Button-1>", on_click)

    def _get_record_book_section_label(self, section_name: str) -> str:
        chapter_label = RECORD_BOOK_CHAPTER_LABELS.get(section_name, section_name)
        if chapter_label == section_name:
            return section_name
        return f"{chapter_label} | {section_name}"

    def _get_record_book_section_bosses(self, section_name: str) -> list[dict]:
        if section_name == "절대자":
            section_bosses = [item for item in self.record_book_catalog if item["display_area"] == "절대자"]
        else:
            section_bosses = [item for item in self.record_book_catalog if item["display_area"] == section_name]
        enabled_bosses = []
        disabled_bosses = []
        for item in section_bosses:
            boss_name = item["boss_name"]
            current_var = self.record_book_boss_enabled_vars.get(boss_name)
            is_enabled = bool(current_var.get()) if current_var is not None else self.record_book_data.get("boss_enabled", {}).get(boss_name, True)
            if is_enabled:
                enabled_bosses.append(item)
            else:
                disabled_bosses.append(item)
        return enabled_bosses + disabled_bosses

    def _get_record_book_daily_records(self, date_key: str | None = None) -> dict:
        effective_date = date_key or self._get_record_book_date_key()
        return self.record_book_data.get("records", {}).get(effective_date, {})

    def _get_record_book_section_order(self) -> list[str]:
        stored_order = self.record_book_data.get("section_order", [])
        valid_sections = [section for section in self.record_book_sections if section != "기타"]
        normalized_order = [section for section in stored_order if section in valid_sections]
        for section in valid_sections:
            if section not in normalized_order:
                normalized_order.append(section)
        self.record_book_data["section_order"] = normalized_order
        return normalized_order

    def _get_ordered_record_book_sections(self) -> list[str]:
        ordered_sections = self._get_record_book_section_order()
        enabled_sections = []
        disabled_sections = []
        for section in ordered_sections:
            current_var = self.record_book_area_enabled_vars.get(section)
            is_enabled = bool(current_var.get()) if current_var is not None else self.record_book_data.get("chapter_enabled", {}).get(section, True)
            if is_enabled:
                enabled_sections.append(section)
            else:
                disabled_sections.append(section)
        return enabled_sections + disabled_sections

    def _get_visible_record_book_sections(self) -> list[str]:
        return [section for section in self._get_ordered_record_book_sections() if self._get_record_book_section_bosses(section)]

    def _get_record_book_movable_sections(self, section_name: str) -> list[str]:
        ordered_sections = self._get_visible_record_book_sections()
        target_var = self.record_book_area_enabled_vars.get(section_name)
        target_enabled = bool(target_var.get()) if target_var is not None else self.record_book_data.get("chapter_enabled", {}).get(section_name, True)
        result = []
        for section in ordered_sections:
            current_var = self.record_book_area_enabled_vars.get(section)
            current_enabled = bool(current_var.get()) if current_var is not None else self.record_book_data.get("chapter_enabled", {}).get(section, True)
            if current_enabled == target_enabled:
                result.append(section)
        return result

    def _move_record_book_section(self, section_name: str, direction: int) -> None:
        visible_sections = self._get_visible_record_book_sections()
        if section_name not in visible_sections:
            return
        movable_sections = self._get_record_book_movable_sections(section_name)
        if section_name not in movable_sections:
            return
        current_group_index = movable_sections.index(section_name)
        target_group_index = current_group_index + direction
        if target_group_index < 0 or target_group_index >= len(movable_sections):
            return
        target_section = movable_sections[target_group_index]
        current_index = visible_sections.index(section_name)
        target_index = visible_sections.index(target_section)
        visible_sections[current_index], visible_sections[target_index] = visible_sections[target_index], visible_sections[current_index]
        self.record_book_data["section_order"] = visible_sections
        self._update_record_book_dirty_from_ui()
        self._rebuild_record_book_rows()
        direction_text = "위" if direction < 0 else "아래"
        self.record_book_status_var.set(f"{self._get_record_book_section_label(section_name)} 지역을 {direction_text}로 이동했습니다. 저장 버튼으로 확정하세요.")

    def _set_record_book_all_enabled(self, enabled: bool) -> bool:
        changed = False
        for area_name, var in self.record_book_area_enabled_vars.items():
            if bool(var.get()) != enabled:
                changed = True
            var.set(enabled)
        for boss_name, var in self.record_book_boss_enabled_vars.items():
            if bool(var.get()) != enabled:
                changed = True
            var.set(enabled)
        if not changed:
            self.record_book_status_var.set("적용할 변경사항이 없습니다.")
            return False
        self._update_record_book_row_enabled_states()
        self._update_record_book_dirty_from_ui()
        self.record_book_status_var.set("전체 보스 활성 상태를 변경했습니다. 저장 버튼으로 확정하세요.")
        return True

    def _toggle_record_book_all_enabled(self) -> None:
        enabled = bool(self.record_book_header_toggle_states.get("enable_all", True))
        changed = self._set_record_book_all_enabled(enabled)
        if not changed:
            return
        self.record_book_header_toggle_states["enable_all"] = not enabled
        self._update_record_book_header_action_buttons_state()
        state_text = "ON" if enabled else "OFF"
        self.record_book_status_var.set(f"전체 보스 활성 상태를 {state_text}로 변경했습니다. 저장 버튼으로 확정하세요.")

    def _set_record_book_bulk_side(self, slot: str, side: str) -> bool:
        if not self.record_book_edit_mode_var.get():
            return False
        if slot == "invasion" and not self.record_book_use_invasion_var.get():
            return False
        changed = False
        current_key, current_extra_key = self._get_record_book_slot_keys(side, slot)
        opposite_side = "enemy" if side == "ally" else "ally"
        opposite_key, opposite_extra_key = self._get_record_book_slot_keys(opposite_side, slot)
        for boss_name, row_vars in self.record_book_row_vars.items():
            metadata = self.record_book_catalog_map.get(boss_name, {})
            area_name = metadata.get("display_area", "기타")
            area_enabled = self.record_book_area_enabled_vars.get(area_name, tk.BooleanVar(value=True)).get()
            boss_enabled = self.record_book_boss_enabled_vars.get(boss_name, tk.BooleanVar(value=True)).get()
            if not (area_enabled and boss_enabled):
                continue
            if (
                not bool(row_vars[current_key].get())
                or bool(row_vars[current_extra_key].get())
                or bool(row_vars[opposite_key].get())
                or bool(row_vars[opposite_extra_key].get())
            ):
                row_vars[current_key].set(True)
                row_vars[current_extra_key].set(False)
                row_vars[opposite_key].set(False)
                row_vars[opposite_extra_key].set(False)
                changed = True
        if not changed:
            self.record_book_status_var.set("적용할 변경사항이 없습니다.")
            return False
        self._update_record_book_row_enabled_states()
        self._update_record_book_dirty_from_ui()
        slot_text = "본섭" if slot == "main" else "침공"
        side_text = "아군" if side == "ally" else "적군"
        self.record_book_status_var.set(f"{slot_text} {side_text} 전체 체크를 적용했습니다. 저장 버튼으로 확정하세요.")
        return True

    def _clear_record_book_bulk_side(self, slot: str, side: str) -> bool:
        if not self.record_book_edit_mode_var.get():
            return False
        if slot == "invasion" and not self.record_book_use_invasion_var.get():
            return False
        changed = False
        current_keys = self._get_record_book_slot_keys(side, slot)
        for boss_name, row_vars in self.record_book_row_vars.items():
            metadata = self.record_book_catalog_map.get(boss_name, {})
            area_name = metadata.get("display_area", "기타")
            area_enabled = self.record_book_area_enabled_vars.get(area_name, tk.BooleanVar(value=True)).get()
            boss_enabled = self.record_book_boss_enabled_vars.get(boss_name, tk.BooleanVar(value=True)).get()
            if not (area_enabled and boss_enabled):
                continue
            for current_key in current_keys:
                if bool(row_vars[current_key].get()):
                    row_vars[current_key].set(False)
                    changed = True
        if not changed:
            self.record_book_status_var.set("적용할 변경사항이 없습니다.")
            return False
        self._update_record_book_row_enabled_states()
        self._update_record_book_dirty_from_ui()
        slot_text = "본섭" if slot == "main" else "침공"
        side_text = "아군" if side == "ally" else "적군"
        self.record_book_status_var.set(f"{slot_text} {side_text} 전체 체크를 해제했습니다. 저장 버튼으로 확정하세요.")
        return True

    def _toggle_record_book_bulk_side(self, slot: str, side: str) -> None:
        state_key = f"{side}_{slot}"
        turn_on = bool(self.record_book_header_toggle_states.get(state_key, True))
        if turn_on:
            changed = self._set_record_book_bulk_side(slot, side)
        else:
            changed = self._clear_record_book_bulk_side(slot, side)
        if not changed:
            return
        self.record_book_header_toggle_states[state_key] = not turn_on
        self._update_record_book_header_action_buttons_state()

    def _initialize_record_book_header_toggle_states(self) -> None:
        all_enabled = True
        for var in self.record_book_area_enabled_vars.values():
            if not bool(var.get()):
                all_enabled = False
                break
        if all_enabled:
            for var in self.record_book_boss_enabled_vars.values():
                if not bool(var.get()):
                    all_enabled = False
                    break
        self.record_book_header_toggle_states["enable_all"] = not all_enabled

        for side in ("ally", "enemy"):
            for slot in ("main", "invasion"):
                state_key = f"{side}_{slot}"
                if slot == "invasion" and not self.record_book_use_invasion_var.get():
                    self.record_book_header_toggle_states[state_key] = True
                    continue
                all_checked = True
                has_target = False
                opposite_side = "enemy" if side == "ally" else "ally"
                for boss_name, row_vars in self.record_book_row_vars.items():
                    metadata = self.record_book_catalog_map.get(boss_name, {})
                    area_name = metadata.get("display_area", "기타")
                    area_enabled = self.record_book_area_enabled_vars.get(area_name, tk.BooleanVar(value=True)).get()
                    boss_enabled = self.record_book_boss_enabled_vars.get(boss_name, tk.BooleanVar(value=True)).get()
                    if not (area_enabled and boss_enabled):
                        continue
                    has_target = True
                    current_count = self._get_record_book_row_slot_count(row_vars, slot, side, boss_name)
                    opposite_count = self._get_record_book_row_slot_count(row_vars, slot, opposite_side, boss_name)
                    if current_count <= 0 or opposite_count > 0:
                        all_checked = False
                        break
                self.record_book_header_toggle_states[state_key] = not (has_target and all_checked)

    def _update_record_book_header_action_buttons_state(self) -> None:
        action_buttons = getattr(self, "record_book_header_action_buttons", {})
        if not action_buttons:
            return
        edit_mode = self.record_book_edit_mode_var.get()
        invasion_enabled = self.record_book_use_invasion_var.get()
        for key, button in action_buttons.items():
            try:
                if key in {"add", "read_log", "memo_delete", "memo_restore"}:
                    button._record_book_state = "disabled"
                    button._record_book_disabled_fg = "#94a3b8"
                    button.config(
                        cursor="arrow",
                        fg="#94a3b8",
                    )
                    continue
                enabled = edit_mode
                if "invasion" in key and not invasion_enabled:
                    enabled = False
                button_text = button.cget("text")
                if key == "enable_all":
                    button_text = "전체 ON" if self.record_book_header_toggle_states.get("enable_all", True) else "전체 OFF"
                elif key.endswith("_main"):
                    button_text = "전체 ON" if self.record_book_header_toggle_states.get(key, True) else "전체 OFF"
                elif key.endswith("_invasion"):
                    button_text = "침공 ON" if self.record_book_header_toggle_states.get(key, True) else "침공 OFF"
                button._record_book_state = "normal" if enabled else "disabled"
                button._record_book_disabled_fg = "#94a3b8"
                normal_fg = getattr(button, "_record_book_action_normal_fg", button.cget("fg"))
                button.config(
                    text=button_text,
                    cursor="hand2" if enabled else "arrow",
                    fg=normal_fg if enabled else "#94a3b8",
                )
            except tk.TclError:
                continue

    def _update_record_book_row_enabled_states(self) -> None:
        edit_mode = self.record_book_edit_mode_var.get()
        invasion_enabled = self.record_book_use_invasion_var.get()
        apply_schedule = self.record_book_apply_schedule_var.get()
        if apply_schedule:
            has_schedule_for_date, schedule_slot_presence = self._get_record_book_schedule_slot_presence()
        else:
            has_schedule_for_date, schedule_slot_presence = False, {}
        self._update_record_book_header_action_buttons_state()
        for area_name, var in self.record_book_area_enabled_vars.items():
            toggle = getattr(self, "record_book_area_toggle_widgets", {}).get(area_name)
            if toggle is not None:
                toggle.config(state="normal" if edit_mode else "disabled")
            movable_sections = self._get_record_book_movable_sections(area_name)
            current_index = movable_sections.index(area_name) if area_name in movable_sections else -1
            up_button, down_button = getattr(self, "record_book_area_move_buttons", {}).get(area_name, (None, None))
            if up_button is not None:
                can_move_up = edit_mode and current_index > 0
                up_button._record_book_move_enabled = can_move_up
                up_button.config(
                    state="normal" if can_move_up else "disabled",
                    bg="#ffffff" if can_move_up else "#e2e8f0",
                    fg="#1e3a8a" if can_move_up else "#94a3b8",
                    activebackground="#dbeafe" if can_move_up else "#e2e8f0",
                    activeforeground="#1e3a8a" if can_move_up else "#94a3b8",
                    disabledforeground="#94a3b8",
                    cursor="hand2" if can_move_up else "arrow",
                )
            if down_button is not None:
                can_move_down = edit_mode and 0 <= current_index < len(movable_sections) - 1
                down_button._record_book_move_enabled = can_move_down
                down_button.config(
                    state="normal" if can_move_down else "disabled",
                    bg="#ffffff" if can_move_down else "#e2e8f0",
                    fg="#1e3a8a" if can_move_down else "#94a3b8",
                    activebackground="#dbeafe" if can_move_down else "#e2e8f0",
                    activeforeground="#1e3a8a" if can_move_down else "#94a3b8",
                    disabledforeground="#94a3b8",
                    cursor="hand2" if can_move_down else "arrow",
                )
        for boss_name, widgets in self.record_book_row_widgets.items():
            metadata = self.record_book_catalog_map.get(boss_name, {})
            area_name = metadata.get("display_area", "기타")
            area_enabled = self.record_book_area_enabled_vars.get(area_name, tk.BooleanVar(value=True)).get()
            boss_enabled = self.record_book_boss_enabled_vars.get(boss_name, tk.BooleanVar(value=True)).get()
            row_vars = self.record_book_row_vars.get(boss_name, {})
            schedule_info = schedule_slot_presence.get(boss_name, {"main": False, "invasion": False})
            if has_schedule_for_date:
                main_available = bool(schedule_info.get("main", False))
                invasion_available = bool(schedule_info.get("invasion", False))
                row_schedule_enabled = main_available or invasion_available
            else:
                main_available = True
                invasion_available = invasion_enabled
                row_schedule_enabled = True
            input_enabled_main = edit_mode and area_enabled and boss_enabled and row_schedule_enabled
            input_enabled_invasion = edit_mode and area_enabled and boss_enabled and invasion_enabled and row_schedule_enabled
            check_state = "normal" if edit_mode and area_enabled else "disabled"
            user_enabled = area_enabled and boss_enabled
            ally_checked = self._get_record_book_row_side_count(row_vars, "ally", include_invasion=invasion_enabled, boss_name=boss_name) > 0
            enemy_checked = self._get_record_book_row_side_count(row_vars, "enemy", include_invasion=invasion_enabled, boss_name=boss_name) > 0
            ally_bg = "#dcfce7" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc"
            enemy_bg = "#fee2e2" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc"
            ally_invasion_bg = "#dcfce7" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc"
            enemy_invasion_bg = "#fee2e2" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc"
            memo_bg = "#f8f1df" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc"
            if not user_enabled:
                boss_bg = "#f8fafc"
                boss_fg = "#94a3b8"
                boss_font = self.record_book_boss_overstrike_font
                avg_font = self.record_book_avg_overstrike_font
            elif has_schedule_for_date and not row_schedule_enabled:
                boss_bg = "#f8fafc"
                boss_fg = "#94a3b8"
                boss_font = self.button_font
                avg_font = (self.current_font_family, 11, "bold")
            elif ally_checked and not enemy_checked:
                boss_bg = "#dcfce7"
                boss_fg = "#166534"
                boss_font = self.button_font
                avg_font = (self.current_font_family, 11, "bold")
            elif enemy_checked and not ally_checked:
                boss_bg = "#fee2e2"
                boss_fg = "#991b1b"
                boss_font = self.button_font
                avg_font = (self.current_font_family, 11, "bold")
            elif ally_checked and enemy_checked:
                boss_bg = "#fef3c7"
                boss_fg = "#92400e"
                boss_font = self.button_font
                avg_font = (self.current_font_family, 11, "bold")
            else:
                boss_bg = "#f8fafc"
                boss_fg = "#0f172a"
                boss_font = self.button_font
                avg_font = (self.current_font_family, 11, "bold")
            widgets["enabled"].config(state=check_state)
            widgets["boss_frame"].config(bg=boss_bg)
            widgets["boss_label"].config(bg=boss_bg, fg=boss_fg, font=boss_font)
            if "avg_frame" in widgets:
                widgets["avg_frame"].config(bg="#f8fafc" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc")
            widgets["ally_main_frame"].config(bg=ally_bg)
            widgets["enemy_main_frame"].config(bg=enemy_bg)
            widgets["memo_container"].config(bg=memo_bg)
            if widgets["ally_invasion_frame"] is not None:
                widgets["ally_invasion_frame"].config(bg=ally_invasion_bg)
            if widgets["enemy_invasion_frame"] is not None:
                widgets["enemy_invasion_frame"].config(bg=enemy_invasion_bg)
            for widget_key in ("ally_main", "ally_main_extra"):
                widget = widgets.get(widget_key)
                if widget is not None:
                    widget.config(
                        state="normal" if input_enabled_main else "disabled",
                        bg=ally_bg,
                        activebackground=ally_bg,
                        selectcolor="#ffffff",
                    )
            for widget_key in ("enemy_main", "enemy_main_extra"):
                widget = widgets.get(widget_key)
                if widget is not None:
                    widget.config(
                        state="normal" if input_enabled_main else "disabled",
                        bg=enemy_bg,
                        activebackground=enemy_bg,
                        selectcolor="#ffffff",
                    )
            for widget_key in ("ally_invasion", "ally_invasion_extra"):
                widget = widgets.get(widget_key)
                if widget is not None:
                    widget.config(
                        state="normal" if input_enabled_invasion else "disabled",
                        bg=ally_invasion_bg,
                        activebackground=ally_invasion_bg,
                        selectcolor="#ffffff",
                    )
            for widget_key in ("enemy_invasion", "enemy_invasion_extra"):
                widget = widgets.get(widget_key)
                if widget is not None:
                    widget.config(
                        state="normal" if input_enabled_invasion else "disabled",
                        bg=enemy_invasion_bg,
                        activebackground=enemy_invasion_bg,
                        selectcolor="#ffffff",
                    )
            widgets["memo"].config(
                state="normal" if edit_mode and user_enabled and row_schedule_enabled else "disabled",
                bg=memo_bg,
            )
            widgets["enabled"].config(
                state="normal" if edit_mode else "disabled",
                bg="#f8fafc" if user_enabled else "#ffffff",
                activebackground="#f8fafc" if user_enabled else "#ffffff",
                selectcolor="#ffffff",
            )
            widgets["avg_label"].config(
                fg="#7c2d12" if user_enabled and row_schedule_enabled else "#94a3b8",
                font=avg_font,
                bg="#f8fafc" if user_enabled and row_schedule_enabled else "#ffffff" if not user_enabled else "#f8fafc",
            )
        self._update_record_book_header_counts()

    def _on_record_book_date_field_change(self, _event=None) -> None:
        self._load_record_book_date_if_changed()

    def _clear_record_book_rows(self) -> None:
        if not hasattr(self, "record_book_inner_frame"):
            return
        for child in self.record_book_inner_frame.winfo_children():
            child.destroy()
        self.record_book_row_vars = {}
        self.record_book_row_widgets = {}
        self.record_book_area_toggle_widgets = {}
        self.record_book_area_move_buttons = {}

    def _render_record_book_header(self) -> None:
        if not hasattr(self, "record_book_header_frame") or not self._widget_available(self.record_book_header_frame):
            return
        header_frame = self.record_book_header_frame
        for child in header_frame.winfo_children():
            child.destroy()
        self.record_book_header_action_buttons = {}
        line_color = "#94a3b8"
        header_frame.configure(bg=line_color)
        row_heights = (28, 24, 24, 32)
        total_height = sum(row_heights)
        x_positions = [0]
        for width in RECORD_BOOK_COLUMN_WIDTHS:
            x_positions.append(x_positions[-1] + width)

        def place_label(text: str, x: int, y: int, width: int, height: int, *, bg: str = "#eff6ff", fg: str = "#0f172a", font=None) -> tk.Label:
            label = tk.Label(
                header_frame,
                text=text,
                font=font or self.button_font,
                bg=bg,
                fg=fg,
                bd=0,
                relief="flat",
                anchor="center",
            )
            label.place(x=x, y=y, width=width, height=height)
            return label

        def place_vline(x: int, y: int, height: int) -> None:
            tk.Frame(header_frame, bg=line_color).place(x=x, y=y, width=1, height=height)

        def place_hline(y: int, x: int, width: int) -> None:
            tk.Frame(header_frame, bg=line_color).place(x=x, y=y, width=width, height=1)

        def place_button(
            text: str,
            x: int,
            y: int,
            width: int,
            height: int,
            *,
            bg: str,
            fg: str,
            activebackground: str,
            command=None,
            state: str = "normal",
        ) -> tk.Label:
            button = tk.Label(
                header_frame,
                text=text,
                font=self.percent_font,
                bg=bg,
                fg=fg,
                relief="flat",
                bd=0,
                cursor="hand2" if state == "normal" else "arrow",
                anchor="center",
            )
            button._record_book_state = state
            button._record_book_command = command
            button._record_book_disabled_fg = "#94a3b8"
            button.place(x=x, y=y, width=width, height=height)
            self._bind_record_book_header_action_hover(button, bg, activebackground, fg, fg)
            return button

        invasion_enabled = self.record_book_use_invasion_var.get()
        header_height = row_heights[0] + row_heights[1] + row_heights[2]
        action_y = header_height
        action_height = row_heights[3]
