    def _update_record_book_header_counts(self) -> None:
        if not hasattr(self, "record_book_header_frame"):
            return
        invasion_enabled = self.record_book_use_invasion_var.get()
        ally_main_count = 0
        ally_invasion_count = 0
        enemy_main_count = 0
        enemy_invasion_count = 0
        for boss_name, row_vars in self.record_book_row_vars.items():
            ally_main_count += self._get_record_book_row_slot_count(row_vars, "main", "ally", boss_name)
            enemy_main_count += self._get_record_book_row_slot_count(row_vars, "main", "enemy", boss_name)
            if invasion_enabled:
                ally_invasion_count += self._get_record_book_row_slot_count(row_vars, "invasion", "ally", boss_name)
                enemy_invasion_count += self._get_record_book_row_slot_count(row_vars, "invasion", "enemy", boss_name)
        try:
            if invasion_enabled and self.record_book_header_ally_main_count_label is not None:
                self.record_book_header_ally_main_count_label.config(text=str(ally_main_count))
                self.record_book_header_ally_invasion_count_label.config(text=str(ally_invasion_count))
                self.record_book_header_enemy_main_count_label.config(text=str(enemy_main_count))
                self.record_book_header_enemy_invasion_count_label.config(text=str(enemy_invasion_count))
            elif getattr(self, "record_book_header_ally_count_label", None) is not None:
                self.record_book_header_ally_count_label.config(text=str(ally_main_count))
                self.record_book_header_enemy_count_label.config(text=str(enemy_main_count))
        except tk.TclError:
            return

    def _make_record_book_cell_frame(self, row: int, column: int, *, columnspan: int = 1, bg: str = "#eef2ff", padx: int = 0, pady: int = 0) -> tk.Frame:
        frame = tk.Frame(self.record_book_inner_frame, bg=bg, relief="flat", bd=0, highlightthickness=0)
        frame.grid(row=row, column=column, columnspan=columnspan, sticky="nsew", padx=padx, pady=pady)
        self._bind_record_book_scroll_target(frame)
        return frame

    def _rebuild_record_book_rows(self) -> None:
        if not hasattr(self, "record_book_inner_frame"):
            return
        self.record_book_rebuild_busy = True
        scroll_fraction = 0.0
        try:
            if self._widget_available(getattr(self, "record_book_canvas", None)):
                try:
                    scroll_fraction = self.record_book_canvas.yview()[0]
                except (tk.TclError, IndexError):
                    scroll_fraction = 0.0
            daily_records = self._get_record_book_daily_records()
            old_frame = self.record_book_inner_frame
            new_frame = tk.Frame(self.record_book_canvas, bg="#eef2ff")
            self.record_book_inner_frame = new_frame
            self.record_book_row_vars = {}
            self.record_book_row_widgets = {}
            self.record_book_area_toggle_widgets = {}
            self.record_book_area_move_buttons = {}
            row_index = 0
            for section_name in self._get_ordered_record_book_sections():
                section_bosses = self._get_record_book_section_bosses(section_name)
                if not section_bosses:
                    continue
                if row_index == 0:
                    tk.Frame(self.record_book_inner_frame, bg="#16a34a", height=4).grid(row=row_index, column=0, columnspan=8, sticky="ew", pady=(8, 6))
                    row_index += 1
                area_var = self.record_book_area_enabled_vars.get(section_name)
                if area_var is None:
                    area_var = tk.BooleanVar(value=self.record_book_data.get("chapter_enabled", {}).get(section_name, True))
                    self.record_book_area_enabled_vars[section_name] = area_var
                section_label = self._get_record_book_section_label(section_name)
                header_bg = "#c7d2fe" if section_name == "절대자" else "#dbeafe"
                area_header_frame = tk.Frame(self.record_book_inner_frame, bg=header_bg, relief="solid", bd=1)
                area_header_frame.grid(row=row_index, column=0, columnspan=8, sticky="ew", pady=(10, 0))
                area_header_frame.grid_columnconfigure(0, weight=1)
                area_toggle = tk.Checkbutton(
                    area_header_frame,
                    text=section_label,
                    variable=area_var,
                    command=lambda current_area=section_name: self._on_record_book_area_toggle(current_area),
                    font=self.label_font,
                    bg=header_bg,
                    fg="#1e3a8a",
                    selectcolor="#bfdbfe",
                    activebackground=header_bg,
                    activeforeground="#1e3a8a",
                    highlightthickness=0,
                    bd=0,
                    anchor="w",
                )
                area_toggle.grid(row=0, column=0, sticky="w", padx=(10, 0), pady=3)
                self._bind_record_book_scroll_target(area_toggle)
                self.record_book_area_toggle_widgets[section_name] = area_toggle
                up_button = tk.Button(
                    area_header_frame,
                    text="▲",
                    font=(self.current_font_family, 8, "bold"),
                    bg="#ffffff",
                    fg="#1e3a8a",
                    activebackground="#dbeafe",
                    activeforeground="#1e3a8a",
                    relief="raised",
                    overrelief="ridge",
                    bd=1,
                    highlightthickness=0,
                    command=lambda current_area=section_name: self._move_record_book_section(current_area, -1),
                    cursor="hand2",
                    padx=0,
                    pady=0,
                )
                up_button.grid(row=0, column=1, sticky="e", padx=(4, 2))
                down_button = tk.Button(
                    area_header_frame,
                    text="▼",
                    font=(self.current_font_family, 8, "bold"),
                    bg="#ffffff",
                    fg="#1e3a8a",
                    activebackground="#dbeafe",
                    activeforeground="#1e3a8a",
                    relief="raised",
                    overrelief="ridge",
                    bd=1,
                    highlightthickness=0,
                    command=lambda current_area=section_name: self._move_record_book_section(current_area, 1),
                    cursor="hand2",
                    padx=0,
                    pady=0,
                )
                down_button.grid(row=0, column=2, sticky="e", padx=(0, 2))
                self._bind_record_book_move_button_hover(up_button)
                self._bind_record_book_move_button_hover(down_button)
                self._bind_record_book_scroll_target(up_button)
                self._bind_record_book_scroll_target(down_button)
                self.record_book_area_move_buttons[section_name] = (up_button, down_button)
                tk.Frame(self.record_book_inner_frame, bg="#bfdbfe", height=1).grid(row=row_index + 2, column=0, columnspan=8, sticky="ew")
                row_index += 3
                for item in section_bosses:
                    row_index = self._build_record_book_boss_row(row_index, item, daily_records.get(item["boss_name"]))
            for column_index, width in enumerate(RECORD_BOOK_COLUMN_WIDTHS):
                self.record_book_inner_frame.grid_columnconfigure(column_index, minsize=width)
            self._update_record_book_row_enabled_states()
            if self._widget_available(getattr(self, "record_book_canvas", None)):
                try:
                    self.record_book_inner_frame.bind("<Configure>", self._on_record_book_canvas_configure)
                    self.record_book_canvas.itemconfig(self.record_book_canvas_window_id, window=self.record_book_inner_frame)
                    self.record_book_inner_frame.update_idletasks()
                    self._on_record_book_canvas_configure()
                    self.record_book_canvas.yview_moveto(scroll_fraction)
                except tk.TclError:
                    pass
            if old_frame is not None and old_frame is not self.record_book_inner_frame:
                try:
                    old_frame.destroy()
                except tk.TclError:
                    pass
        finally:
            self.record_book_rebuild_busy = False

    def _build_record_book_boss_row(self, row_index: int, item: dict, entry: dict | None = None) -> int:
        boss_name = item["boss_name"]
        invasion_enabled = self.record_book_use_invasion_var.get()
        double_slot_enabled = self._record_book_boss_uses_double_check(boss_name)
        enabled_var = self.record_book_boss_enabled_vars.get(boss_name)
        if enabled_var is None:
            enabled_var = tk.BooleanVar(value=self.record_book_data.get("boss_enabled", {}).get(boss_name, True))
            self.record_book_boss_enabled_vars[boss_name] = enabled_var
        effective_entry = entry or self._get_default_record_book_entry()
        ally_main_var = tk.BooleanVar(value=bool(effective_entry.get("ally_main", False)))
        ally_invasion_var = tk.BooleanVar(value=bool(effective_entry.get("ally_invasion", False)))
        ally_main_extra_var = tk.BooleanVar(value=bool(effective_entry.get("ally_main_extra", False)))
        ally_invasion_extra_var = tk.BooleanVar(value=bool(effective_entry.get("ally_invasion_extra", False)))
        enemy_main_var = tk.BooleanVar(value=bool(effective_entry.get("enemy_main", False)))
        enemy_invasion_var = tk.BooleanVar(value=bool(effective_entry.get("enemy_invasion", False)))
        enemy_main_extra_var = tk.BooleanVar(value=bool(effective_entry.get("enemy_main_extra", False)))
        enemy_invasion_extra_var = tk.BooleanVar(value=bool(effective_entry.get("enemy_invasion_extra", False)))
        if not double_slot_enabled:
            ally_main_extra_var.set(False)
            ally_invasion_extra_var.set(False)
            enemy_main_extra_var.set(False)
            enemy_invasion_extra_var.set(False)
        memo_text = str(effective_entry.get("memo", ""))
        memo_var = tk.StringVar(value=memo_text)
        average_cut_seconds = self._get_record_book_average_cut_seconds(boss_name)
        avg_var = tk.StringVar(value=format_seconds(average_cut_seconds, show_centiseconds=True) if average_cut_seconds is not None else "--:--:--")
        self.record_book_row_vars[boss_name] = {
            "ally_main": ally_main_var,
            "ally_invasion": ally_invasion_var,
            "ally_main_extra": ally_main_extra_var,
            "ally_invasion_extra": ally_invasion_extra_var,
            "enemy_main": enemy_main_var,
            "enemy_invasion": enemy_invasion_var,
            "enemy_main_extra": enemy_main_extra_var,
            "enemy_invasion_extra": enemy_invasion_extra_var,
            "memo": memo_var,
            "avg": avg_var,
        }

        def create_slot_buttons(
            parent: tk.Widget,
            *,
            slot: str,
            side: str,
            primary_var: tk.BooleanVar,
            extra_var: tk.BooleanVar,
            bg: str,
            fg: str,
            allow_extra: bool,
        ) -> tuple[tk.Checkbutton, tk.Checkbutton | None]:
            primary_key, extra_key = self._get_record_book_slot_keys(side, slot)
            primary_button = tk.Checkbutton(
                parent,
                variable=primary_var,
                command=lambda current_boss=boss_name, current_slot=slot, current_side=side, current_key=primary_key: self._on_record_book_side_toggle(current_boss, current_slot, current_side, current_key),
                bg=bg,
                fg=fg,
                selectcolor="#ffffff",
                activebackground=bg,
                activeforeground=fg,
                highlightthickness=0,
                bd=0,
            )
            if allow_extra:
                primary_button.pack(side="left", expand=True, padx=(10, 2), pady=1)
            else:
                primary_button.pack(anchor="center", pady=1)
            self._bind_record_book_scroll_target(primary_button)
            extra_button = None
            if allow_extra:
                button = tk.Checkbutton(
                    parent,
                    variable=extra_var,
                    command=lambda current_boss=boss_name, current_slot=slot, current_side=side, current_key=extra_key: self._on_record_book_side_toggle(current_boss, current_slot, current_side, current_key),
                    bg=bg,
                    fg=fg,
                    selectcolor="#ffffff",
                    activebackground=bg,
                    activeforeground=fg,
                    highlightthickness=0,
                    bd=0,
                )
                button.pack(side="left", expand=True, padx=(2, 10), pady=1)
                self._bind_record_book_scroll_target(button)
                extra_button = button
            return primary_button, extra_button

        enabled_frame = self._make_record_book_cell_frame(row_index, 0, bg="#f8fafc")
        enabled_button = tk.Checkbutton(
            enabled_frame,
            variable=enabled_var,
            command=lambda current_boss=boss_name: self._on_record_book_boss_enabled_change(current_boss),
            bg="#f8fafc",
            fg="#1e3a8a",
            selectcolor="#ffffff",
            activebackground="#f8fafc",
            highlightthickness=0,
            bd=0,
        )
        enabled_button.pack(anchor="center", pady=1)
        self._bind_record_book_scroll_target(enabled_button)

        boss_frame = self._make_record_book_cell_frame(row_index, 1, bg="#f8fafc")
        display_boss_name = self._get_record_book_display_name(boss_name) or boss_name
        boss_label = tk.Label(boss_frame, text=display_boss_name, font=self.button_font, bg="#f8fafc", fg="#0f172a", anchor="w")
        boss_label.pack(fill="both", expand=True, padx=6)
        self._bind_record_book_scroll_target(boss_label)

        avg_frame = self._make_record_book_cell_frame(row_index, 2, bg="#f8fafc")
        avg_label = tk.Label(avg_frame, textvariable=avg_var, font=(self.current_font_family, 11, "bold"), bg="#f8fafc", fg="#7c2d12", anchor="center")
        avg_label.pack(fill="both", expand=True, padx=6)
        self._bind_record_book_scroll_target(avg_label)

        ally_main_frame = self._make_record_book_cell_frame(row_index, 3, columnspan=2 if not invasion_enabled else 1, bg="#dcfce7")
        ally_main_button, ally_main_extra_button = create_slot_buttons(
            ally_main_frame,
            slot="main",
            side="ally",
            primary_var=ally_main_var,
            extra_var=ally_main_extra_var,
            bg="#dcfce7",
            fg="#166534",
            allow_extra=double_slot_enabled,
        )

        ally_invasion_button = None
        ally_invasion_extra_button = None
        ally_invasion_frame = None
        if invasion_enabled:
            ally_invasion_frame = self._make_record_book_cell_frame(row_index, 4, bg="#dcfce7")
            ally_invasion_button, ally_invasion_extra_button = create_slot_buttons(
                ally_invasion_frame,
                slot="invasion",
                side="ally",
                primary_var=ally_invasion_var,
                extra_var=ally_invasion_extra_var,
                bg="#dcfce7",
                fg="#166534",
                allow_extra=double_slot_enabled,
            )

        enemy_main_frame = self._make_record_book_cell_frame(row_index, 5, columnspan=2 if not invasion_enabled else 1, bg="#fee2e2")
        enemy_main_button, enemy_main_extra_button = create_slot_buttons(
            enemy_main_frame,
            slot="main",
            side="enemy",
            primary_var=enemy_main_var,
            extra_var=enemy_main_extra_var,
            bg="#fee2e2",
            fg="#991b1b",
            allow_extra=double_slot_enabled,
        )

        enemy_invasion_button = None
        enemy_invasion_extra_button = None
        enemy_invasion_frame = None
        if invasion_enabled:
            enemy_invasion_frame = self._make_record_book_cell_frame(row_index, 6, bg="#fee2e2")
            enemy_invasion_button, enemy_invasion_extra_button = create_slot_buttons(
                enemy_invasion_frame,
                slot="invasion",
                side="enemy",
                primary_var=enemy_invasion_var,
                extra_var=enemy_invasion_extra_var,
                bg="#fee2e2",
                fg="#991b1b",
                allow_extra=double_slot_enabled,
            )

        memo_container = tk.Frame(self.record_book_inner_frame, bg="#f8f1df")
        memo_container.grid(row=row_index, column=7, sticky="nsew", pady=2)
        memo_entry = tk.Text(memo_container, height=2, wrap="word", font=(self.current_font_family, 9), bg="#f8f1df", fg="#7c2d12", relief="flat", bd=0)
        memo_scroll = tk.Scrollbar(memo_container, orient="vertical", command=memo_entry.yview)
        memo_entry.configure(yscrollcommand=memo_scroll.set)
        memo_width = max(220, RECORD_BOOK_COLUMN_WIDTHS[7] - 18)
        memo_entry.place(x=0, y=0, width=memo_width, height=38)
        memo_scroll.place(x=memo_width, y=0, width=16, height=38)
        if memo_text:
            memo_entry.insert("1.0", memo_text)
        self._bind_record_book_scroll_target(memo_entry)
        self._bind_record_book_scroll_target(memo_scroll)
        memo_entry.bind("<KeyRelease>", lambda _event, current_boss=boss_name: self._on_record_book_memo_change(current_boss))
        memo_entry.bind("<FocusOut>", lambda _event, current_boss=boss_name: self._on_record_book_memo_focus_out(current_boss))

        tk.Frame(self.record_book_inner_frame, bg="#dbeafe", height=1).grid(row=row_index + 1, column=0, columnspan=8, sticky="ew")
        self.record_book_row_widgets[boss_name] = {
            "enabled": enabled_button,
            "boss_frame": boss_frame,
            "boss_label": boss_label,
            "avg_frame": avg_frame,
            "avg_label": avg_label,
            "ally_main_frame": ally_main_frame,
            "ally_invasion_frame": ally_invasion_frame if invasion_enabled else None,
            "enemy_main_frame": enemy_main_frame,
            "enemy_invasion_frame": enemy_invasion_frame if invasion_enabled else None,
            "memo_container": memo_container,
            "ally_main": ally_main_button,
            "ally_main_extra": ally_main_extra_button,
            "ally_invasion": ally_invasion_button,
            "ally_invasion_extra": ally_invasion_extra_button,
            "enemy_main": enemy_main_button,
            "enemy_main_extra": enemy_main_extra_button,
            "enemy_invasion": enemy_invasion_button,
            "enemy_invasion_extra": enemy_invasion_extra_button,
            "memo": memo_entry,
        }
        return row_index + 2

