    def _load_record_book_date(self) -> None:
        date_key = self._get_record_book_date_key()
        self._ensure_record_book_data_for_date(date_key)
        self.record_book_loaded_date_key = date_key
        daily_records = self.record_book_data.get("records", {}).get(date_key, {})
        for section_name, var in self.record_book_area_enabled_vars.items():
            var.set(bool(self.record_book_data.get("chapter_enabled", {}).get(section_name, True)))
        for boss_name, var in self.record_book_boss_enabled_vars.items():
            var.set(bool(self.record_book_data.get("boss_enabled", {}).get(boss_name, True)))
            entry = daily_records.get(boss_name, self._get_default_record_book_entry())
            row_vars = self.record_book_row_vars[boss_name]
            double_slot_enabled = self._record_book_boss_uses_double_check(boss_name)
            row_vars["ally_main"].set(bool(entry.get("ally_main", False)))
            row_vars["ally_invasion"].set(bool(entry.get("ally_invasion", False)))
            row_vars["ally_main_extra"].set(bool(entry.get("ally_main_extra", False)) if double_slot_enabled else False)
            row_vars["ally_invasion_extra"].set(bool(entry.get("ally_invasion_extra", False)) if double_slot_enabled else False)
            row_vars["enemy_main"].set(bool(entry.get("enemy_main", False)))
            row_vars["enemy_invasion"].set(bool(entry.get("enemy_invasion", False)))
            row_vars["enemy_main_extra"].set(bool(entry.get("enemy_main_extra", False)) if double_slot_enabled else False)
            row_vars["enemy_invasion_extra"].set(bool(entry.get("enemy_invasion_extra", False)) if double_slot_enabled else False)
            row_vars["memo"].set(str(entry.get("memo", "")))
            memo_widget = self.record_book_row_widgets[boss_name]["memo"]
            memo_widget.delete("1.0", "end")
            memo_widget.insert("1.0", row_vars["memo"].get())
            average_cut_seconds = self._get_record_book_average_cut_seconds(boss_name)
            row_vars["avg"].set(format_seconds(average_cut_seconds, show_centiseconds=True) if average_cut_seconds is not None else "--:--:--")
        self._initialize_record_book_header_toggle_states()
        self._update_record_book_row_enabled_states()
        self._store_record_book_loaded_snapshot(date_key)
        self._set_record_book_dirty(False)
        self.record_book_status_var.set(f"{date_key} 기록지를 불러왔습니다.")

    def _save_record_book_date(self, date_key: str | None = None, *, quiet: bool = False, refresh_stats: bool = True) -> None:
        if not self.record_book_dirty and not quiet:
            self.record_book_status_var.set("저장할 변경사항이 없습니다.")
            return
        effective_date = self._capture_record_book_ui_state_to_memory(date_key)
        self._save_record_book_data(self.record_book_data)
        self._rebuild_record_book_rows()
        self.record_book_loaded_date_key = effective_date
        self._store_record_book_loaded_snapshot(effective_date)
        self._set_record_book_dirty(False)
        if not quiet:
            self.record_book_status_var.set(f"{effective_date} 기록지를 저장했습니다.")
        if refresh_stats:
            self._refresh_record_stats_if_visible()

    def _on_record_book_edit_mode_change(self) -> None:
        self._save_settings()
        self._update_record_book_row_enabled_states()
        self.record_book_status_var.set("수정 모드 설정을 저장했습니다.")

    def _on_record_book_apply_schedule_toggle(self) -> None:
        self._save_settings()
        self._update_record_book_row_enabled_states()
        if self.record_book_apply_schedule_var.get():
            self.record_book_status_var.set("보스 스케쥴 적용을 켰습니다.")
        else:
            self.record_book_status_var.set("보스 스케쥴 적용을 껐습니다.")

    def _on_record_book_invasion_toggle(self) -> None:
        self._capture_record_book_ui_state_to_memory(self.record_book_loaded_date_key)
        self._save_settings()
        self._render_record_book_header()
        self._rebuild_record_book_rows()
        self._initialize_record_book_header_toggle_states()
        self._update_record_book_header_action_buttons_state()
        self._refresh_record_stats_if_visible()
        self.record_book_status_var.set("침공 기록 사용 설정을 반영했습니다.")

    def _on_record_book_area_toggle(self, area_name: str) -> None:
        enabled = self.record_book_area_enabled_vars[area_name].get()
        for item in self._get_record_book_section_bosses(area_name):
            boss_name = str(item.get("boss_name", ""))
            if not boss_name or boss_name not in self.record_book_boss_enabled_vars:
                continue
            self.record_book_boss_enabled_vars[boss_name].set(enabled)
        if not enabled:
            ordered_sections = self._get_record_book_section_order()
            if area_name in ordered_sections:
                ordered_sections.remove(area_name)
                ordered_sections.append(area_name)
                self.record_book_data["section_order"] = ordered_sections
        self._initialize_record_book_header_toggle_states()
        self._update_record_book_row_enabled_states()
        self._update_record_book_dirty_from_ui()
        section_label = self._get_record_book_section_label(area_name)
        if enabled:
            self.record_book_status_var.set(f"{section_label} 지역 변경사항이 저장 대기 상태입니다.")
        else:
            self.record_book_status_var.set(f"{section_label} 지역이 비활성화됨에 따라 최하단부로 내려갑니다. 저장 버튼으로 확정하세요.")

    def _on_record_book_boss_enabled_change(self, boss_name: str) -> None:
        self._initialize_record_book_header_toggle_states()
        self._update_record_book_row_enabled_states()
        self._update_record_book_dirty_from_ui()
        state_text = "사용" if self.record_book_boss_enabled_vars[boss_name].get() else "비활성화"
        display_name = self._get_record_book_display_name(boss_name) or boss_name
        self.record_book_status_var.set(f"{display_name} 기록/통계를 {state_text} 상태로 변경했습니다. 저장 버튼으로 확정하세요.")

    def _on_record_book_side_toggle(self, boss_name: str, slot: str, side: str, current_key: str) -> None:
        row_vars = self.record_book_row_vars[boss_name]
        opposite_side = "enemy" if side == "ally" else "ally"
        if row_vars[current_key].get():
            if self._record_book_boss_uses_double_check(boss_name):
                opposite_key = f"{opposite_side}_{slot}_extra" if current_key.endswith("_extra") else f"{opposite_side}_{slot}"
                row_vars[opposite_key].set(False)
            else:
                for opposite_key in self._get_record_book_slot_keys(opposite_side, slot):
                    row_vars[opposite_key].set(False)
        self._update_record_book_row_enabled_states()
        self._update_record_book_dirty_from_ui()
        display_name = self._get_record_book_display_name(boss_name) or boss_name
        self.record_book_status_var.set(f"{display_name} {('본섭' if slot == 'main' else '침공')} 기록을 변경했습니다. 저장 버튼으로 확정하세요.")

    def _on_record_book_memo_focus_out(self, boss_name: str) -> None:
        if not self.record_book_edit_mode_var.get():
            return
        memo_widget = self.record_book_row_widgets[boss_name]["memo"]
        current_text = memo_widget.get("1.0", "end-1c")
        if current_text == self.record_book_row_vars[boss_name]["memo"].get():
            return
        self.record_book_row_vars[boss_name]["memo"].set(current_text)
        self._update_record_book_dirty_from_ui()
        display_name = self._get_record_book_display_name(boss_name) or boss_name
        self.record_book_status_var.set(f"{display_name} 메모를 변경했습니다. 저장 버튼으로 확정하세요.")

    def _on_record_book_memo_change(self, boss_name: str) -> None:
        if not self.record_book_edit_mode_var.get():
            return
        memo_widget = self.record_book_row_widgets[boss_name]["memo"]
        current_text = memo_widget.get("1.0", "end-1c")
        if current_text == self.record_book_row_vars[boss_name]["memo"].get():
            return
        self.record_book_row_vars[boss_name]["memo"].set(current_text)
        self._update_record_book_dirty_from_ui()

    def open_record_stats_window(self) -> None:
        if self.record_stats_window_busy:
            return
        self.record_stats_window_busy = True
        try:
            self._ensure_record_stats_window()
            if self.record_stats_window_open and self.record_stats_window is not None and self.record_stats_window.winfo_exists():
                self.record_stats_window.deiconify()
                self.record_stats_window.lift()
                self.refresh_record_stats_view()
                return
            self.record_stats_window_open = True
            self._position_record_stats_window()
            self.record_stats_window.deiconify()
            self.record_stats_window.lift()
            self.refresh_record_stats_view()
        except tk.TclError:
            return
        finally:
            self.record_stats_window_busy = False

    def close_record_stats_window(self) -> None:
        try:
            if self.record_stats_window is not None and self.record_stats_window.winfo_exists():
                self.record_stats_window.withdraw()
            self.record_stats_window_open = False
        except tk.TclError:
            self.record_stats_window_open = False

    def _position_record_stats_window(self) -> None:
        if self.record_stats_window is None or not self.record_stats_window.winfo_exists() or not self.record_stats_window_open:
            return
        if self.record_book_window is not None and self.record_book_window.winfo_exists() and self.record_book_window_open:
            x = self.record_book_window.winfo_x() + 32
            y = self.record_book_window.winfo_y() + 42
        elif self.schedule_window is not None and self.schedule_window.winfo_exists() and self.schedule_window_open:
            x = self.schedule_window.winfo_x() + 32
            y = self.schedule_window.winfo_y() + 42
        else:
            x = self.root.winfo_x() + 48
            y = self.root.winfo_y() + 48
