    def _build_record_stats(self) -> tuple[list[dict], dict]:
        recent_count = max(1, self._parse_int(self.record_book_recent_count_var.get(), RECORD_BOOK_DEFAULT_RECENT_COUNT))
        recent_days = max(1, self._parse_int(self.record_book_recent_days_var.get(), RECORD_BOOK_DEFAULT_RECENT_DAYS))
        now_ordinal = datetime.now().date().toordinal()
        use_invasion = self.record_book_use_invasion_var.get()
        overall_events: list[tuple[int, str]] = []
        overall_recent_day_events: list[tuple[int, str]] = []
        rows: list[dict] = []
        for item in self.record_book_catalog:
            boss_name = item["boss_name"]
            display_area = item["display_area"]
            if not self.record_book_data.get("chapter_enabled", {}).get(display_area, True):
                continue
            if not self.record_book_data.get("boss_enabled", {}).get(boss_name, True):
                continue
            ally_total = 0
            enemy_total = 0
            events: list[tuple[int, str]] = []
            for date_key, boss_map in self.record_book_data.get("records", {}).items():
                if boss_name not in boss_map:
                    continue
                try:
                    ordinal = datetime.strptime(date_key, RECORD_BOOK_DATE_FORMAT).date().toordinal()
                except ValueError:
                    continue
                entry = boss_map[boss_name]
                slot_events = []
                slot_events.extend(["ally"] * self._get_record_book_entry_slot_count(entry, "main", "ally", boss_name))
                slot_events.extend(["enemy"] * self._get_record_book_entry_slot_count(entry, "main", "enemy", boss_name))
                if use_invasion:
                    slot_events.extend(["ally"] * self._get_record_book_entry_slot_count(entry, "invasion", "ally", boss_name))
                    slot_events.extend(["enemy"] * self._get_record_book_entry_slot_count(entry, "invasion", "enemy", boss_name))
                ally_count = sum(1 for side in slot_events if side == "ally")
                enemy_count = sum(1 for side in slot_events if side == "enemy")
                ally_total += ally_count
                enemy_total += enemy_count
                for side in slot_events:
                    events.append((ordinal, side))
                    overall_events.append((ordinal, side))
                    if ordinal >= now_ordinal - recent_days:
                        overall_recent_day_events.append((ordinal, side))
            total_count = ally_total + enemy_total
            if total_count <= 0:
                continue
            events.sort(key=lambda item_value: item_value[0], reverse=True)
            recent_count_events = events[:recent_count]
            recent_day_events = [event for event in events if event[0] >= now_ordinal - recent_days]
            recent_count_ally = sum(1 for _, side in recent_count_events if side == "ally")
            recent_day_ally = sum(1 for _, side in recent_day_events if side == "ally")
            average_cut_seconds = self._get_record_book_average_cut_seconds(boss_name)
            rows.append(
                {
                    "group": f"        {self._format_record_stats_group_label(item)}",
                    "boss": boss_name,
                    "avg_cut": format_seconds(average_cut_seconds, show_centiseconds=True) if average_cut_seconds is not None else "",
                    "ally": ally_total,
                    "enemy": enemy_total,
                    "total": total_count,
                    "ally_rate": ally_total / total_count if total_count else 0.0,
                    "recent_count_rate": recent_count_ally / len(recent_count_events) if recent_count_events else None,
                    "recent_days_rate": recent_day_ally / len(recent_day_events) if recent_day_events else None,
                }
            )
        overall_events.sort(key=lambda item_value: item_value[0], reverse=True)
        overall_ally = sum(1 for _, side in overall_events if side == "ally")
        overall_enemy = sum(1 for _, side in overall_events if side == "enemy")
        overall_recent_count_events = overall_events[:recent_count]
        overall_recent_days_ally = sum(1 for _, side in overall_recent_day_events if side == "ally")
        summary = {
            "overall_ally": overall_ally,
            "overall_enemy": overall_enemy,
            "overall_total": overall_ally + overall_enemy,
            "overall_rate": overall_ally / (overall_ally + overall_enemy) if (overall_ally + overall_enemy) else 0.0,
            "recent_count_rate": (sum(1 for _, side in overall_recent_count_events if side == "ally") / len(overall_recent_count_events)) if overall_recent_count_events else None,
            "recent_days_rate": (overall_recent_days_ally / len(overall_recent_day_events)) if overall_recent_day_events else None,
            "recent_count": recent_count,
            "recent_days": recent_days,
        }
        return rows, summary

    def _format_record_stats_group_label(self, item: dict) -> str:
        source_area = str(item.get("source_area", "") or "").strip()
        display_area = str(item.get("display_area", "") or "").strip()
        chapter_label = str(item.get("chapter_label", "") or "").strip()
        is_absolute = bool(item.get("absolute"))
        if is_absolute:
            if source_area and source_area != "절대자":
                source_chapter = RECORD_BOOK_CHAPTER_LABELS.get(source_area, chapter_label or source_area)
                return f"{source_chapter} (절대자)"
            return "절대자"
        if chapter_label and display_area and chapter_label == display_area:
            return chapter_label
        if chapter_label and display_area:
            return f"{chapter_label} ({display_area})"
        return chapter_label or display_area or "-"

    def refresh_record_stats_view(self) -> None:
        if self.record_stats_window is None or not self.record_stats_window.winfo_exists():
            return
        self.record_stats_dirty = False
        rows, summary = self._build_record_stats()
        if hasattr(self, "record_stats_tree") and self.record_stats_tree is not None:
            self.record_stats_tree.heading("recent_count", text=f"최근 {summary['recent_count']}개 확률")
            self.record_stats_tree.heading("recent_days", text=f"최근 {summary['recent_days']}일 확률")
        tree = self.record_stats_tree
        for item_id in tree.get_children():
            tree.delete(item_id)
        if not rows:
            self.record_stats_overall_ally_label.config(text="전체 아군 0")
            self.record_stats_overall_enemy_label.config(text="전체 적군 0")
            self.record_stats_summary_label.config(text="표시할 통계가 없습니다. 기록지에서 데이터를 먼저 저장하세요.")
            return
        rows.sort(key=lambda row: (-row["ally"], row["boss"]))
        for row in rows:
            tree.insert(
                "",
                "end",
                values=(
                    row["group"],
                    row["boss"],
                    row["avg_cut"] or "-",
                    row["ally"],
                    row["enemy"],
                    row["total"],
                    f"{row['ally_rate'] * 100:.1f}%",
                    f"{row['recent_count_rate'] * 100:.1f}%" if row["recent_count_rate"] is not None else "-",
                    f"{row['recent_days_rate'] * 100:.1f}%" if row["recent_days_rate"] is not None else "-",
                ),
            )
        recent_count_text = f"{summary['recent_count_rate'] * 100:.1f}%" if summary["recent_count_rate"] is not None else "-"
        recent_days_text = f"{summary['recent_days_rate'] * 100:.1f}%" if summary["recent_days_rate"] is not None else "-"
        self.record_stats_overall_ally_label.config(text=f"전체 아군 {summary['overall_ally']}")
        self.record_stats_overall_enemy_label.config(text=f"전체 적군 {summary['overall_enemy']}")
        self.record_stats_summary_label.config(
            text=(
                f"전체 아군 확률 {summary['overall_rate'] * 100:.1f}% | "
                f"최근 {summary['recent_count']}개 아군 확률 {recent_count_text} | "
                f"최근 {summary['recent_days']}일 아군 확률 {recent_days_text}"
            )
        )

    def open_log_stats_window(self) -> None:
        if self.log_stats_window_busy:
            return
        self.log_stats_window_busy = True
        try:
            self._ensure_log_stats_window()
            if self.log_stats_window_open and self.log_stats_window is not None and self.log_stats_window.winfo_exists():
                self.log_stats_window.deiconify()
                self.log_stats_window.lift()
                return
            self._reset_log_stats_pending_state()
            self.log_stats_window_open = True
            self._position_log_stats_window()
            self.log_stats_window.deiconify()
            self.log_stats_window.lift()
            self.refresh_log_stats_view()
        except tk.TclError:
            return
        finally:
            self.log_stats_window_busy = False

    def close_log_stats_window(self) -> None:
        if self.log_stats_settings_dirty and self.log_stats_window is not None and self.log_stats_window.winfo_exists():
            answer = self._show_log_stats_save_dialog("변경된 통계 설정을 저장할까요?")
            if answer is None:
                return
            if answer:
                self._save_log_stats_settings(reload_view=False)
            else:
                self._reset_log_stats_pending_state()
        try:
            if self.log_stats_window is not None and self.log_stats_window.winfo_exists():
                self.log_stats_window.withdraw()
            self.log_stats_window_open = False
        except tk.TclError:
            self.log_stats_window_open = False

    def _get_log_stats_section_bosses(self, section_name: str) -> list[str]:
        if not section_name:
            return []
        if section_name == "기타":
            return [name for name in self.log_stats_cached_boss_data if name not in self.record_book_catalog_map]
        return [item["boss_name"] for item in self.record_book_catalog if item["display_area"] == section_name]

    def _get_log_stats_settings_changed(self) -> bool:
        current_exclude = bool(self.log_stats_exclude_extremes_var.get()) if self.log_stats_exclude_extremes_var is not None else self.log_stats_exclude_extremes_default
        current_include_unconfirmed = bool(self.log_stats_include_unconfirmed_var.get()) if self.log_stats_include_unconfirmed_var is not None else self.log_stats_include_unconfirmed_default
        if current_exclude != bool(self.log_stats_exclude_extremes_default):
            return True
        if current_include_unconfirmed != bool(self.log_stats_include_unconfirmed_default):
            return True
        all_boss_names = (
            set(self.log_stats_boss_enabled.keys())
            | set(self.log_stats_enabled_saved_map.keys())
            | set(self.record_book_catalog_map.keys())
            | set(self.log_stats_cached_boss_data.keys())
        )
        for boss_name in all_boss_names:
            current_value = bool(self.log_stats_boss_enabled.get(boss_name, True))
            saved_value = bool(self.log_stats_enabled_saved_map.get(boss_name, True))
            if current_value != saved_value:
                return True
        return False

    def _update_log_stats_save_button_state(self) -> None:
        if self.log_stats_save_button is None:
            return
        if self.log_stats_settings_dirty:
            self.log_stats_save_button.config(
                state="normal",
                bg="#2563eb",
                fg="#ffffff",
                activebackground="#1d4ed8",
                activeforeground="#ffffff",
                cursor="hand2",
            )
        else:
            self.log_stats_save_button.config(
                state="disabled",
                bg="#bfdbfe",
                fg="#eff6ff",
                activebackground="#bfdbfe",
                activeforeground="#eff6ff",
                cursor="arrow",
            )

    def _mark_log_stats_settings_dirty(self) -> None:
        self.log_stats_settings_dirty = self._get_log_stats_settings_changed()
        self._update_log_stats_save_button_state()

    def _sync_log_stats_checkbox_vars(self) -> None:
        for boss_name, state_var in self.log_stats_boss_vars.items():
            state_var.set(bool(self.log_stats_boss_enabled.get(boss_name, True)))
        for section_name, state_var in self.log_stats_section_vars.items():
            section_bosses = self._get_log_stats_section_bosses(section_name)
            state_var.set(any(self.log_stats_boss_enabled.get(boss_name, False) for boss_name in section_bosses))

    def _reset_log_stats_pending_state(self) -> None:
        if self.log_stats_exclude_extremes_var is not None:
            self.log_stats_exclude_extremes_var.set(bool(self.log_stats_exclude_extremes_default))
        if self.log_stats_include_unconfirmed_var is not None:
            self.log_stats_include_unconfirmed_var.set(bool(self.log_stats_include_unconfirmed_default))
        self.log_stats_boss_enabled = {str(key): bool(value) for key, value in self.log_stats_enabled_saved_map.items()}
        for boss_name in self.record_book_catalog_map:
            self.log_stats_boss_enabled.setdefault(boss_name, True)
        for boss_name in self.log_stats_cached_boss_data:
            self.log_stats_boss_enabled.setdefault(boss_name, True)
        self.log_stats_settings_dirty = False
        self._sync_log_stats_checkbox_vars()
        self._update_log_stats_save_button_state()

    def _save_log_stats_settings(self, reload_view: bool = True) -> None:
        self.log_stats_exclude_extremes_default = bool(self.log_stats_exclude_extremes_var.get()) if self.log_stats_exclude_extremes_var is not None else False
        self.log_stats_include_unconfirmed_default = bool(self.log_stats_include_unconfirmed_var.get()) if self.log_stats_include_unconfirmed_var is not None else False
        self.log_stats_enabled_saved_map = {str(key): bool(value) for key, value in self.log_stats_boss_enabled.items()}
        self._save_settings()
        self.log_stats_settings_dirty = False
        self._update_log_stats_save_button_state()
        if reload_view:
            self.refresh_log_stats_view()

    def _position_log_stats_window(self) -> None:
        if self.log_stats_window is None or not self.log_stats_window.winfo_exists() or not self.log_stats_window_open:
            return
        if self.schedule_window is not None and self.schedule_window.winfo_exists() and self.schedule_window_open:
            x = self.schedule_window.winfo_x() + 24
            y = self.schedule_window.winfo_y() + 42
        elif self.log_panel is not None and self.log_panel.winfo_exists() and self.log_panel_open:
            x = self.log_panel.winfo_x() + 24
            y = self.log_panel.winfo_y() + 42
        else:
            x = self.root.winfo_x() + 64
            y = self.root.winfo_y() + 56
        self.log_stats_window.geometry(f"{LOG_STATS_WINDOW_WIDTH}x{LOG_STATS_WINDOW_HEIGHT}+{x}+{y}")

