    def _on_log_stats_rows_configure(self, _event=None) -> None:
        if not self._widget_available(self.log_stats_canvas):
            return
        try:
            self.log_stats_canvas.configure(scrollregion=self.log_stats_canvas.bbox("all"))
        except tk.TclError:
            return

    def _on_log_stats_canvas_configure(self, event) -> None:
        if self.log_stats_canvas_window is None or not self._widget_available(self.log_stats_canvas):
            return
        try:
            self.log_stats_canvas.itemconfigure(self.log_stats_canvas_window, width=max(1, event.width - 2))
        except tk.TclError:
            return

    def _on_log_stats_mousewheel(self, event) -> str | None:
        if not self._widget_available(self.log_stats_canvas):
            return None
        try:
            self.log_stats_canvas.yview_scroll(int(-1 * (event.delta / 120)), "units")
        except tk.TclError:
            return None
        return "break"

    def _bind_log_stats_scroll_recursive(self, widget: tk.Widget) -> None:
        try:
            widget.bind("<MouseWheel>", self._on_log_stats_mousewheel)
        except tk.TclError:
            return
        for child in widget.winfo_children():
            self._bind_log_stats_scroll_recursive(child)

    def _update_log_stats_search_button_state(self) -> None:
        if self.log_stats_search_button is None:
            return
        has_query = bool(self._get_log_stats_search_query())
        if has_query:
            self.log_stats_search_button.config(state="normal", bg="#f8f1df", fg="#7c2d12", cursor="hand2")
        else:
            self.log_stats_search_button.config(state="disabled", bg="#e2e8f0", fg="#94a3b8", cursor="arrow")

    def _on_log_stats_exclude_toggle(self) -> None:
        self._mark_log_stats_settings_dirty()

    def _get_log_stats_column_widths(self) -> dict[str, int]:
        return {
            "enabled": 66,
            "updated": 134,
            "boss": 176,
            "count": 132,
            "avg_cut": 108,
            "avg_expected": 108,
            "avg_overrun": 124,
            "avg_gwang": 108,
            "analysis": 104,
        }

    def _get_log_stats_file_signature(self, log_path: str) -> str:
        try:
            stat = os.stat(log_path)
        except OSError:
            return ""
        return f"{stat.st_mtime_ns}:{stat.st_size}"

    def _parse_log_stats_recorded_at(self, raw_value: str) -> datetime | None:
        value = (raw_value or "").strip()
        if not value:
            return None
        for fmt in ("%Y-%m-%d %H:%M:%S", "%Y-%m-%d"):
            try:
                return datetime.strptime(value, fmt)
            except ValueError:
                continue
        return None

    def _normalize_log_stats_boss_names(self, raw_name: str) -> tuple[str, str]:
        canonical_name = self._get_canonical_boss_name(raw_name)
        if not canonical_name:
            return "", ""
        return canonical_name, self._get_display_boss_name(canonical_name)

    def _get_cached_log_file_records(self, log_path: str) -> list[dict]:
        signature = self._get_log_stats_file_signature(log_path)
        cached = self.log_stats_file_cache.get(log_path)
        if isinstance(cached, dict) and cached.get("signature") == signature:
            return list(cached.get("records", []))
        records = self._read_log_records_from_path(log_path)
        parsed_records: list[dict] = []
        file_boss_name = self._get_fallback_boss_name_from_log_path(log_path)
        for parsed in records:
            raw_boss_name = parsed.get("boss_name") or file_boss_name
            catalog_name, display_name = self._normalize_log_stats_boss_names(raw_boss_name)
            enriched = dict(parsed)
            enriched["log_stats_catalog_name"] = catalog_name or raw_boss_name
            enriched["log_stats_display_name"] = display_name or raw_boss_name
            enriched["log_stats_updated_at"] = self._parse_log_stats_recorded_at(parsed.get("recorded_at", ""))
            enriched["gwang_seconds"] = self._parse_log_time_value(parsed.get("gwang_time", "")) if parsed.get("gwang_time") not in ("", "미확정") else None
            parsed_records.append(enriched)
        self.log_stats_file_cache[log_path] = {
            "signature": signature,
            "records": list(parsed_records),
        }
        return parsed_records

    def _collect_log_stats_boss_data_from_folder(self, folder_path: str) -> dict[str, dict[str, object]]:
        file_paths = self._list_log_file_paths(folder_path)
        boss_data: dict[str, dict[str, object]] = {}
        for log_path in file_paths:
            records = self._get_cached_log_file_records(log_path)
            file_boss_name = self._get_boss_name_from_log_path(log_path)
            for record in records:
                catalog_name = str(record.get("log_stats_catalog_name") or file_boss_name)
                display_name = str(record.get("log_stats_display_name") or catalog_name)
                bucket = boss_data.setdefault(
                    catalog_name,
                    {
                        "catalog_name": catalog_name,
                        "display_name": display_name,
                        "records": [],
                        "latest_updated_at": None,
                        "source_path": "",
                    },
                )
                bucket["display_name"] = display_name
                bucket["records"].append(record)
                updated_at = record.get("log_stats_updated_at")
                if isinstance(updated_at, datetime):
                    latest = bucket.get("latest_updated_at")
                    if not isinstance(latest, datetime) or updated_at > latest:
                        bucket["latest_updated_at"] = updated_at
                        bucket["source_path"] = log_path
                elif not bucket.get("source_path"):
                    bucket["source_path"] = log_path
        for item in self.record_book_catalog:
            boss_name = str(item["boss_name"])
            boss_data.setdefault(
                boss_name,
                {
                    "catalog_name": boss_name,
                    "display_name": self._get_record_book_display_name(boss_name) or boss_name,
                    "records": [],
                    "latest_updated_at": None,
                    "source_path": "",
                },
            )
        for boss_name, bucket in boss_data.items():
            if boss_name not in self.log_stats_boss_enabled:
                self.log_stats_boss_enabled[boss_name] = self.log_stats_enabled_saved_map.get(boss_name, True)
        return boss_data

    def _collect_log_stats_boss_data(self) -> dict[str, dict[str, object]]:
        folder_path = self._get_log_stats_scope_folder_path()
        boss_data = self._collect_log_stats_boss_data_from_folder(folder_path)
        self.log_stats_cached_boss_data = boss_data
        return boss_data

    def _extract_log_stats_latest_updated_at(self, records: list[dict]) -> datetime | None:
        latest_updated_at: datetime | None = None
        for record in records:
            for key in ("updated_at", "recorded_at", "created_at"):
                try:
                    candidate = datetime.strptime(str(record.get(key) or ""), "%Y-%m-%d %H:%M:%S")
                except ValueError:
                    continue
                if latest_updated_at is None or candidate > latest_updated_at:
                    latest_updated_at = candidate
                break
        return latest_updated_at

    def _build_log_stats_boss_bucket_for_folder(self, folder_path: str, boss_name: str) -> dict[str, object]:
        canonical_name = self._get_canonical_boss_name(boss_name) or boss_name
        records = self._read_log_records_for_boss_from_folder(folder_path, canonical_name)
        metadata = self.record_book_catalog_map.get(canonical_name, {})
        return {
            "catalog_name": canonical_name,
            "display_name": self._get_record_book_display_name(str(metadata.get("boss_name") or canonical_name)) or canonical_name,
            "records": records,
            "latest_updated_at": self._extract_log_stats_latest_updated_at(records),
            "source_path": self._find_latest_log_path_for_boss_in_folder(folder_path, canonical_name) or "",
        }

    def _format_log_stats_section_label(self, section_name: str) -> str:
        if section_name in ("절대자", "기타"):
            return section_name
        chapter_label = RECORD_BOOK_CHAPTER_LABELS.get(section_name, section_name)
        if chapter_label == section_name:
            return chapter_label
        return f"{chapter_label} ({section_name})"

    def _build_log_stats_row_summary(
        self,
        boss_name: str,
        boss_data: dict[str, object],
        *,
        analysis_scope_value: str = "",
        analysis_scope_folder_path: str = "",
    ) -> dict[str, object]:
        raw_records = list(boss_data.get("records", []))
        dataset = self._build_log_analysis_dataset(raw_records, fallback_boss_name=boss_name)
        normalized_records = list(dataset["normalized_records"])
        skipped = dict(dataset["skipped"])
        included_records = list(dataset["included_records"])
        metadata = self.record_book_catalog_map.get(boss_name, {})
        section_name = str(metadata.get("display_area") or "기타")
        if boss_name not in self.record_book_catalog_map:
            section_name = "기타"
        latest_updated_at = boss_data.get("latest_updated_at")
        return {
            "boss_name": boss_name,
            "display_name": str(boss_data.get("display_name") or boss_name),
            "section": section_name,
            "source_path": str(boss_data.get("source_path") or ""),
            "latest_updated_text": latest_updated_at.strftime("%m-%d %H:%M") if isinstance(latest_updated_at, datetime) else "--",
            "raw_count": int(dataset["raw_count"]),
            "valid_count": int(dataset["included_count"]),
            "invalid_count": int(dataset["invalid_count"]),
            "count_text": str(dataset["count_text"]),
            "avg_cut": format_seconds(dataset["avg_cut_seconds"], show_centiseconds=True) if dataset["avg_cut_seconds"] is not None else "-",
            "avg_expected": format_seconds(dataset["avg_expected_seconds"], show_centiseconds=True) if dataset["avg_expected_seconds"] is not None else "-",
            "avg_overrun": format_seconds(dataset["avg_overrun_seconds"], show_centiseconds=True) if dataset["avg_overrun_seconds"] is not None else "-",
            "avg_gwang": format_seconds(dataset["avg_gwang_seconds"], show_centiseconds=True) if dataset["avg_gwang_seconds"] is not None else "-",
            "has_records": bool(dataset["included_count"]),
            "skipped_count": int(dataset["invalid_count"]),
            "analysis_scope_value": str(analysis_scope_value or "").strip(),
            "analysis_scope_folder_path": str(analysis_scope_folder_path or "").strip(),
        }

    def _get_log_stats_compare_seasons(self) -> list[tuple[str, str]]:
        seasons: list[tuple[str, str]] = []
        seen: set[str] = set()
        if self._has_active_season():
            current_label = self._get_archive_season_label(self.current_season_no)
            seasons.append((str(self.current_season_no), current_label))
            seen.add(current_label)
        for entry in self._get_archive_management_all_entries():
            season_label = str(entry.get("season_label") or "").strip()
            season_no_text = str(entry.get("season_no_text") or "").strip()
            if not season_label or not season_no_text or season_label in seen:
                continue
            seasons.append((season_no_text, season_label))
            seen.add(season_label)
        return seasons

    def _match_log_stats_search_boss_name(self, query: str) -> str:
        lowered_query = query.lower()
        for item in self.record_book_catalog:
            boss_name = str(item["boss_name"])
            display_name = self._get_record_book_display_name(boss_name) or boss_name
            if lowered_query in boss_name.lower() or lowered_query in display_name.lower():
                return boss_name
        return ""

    def _match_log_stats_search_section_name(self, query: str) -> str:
        lowered_query = query.lower()
        for section_name in self.record_book_sections:
            if section_name == "기타":
                continue
            chapter_label = str(RECORD_BOOK_CHAPTER_LABELS.get(section_name, section_name))
            if lowered_query in section_name.lower() or lowered_query in chapter_label.lower():
                return section_name
        return ""

    def _build_log_stats_compare_rows(self, query: str) -> list[dict[str, object]]:
        boss_name = self._match_log_stats_search_boss_name(query)
        section_name = "" if boss_name else self._match_log_stats_search_section_name(query)
        if not boss_name and not section_name:
            return []
        compare_rows: list[dict[str, object]] = []
        season_targets = self._get_log_stats_compare_seasons()
        if boss_name:
            metadata = self.record_book_catalog_map.get(boss_name, {})
            section_name = str(metadata.get("display_area") or "기타")
            display_name = self._get_record_book_display_name(str(metadata.get("boss_name") or boss_name)) or boss_name
            for season_no_text, season_label in season_targets:
                folder_path = self._get_archive_season_dir(season_no_text)
                boss_bucket = self._build_log_stats_boss_bucket_for_folder(folder_path, boss_name)
                summary = self._build_log_stats_row_summary(
                    boss_name,
                    boss_bucket,
                    analysis_scope_value=season_label,
                    analysis_scope_folder_path=folder_path,
                )
                compare_rows.append(
                    {
                        "kind": "chapter",
                        "section": section_name,
                        "enabled": True,
                        "group": f"{season_label}  |  {display_name}",
                    }
                )
                compare_rows.append({"kind": "boss", "enabled": True, **summary})
            return compare_rows
        section_bosses = [item["boss_name"] for item in self.record_book_catalog if item["display_area"] == section_name]
        for season_no_text, season_label in season_targets:
            compare_rows.append(
                {
                    "kind": "chapter",
                    "section": section_name,
                    "enabled": True,
                    "group": f"{season_label}  |  {self._format_log_stats_section_label(section_name)}",
                }
            )
            folder_path = self._get_archive_season_dir(season_no_text)
            for section_boss_name in section_bosses:
                boss_bucket = self._build_log_stats_boss_bucket_for_folder(folder_path, section_boss_name)
                summary = self._build_log_stats_row_summary(
                    section_boss_name,
                    boss_bucket,
                    analysis_scope_value=season_label,
                    analysis_scope_folder_path=folder_path,
                )
                compare_rows.append({"kind": "boss", "enabled": True, **summary})
        return compare_rows

    def _build_log_stats_display_rows(self) -> list[dict[str, object]]:
        query = self._get_log_stats_search_query()
        if query:
            compare_rows = self._build_log_stats_compare_rows(query)
            if compare_rows:
                return compare_rows
        boss_data = self.log_stats_cached_boss_data or self._collect_log_stats_boss_data()
        scope_value = self._get_log_stats_scope_value()
        scope_folder_path = self._get_log_stats_scope_folder_path()
        summaries = {
            boss_name: self._build_log_stats_row_summary(
                boss_name,
                data,
                analysis_scope_value=scope_value,
                analysis_scope_folder_path=scope_folder_path,
            )
            for boss_name, data in boss_data.items()
        }
        rows: list[dict[str, object]] = []
        section_payloads: list[tuple[str, bool, list[str]]] = []
        for section_name in self.record_book_sections:
            if section_name == "기타":
                section_bosses = [name for name in summaries if name not in self.record_book_catalog_map]
                section_bosses.sort(key=lambda boss_name: summaries[boss_name]["display_name"])
                if not section_bosses:
                    continue
            else:
                section_bosses = [item["boss_name"] for item in self.record_book_catalog if item["display_area"] == section_name]
            if not section_bosses:
                continue
            section_any_enabled = any(self.log_stats_boss_enabled.get(boss_name, False) for boss_name in section_bosses)
            section_payloads.append((section_name, section_any_enabled, section_bosses))
        ordered_sections = [payload for payload in section_payloads if payload[1]] + [payload for payload in section_payloads if not payload[1]]
        for section_name, section_any_enabled, section_bosses in ordered_sections:
            rows.append({"kind": "chapter", "section": section_name, "enabled": section_any_enabled, "group": self._format_log_stats_section_label(section_name)})
            enabled_bosses = [boss_name for boss_name in section_bosses if self.log_stats_boss_enabled.get(boss_name, False)]
            disabled_bosses = [boss_name for boss_name in section_bosses if not self.log_stats_boss_enabled.get(boss_name, False)]
            for boss_name in enabled_bosses + disabled_bosses:
                summary = summaries.get(boss_name, {})
                rows.append({"kind": "boss", "enabled": self.log_stats_boss_enabled.get(boss_name, False), **summary})
        return rows

    def refresh_log_stats_view(self, force_reload: bool = False) -> None:
        if self.log_stats_window is None or not self.log_stats_window.winfo_exists():
            return
        self._update_log_stats_scope_options()
        self._update_log_stats_header_info()
        if force_reload:
            self._invalidate_log_stats_cache()
        if self.log_stats_dirty or not self.log_stats_cached_boss_data:
            self._collect_log_stats_boss_data()
        self.log_stats_dirty = False
        self._render_log_stats_tree()

    def _render_log_stats_tree(self) -> None:
        if self.log_stats_rows_frame is None or self.log_stats_canvas is None:
            return
        widths = self._get_log_stats_column_widths()
        self.log_stats_tree_item_meta.clear()
        self.log_stats_row_widgets.clear()
        self.log_stats_section_vars.clear()
        self.log_stats_boss_vars.clear()
        for child in self.log_stats_rows_frame.winfo_children():
            child.destroy()
        query = self._get_log_stats_search_query()
        query_mode = bool(query)
        display_rows = self._build_log_stats_display_rows()
        scope_value = self._get_log_stats_scope_value()
        recorded_boss_count = sum(1 for row in display_rows if row["kind"] == "boss" and row.get("valid_count", 0) > 0)
        skipped_count = sum(int(row.get("skipped_count", 0)) for row in display_rows if row.get("kind") == "boss")
        if query:
            status_text = f"검색 비교: {query} | 기록 있는 보스 {recorded_boss_count}개"
        else:
            status_text = f"{scope_value} 기준 | 기록 있는 보스 {recorded_boss_count}개"
        if self.log_stats_include_unconfirmed_var is not None and self.log_stats_include_unconfirmed_var.get():
            status_text += " | 검증 완료 + 광 시간 미확정"
        else:
            status_text += " | 검증 완료만"
        if skipped_count > 0:
            status_text += f" | 제외 {skipped_count}건"
        self.log_stats_status_var.set(status_text)
        if not display_rows:
            tk.Label(
                self.log_stats_rows_frame,
                text="검색 결과가 없습니다." if query else "표시할 통계가 없습니다.",
                font=(self.current_font_family, 10, "bold"),
                bg="#f8fafc",
                fg="#475569",
                anchor="w",
                justify="left",
            ).place(x=12, y=10, width=sum(widths.values()) - 24, height=22)
            self.log_stats_rows_frame.configure(height=42, width=sum(widths.values()))
            self._on_log_stats_rows_configure()
            return
        section_colors = {
            "요툰하임": ("#eff6ff", "#1d4ed8"),
            "니다벨리르": ("#f0fdf4", "#15803d"),
            "알브하임": ("#fff7ed", "#c2410c"),
            "무스펠하임": ("#fef2f2", "#b91c1c"),
            "아스가르드": ("#f5f3ff", "#6d28d9"),
            "니플하임": ("#ecfeff", "#0f766e"),
            "바나하임": ("#eef2ff", "#4338ca"),
            "던전": ("#f8fafc", "#334155"),
            "절대자": ("#fefce8", "#854d0e"),
            "기타": ("#faf5ff", "#7e22ce"),
        }
        section_header_colors = {
            "요툰하임": ("#bfdbfe", "#1d4ed8"),
            "니다벨리르": ("#bbf7d0", "#15803d"),
            "알브하임": ("#fed7aa", "#c2410c"),
            "무스펠하임": ("#fecaca", "#b91c1c"),
            "아스가르드": ("#ddd6fe", "#6d28d9"),
            "니플하임": ("#a5f3fc", "#0f766e"),
            "바나하임": ("#c7d2fe", "#4338ca"),
            "던전": ("#cbd5e1", "#334155"),
            "절대자": ("#fde68a", "#854d0e"),
            "기타": ("#e9d5ff", "#7e22ce"),
        }
        row_y = 0
        for row in display_rows:
            if row["kind"] == "chapter":
                bg_color, fg_color = section_header_colors.get(str(row.get("section", "")), ("#dbeafe", "#0f172a"))
                chapter_frame = tk.Frame(self.log_stats_rows_frame, bg=bg_color, highlightthickness=1, highlightbackground=fg_color)
                chapter_frame.place(x=0, y=row_y, width=sum(widths.values()), height=30)
                chapter_enabled_var = tk.BooleanVar(value=bool(row["enabled"]))
                toggle_button = tk.Checkbutton(
                    chapter_frame,
                    variable=chapter_enabled_var,
                    onvalue=True,
                    offvalue=False,
                    font=(self.current_font_family, 11, "bold"),
                    bg=bg_color,
                    fg=fg_color,
                    activebackground=bg_color,
                    activeforeground=fg_color,
                    selectcolor="#ffffff",
                    relief="flat",
                    bd=0,
                    highlightthickness=0,
                    cursor="arrow" if query_mode else "hand2",
                    command=lambda section_name=row["section"]: self._toggle_log_stats_section(str(section_name)),
                    state="disabled" if query_mode else "normal",
                )
                toggle_button._state_var = chapter_enabled_var
                toggle_button.place(x=0, y=0, width=widths["enabled"], height=30)
                if not query_mode:
                    self.log_stats_section_vars[str(row["section"])] = chapter_enabled_var
                tk.Label(
                    chapter_frame,
                    text=str(row.get("group", "")),
                    font=(self.current_font_family, 10, "bold"),
                    bg=bg_color,
                    fg=fg_color,
                    anchor="w",
                    padx=10,
                ).place(x=widths["enabled"], y=0, width=sum(widths.values()) - widths["enabled"], height=30)
                self.log_stats_row_widgets.append({"kind": "chapter", "section": row["section"], "frame": chapter_frame})
                row_y += 30
                continue
            has_records = bool(row.get("has_records"))
            enabled = bool(row.get("enabled"))
            section_name = str(row.get("section", ""))
            section_bg, section_fg = section_colors.get(section_name, ("#ffffff", "#0f172a"))
            row_bg = section_bg if enabled else "#f8fafc"
            row_fg = section_fg if enabled else "#94a3b8"
            row_frame = tk.Frame(self.log_stats_rows_frame, bg=row_bg)
            row_frame.place(x=0, y=row_y, width=sum(widths.values()), height=30)
            enabled_cell = tk.Frame(row_frame, bg=row_bg, highlightthickness=1, highlightbackground="#e2e8f0")
            enabled_cell.place(x=0, y=0, width=widths["enabled"], height=30)
            boss_enabled_var = tk.BooleanVar(value=enabled)
            enabled_button = tk.Checkbutton(
                enabled_cell,
                variable=boss_enabled_var,
                onvalue=True,
                offvalue=False,
                font=(self.current_font_family, 11, "bold"),
                bg=row_bg,
                fg="#0f172a" if enabled else "#94a3b8",
                activebackground=row_bg,
                activeforeground="#0f172a" if enabled else "#94a3b8",
                selectcolor="#ffffff",
                relief="flat",
                bd=0,
                highlightthickness=0,
                cursor="arrow" if query_mode else "hand2",
                command=lambda boss_name=row.get("boss_name", ""): self._toggle_log_stats_boss(str(boss_name)),
                state="disabled" if query_mode else "normal",
            )
            enabled_button._state_var = boss_enabled_var
            enabled_button.place(x=0, y=0, width=widths["enabled"], height=30)
            if not query_mode:
                self.log_stats_boss_vars[str(row.get("boss_name", ""))] = boss_enabled_var
            cursor_x = widths["enabled"]
            for column_name, text_value, fg_color in (
                ("updated", row.get("latest_updated_text", "--"), section_fg if enabled else "#94a3b8"),
                ("boss", row.get("display_name", row.get("boss_name", "")), row_fg),
            ):
                cell = tk.Frame(row_frame, bg=row_bg, highlightthickness=1, highlightbackground="#e2e8f0")
                cell.place(x=cursor_x, y=0, width=widths[column_name], height=30)
                tk.Label(
                    cell,
                    text=str(text_value),
                    font=(self.current_font_family, 10, "bold"),
                    bg=row_bg,
                    fg=fg_color if enabled or column_name in {"avg_cut", "avg_expected", "avg_overrun", "avg_gwang"} else "#94a3b8",
                    anchor="w" if column_name == "boss" else "center",
                    padx=10 if column_name == "boss" else 0,
                ).place(x=0, y=0, width=widths[column_name], height=30)
                cursor_x += widths[column_name]
            count_cell = tk.Frame(row_frame, bg=row_bg, highlightthickness=1, highlightbackground="#e2e8f0")
            count_cell.place(x=cursor_x, y=0, width=widths["count"], height=30)
            valid_count = int(row.get("valid_count", 0))
            invalid_count = int(row.get("invalid_count", 0))
            tk.Label(
                count_cell,
                text=str(valid_count),
                font=(self.current_font_family, 10, "bold"),
                bg=row_bg,
                fg="#15803d" if valid_count > 0 else "#94a3b8",
                anchor="e",
            ).place(x=8, y=0, width=48, height=30)
            tk.Label(
                count_cell,
                text="/",
                font=(self.current_font_family, 10, "bold"),
                bg=row_bg,
                fg="#64748b",
                anchor="center",
            ).place(x=58, y=0, width=12, height=30)
            tk.Label(
                count_cell,
                text=str(invalid_count),
                font=(self.current_font_family, 10, "bold"),
                bg=row_bg,
                fg="#dc2626" if invalid_count > 0 else "#94a3b8",
                anchor="w",
            ).place(x=74, y=0, width=50, height=30)
            cursor_x += widths["count"]
            for column_name, text_value, fg_color in (
                ("avg_cut", row.get("avg_cut", "-"), "#dc2626"),
                ("avg_gwang", row.get("avg_gwang", "-"), "#2563eb"),
                ("avg_overrun", row.get("avg_overrun", "-"), "#b45309"),
                ("avg_expected", row.get("avg_expected", "-"), "#15803d"),
            ):
                cell = tk.Frame(row_frame, bg=row_bg, highlightthickness=1, highlightbackground="#e2e8f0")
                cell.place(x=cursor_x, y=0, width=widths[column_name], height=30)
                tk.Label(
                    cell,
                    text=str(text_value),
                    font=(self.current_font_family, 10, "bold"),
                    bg=row_bg,
                    fg=fg_color if enabled else fg_color,
                    anchor="center",
                ).place(x=0, y=0, width=widths[column_name], height=30)
                cursor_x += widths[column_name]
            analysis_cell = tk.Frame(row_frame, bg=row_bg, highlightthickness=1, highlightbackground="#e2e8f0")
            analysis_cell.place(x=cursor_x, y=0, width=widths["analysis"], height=30)
            analysis_button = tk.Button(
                analysis_cell,
                text="열기",
                font=(self.current_font_family, 9, "bold"),
                bg="#f8f1df" if has_records else "#e2e8f0",
                fg="#7c2d12" if has_records else "#94a3b8",
                activebackground="#efe2c5" if has_records else "#e2e8f0",
                activeforeground="#7c2d12" if has_records else "#94a3b8",
                relief="raised" if has_records else "flat",
                bd=1 if has_records else 0,
                cursor="hand2" if has_records else "arrow",
                state="normal" if has_records else "disabled",
                command=lambda boss_name=row.get("boss_name", ""), source_path=row.get("source_path", ""), scope_value=row.get("analysis_scope_value", ""), scope_folder_path=row.get("analysis_scope_folder_path", ""): self._open_log_stats_analysis_for_source(
                    str(boss_name),
                    str(source_path),
                    str(scope_value),
                    str(scope_folder_path),
                ),
            )
            analysis_button.place(x=10, y=4, width=widths["analysis"] - 20, height=22)
            if has_records:
                self._bind_hover_button(analysis_button, "#f8f1df", "#efe2c5", "#7c2d12", "#7c2d12")
            self.log_stats_row_widgets.append(
                {
                    "kind": "boss",
                    "boss_name": row.get("boss_name", ""),
                    "display_name": row.get("display_name", row.get("boss_name", "")),
                    "frame": row_frame,
                    "has_records": has_records,
                }
            )
            row_y += 30
        self.log_stats_rows_frame.configure(height=max(row_y, 1), width=sum(widths.values()))
        self.log_stats_rows_frame.update_idletasks()
        self._bind_log_stats_scroll_recursive(self.log_stats_rows_frame)
        self._on_log_stats_rows_configure()

    def _on_log_stats_tree_click(self, event) -> None:
        if self.log_stats_tree is None:
            return
        row_id = self.log_stats_tree.identify_row(event.y)
        column_id = self.log_stats_tree.identify_column(event.x)
        if not row_id or not column_id:
            return
        meta = self.log_stats_tree_item_meta.get(row_id, {})
        if column_id == "#1":
            if meta.get("kind") == "chapter":
                self._toggle_log_stats_section(str(meta.get("section", "")))
            elif meta.get("kind") == "boss":
                self._toggle_log_stats_boss(str(meta.get("boss_name", "")))
            return
        if column_id == "#9" and meta.get("kind") == "boss" and meta.get("has_records"):
            self._open_log_stats_analysis(str(meta.get("boss_name", "")))

    def _toggle_log_stats_section(self, section_name: str) -> None:
        if not section_name:
            return
        section_bosses = self._get_log_stats_section_bosses(section_name)
        if not section_bosses:
            return
        section_var = self.log_stats_section_vars.get(section_name)
        turn_on = bool(section_var.get()) if section_var is not None else not all(self.log_stats_boss_enabled.get(boss_name, False) for boss_name in section_bosses)
        for boss_name in section_bosses:
            self.log_stats_boss_enabled[boss_name] = turn_on
        self._sync_log_stats_checkbox_vars()
        self._mark_log_stats_settings_dirty()

    def _toggle_log_stats_boss(self, boss_name: str) -> None:
        if not boss_name:
            return
        boss_var = self.log_stats_boss_vars.get(boss_name)
        self.log_stats_boss_enabled[boss_name] = bool(boss_var.get()) if boss_var is not None else not self.log_stats_boss_enabled.get(boss_name, False)
        self._sync_log_stats_checkbox_vars()
        self._mark_log_stats_settings_dirty()

    def _open_analysis_with_context(
        self,
        boss_name: str,
        *,
        scope_value: str = "",
        scope_folder_path: str = "",
        selected_file_path: str = "",
    ) -> None:
        if not boss_name:
            return
        canonical_boss_name = self._get_canonical_boss_name(boss_name) or boss_name
        chosen_file_path = str(selected_file_path or "").strip()
        resolved_boss_name = canonical_boss_name
        if chosen_file_path and os.path.exists(chosen_file_path):
            resolved_boss_name = self._get_canonical_boss_name(self._get_boss_name_from_log_path(chosen_file_path) or canonical_boss_name) or canonical_boss_name
        self._set_analysis_scope_context(scope_value, scope_folder_path, selected_file_path=chosen_file_path)
        self.analysis_boss_name_var.set(resolved_boss_name)
        self.open_analysis_window()
        self.refresh_analysis_view()

    def _open_log_stats_analysis(self, boss_name: str) -> None:
        if not boss_name:
            return
        try:
            self._open_analysis_with_context(
                boss_name,
                scope_value=self._get_log_stats_scope_value(),
                scope_folder_path=self._get_log_stats_scope_folder_path(),
            )
        except Exception as exc:
            try:
                with open(os.path.join(get_app_root(), "boss_timer_runtime_error.log"), "a", encoding="utf-8") as error_file:
                    error_file.write(f"\n[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] log_stats_analysis_open\n")
                    error_file.write("".join(traceback.format_exception(type(exc), exc, exc.__traceback__)))
            except OSError:
                pass
            if self.log_stats_status_var is not None:
                self.log_stats_status_var.set("개별분석을 여는 중 오류가 발생했습니다.")

    def _open_log_stats_analysis_for_source(
        self,
        boss_name: str,
        source_path: str = "",
        scope_value: str = "",
        scope_folder_path: str = "",
    ) -> None:
        try:
            self._open_analysis_with_context(
                boss_name,
                scope_value=scope_value or self._get_log_stats_scope_value(),
                scope_folder_path=scope_folder_path or self._get_log_stats_scope_folder_path(),
                selected_file_path=source_path if source_path and os.path.exists(source_path) else "",
            )
        except Exception as exc:
            try:
                with open(os.path.join(get_app_root(), "boss_timer_runtime_error.log"), "a", encoding="utf-8") as error_file:
                    error_file.write(f"\n[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}] log_stats_analysis_open_source\n")
                    error_file.write("".join(traceback.format_exception(type(exc), exc, exc.__traceback__)))
            except OSError:
                pass
            if self.log_stats_status_var is not None:
                self.log_stats_status_var.set("개별분석을 여는 중 오류가 발생했습니다.")

    def _search_log_stats_boss(self) -> None:
        query = self._get_log_stats_search_query()
        if not query or self.log_stats_canvas is None or self.log_stats_rows_frame is None:
            return
        self.refresh_log_stats_view(force_reload=True)
        try:
            self.log_stats_canvas.yview_moveto(0.0)
        except tk.TclError:
            pass

    def toggle_log_panel(self) -> None:
        if self.log_panel_open:
            self.close_log_panel()
        else:
            self.open_log_panel()

    def open_log_panel(self) -> None:
        if self.log_panel_busy:
            return
        if not self._ensure_season_ready(self.root):
            return
        self.log_panel_busy = True
        try:
            self._ensure_log_panel()
            if self.log_panel_open and self.log_panel is not None and self.log_panel.winfo_exists():
                self.log_panel.deiconify()
                self.log_panel.lift()
                return
            self.log_panel_open = True
            self._position_log_panel()
            self.log_panel.deiconify()
            self.log_panel.lift()
            self.log_panel_toggle_button.config(text="닫기")
            self._refresh_log_panel()
        except tk.TclError:
            return
        finally:
            self.log_panel_busy = False

    def close_log_panel(self) -> None:
        try:
            if self.log_panel is not None and self.log_panel.winfo_exists():
                self.log_panel.withdraw()
            self.log_panel_open = False
            if self.log_panel_toggle_button is not None:
                self.log_panel_toggle_button.config(text="로그")
        except tk.TclError:
            self.log_panel_open = False

    def open_analysis_window(self) -> None:
        if self.analysis_window_busy:
            return
        self.analysis_window_busy = True
        try:
            if not self._sanitize_boss_name(self.analysis_boss_name_var.get()):
                self.analysis_boss_name_var.set(self._sanitize_boss_name(self.log_boss_name_var.get()))
            if not str(self.analysis_scope_value or "").strip() and not str(self.analysis_scope_folder_path or "").strip() and not self.analysis_selected_file_path:
                current_scope_value = self._get_log_stats_scope_current_label()
                self._set_analysis_scope_context(
                    current_scope_value,
                    self._get_scope_folder_path_from_value(current_scope_value),
                    selected_file_path="",
                )
            if not self.analysis_selected_file_path and not self._get_analysis_scope_folder_path() and self.log_history_selected_file_path:
                self.analysis_selected_file_path = self.log_history_selected_file_path
            if self.analysis_window is None or not self.analysis_window.winfo_exists():
                self._reset_analysis_window_references()
                self._ensure_analysis_window()
            elif self.analysis_window_open:
                self._update_analysis_scope_options()
                self.analysis_window.lift()
                return
            self.analysis_window_open = True
            self._update_analysis_scope_options()
            self._position_analysis_window()
            try:
                self.analysis_window.deiconify()
            except tk.TclError:
                pass
            self.analysis_window.lift()
            if self.analysis_auto_load_requested:
                self._schedule_analysis_auto_load()
        except tk.TclError:
            self._reset_analysis_window_references()
            return
        except Exception as exc:
            self._reset_analysis_window_references()
            try:
                with open(os.path.join(get_app_root(), "boss_timer_runtime_error.log"), "a", encoding="utf-8") as error_file:
                    error_file.write(f"\n[{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}]\n")
                    error_file.write("".join(traceback.format_exception(type(exc), exc, exc.__traceback__)))
            except OSError:
                pass
            try:
                self._show_centered_error("분석창 오류", f"{exc}\n\n자세한 내용은 boss_timer_runtime_error.log를 확인하세요.", parent=self.analysis_window)
            except tk.TclError:
                pass
            return
        finally:
            self.analysis_window_busy = False

    def _reset_analysis_window_references(self) -> None:
        try:
            if self.analysis_window is not None and self.analysis_window.winfo_exists():
                self.analysis_window.destroy()
        except tk.TclError:
            pass
        self.analysis_window = None
        self.analysis_window_open = False
        self.analysis_window_boss_entry = None
        self.analysis_window_load_button = None
        self.analysis_scope_combo = None
        self.analysis_window_count_menu = None
        self.analysis_info_box = None
        self.analysis_info_title_label = None
        self.analysis_info_note_label = None
        self.analysis_metric_box = None
        self.analysis_average_cut_label = None
        self.analysis_average_expected_label = None
        self.analysis_window_canvas = None
        self.analysis_summary_box = None
        self.analysis_summary_labels = {}
        self.analysis_window_list_text = None
        self.analysis_window_list_scrollbar = None

    def close_analysis_window(self) -> None:
        if self.analysis_auto_load_after_id is not None and self.analysis_window is not None and self._widget_available(self.analysis_window):
            try:
                self.analysis_window.after_cancel(self.analysis_auto_load_after_id)
            except tk.TclError:
                pass
        self.analysis_auto_load_after_id = None
        self.analysis_auto_load_requested = False
        try:
            if self.analysis_window is not None and self.analysis_window.winfo_exists():
                self.analysis_window.destroy()
        except tk.TclError:
            pass
        self._reset_analysis_window_references()

    def _open_analysis_window_from_log_panel(self) -> None:
        boss_name = self._sanitize_boss_name(self.log_boss_name_var.get())
        if boss_name:
            self.analysis_boss_name_var.set(boss_name)
        self._set_analysis_scope_context("", "", selected_file_path="")
        if self.log_history_selected_file_path:
            self.analysis_selected_file_path = self.log_history_selected_file_path
        self.analysis_auto_load_requested = bool(
            self._sanitize_boss_name(self.analysis_boss_name_var.get()) or self.analysis_selected_file_path
        )
        self.open_analysis_window()

    def _schedule_analysis_auto_load(self) -> None:
        if self.analysis_window is None or not self._widget_available(self.analysis_window):
            self.analysis_auto_load_requested = False
            self.analysis_auto_load_after_id = None
            return
        if self.analysis_auto_load_after_id is not None:
            try:
                self.analysis_window.after_cancel(self.analysis_auto_load_after_id)
            except tk.TclError:
                pass
        self.analysis_auto_load_after_id = self.analysis_window.after(100, self._run_analysis_auto_load)

    def _run_analysis_auto_load(self) -> None:
        self.analysis_auto_load_after_id = None
        should_load = self.analysis_auto_load_requested
        self.analysis_auto_load_requested = False
        if not should_load:
            return
        if not (self.analysis_window is not None and self._widget_available(self.analysis_window)):
            return
        if not (self._sanitize_boss_name(self.analysis_boss_name_var.get()) or self.analysis_selected_file_path):
            return
        try:
            self._load_analysis_for_current_boss()
        except Exception:
            pass

    def _position_analysis_window(self) -> None:
        if self.analysis_window is None or not self.analysis_window.winfo_exists() or not self.analysis_window_open:
            return
        if self.log_stats_window is not None and self.log_stats_window.winfo_exists() and self.log_stats_window_open:
            try:
                self.log_stats_window.update_idletasks()
            except tk.TclError:
                pass
            x = self.log_stats_window.winfo_x() + max(0, (self.log_stats_window.winfo_width() - ANALYSIS_WINDOW_WIDTH) // 2)
            y = self.log_stats_window.winfo_y() + max(0, (self.log_stats_window.winfo_height() - ANALYSIS_WINDOW_HEIGHT) // 2)
        elif self.log_panel is not None and self.log_panel.winfo_exists() and self.log_panel_open:
            x = self.log_panel.winfo_x() + self.log_panel.winfo_width() - ANALYSIS_WINDOW_WIDTH
            y = self.log_panel.winfo_y() + self.log_panel.winfo_height() + 34
        else:
            x = self.root.winfo_x() + WINDOW_WIDTH + 8
            y = self.root.winfo_y()
        self.analysis_window.geometry(f"{ANALYSIS_WINDOW_WIDTH}x{ANALYSIS_WINDOW_HEIGHT}+{x}+{y}")

    def _position_log_panel(self) -> None:
        if self.log_panel is None or not self.log_panel.winfo_exists() or not self.log_panel_open:
            return
        x = self.root.winfo_x() + WINDOW_WIDTH + 8
        y = self.root.winfo_y()
        self.log_panel.geometry(f"{LOG_PANEL_WIDTH}x{LOG_PANEL_HEIGHT}+{x}+{y}")

