    def _set_text_widget(self, widget: tk.Text, value: str, readonly: bool = True) -> None:
        if not self._widget_available(widget):
            return
        try:
            widget.config(state="normal")
            widget.delete("1.0", tk.END)
            for line in value.splitlines():
                tag = None
                if line.startswith("보스이름:"):
                    tag = "boss_name"
                elif line.startswith("컷 시간:"):
                    tag = "cut_time"
                elif line.startswith("광타임:"):
                    tag = "gwang_time"
                elif line.startswith("컷 예상:"):
                    tag = "expected_time"
                elif line.startswith("검증상태:"):
                    validation_state = line.split(":", 1)[1].strip() if ":" in line else ""
                    tag = self._get_log_validation_text_tag(validation_state)
                elif line.startswith("비고:"):
                    tag = "validation_note"
                widget.insert(tk.END, line + "\n", tag)
            widget.tag_configure("boss_name", foreground="#7c3aed")
            widget.tag_configure("cut_time", foreground="#dc2626")
            widget.tag_configure("gwang_time", foreground="#2563eb")
            widget.tag_configure("expected_time", foreground="#15803d")
            widget.tag_configure("validation_ok", foreground="#15803d")
            widget.tag_configure("validation_missing", foreground="#2563eb")
            widget.tag_configure("validation_warn", foreground="#b45309")
            widget.tag_configure("validation_error", foreground="#dc2626")
            widget.tag_configure("validation_note", foreground="#7c2d12")
            widget.config(state="disabled" if readonly else "normal")
        except tk.TclError:
            return

    def _get_log_validation_text_tag(self, validation_state: str) -> str:
        state = str(validation_state or "").strip()
        if state.startswith("검증 완료"):
            return "validation_ok"
        if state.startswith("광 시간 미확정"):
            return "validation_missing"
        if state.startswith("검증 불일치"):
            return "validation_error"
        if state in {"예상시간 계산 불가", "계산 조건 불충족", "내부 검증 불가"}:
            return "validation_warn"
        return "validation_note"

    def _on_log_history_rows_configure(self, _event=None) -> None:
        if not self._widget_available(self.log_history_canvas):
            return
        try:
            self.log_history_canvas.configure(scrollregion=self.log_history_canvas.bbox("all"))
        except tk.TclError:
            return

    def _on_log_history_canvas_configure(self, event) -> None:
        if not self._widget_available(self.log_history_canvas) or self.log_history_canvas_window is None:
            return
        try:
            self.log_history_canvas.itemconfigure(self.log_history_canvas_window, width=max(1, event.width - 2))
        except tk.TclError:
            return

    def _on_log_history_mousewheel(self, event) -> str | None:
        if not self._widget_available(self.log_history_canvas):
            return None
        delta = getattr(event, "delta", 0)
        if delta == 0:
            return "break"
        steps = int(-delta / 120)
        if steps == 0:
            steps = -1 if delta > 0 else 1
        try:
            self.log_history_canvas.yview_scroll(steps, "units")
        except tk.TclError:
            return None
        return "break"

    def _clear_log_history_rows(self) -> None:
        if not self._widget_available(self.log_history_rows_frame):
            return
        for child in self.log_history_rows_frame.winfo_children():
            try:
                child.destroy()
            except tk.TclError:
                continue

    def _get_log_history_folder_path(self) -> str:
        folder_path = (self.log_history_folder_path_var.get() or "").strip()
        if not folder_path:
            folder_path = self._get_logs_dir()
            self.log_history_folder_path_var.set(folder_path)
        return folder_path

    def _list_log_file_paths(self, folder_path: str) -> list[str]:
        if not os.path.isdir(folder_path):
            return []
        file_paths = []
        for current_root, _dirs, files in os.walk(folder_path):
            for name in files:
                if not name.lower().endswith(".json"):
                    continue
                log_path = os.path.join(current_root, name)
                if not self._read_log_records_from_path(log_path):
                    continue
                file_paths.append(log_path)
        file_paths.sort(key=lambda path: os.path.getmtime(path), reverse=True)
        return file_paths

    def _format_log_relative_updated_text(self, modified_at: datetime | None) -> str:
        if modified_at is None:
            return "--"
        delta = datetime.now() - modified_at
        total_seconds = max(0, int(delta.total_seconds()))
        if total_seconds < 300:
            return "방금전"
        if total_seconds < 3600:
            return "1시간이내"
        if total_seconds < 43200:
            return "12시간 이내"
        if modified_at.date() == datetime.now().date():
            return "오늘"
        days_ago = (datetime.now().date() - modified_at.date()).days
        return f"{days_ago}일전" if days_ago > 0 else "오늘"

    def _build_log_summary_from_records(self, boss_name: str, records: list[dict], *, period_text: str = "") -> dict[str, str]:
        sorted_records = sorted(records, key=lambda item: str(item.get("recorded_at") or ""), reverse=True)
        visible_records = sorted_records[:LOG_MAX_ENTRIES]
        cut_values = [record["actual_cut_seconds"] for record in visible_records if record.get("actual_cut_seconds") is not None]
        expected_values = [record["expected_total_seconds"] for record in visible_records if record.get("expected_total_seconds") is not None]
        created_at = "--"
        created_candidates = []
        updated_candidates = []
        for record in sorted_records:
            for key in ("created_at", "recorded_at"):
                try:
                    created_candidates.append(datetime.strptime(str(record.get(key) or ""), "%Y-%m-%d %H:%M:%S"))
                    break
                except ValueError:
                    continue
            for key in ("updated_at", "recorded_at"):
                try:
                    updated_candidates.append(datetime.strptime(str(record.get(key) or ""), "%Y-%m-%d %H:%M:%S"))
                    break
                except ValueError:
                    continue
        if created_candidates:
            created_at = min(created_candidates).strftime("%Y-%m-%d")
        updated_text = self._format_log_relative_updated_text(max(updated_candidates) if updated_candidates else None)
        average_cut = format_seconds(sum(cut_values) / len(cut_values), show_centiseconds=True) if cut_values else "--:--:--"
        average_expected = format_seconds(sum(expected_values) / len(expected_values), show_centiseconds=True) if expected_values else "--:--:--"
        return {
            "boss_name": boss_name,
            "period": period_text,
            "average_cut": average_cut,
            "average_expected": average_expected,
            "created_at": created_at,
            "updated_text": updated_text,
            "count": str(len(visible_records)),
        }

    def _get_log_file_summary(self, log_path: str) -> dict[str, str]:
        parsed_records = self._read_log_records_from_path(log_path)
        cut_values = [record["actual_cut_seconds"] for record in parsed_records if record.get("actual_cut_seconds") is not None]
        expected_values = [record["expected_total_seconds"] for record in parsed_records if record.get("expected_total_seconds") is not None]
        raw_name = self._get_boss_name_from_log_path(log_path)
        if "__" in raw_name:
            boss_name, period = raw_name.split("__", 1)
            period_text = period.replace("_", " ~ ")
        else:
            boss_name = raw_name
            period_text = ""
        created_at = "--"
        try:
            created_at = datetime.fromtimestamp(os.path.getctime(log_path)).strftime("%Y-%m-%d")
        except OSError:
            pass
        updated_text = "--"
        try:
            modified_at = datetime.fromtimestamp(os.path.getmtime(log_path))
            delta = datetime.now() - modified_at
            total_seconds = max(0, int(delta.total_seconds()))
            if total_seconds < 300:
                updated_text = "방금전"
            elif total_seconds < 3600:
                updated_text = "1시간이내"
            elif modified_at.date() == datetime.now().date():
                updated_text = "오늘"
            else:
                days_ago = (datetime.now().date() - modified_at.date()).days
                updated_text = f"{days_ago}일전" if days_ago > 0 else "오늘"
        except OSError:
            pass
        average_cut = format_seconds(sum(cut_values) / len(cut_values), show_centiseconds=True) if cut_values else "--:--:--"
        average_expected = format_seconds(sum(expected_values) / len(expected_values), show_centiseconds=True) if expected_values else "--:--:--"
        return {
            "boss_name": boss_name,
            "period": period_text,
            "average_cut": average_cut,
            "average_expected": average_expected,
            "created_at": created_at,
            "updated_text": updated_text,
            "count": str(len(parsed_records)),
        }

    def _collect_current_season_boss_summaries(self, folder_path: str) -> list[dict[str, str]]:
        grouped_records: dict[str, list[dict]] = {}
        latest_map: dict[str, datetime] = {}
        for log_path in self._list_log_file_paths(folder_path):
            for record in self._read_log_records_from_path(log_path):
                boss_name = self._get_canonical_boss_name(record.get("boss_name") or self._get_fallback_boss_name_from_log_path(log_path))
                if not boss_name:
                    continue
                grouped_records.setdefault(boss_name, []).append(record)
                try:
                    updated_at = datetime.strptime(str(record.get("updated_at") or record.get("recorded_at") or ""), "%Y-%m-%d %H:%M:%S")
                    latest_map[boss_name] = max(updated_at, latest_map.get(boss_name, updated_at))
                except ValueError:
                    continue
        summaries = [self._build_log_summary_from_records(boss_name, records) for boss_name, records in grouped_records.items()]
        summaries.sort(key=lambda item: latest_map.get(item["boss_name"], datetime.min), reverse=True)
        return summaries

    def _bind_log_history_card_click(self, widget: tk.Widget, callback) -> None:
        try:
            widget.bind("<Button-1>", lambda _event: callback())
        except tk.TclError:
            return
        for child in widget.winfo_children():
            if isinstance(child, (tk.Button, tk.Entry, tk.Text, tk.Scrollbar)):
                continue
            self._bind_log_history_card_click(child, callback)

    def _set_log_history_card_bg(self, widget: tk.Widget, bg_color: str) -> None:
        try:
            widget_type = widget.winfo_class()
            if widget_type in {"Frame", "Label"}:
                widget.configure(bg=bg_color)
        except tk.TclError:
            return
        for child in widget.winfo_children():
            self._set_log_history_card_bg(child, bg_color)

    def _bind_log_history_card_hover(self, widget: tk.Widget, card: tk.Widget, normal_bg: str, hover_bg: str) -> None:
        try:
            widget.bind("<Enter>", lambda _event: self._set_log_history_card_bg(card, hover_bg))
            widget.bind("<Leave>", lambda _event: self._set_log_history_card_bg(card, normal_bg))
        except tk.TclError:
            return
        for child in widget.winfo_children():
            self._bind_log_history_card_hover(child, card, normal_bg, hover_bg)

    def _get_log_history_card_hover_colors(self, boss_name: str) -> tuple[str, str]:
        canonical_name = self._get_canonical_boss_name(boss_name)
        section_name = str(self.record_book_catalog_map.get(canonical_name, {}).get("display_area") or "기타")
        hover_colors = {
            "절대자": "#fef3c7",
            "요툰하임": "#dbeafe",
            "니다벨리르": "#dcfce7",
            "알브하임": "#ffedd5",
            "무스펠하임": "#fee2e2",
            "아스가르드": "#ede9fe",
            "니플하임": "#cffafe",
            "바나하임": "#e0e7ff",
            "던전": "#e2e8f0",
            "기타": "#f3e8ff",
        }
        return "#f8f1df", hover_colors.get(section_name, "#eff6ff")

    def _get_log_record_boss_color(self, boss_name: str) -> str:
        canonical_name = self._get_canonical_boss_name(boss_name)
        section_name = str(self.record_book_catalog_map.get(canonical_name, {}).get("display_area") or "기타")
        fg_colors = {
            "절대자": "#854d0e",
            "요툰하임": "#1d4ed8",
            "니다벨리르": "#15803d",
            "알브하임": "#c2410c",
            "무스펠하임": "#b91c1c",
            "아스가르드": "#6d28d9",
            "니플하임": "#0f766e",
            "바나하임": "#4338ca",
            "던전": "#334155",
            "기타": "#7e22ce",
        }
        return fg_colors.get(section_name, "#7e22ce")

    def _get_log_validation_colors(self, validation_state: str) -> tuple[str, str]:
        state = str(validation_state or "").strip()
        if state.startswith("검증 완료"):
            return "#15803d", "#15803d"
        if state.startswith("광 시간 미확정"):
            return "#2563eb", "#2563eb"
        if state.startswith("검증 불일치"):
            return "#dc2626", "#dc2626"
        if state in {"예상시간 계산 불가", "계산 조건 불충족", "내부 검증 불가"}:
            return "#b45309", "#b45309"
        return "#334155", "#7c2d12"

    def _render_log_file_summary_cards(self, summaries: list[dict[str, str]], open_callback) -> None:
        self._clear_log_history_rows()
        for summary in summaries:
            normal_bg, hover_bg = self._get_log_history_card_hover_colors(summary["boss_name"])
            card = tk.Frame(self.log_history_rows_frame, bg=normal_bg, relief="solid", bd=1, cursor="hand2")
            card.pack(fill="x", padx=8, pady=4)
            top = tk.Frame(card, bg=normal_bg, height=24)
            top.pack(fill="x", padx=7, pady=(6, 1))
            top.pack_propagate(False)
            top_columns = [
                ("보스이름:", summary["boss_name"], "#0f172a", 172),
                ("생성:", summary["created_at"], "#475569", 122),
            ]
            for label_text, value_text, value_color, column_width in top_columns:
                cell = tk.Frame(top, bg=normal_bg, width=column_width, height=24)
                cell.pack(side="left", fill="y")
                cell.pack_propagate(False)
                tk.Label(
                    cell,
                    text=label_text,
                    font=(self.current_font_family, 8, "bold"),
                    bg=normal_bg,
                    fg="#64748b",
                    anchor="w",
                ).pack(side="left")
                tk.Label(
                    cell,
                    text=value_text,
                    font=(self.current_font_family, 9, "bold"),
                    bg=normal_bg,
                    fg=value_color,
                    anchor="w",
                ).pack(side="left", padx=(2, 0))
            body = tk.Frame(card, bg=normal_bg, height=24)
            body.pack(fill="x", padx=7, pady=(0, 6))
            body.pack_propagate(False)
            left_metrics = tk.Frame(body, bg=normal_bg)
            left_metrics.pack(side="left", fill="both", expand=True)
            right_metric = tk.Frame(body, bg=normal_bg, width=104, height=24)
            right_metric.pack(side="right", fill="y", padx=(0, 12))
            right_metric.pack_propagate(False)

            left_columns = [
                ("평균 컷", summary["average_cut"], "#dc2626", 107, "w"),
                ("기록", summary["count"], "#1d4ed8", 56, "center"),
            ]
            for index, (label_text, value_text, value_color, column_width, align_mode) in enumerate(left_columns):
                cell = tk.Frame(left_metrics, bg=normal_bg, width=column_width, height=24)
                cell.pack(side="left", fill="y")
                cell.pack_propagate(False)
                anchor_mode = "center" if align_mode == "center" else "w"
                tk.Label(
                    cell,
                    text=label_text,
                    font=(self.current_font_family, 8, "bold"),
                    bg=normal_bg,
                    fg="#64748b",
                    anchor=anchor_mode,
                    justify="center" if align_mode == "center" else "left",
                ).pack(side="left", padx=(0, 3) if align_mode != "center" else (0, 0))
                tk.Label(
                    cell,
                    text=value_text,
                    font=(self.current_font_family, 8, "bold"),
                    bg=normal_bg,
                    fg=value_color,
                    anchor=anchor_mode,
                    justify="center" if align_mode == "center" else "left",
                ).pack(side="left", padx=(0, 0))
                if index < len(left_columns) - 1:
                    divider = tk.Frame(left_metrics, bg="#e2e8f0", width=1, height=18)
                    divider.pack(side="left", padx=(3, 5), pady=3)

            tk.Label(
                right_metric,
                text="갱신:",
                font=(self.current_font_family, 8, "bold"),
                bg=normal_bg,
                fg="#64748b",
                anchor="w",
            ).pack(side="left")
            tk.Label(
                right_metric,
                text=summary["updated_text"],
                font=(self.current_font_family, 8, "bold"),
                bg=normal_bg,
                fg="#475569",
                anchor="w",
            ).pack(side="left", padx=(3, 0))
            self._bind_log_history_card_click(card, lambda item=summary: open_callback(item))
            self._bind_log_history_card_hover(card, card, normal_bg, hover_bg)
        self._bind_log_history_scroll_recursive(self.log_history_rows_frame)
        self._on_log_history_rows_configure()
        if self._widget_available(self.log_history_canvas):
            self.log_history_canvas.yview_moveto(0.0)

    def _bind_log_history_scroll_recursive(self, widget: tk.Widget) -> None:
        try:
            widget.bind("<MouseWheel>", self._on_log_history_mousewheel)
        except tk.TclError:
            return
        for child in widget.winfo_children():
            self._bind_log_history_scroll_recursive(child)

    def _render_log_history_message(self, message: str) -> None:
        self._clear_log_history_rows()
        if not self._widget_available(self.log_history_rows_frame):
            return
        label = tk.Label(
            self.log_history_rows_frame,
            text=message,
            font=(self.current_font_family, 10, "bold"),
            bg="#eff6ff",
            fg="#475569",
            justify="left",
            anchor="nw",
            wraplength=286,
        )
        label.pack(fill="x", padx=10, pady=10)
        self._bind_log_history_scroll_recursive(self.log_history_rows_frame)
        self._on_log_history_rows_configure()

    def open_log_history_folder(self) -> None:
        folder_path = self._get_log_history_folder_path()
        if not os.path.isdir(folder_path):
            self.log_status_var.set("입력한 폴더 경로가 없습니다.")
            return
        try:
            os.startfile(folder_path)
        except OSError:
            self.log_status_var.set("폴더를 열 수 없습니다.")

    def open_log_archive_folder(self) -> None:
        folder_path = self._get_log_archive_dir()
        if not os.path.isdir(folder_path):
            self.log_archive_status_var.set("보관 폴더 경로가 없습니다.")
            return
        try:
            os.startfile(folder_path)
        except OSError:
            self.log_archive_status_var.set("보관 폴더를 열 수 없습니다.")

    def _get_archive_keep_seasons_value(self) -> int:
        return max(0, self._parse_int(self.archive_keep_seasons_var.get(), self.archive_keep_seasons_default))

    def _sync_log_archive_view_text(self, *_args) -> None:
        if not self._widget_available(self.log_archive_view_text):
            return
        summary_text = str(self.log_archive_summary_var.get() or "").strip()
        status_text = str(self.log_archive_status_var.get() or "").strip()
        message_parts = [text for text in (summary_text, status_text) if text]
        self._set_text_widget(
            self.log_archive_view_text,
            "\n".join(message_parts) if message_parts else "보관 시즌 정보를 불러오세요.",
        )
        self.log_archive_view_text.config(bg="#f8f1df")
        self.log_archive_view_text.config(fg="#1d4ed8")

    def _update_archive_keep_seasons_description(self) -> None:
        self.log_archive_current_season_var.set(
            f"현재 시즌: {self._get_archive_season_label(self.current_season_no) if self._has_active_season() else '-'}"
        )

    def _on_archive_keep_seasons_var_write(self, *_args) -> None:
        raw_value = self.archive_keep_seasons_var.get()
        cleaned = re.sub(r"[^0-9]", "", raw_value)
        if cleaned != raw_value:
            self.archive_keep_seasons_var.set(cleaned)
            return
        self._update_archive_keep_seasons_description()
        self._save_settings()

    def _on_log_archive_rows_configure(self, _event=None) -> None:
        if not self._widget_available(self.log_archive_rows_canvas) or not self._widget_available(self.log_archive_rows_frame):
            return
        self.log_archive_rows_canvas.configure(scrollregion=self.log_archive_rows_canvas.bbox("all"))
        try:
            self.log_archive_rows_canvas.itemconfigure(self.log_archive_rows_window, width=max(1, self.log_archive_rows_canvas.winfo_width() - 2))
        except tk.TclError:
            return

    def _get_log_archive_filter_mode(self) -> str:
        return "all"

    def _on_log_archive_previous_season_selected(self, _event=None) -> None:
        return

    def _set_log_archive_filter(self, mode: str) -> None:
        self._refresh_archive_management_view()

    def _update_log_archive_filter_buttons(self) -> None:
        return

    def _get_archive_management_all_entries(self) -> list[dict[str, str]]:
        archive_dir = self._get_log_archive_dir()
        entries: list[dict[str, str]] = []
        try:
            season_names = [name for name in os.listdir(archive_dir) if os.path.isdir(os.path.join(archive_dir, name))]
        except OSError:
            season_names = []
        current_season_text = re.sub(r"[^0-9]", "", str(self.current_season_no or "").strip())
        for season_name in season_names:
            season_no_text = self._get_archive_entry_season_no_from_label(season_name)
            season_root = os.path.join(archive_dir, season_name)
            json_paths: list[str] = []
            month_names: set[str] = set()
            for current_root, _dirs, files in os.walk(season_root):
                relative_dir = os.path.relpath(current_root, season_root)
                if relative_dir not in {".", ""}:
                    month_names.add(relative_dir.split(os.sep, 1)[0])
                for name in files:
                    if name.lower().endswith(".json"):
                        json_paths.append(os.path.join(current_root, name))
            if not json_paths:
                continue
            latest_timestamp = 0.0
            total_record_count = 0
            for file_path in json_paths:
                try:
                    latest_timestamp = max(latest_timestamp, os.path.getmtime(file_path))
                except OSError:
                    continue
                total_record_count += len(self._read_log_records_from_path(file_path))
            season_history = dict(self.season_history_map.get(season_no_text) or {})
            started_at_text = str(season_history.get("started_at") or "").strip()
            ended_at_text = str(season_history.get("ended_at") or "").strip()
            if not started_at_text and current_season_text and season_no_text == current_season_text:
                started_at_text = str(self.current_season_started_at or "").strip()
            entries.append(
                {
                    "season_label": season_name,
                    "folder_name": season_name,
                    "season_no_text": season_no_text,
                    "file_count": str(len(json_paths)),
                    "record_count": str(total_record_count),
                    "month_count": str(len(month_names)),
                    "latest_text": datetime.fromtimestamp(latest_timestamp).strftime("%Y-%m-%d") if latest_timestamp > 0 else "--",
                    "started_at": started_at_text,
                    "ended_at": ended_at_text,
                    "is_current": str(bool(current_season_text and season_no_text == current_season_text)),
                    "is_cleanup_target": str(
                        bool(
                            current_season_text
                            and season_no_text
                            and int(season_no_text) < max(0, int(current_season_text) - self._get_archive_keep_seasons_value())
                        )
                    ),
                }
            )
        def sort_key(entry: dict[str, str]) -> tuple[int, int, str]:
            season_no_text = entry.get("season_no_text", "")
            if season_no_text.isdigit():
                return (1, int(season_no_text), entry["season_label"])
            return (0, -1, entry["season_label"])
        return sorted(entries, key=sort_key, reverse=True)

    def _update_log_archive_previous_season_options(self) -> None:
        return

    def _collect_archive_management_entries(self) -> list[dict[str, str]]:
        return self._get_archive_management_all_entries()

    def _set_log_archive_detail_text(self, text: str) -> None:
        if not self._widget_available(self.log_archive_detail_text):
            return
        self._set_text_widget(self.log_archive_detail_text, text)

    def _get_log_archive_selected_entry(self, entries: list[dict[str, str]]) -> dict[str, str] | None:
        if not entries:
            self.log_archive_selected_season_var.set("")
            return None
        selected_label = str(self.log_archive_selected_season_var.get() or "").strip()
        if selected_label:
            for entry in entries:
                if entry.get("season_label") == selected_label:
                    return entry
        selected_label = str(entries[0].get("season_label") or "")
        self.log_archive_selected_season_var.set(selected_label)
        return entries[0]

    def _select_log_archive_season(self, season_label: str) -> None:
        self.log_archive_selected_season_var.set(str(season_label or "").strip())
        self._refresh_archive_management_view()

    def _build_log_archive_detail_text(self, entry: dict[str, str] | None) -> str:
        if not entry:
            return "선택된 시즌이 없습니다."
        ended_at = str(entry.get("ended_at") or "").strip()
        status_text = "진행중" if entry.get("is_current") == "True" and not ended_at else ("종료됨" if ended_at else "기록만 존재")
        detail_lines = [
            f"시즌: {entry.get('season_label', '-')}",
            f"폴더: {entry.get('folder_name', '-')}",
            f"상태: {status_text}",
            f"시작일: {str(entry.get('started_at') or '-').strip() or '-'}",
            f"종료일: {ended_at or '-'}",
            f"파일 수: {entry.get('file_count', '0')}개",
            f"개월 수: {entry.get('month_count', '0')}개",
            f"기록 수: {entry.get('record_count', '0')}건",
            f"최근 기록: {entry.get('latest_text', '--')}",
        ]
        if entry.get("is_cleanup_target") == "True":
            detail_lines.append("정리대상: 현재 파일 유지 기준에서 벗어난 시즌입니다.")
        return "\n".join(detail_lines)

    def _open_selected_archive_management_season_folder(self) -> None:
        season_label = str(self.log_archive_selected_season_var.get() or "").strip()
        if not season_label:
            self.log_archive_status_var.set("선택된 시즌이 없습니다.")
            return
        self._open_archive_management_season_folder(season_label)

    def _rename_selected_archive_management_season(self) -> None:
        entries = self._collect_archive_management_entries()
        selected_entry = self._get_log_archive_selected_entry(entries)
        if not selected_entry:
            self.log_archive_status_var.set("이름을 바꿀 시즌이 없습니다.")
            return
        current_label = str(selected_entry.get("season_label") or "").strip()
        if not current_label:
            self.log_archive_status_var.set("선택된 시즌 이름을 찾지 못했습니다.")
            return
        host = self.log_panel if self._widget_available(self.log_panel) else self.root
        if host is None:
            return
        dialog = tk.Toplevel(host)
        dialog.title("시즌명 변경")
        dialog.resizable(False, False)
        dialog.configure(bg="#eff6ff")
        self._center_window_over_parent(dialog, host, 392, 190)
        tk.Label(dialog, text="보관 시즌명 변경", font=self.header_font, bg="#dbeafe", fg="#0f172a").place(x=0, y=0, width=392, height=40)
        tk.Label(dialog, text="현재 이름", font=self.label_font, bg="#eff6ff", fg="#0f172a", anchor="w").place(x=18, y=56, width=72, height=22)
        tk.Label(dialog, text=current_label, font=(self.current_font_family, 9, "bold"), bg="#eff6ff", fg="#475569", anchor="w").place(x=92, y=56, width=282, height=22)
        tk.Label(dialog, text="새 이름", font=self.label_font, bg="#eff6ff", fg="#0f172a", anchor="w").place(x=18, y=88, width=72, height=22)
        new_name_var = tk.StringVar(value=current_label)
        status_var = tk.StringVar(value="폴더 이름이 실제로 변경됩니다.")
        entry = tk.Entry(
            dialog,
            textvariable=new_name_var,
            font=(self.current_font_family, 10, "bold"),
            bd=1,
            relief="solid",
            bg="#ffffff",
            fg="#0f172a",
        )
        entry.place(x=92, y=86, width=282, height=28)
        tk.Label(dialog, textvariable=status_var, font=(self.current_font_family, 9, "bold"), bg="#eff6ff", fg="#475569", anchor="w").place(x=18, y=122, width=356, height=18)

        def close_dialog() -> None:
            try:
                dialog.grab_release()
            except tk.TclError:
                pass
            dialog.destroy()

        def apply_rename() -> None:
            new_label = str(new_name_var.get() or "").strip()
            if not new_label:
                status_var.set("새 이름을 입력하세요.")
                return
            if new_label == current_label:
                close_dialog()
                return
            if re.search(r'[<>:\"/\\\\|?*]', new_label):
                status_var.set("Windows 폴더 이름에 사용할 수 없는 문자가 포함되어 있습니다.")
                return
            old_dir = os.path.join(self._get_log_archive_dir(), current_label)
            new_dir = os.path.join(self._get_log_archive_dir(), new_label)
            if not os.path.isdir(old_dir):
                status_var.set("원본 시즌 폴더를 찾지 못했습니다.")
                return
            if os.path.exists(new_dir):
                status_var.set("같은 이름의 시즌 폴더가 이미 있습니다.")
                return
            try:
                os.rename(old_dir, new_dir)
            except OSError:
                status_var.set("시즌 폴더 이름을 변경하지 못했습니다.")
                return
            season_no_text = str(selected_entry.get("season_no_text") or "").strip()
            if season_no_text:
                season_entry = dict(self.season_history_map.get(season_no_text) or {"season_no": season_no_text})
                default_label = f"{int(season_no_text)}차 시즌"
                season_entry["archive_label"] = "" if new_label == default_label else new_label
                self.season_history_map[season_no_text] = season_entry
                self._save_season_history()
            self.log_archive_selected_season_var.set(new_label)
            self.log_archive_status_var.set(f"보관 시즌 이름을 '{new_label}'로 변경했습니다.")
            self._refresh_archive_management_view()
            close_dialog()

        tk.Button(dialog, text="변경", font=self.button_font, bg="#2563eb", fg="#ffffff", activebackground="#1d4ed8", activeforeground="#ffffff", relief="raised", bd=1, highlightthickness=0, command=apply_rename, cursor="hand2").place(x=202, y=150, width=80, height=28)
        tk.Button(dialog, text="취소", font=self.button_font, bg="#e2e8f0", fg="#334155", activebackground="#cbd5e1", activeforeground="#334155", relief="raised", bd=1, highlightthickness=0, command=close_dialog, cursor="hand2").place(x=294, y=150, width=80, height=28)
        dialog.bind("<Return>", lambda _event: apply_rename())
        dialog.bind("<Escape>", lambda _event: close_dialog())
        dialog.grab_set()
        entry.focus_force()
        entry.selection_range(0, "end")

    def _delete_selected_archive_management_season(self) -> None:
        entries = self._collect_archive_management_entries()
        selected_entry = self._get_log_archive_selected_entry(entries)
        if not selected_entry:
            self.log_archive_status_var.set("삭제할 시즌이 없습니다.")
            return
        if str(selected_entry.get("is_current") or "") == "True":
            self.log_archive_status_var.set("현재 시즌은 삭제할 수 없습니다.")
            return
        current_label = str(selected_entry.get("season_label") or "").strip()
        if not current_label:
            self.log_archive_status_var.set("선택된 시즌 이름을 찾지 못했습니다.")
            return
        host = self.log_panel if self._widget_available(self.log_panel) else self.root
        if host is None:
            return
        dialog = tk.Toplevel(host)
        dialog.title("시즌 삭제")
        dialog.resizable(False, False)
        dialog.configure(bg="#fff1f2")
        self._center_window_over_parent(dialog, host, 420, 228)
        tk.Label(dialog, text="과거 시즌 완전 삭제", font=self.header_font, bg="#fecdd3", fg="#881337").place(x=0, y=0, width=420, height=40)
        tk.Label(
            dialog,
            text="폴더와 시즌 메타데이터가 함께 삭제됩니다.\n삭제하려면 아래에 시즌명을 정확히 입력하세요.",
            font=(self.current_font_family, 9, "bold"),
            bg="#fff1f2",
            fg="#881337",
            justify="left",
            anchor="w",
        ).place(x=18, y=54, width=384, height=40)
        tk.Label(dialog, text="삭제 대상", font=self.label_font, bg="#fff1f2", fg="#0f172a", anchor="w").place(x=18, y=102, width=72, height=22)
        tk.Label(dialog, text=current_label, font=(self.current_font_family, 9, "bold"), bg="#fff1f2", fg="#475569", anchor="w").place(x=94, y=102, width=308, height=22)
        tk.Label(dialog, text="시즌명 입력", font=self.label_font, bg="#fff1f2", fg="#0f172a", anchor="w").place(x=18, y=132, width=72, height=22)
        confirm_var = tk.StringVar(value="")
        status_var = tk.StringVar(value="시즌명을 정확히 입력해야 삭제됩니다.")
        entry = tk.Entry(
            dialog,
            textvariable=confirm_var,
            font=(self.current_font_family, 10, "bold"),
            bd=1,
            relief="solid",
            bg="#ffffff",
            fg="#0f172a",
        )
        entry.place(x=94, y=130, width=308, height=28)
        tk.Label(dialog, textvariable=status_var, font=(self.current_font_family, 9, "bold"), bg="#fff1f2", fg="#9f1239", anchor="w").place(x=18, y=166, width=384, height=18)

        def close_dialog() -> None:
            try:
                dialog.grab_release()
            except tk.TclError:
                pass
            dialog.destroy()

        def apply_delete() -> None:
            if str(confirm_var.get() or "").strip() != current_label:
                status_var.set("시즌명이 일치하지 않습니다.")
                return
            season_dir = os.path.join(self._get_log_archive_dir(), current_label)
            try:
                if os.path.isdir(season_dir):
                    shutil.rmtree(season_dir)
            except OSError:
                status_var.set("시즌 폴더를 삭제하지 못했습니다.")
                return
            season_no_text = str(selected_entry.get("season_no_text") or "").strip()
            if season_no_text:
                self.season_history_map.pop(season_no_text, None)
                self._save_season_history()
            self.log_archive_selected_season_var.set("")
            self.log_archive_status_var.set(f"보관 시즌 '{current_label}'을 삭제했습니다.")
            self._refresh_archive_management_view()
            close_dialog()

        tk.Button(dialog, text="삭제", font=self.button_font, bg="#dc2626", fg="#ffffff", activebackground="#b91c1c", activeforeground="#ffffff", relief="raised", bd=1, highlightthickness=0, command=apply_delete, cursor="hand2").place(x=230, y=188, width=80, height=28)
        tk.Button(dialog, text="취소", font=self.button_font, bg="#e2e8f0", fg="#334155", activebackground="#cbd5e1", activeforeground="#334155", relief="raised", bd=1, highlightthickness=0, command=close_dialog, cursor="hand2").place(x=322, y=188, width=80, height=28)
        dialog.bind("<Return>", lambda _event: apply_delete())
        dialog.bind("<Escape>", lambda _event: close_dialog())
        dialog.grab_set()
        entry.focus_force()

    def _refresh_archive_management_view(self) -> None:
        self._prune_missing_archive_history_entries()
        self._update_archive_keep_seasons_description()
        self._update_log_archive_filter_buttons()
        self._update_log_archive_previous_season_options()
        if not self._widget_available(self.log_archive_rows_frame):
            return
        for child in self.log_archive_rows_frame.winfo_children():
            child.destroy()
        entries = self._collect_archive_management_entries()
        total_files = sum(int(entry.get("file_count", "0") or 0) for entry in entries)
        self.log_archive_summary_var.set(f"시즌 {len(entries)}개 | 파일 {total_files}개")
        selected_entry = self._get_log_archive_selected_entry(entries)
        if self._widget_available(self.log_archive_detail_open_button):
            self.log_archive_detail_open_button.config(state="normal" if selected_entry else "disabled")
        if self._widget_available(self.log_archive_rename_button):
            self.log_archive_rename_button.config(state="normal" if selected_entry else "disabled")
        if self._widget_available(self.log_archive_delete_button):
            can_delete = bool(selected_entry and str(selected_entry.get("is_current") or "") != "True")
            self.log_archive_delete_button.config(state="normal" if can_delete else "disabled")
        if not entries:
            self._set_log_archive_detail_text("표시할 시즌이 없습니다.")
            label = tk.Label(
                self.log_archive_rows_frame,
                text="보관된 시즌 파일이 없습니다.",
                font=(self.current_font_family, 10, "bold"),
                bg="#eff6ff",
                fg="#475569",
                anchor="w",
                justify="left",
            )
            label.pack(fill="x", padx=10, pady=10)
        else:
            self._set_log_archive_detail_text(self._build_log_archive_detail_text(selected_entry))
            for entry in entries:
                season_label = entry["season_label"]
                selected = bool(selected_entry and selected_entry.get("season_label") == season_label)
                row_bg = "#dbeafe" if selected else ("#eef2ff" if entry.get("is_current") == "True" else "#ffffff")
                row_fg = "#1d4ed8" if selected else "#0f172a"
                row_button = tk.Button(
                    self.log_archive_rows_frame,
                    text=season_label,
                    font=(self.current_font_family, 9, "bold"),
                    bg=row_bg,
                    fg=row_fg,
                    activebackground="#bfdbfe" if selected else "#e2e8f0",
                    activeforeground=row_fg,
                    relief="sunken" if selected else "raised",
                    bd=1,
                    highlightthickness=0,
                    command=lambda label=season_label: self._select_log_archive_season(label),
                    cursor="hand2",
                    anchor="w",
                    padx=8,
                )
                row_button.pack(fill="x", padx=6, pady=4)
        self._bind_log_history_scroll_recursive(self.log_archive_rows_frame)
        self._on_log_archive_rows_configure()
        if self._widget_available(self.log_archive_rows_canvas):
            self.log_archive_rows_canvas.yview_moveto(0.0)

    def _open_archive_management_season_folder(self, season_label: str) -> None:
        season_dir = os.path.join(self._get_log_archive_dir(), season_label)
        if not os.path.isdir(season_dir):
            self.log_archive_status_var.set("선택한 시즌 폴더를 찾을 수 없습니다.")
            return
        try:
            os.startfile(season_dir)
        except OSError:
            self.log_archive_status_var.set("시즌 폴더를 열 수 없습니다.")

    def run_archive_management_cleanup(self) -> None:
        if not self._has_active_season():
            self.log_archive_status_var.set("먼저 시즌을 시작해야 보관 정리를 실행할 수 있습니다.")
            return
        current_season = int(self.current_season_no)
        keep_seasons = self._get_archive_keep_seasons_value()
        threshold = current_season - keep_seasons
        archive_dir = self._get_log_archive_dir()
        removable_dirs: list[str] = []
        removable_labels: list[str] = []
        for name in os.listdir(archive_dir):
            full_path = os.path.join(archive_dir, name)
            if not os.path.isdir(full_path):
                continue
            match = re.fullmatch(r"(\d+)차 시즌", name)
            if not match:
                continue
            if int(match.group(1)) < threshold:
                removable_dirs.append(full_path)
                removable_labels.append(name)
        if not removable_dirs:
            self.log_archive_status_var.set("정리할 오래된 시즌 보관 파일이 없습니다.")
            self._refresh_archive_management_view()
            return
        message = (
            f"현재 시즌 기준 {keep_seasons} 시즌 전까지 유지합니다.\n\n"
            f"다음 시즌 보관 폴더를 정리할까요?\n- " + "\n- ".join(removable_labels)
        )
        if not self._show_centered_yesno("보관 정리", message, parent=self.log_panel):
            self.log_archive_status_var.set("보관 정리를 취소했습니다.")
            return
        removed_count = 0
        for directory in removable_dirs:
            try:
                shutil.rmtree(directory)
                removed_count += 1
            except OSError:
                continue
        self.log_archive_status_var.set(f"보관 시즌 폴더 {removed_count}개를 정리했습니다.")
        self._refresh_archive_management_view()

    def browse_log_history_folder(self) -> None:
        initial_dir = self._get_log_history_folder_path()
        try:
            selected_dir = filedialog.askdirectory(
                parent=self.log_panel,
                initialdir=initial_dir if os.path.isdir(initial_dir) else get_app_root(),
                title="로그 폴더 선택",
            )
        except tk.TclError:
            return
        if not selected_dir:
            return
        self.log_history_folder_path_var.set(selected_dir)
        self.log_status_var.set("로그 폴더 경로를 선택했습니다.")

    def show_log_file_list(self) -> None:
        folder_path = self._get_log_history_folder_path()
        current_boss_name = self._sanitize_boss_name(self.log_boss_name_var.get())
        if current_boss_name:
            self.log_non_archive_boss_name = self.log_boss_name_var.get()
        self.log_history_mode_var.set("files")
        self.log_history_selected_file_path = ""
        if not os.path.isdir(folder_path):
            self.log_status_var.set("입력한 폴더 경로가 없습니다.")
            self._render_log_history_message("유효한 폴더 경로를 입력한 뒤 보스목록 보기를 눌러주세요.")
            return
        summaries = self._collect_current_season_boss_summaries(folder_path)
        if not summaries:
            self.log_status_var.set("표시할 로그 파일이 없습니다.")
            self._render_log_history_message("표시할 로그 파일이 없습니다.")
            return
        self._render_log_file_summary_cards(summaries, self._open_log_history_file)
        self.log_status_var.set("로그 파일 목록을 불러왔습니다.")

    def _open_log_history_file(self, summary: dict[str, str]) -> None:
        boss_name = self._get_canonical_boss_name(summary.get("boss_name") or "") or str(summary.get("boss_name") or "")
        self.log_history_selected_file_path = ""
        self.log_history_mode_var.set("records")
        self.log_boss_name_var.set(boss_name)
        self.load_current_boss_log()

