    def _parse_log_record_text(self, raw_text: str, fallback_boss_name: str = "") -> tuple[dict | None, str | None]:
        block_text = (raw_text or "").strip()
        if not block_text:
            return None, "기록 내용이 비어 있습니다."
        parsed = self._parse_log_block(block_text)
        boss_name = self._sanitize_boss_name(self._get_canonical_boss_name(parsed.get("boss_name") or fallback_boss_name))
        if not boss_name:
            return None, "보스 이름을 확인하세요."
        actual_cut_time = parsed.get("actual_cut_time", "")
        actual_cut_seconds = self._parse_log_time_value(actual_cut_time)
        if actual_cut_seconds is None:
            return None, "컷 시간 형식을 확인하세요."
        expected_time = parsed.get("expected_time") or "계산 불가"
        overrun_time = parsed.get("overrun_time") or "계산 불가"
        gwang_time = parsed.get("gwang_time") or "미확정"
        expected_total_seconds = self._parse_log_time_value(expected_time) if expected_time != "계산 불가" else None
        overrun_seconds = self._parse_log_time_value(overrun_time) if overrun_time != "계산 불가" else None
        gwang_seconds = self._parse_log_time_value(gwang_time) if gwang_time != "미확정" else None
        if expected_time != "계산 불가" and expected_total_seconds is None:
            return None, "컷 예상 형식을 확인하세요."
        if overrun_time != "계산 불가" and overrun_seconds is None:
            return None, "초과시간 형식을 확인하세요."
        if gwang_time != "미확정" and gwang_seconds is None:
            return None, "광타임 형식을 확인하세요."
        record = {
            "recorded_at": parsed.get("recorded_at") or datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
            "boss_name": boss_name,
            "validation_state": parsed.get("validation_state") or "수동 수정",
            "validation_note": parsed.get("validation_note", ""),
            "gwang_time": gwang_time,
            "expected_time": expected_time,
            "actual_cut_time": actual_cut_time,
            "overrun_time": overrun_time,
            "gwang_seconds": gwang_seconds,
            "expected_total_seconds": expected_total_seconds,
            "actual_cut_seconds": actual_cut_seconds,
            "overrun_seconds": overrun_seconds,
        }
        return record, None

    def _open_log_record_edit_dialog(self, log_path: str, record_id: str) -> None:
        if self.log_panel is None or not self.log_panel.winfo_exists():
            return
        records = self._read_log_records_from_path(log_path)
        block_index = next((index for index, item in enumerate(records) if str(item.get("record_id") or "") == str(record_id)), -1)
        if block_index < 0:
            return
        dialog = tk.Toplevel(self.log_panel)
        dialog.title("기록 수정")
        dialog.resizable(False, False)
        dialog.configure(bg="#eff6ff")
        self._center_window_over_parent(dialog, self.log_panel, 420, 360)
        tk.Label(dialog, text="기록 수정", font=self.header_font, bg="#dbeafe", fg="#0f172a").place(x=0, y=0, width=420, height=40)
        status_var = tk.StringVar(value="기록 내용을 수정한 뒤 저장하세요.")
        editor = tk.Text(
            dialog,
            font=(self.current_font_family, 10, "bold"),
            bg="#ffffff",
            fg="#334155",
            relief="solid",
            bd=1,
            wrap="word",
        )
        editor.place(x=16, y=54, width=388, height=244)
        editor.insert("1.0", self._format_log_record_block(records[block_index]))
        tk.Label(dialog, textvariable=status_var, font=(self.current_font_family, 9, "bold"), bg="#eff6ff", fg="#475569", anchor="w", justify="left").place(x=16, y=306, width=388, height=20)

        def save_edit() -> None:
            updated_record, error_message = self._parse_log_record_text(
                editor.get("1.0", "end"),
                fallback_boss_name=self._get_fallback_boss_name_from_log_path(log_path),
            )
            if updated_record is None:
                status_var.set(error_message or "수정 내용을 저장할 수 없습니다.")
                return
            source_records = self._read_log_records_from_path(log_path)
            if not (0 <= block_index < len(source_records)):
                status_var.set("원본 기록을 찾을 수 없습니다.")
                return
            existing_record = source_records.pop(block_index)
            updated_record["updated_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            prepared_record = self._prepare_log_record_for_storage(updated_record, existing_record=existing_record)
            target_path = os.path.join(
                self._get_log_month_dir(prepared_record.get("season_no"), prepared_record.get("recorded_at")),
                f"{self._sanitize_boss_name(updated_record['boss_name']) or '미지정보스'}.json",
            )
            if os.path.normcase(os.path.abspath(target_path)) == os.path.normcase(os.path.abspath(log_path)):
                source_records.insert(block_index, prepared_record)
                self._save_or_remove_log_records_to_path(log_path, source_records, max_entries=None)
                selected_path = log_path
            else:
                self._save_or_remove_log_records_to_path(log_path, source_records, max_entries=None)
                target_records = self._read_log_records_from_path(target_path)
                target_records.insert(0, prepared_record)
                self._write_log_records_to_path(target_path, target_records)
                selected_path = target_path
            self._invalidate_record_book_average_cache()
            self._refresh_record_stats_if_visible()
            self._refresh_log_stats_if_visible(force_reload=True)
            self.log_status_var.set(f"{updated_record['boss_name']} 기록을 수정했습니다.")
            self.log_history_selected_file_path = selected_path
            self.log_history_mode_var.set("records")
            self.log_boss_name_var.set(updated_record["boss_name"])
            self.load_current_boss_log()
            dialog.destroy()

        tk.Button(dialog, text="저장", font=self.button_font, bg="#16a34a", fg="#ffffff", activebackground="#15803d", activeforeground="#ffffff", relief="raised", bd=1, highlightthickness=0, command=save_edit, cursor="hand2").place(x=211, y=325, width=88, height=30)
        tk.Button(dialog, text="취소", font=self.button_font, bg="#e2e8f0", fg="#334155", activebackground="#cbd5e1", activeforeground="#334155", relief="raised", bd=1, highlightthickness=0, command=dialog.destroy, cursor="hand2").place(x=312, y=325, width=88, height=30)
        dialog.grab_set()

